int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // To maximize the number, we want to have as many '1's as possible, followed by '0's.
    // Each "one" uses 'o', 'n', 'e'.
    // Each "zero" uses 'z', 'e', 'r', 'o'.

    // Count how many '1's we can form
    // 'n' is unique to "one" (among 'n', 'z')
    int num_ones = count_n;

    // Count how many '0's we can form
    // 'z' is unique to "zero" (among 'n', 'z')
    int num_zeros = count_z;

    bool first_output = true;

    for (int i = 0; i < num_ones; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 1;
        first_output = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 0;
        first_output = false;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long min_val = a[0];
    long long operations = 0;

    for (int i = 1; i < n; ++i) {
        // For each pile a[i] (where i > 0, so a[i] >= min_val),
        // we can add min_val to it as many times as possible
        // without exceeding k.
        // The number of times min_val can be added to a[i] is
        // floor((k - a[i]) / min_val).
        if (a[i] < k) { // Only perform operations if a[i] can still be increased
            operations += (k - a[i]) / min_val;
        }
    }

    std::cout << operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

