#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks required: k sticks for torches + k * y sticks for k coal
        long long total_sticks_required = k * y + k;

        // We start with 1 stick. So, we need to acquire (total_sticks_required - 1) more sticks.
        long long sticks_to_acquire = total_sticks_required - 1;

        // Each trade of type 1 (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        // Number of trades of type 1 needed: ceil(sticks_to_acquire / (x - 1))
        long long trades_for_sticks = (sticks_to_acquire + (x - 1) - 1) / (x - 1);

        // Total trades = trades_for_sticks + trades_for_coal
        // Trades for coal = k (one trade for each coal)
        long long total_trades = trades_for_sticks + k;

        std::cout << total_trades << std::endl;
    }
    return 0;
}

