#include <iostream>
#include <vector>
#include <numeric>
#include <string>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The flags for has_pos_one and has_neg_one are for elements *before* current i.
            // So, if a[i] is 1 or -1, it contributes to the flags for elements j < i.
            // But we are iterating backwards, so we update flags *after* checking a[i] vs b[i].
            // The flags `has_pos_one` and `has_neg_one` should reflect if there's a 1 or -1
            // at an index `k < i`.
            // So, if a[i] is 1 or -1, it means it *could* have been used to modify elements j > i.
            // But for elements j < i, a[i] itself is not available.
            // The current `has_pos_one` and `has_neg_one` correctly reflect elements `a[0]...a[i-1]`.
        } else if (a[i] < b[i]) {
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }
        // Update flags for the next iteration (i-1)
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

