    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<bool> row_blocked(n, false);
    std::vector<bool> col_blocked(m, false);
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            int cell_val;
            std::cin >> cell_val;
            if (cell_val == 1) {
                row_blocked[i] = true;
                col_blocked[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_blocked[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_blocked[j]) {
            available_cols++;
        }
    }

    int moves = std::min(available_rows, available_cols);

    if (moves % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

