        // $n=5$. $a_{n-1} = a_4 = 8$. $a_n = a_5 = 13$.
        // Difference $a_5 - a_4 = 13 - 8 = 5$. Correct.
        //
        // The logic seems to hold for all examples.
        // The solution is to sort the array and output $a_n - a_{n-1}$.

        std::cout << a[n] - a[n - 1] << "\n";
    }
