#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::vector<bool> used(n + 1, false);
    std::set<int> available_small_numbers;

    // p_1 must be q_1
    p[0] = q[0];
    if (p[0] < 1 || p[0] > n) { // q_1 must be within [1, n]
        std::cout << -1 << "\n";
        return;
    }
    used[p[0]] = true;

    // Fill available_small_numbers with numbers not yet used and smaller than current max
    for (int i = 1; i < p[0]; ++i) {
        available_small_numbers.insert(i);
    }

    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (p[i] < 1 || p[i] > n || used[p[i]]) {
                // q_i must be within [1, n] and not used before
                std::cout << -1 << "\n";
                return;
            }
            used[p[i]] = true;
            // Add numbers between q[i-1] and q[i] (exclusive) to available_small_numbers
            for (int j = q[i-1] + 1; j < q[i]; ++j) {
                if (!used[j]) { // Should always be true if logic is correct
                    available_small_numbers.insert(j);
                }
            }
        } else { // q[i] == q[i-1]
            // If q_i is not a new maximum, p_i must be some unused number less than q_i
            // We need to pick the smallest available number to maximize chances for future steps
            if (available_small_numbers.empty()) {
                std::cout << -1 << "\n";
                return;
            }
            p[i] = *available_small_numbers.begin();
            available_small_numbers.erase(available_small_numbers.begin());
            used[p[i]] = true;
        }
    }

    // Final check for validity (all numbers 1 to n used exactly once)
    // This is implicitly handled by the logic if no -1 was printed,
    // but a quick check for safety.
    // The problem guarantees q_i <= q_{i+1}, so q_n is the overall maximum.
    // If q_n is not n, then it's impossible to form a permutation of 1..n.
    // However, the problem statement says q_i <= n, so q_n could be less than n.
    // But if q_n < n, then n itself is never used, which is impossible for a permutation.
    // So, q_n must be n.
    if (q[n-1] != n) {
        std::cout << -1 << "\n";
        return;
    }

    // Print the permutation
    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

