#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we will use for the alternating part to generate k distinct differences

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers are k+2, k+3, ..., n.
    // We need to append them in increasing order to maintain a difference of 1.
    // The last number placed was either left-1 or right+1.
    // If k is even, the last number placed was left-1. The next number should be left.
    // If k is odd, the last number placed was right+1. The next number should be right.
    // In both cases, the next available number is min(left, right).
    // Since left was incremented and right decremented, and they started as 1 and k+1,
    // after k+1 elements are placed, left will be (k/2)+1 if k is even, or (k/2)+2 if k is odd.
    // And right will be (k/2)+1 if k is odd, or (k/2)+2 if k is even.
    // So min(left, right) will be (k/2)+1.
    // This is exactly k+2 if we consider the numbers 1 to k+1.
    // The numbers used are 1, ..., k+1.
    // The next number to append is k+2.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

