            pos[p[i]] = i;
        }

        std::string result = "";
        int current_min_idx = pos[1];
        int current_max_idx = pos[1];

        for (int m = 1; m <= n; ++m) {
            // For m=1, the segment is just [1], which is at pos[1].
            // min_idx and max_idx are already initialized to pos[1].
            // The length is 1, min value is 1, max value is 1.
            // So m=1 is always beautiful.

            // For m > 1, we need to expand the segment to include 'm'.
            // The segment must contain all numbers from 1 to m.
            // This means the segment must span from min(pos[1...m]) to max(pos[1...m]).
            // We maintain current_min_idx and current_max_idx for numbers 1 to (m-1).
            // When considering 'm', we update these to include pos[m].
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);

            // A number m is beautiful if the segment [current_min_idx, current_max_idx]
            // has length m.
            // The length of the segment is (current_max_idx - current_min_idx + 1).
            if (current_max_idx - current_min_idx + 1 == m) {
                result += '1';
            } else {
                result += '0';
            }
        }
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return;
    }

    std::vector<int> result;
    result.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a peak if p[i] > p[i-1] and p[i] > p[i+1]
        // p[i] is a valley if p[i] < p[i-1] and p[i] < p[i+1]
        bool is_peak = (p[i] > p[i-1] && p[i] > p[i+1]);
        bool is_valley = (p[i] < p[i-1] && p[i] < p[i+1]);

        if (is_peak || is_valley) {
            result.push_back(p[i]);
        }
    }
    result.push_back(p[n-1]);

    std::cout << result.size() << "\n";
    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i] << (i == result.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

