int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int current_diff_01 = 0; // Count of positions where a[k]='0', b[k]='1'
    int current_diff_10 = 0; // Count of positions where a[k]='1', b[k]='0'

    for (int i = 0; i < n; ++i) {
        if (a[i] == '0' && b[i] == '1') {
            // Current position is '0' but should be '1'
            if (current_diff_10 > 0) {
                // We have a pending '1' that should be '0'.
                // We can swap a[i] ('0') with a[j] ('1') where a[j] should be '0'.
                // This fixes both positions. Cost is 0 for this pair, as it's already accounted for.
                // The '1' from a[j] goes to a[i], making a[i] correct.
                // The '0' from a[i] goes to a[j], making a[j] correct.
                current_diff_10--;
            } else {
                // No pending '1' that should be '0'.
                // This '0' needs to become '1'.
                // It contributes to the count of '0's that need to become '1's.
                current_diff_01++;
            }
        } else if (a[i] == '1' && b[i] == '0') {
            // Current position is '1' but should be '0'
            if (current_diff_01 > 0) {
                // We have a pending '0' that should be '1'.
                // We can swap a[i] ('1') with a[j] ('0') where a[j] should be '1'.
                // This fixes both positions. Cost is 0 for this pair, as it's already accounted for.
                // The '0' from a[j] goes to a[i], making a[i] correct.
                // The '1' from a[i] goes to a[j], making a[j] correct.
                current_diff_01--;
            } else {
                // No pending '0' that should be '1'.
                // This '1' needs to become '0'.
                // It contributes to the count of '1's that need to become '0's.
                current_diff_10++;
            }
        }
        // If a[i] == b[i], nothing changes for this position.
        // The cost for any pending mismatches (current_diff_01 or current_diff_10)
        // is accumulated at each step.
        cost += current_diff_01 + current_diff_10;
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak"; // Box 1: (-inf, -1]
    std::string ans2 = "Tidak"; // Box 2: (-1, 0)
    std::string ans3 = "Tidak"; // Box 3: (0, 1)
    std::string ans4 = "Tidak"; // Box 4: [1, inf)

    if (total_toys == 1) {
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
    } else {
        // Case 1: Final product is negative (odd number of initial negative toys)
        // This means (a+b) is odd.
        if ((a + b) % 2 != 0) {
            // Can it be in Box 1? (value <= -1)
            // This requires at least one toy with magnitude >= 1 (from Box 1 or Box 4)
            // AND not all toys with magnitude < 1 (from Box 2 or Box 3)
            // If all toys are from Box 2 or Box 3, the magnitude will be < 1.
            // If there's at least one toy from Box 1 or Box 4, we can potentially get magnitude >= 1.
            // Exception: If all toys are from Box 2, and there are at least two, we can get a positive product in Box 3.
            // If a+d > 0, it's possible to get magnitude >= 1.
            // If a+d == 0, then all toys are from Box 2 or Box 3.
            // If a+d == 0, then a=0, d=0. All toys are from B or C.
            // If a=0, d=0, and b+c > 0, then the product will have magnitude < 1.
            // So, if a+d > 0, it's possible to get magnitude >= 1.
            // If a+d == 0, it's impossible to get magnitude >= 1.
            if (a + d > 0) {
                ans1 = "Ya";
            }

            // Can it be in Box 2? (value in (-1, 0))
            // This requires the magnitude to be < 1.
            // This is always possible if there are enough toys from Box 2 or Box 3.
            // If a+d > 0, we can always pick a toy from Box 2 or Box 3 to multiply last,
            // or arrange multiplications to result in a small magnitude.
            // The only way it's NOT possible is if all toys are from Box 1 or Box 4,
            // and there are no toys from Box 2 or Box 3.
            // If b+c > 0, it's possible to get magnitude < 1.
            // If b+c == 0, then b=0, c=0. All toys are from A or D.
            // If b=0, c=0, and a+d > 0, then the product will have magnitude >= 1.
            // So, if b+c > 0, it's possible to get magnitude < 1.
            // If b+c == 0, it's impossible to get magnitude < 1.
            if (b + c > 0) {
                ans2 = "Ya";
            }
        }

        // Case 2: Final product is positive (even number of initial negative toys)
        // This means (a+b) is even.
        if ((a + b) % 2 == 0) {
            // Can it be in Box 3? (value in (0, 1))
            // This requires the magnitude to be < 1.
            // Similar logic to Box 2. If b+c > 0, it's possible.
            if (b + c > 0) {
                ans3 = "Ya";
            }

            // Can it be in Box 4? (value >= 1)
            // This requires the magnitude to be >= 1.
            // Similar logic to Box 1. If a+d > 0, it's possible.
            if (a + d > 0) {
                ans4 = "Ya";
            }
        }

        // Special case: If all toys are from Box 2 (b > 0, a=c=d=0)
        // If b is odd, final product is negative.
        // If b is even, final product is positive.
        // All products will have magnitude < 1.
        // So, if b is odd, only Box 2 is possible.
        // If b is even, only Box 3 is possible.
        if (a == 0 && c == 0 && d == 0 && b > 0) {
            ans1 = "Tidak";
            ans4 = "Tidak";
            if (b % 2 != 0) { // Odd number of negative toys
                ans2 = "Ya";
                ans3 = "Tidak";
            } else { // Even number of negative toys
                ans2 = "Tidak";
                ans3 = "Ya";
            }
        }

        // Special case: If all toys are from Box 3 (c > 0, a=b=d=0)
        // All products are positive. All products have magnitude < 1.
        // Only Box 3 is possible.
        if (a == 0 && b == 0 && d == 0 && c > 0) {
            ans1 = "Tidak";
            ans2 = "Tidak";
            ans3 = "Ya";
            ans4 = "Tidak";
        }

        // Special case: If all toys are from Box 1 (a > 0, b=c=d=0)
        // If a is odd, final product is negative.
        // If a is even, final product is positive.
        // All products will have magnitude >= 1.
        // So, if a is odd, only Box 1 is possible.
        // If a is even, only Box 4 is possible.
        if (b == 0 && c == 0 && d == 0 && a > 0) {
            ans2 = "Tidak";
            ans3 = "Tidak";
            if (a % 2 != 0) { // Odd number of negative toys
                ans1 = "Ya";
                ans4 = "Tidak";
            } else { // Even number of negative toys
                ans1 = "Tidak";
                ans4 = "Ya";
            }
        }

        // Special case: If all toys are from Box 4 (d > 0, a=b=c=0)
        // All products are positive. All products have magnitude >= 1.
        // Only Box 4 is possible.
        if (a == 0 && b == 0 && c == 0 && d > 0) {
            ans1 = "Tidak";
            ans2 = "Tidak";
            ans3 = "Tidak";
            ans4 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

