#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Operations for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Operations for elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Operations for elements to the right of the median
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each x[i] as the leftmost point of a triplet,
        // find the maximum index 'right_ptr' such that x[right_ptr] - x[i] <= d.
        // Since x is sorted, we can advance right_ptr monotonically.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points x[j] where i < j < right_ptr satisfy x[j] - x[i] <= d.
        // And all points x[k] where i < k < right_ptr satisfy x[k] - x[i] <= d.
        // We need to choose two points x_j and x_k such that i < j < k < right_ptr.
        // The number of available points for x_j and x_k is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = right_ptr - 1 - i; // Number of points between x[i] and x[right_ptr] (exclusive of x[i], exclusive of x[right_ptr])
                                         // These are points x[i+1], x[i+2], ..., x[right_ptr-1].
                                         // If m < 2, we cannot form a triplet, so this term will be 0 or negative.
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    std::sort(a.begin(), a.end());

    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_indexed[i] = {b[i], i};
    }

    std::sort(b_indexed.begin(), b_indexed.end(), [](const auto& p1, const auto& p2) {
        return p1.first < p2.first;
    });

    std::vector<long long> result(m);
    int a_ptr = 0;
    int b_ptr = 0;

    // Use a map to store counts of A values that are available for assignment.
    // This allows efficient retrieval of the smallest available A value.
    std::map<long long, int> available_a_counts;

    // Iterate through sorted B values.
    // For each B_i, we want to assign the smallest possible A_j such that A_j >= B_i.
    // This is because larger A values are more "valuable" for smaller B values.
    // F(n, k) = (n+1)/(k+1).
    // To maximize sum( (A_i+1)/(B_i+1) ), we want to pair large A_i with small B_i.
    // However, the problem states A_i >= B_j for all i, j.
    // The actual formula is F(n, k) = (n+1)/(k+1).
    // To maximize sum (A'_i+1)/(B_i+1), we should pair the largest A_i with the smallest B_i.
    // This is a standard rearrangement inequality type problem.
    // Sort A in ascending order. Sort B in ascending order.
    // To maximize sum(f(A_i, B_i)), if f is increasing in A and decreasing in B,
    // we should pair largest A with smallest B.
    // F(n, k) = (n+1)/(k+1). This is increasing in n and decreasing in k.
    // So, we should pair largest A with smallest B.
    // A is sorted ascending. B is sorted ascending.
    // We want to assign A[m-1] to B[0], A[m-2] to B[1], ..., A[0] to B[m-1].
    // This means we should assign A in descending order to B in ascending order.

    // Let's re-evaluate the strategy.
    // We have sorted A: a_0 <= a_1 <= ... <= a_{m-1}
    // We have sorted B (with original indices): (b'_0, idx_0), (b'_1, idx_1), ..., (b'_{m-1}, idx_{m-1})
    // where b'_0 <= b'_1 <= ... <= b'_{m-1}.
    // We want to assign a permutation A' to B such that sum (A'_i+1)/(B_i+1) is maximized.
    // This is achieved by pairing the largest A values with the smallest B values.
    // So, A'_{idx_0} should be a_{m-1}, A'_{idx_1} should be a_{m-2}, and so on.
    // A'_{idx_j} = a_{m-1-j}.

    for (int i = 0; i < m; ++i) {
        result[b_indexed[i].second] = a[m - 1 - i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation(const std::vector<int>& arr, int len) {
    if (len <= 0) return false;
    if (arr.size() < len) return false;

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] <= 0 || arr[i] > len) {
            return false;
        }
        if (seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        int max_val_a = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] > max_val_a) {
                max_val_a = a[i];
            }
        }

        std::set<std::pair<int, int>> solutions;

        // Case 1: p1 is a permutation of length max_val_a
        // This implies l1 = max_val_a.
        // Check if a[0...max_val_a-1] is a permutation of length max_val_a.
        // Check if a[max_val_a...n-1] is a permutation of length n - max_val_a.
        if (max_val_a > 0 && max_val_a < n) {
            std::vector<bool> seen_p1(max_val_a + 1, false);
            bool p1_ok = true;
            for (int i = 0; i < max_val_a; ++i) {
                if (a[i] <= 0 || a[i] > max_val_a || seen_p1[a[i]]) {
                    p1_ok = false;
                    break;
                }
                seen_p1[a[i]] = true;
            }

            if (p1_ok) {
                int l2 = n - max_val_a;
                if (l2 > 0) {
                    std::vector<bool> seen_p2(l2 + 1, false);
                    bool p2_ok = true;
                    int max_val_p2 = 0;
                    for (int i = max_val_a; i < n; ++i) {
                        if (a[i] <= 0 || a[i] > l2 || seen_p2[a[i]]) {
                            p2_ok = false;
                            break;
                        }
                        seen_p2[a[i]] = true;
                        if (a[i] > max_val_p2) {
                            max_val_p2 = a[i];
                        }
                    }
                    if (p2_ok && max_val_p2 == l2) {
                        solutions.insert({max_val_a, l2});
                    }
                }
            }
        }

        // Case 2: p2 is a permutation of length max_val_a
        // This implies l2 = max_val_a.
        // Check if a[0...n-max_val_a-1] is a permutation of length n - max_val_a.
        // Check if a[n-max_val_a...n-1] is a permutation of length max_val_a.
        if (max_val_a > 0 && max_val_a < n) {
            int l1 = n - max_val_a;
            if (l1 > 0) {
                std::vector<bool> seen_p1(l1 + 1, false);
                bool p1_ok = true;
                int max_val_p1 = 0;
                for (int i = 0; i < l1; ++i) {
                    if (a[i] <= 0 || a[i] > l1 || seen_p1[a[i]]) {
                        p1_ok = false;
                        break;
                    }
                    seen_p1[a[i]] = true;
                    if (a[i] > max_val_p1) {
                        max_val_p1 = a[i];
                    }
                }

                if (p1_ok && max_val_p1 == l1) {
                    std::vector<bool> seen_p2(max_val_a + 1, false);
                    bool p2_ok = true;
                    for (int i = l1; i < n; ++i) {
                        if (a[i] <= 0 || a[i] > max_val_a || seen_p2[a[i]]) {
                            p2_ok = false;
                            break;
                        }
                        seen_p2[a[i]] = true;
                    }
                    if (p2_ok) {
                        solutions.insert({l1, max_val_a});
                    }
                }
            }
        }

        std::cout << solutions.size() << "\n";
        for (const auto& p : solutions) {
            std::cout << p.first << " " << p.second << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (wins == 0) { // All 'L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 2 * k - 1 << "\n"; // Convert k 'L's to 'W's. First 'W' gives 1, others 2.
            }
            continue;
        }

        // If there are some 'W's initially
        // Strategy: fill gaps between 'W's first, then extend from ends.
        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        int current_gap_len = 0;
        for (int i = first_W + 1; i < last_W; ++i) {
            if (s[i] == 'L') {
                current_gap_len++;
            } else { // s[i] == 'W'
                if (current_gap_len > 0) {
                    gaps.push_back(current_gap_len);
                }
                current_gap_len = 0;
            }
        }
        if (current_gap_len > 0) { // Last gap before last_W
            gaps.push_back(current_gap_len);
        }
        std::sort(gaps.begin(), gaps.end());

        int score_from_gaps = 0;
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                score_from_gaps += 2 * gap_len + 1; // Each L becomes W, connecting two Ws.
                                                     // The gap_len L's become W's.
                                                     // The first L in the gap connects to previous W, gives 2.
                                                     // Subsequent L's in gap connect to previous W, give 2.
                                                     // Total 2*gap_len.
                                                     // Plus 1 for the connection of the first W in the gap to the previous W.
                                                     // No, it's simpler: each L converted to W adds 2 points, except the first one in a sequence of Ls that connects to a W.
                                                     // If we fill a gap of length `g`, we convert `g` 'L's to 'W's.
                                                     // This adds `g` new 'W's.
                                                     // Each of these `g` 'W's will be adjacent to another 'W' (either original or newly converted).
                                                     // So each of these `g` 'W's will contribute 2 points.
                                                     // The total points added is 2 * `g`.
                                                     // However, the problem states that if you win the previous game you get 2 points.
                                                     // When we fill a gap, say W L L L W -> W W W W W.
                                                     // The first L becomes W, it gets 2 points (because previous is W).
                                                     // The second L becomes W, it gets 2 points (because previous is W).
                                                     // ...
                                                     // The last L becomes W, it gets 2 points (because previous is W).
                                                     // So, for a gap of length `g`, we add `2 * g` points.
                                                     // This is correct.
            } else {
                score_from_gaps += 2 * k;
                k = 0;
                break;
            }
        }

        int score_from_ends = 0;
        // Extend to the left
        int left_L_count = first_W;
        if (k >= left_L_count) {
            k -= left_L_count;
            score_from_ends += 2 * left_L_count; // Each L becomes W, connecting to previous W.
                                                  // The first W in the original string was 1 point.
                                                  // If we convert L L W to W W W, the original W was 1.
                                                  // The first L becomes W, previous is W, so 2 points.
                                                  // The second L becomes W, previous is W, so 2 points.
                                                  // Total added: 4 points.
                                                  // This is 2 * left_L_count.
        } else {
            score_from_ends += 2 * k;
            k = 0;
        }

        // Extend to the right
        int right_L_count = n - 1 - last_W;
        if (k > 0 && right_L_count > 0) { // Only if k is still available and there are L's to convert
            if (k >= right_L_count) {
                k -= right_L_count;
                score_from_ends += 2 * right_L_count; // Each L becomes W, connecting to previous W.
            } else {
                score_from_ends += 2 * k;
                k = 0;
            }
        }

        std::cout << initial_score + score_from_gaps + score_from_ends << "\n";
    }
    return 0;
}

