#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;
    int a_ptr_left = 0;
    int a_ptr_right = n - 1;

    // Friends who receive w_i = 1 items
    // These friends get 2 * largest_available_item
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += a[a_ptr_right] * 2;
            a_ptr_right--;
        } else {
            // All remaining w_i will be > 1, as w is sorted
            break;
        }
    }

    // Friends who receive w_i > 1 items
    // These friends get largest_available_item + smallest_available_item
    // To maximize, give the largest remaining 'a' to be the max,
    // and the smallest remaining 'a' to be the min.
    // The intermediate w_i - 2 items don't affect happiness.
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_right]; // Max value for this friend
            a_ptr_right--;
            total_happiness += a[a_ptr_left]; // Min value for this friend
            a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest values
        }
    }

    std::cout << total_happiness << std::endl;
}

