    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum and X = current_xor_sum.
    // We want S' = 2X'.
    // S' = S + b1 + b2 + b3
    // X' = X ^ b1 ^ b2 ^ b3

    // Strategy: Append at most 3 elements.
    // It's always possible to make S' = 2X' by appending at most 3 elements.

    // Step 1: Append X.
    // New sum: S + X
    // New XOR sum: X ^ X = 0
    // Now we need (S + X + b2 + b3) = 2 * (0 ^ b2 ^ b3)
    // (S + X + b2 + b3) = 2 * (b2 ^ b3)

    // Step 2: Append S + X.
    // Let S_new = S + X.
    // Let X_new = 0.
    // We need (S_new + b2 + b3) = 2 * (X_new ^ b2 ^ b3)
    // (S_new + b2 + b3) = 2 * (b2 ^ b3)
    // Let b2 = S_new.
    // New sum: S_new + S_new = 2 * S_new
    // New XOR sum: X_new ^ S_new = 0 ^ S_new = S_new
    // Now we have 2 * S_new = 2 * S_new. This is true.
    // So, appending X and then S+X makes the array good.

    // The elements to append are X and S+X.
    // The number of elements to append is 2.

    std::cout << 2 << std::endl;
