int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will cause this 'b' to duplicate
            // and move past the 'a'.
            // The number of 'a's currently accumulated (a_count)
            // represents the number of 'a's that will "pass through"
            // this 'b'.
            // Each such 'a' passing through this 'b' contributes
            // a_count steps.
            total_steps = (total_steps + a_count) % mod;
            // After all 'a's pass through this 'b', this 'b' effectively
            // becomes two 'b's for the 'a's further to the left.
            // So, the effective 'a_count' for the next 'b' (or 'a')
            // to its left doubles.
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to move past all 'b's to its right.
            // This 'a' itself contributes 1 to the 'a_count' for
            // 'b's further to its left.
            a_count = (a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

