int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_elements = 0;
    long long correct_pairs = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        total_elements += m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }
        for (int j = 0; j < m - 1; ++j) {
            if (chain[j] + 1 == chain[j+1]) {
                correct_pairs++;
            }
        }
    }

    // Operations to disassemble:
    // Each chain of length m has m-1 nestings.
    // To disassemble a chain of length m into m individual dolls,
    // we need m-1 "get out" operations.
    // Total initial nestings = total_elements - k (since k chains)
    // Total "get out" operations = (total_elements - k) - correct_pairs
    // This is equivalent to:
    // (n - 1) - correct_pairs operations to break existing correct pairs
    // plus (k - 1) operations to break the "first" element of each chain
    // that is not 1.
    // No, this is simpler:
    // Total elements = n.
    // Total nestings in initial configuration = n - k.
    // We want to achieve n-1 nestings in the final configuration.
    // The number of nestings we need to break is (n - k) - correct_pairs.
    // Each broken nesting costs 1 second.
    // So, operations_to_disassemble = (n - k) - correct_pairs.

    // Operations to assemble:
    // We need to form n-1 nestings in the final configuration.
    // We already have 'correct_pairs' nestings.
    // So, we need to create (n - 1) - correct_pairs new nestings.
    // Each new nesting costs 1 second.
    // So, operations_to_assemble = (n - 1) - correct_pairs.

    // Total operations = operations_to_disassemble + operations_to_assemble
    // Total operations = ((n - k) - correct_pairs) + ((n - 1) - correct_pairs)
    // Total operations = n - k - correct_pairs + n - 1 - correct_pairs
    // Total operations = 2*n - k - 1 - 2*correct_pairs

    // Let's re-evaluate.
    // The number of dolls that are NOT 1 and are the start of a chain (or a standalone doll)
    // needs to be put into its predecessor.
    // There are k chains. One of them might start with 1.
    // If a chain starts with 1, say 1 -> 2 -> ...
    // And if 1 -> 2 is a correct pair, we don't touch it.
    // If 1 -> 2 is NOT a correct pair (e.g., 1 -> 3), then 1 needs to be taken out of 3.
    // This logic is getting complicated.

    // Let's use the simpler logic from the problem statement's example:
    // Example 2: 7 3, chains: (1 3 7), (2 5), (4 6)
    // n=7, k=3
    // Chain 1: 1 3 7. Pairs: (1,3), (3,7). No correct pairs.
    // Chain 2: 2 5. Pairs: (2,5). No correct pairs.
    // Chain 3: 4 6. Pairs: (4,6). No correct pairs.
    // correct_pairs = 0.
    // Total elements = 3+2+2 = 7.
    //
    // Disassemble:
    // (1 3 7) -> 1, 3, 7. Cost: 2 (take 1 out of 3, take 3 out of 7)
    // (2 5) -> 2, 5. Cost: 1 (take 2 out of 5)
    // (4 6) -> 4, 6. Cost: 1 (take 4 out of 6)
    // Total disassemble cost = 2+1+1 = 4.
    // This is (total_elements - k) - correct_pairs = (7 - 3) - 0 = 4. This matches.

    // Assemble:
    // We need 1->2->3->4->5->6->7. This is 6 nestings.
    // We have 0 correct pairs. So we need to create 6 nestings.
    // Cost = 6.
    // This is (n - 1) - correct_pairs = (7 - 1) - 0 = 6. This matches.

    // Total = 4 + 6 = 10. This matches the example.

    // Let's check Example 1: 3 2, chains: (1 2), (3)
    // n=3, k=2
    // Chain 1: 1 2. Pair: (1,2). This is a correct pair.
    // Chain 2: 3. No pairs.
    // correct_pairs = 1.
    // Total elements = 2+1 = 3.
    //
    // Disassemble:
    // (1 2) -> 1, 2. Cost: 0 (1->2 is correct, we don't break it).
    // (3) -> 3. Cost: 0.
    // Total disassemble cost = 0.
    // This is (total_elements - k) - correct_pairs = (3 - 2) - 1 = 0. This matches.

    // Assemble:
    // We need 1->2->3. This is 2 nestings.
    // We have 1 correct pair (1->2). So we need to create 1 new nesting (2->3).
    // Cost = 1.
    // This is (n - 1) - correct_pairs = (3 - 1) - 1 = 1. This matches.

    // Total = 0 + 1 = 1. This matches the example.

    // The formula seems to be:
    // (Total initial nestings - correct_pairs) + (Total target nestings - correct_pairs)
    // Total initial nestings = n - k (since there are k chains, each chain of length m has m-1 nestings, sum of m is n, sum of m-1 is n-k)
    // Total target nestings = n - 1
    //
    // Result = ( (n - k) - correct_pairs ) + ( (n - 1) - correct_pairs )
    // Result = n - k - correct_pairs + n - 1 - correct_pairs
    // Result = 2 * n - k - 1 - 2 * correct_pairs

    long long result = 2LL * n - k - 1 - 2LL * correct_pairs;
    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_consecutive_R_gap = 0;
        int current_R_gap = 0;

        // The frog starts at cell 0.
        // It needs to reach cell n+1.
        // The first jump is from 0.
        // If s[i] is 'R', it can jump right from cell i+1.
        // If s[i] is 'L', it can jump left from cell i+1.
        // From cell 0, it can only jump right.

        // We are looking for the minimum d.
        // The frog must always be able to jump to the right to make progress.
        // This means it must always land on an 'R' cell or jump directly to n+1.
        // Or, more simply, it must be able to jump over all 'L' segments.

        // Consider the sequence of cells visited.
        // If the frog is at cell `i` and `s[i-1]` is 'R', it can jump to `[i+1, min(n+1, i+d)]`.
        // If the frog is at cell `i` and `s[i-1]` is 'L', it can jump to `[max(0, i-d), i-1]`.
        // From cell 0, it can jump to `[1, min(n+1, d)]`.

        // To reach n+1, the frog must always be able to jump to a cell `j` such that `j > current_pos`.
        // The only way to do this is to jump from cell 0, or from a cell `i` where `s[i-1]` is 'R'.
        // If the frog lands on a cell `i` where `s[i-1]` is 'L', it can only jump left, which is bad.
        // So, the frog must always jump over any 'L' cells.

        // This means the frog must be able to jump from the last 'R' cell (or 0)
        // to the next 'R' cell (or n+1), skipping any 'L' cells in between.

        // Let's find the positions of all 'R' cells.
        // The starting point is effectively an 'R' cell at index -1 (cell 0).
        // The target is effectively an 'R' cell at index n (cell n+1).

        // We need to find the maximum distance between consecutive 'R' cells (or 0 and first 'R', or last 'R' and n+1).
        // Let `last_R_pos` be the index of the last 'R' character encountered.
        // Initially, `last_R_pos` can be considered -1 (representing cell 0).

        int last_R_idx = -1; // Represents cell 0
        int max_jump_needed = 0;

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at index i, which corresponds to cell i+1.
                // The previous 'R' (or start) was at last_R_idx, which corresponds to cell last_R_idx+1.
                // The distance between these two cells is (i+1) - (last_R_idx+1) = i - last_R_idx.
                max_jump_needed = std::max(max_jump_needed, i - last_R_idx);
                last_R_idx = i;
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // to the target cell n+1.
        // The last 'R' was at index last_R_idx (cell last_R_idx+1).
        // The target is cell n+1.
        // The distance is (n+1) - (last_R_idx+1) = n - last_R_idx.
        max_jump_needed = std::max(max_jump_needed, n - last_R_idx);

        std::cout << max_jump_needed << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
