#include <cmath>
#include <map>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            long long current_prime = i;
            long long p_copy = p;
            while (p_copy % current_prime == 0 && p_copy % q == 0) {
                p_copy /= current_prime;
            }
            max_x = std::max(max_x, p_copy);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    if (temp_q > 1) { // temp_q is now a prime factor itself
        long long current_prime = temp_q;
        long long p_copy = p;
        while (p_copy % current_prime == 0 && p_copy % q == 0) {
            p_copy /= current_prime;
        }
        max_x = std::max(max_x, p_copy);
    }

    return max_x;
}

