void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] is the start of a non-increasing suffix.
    // This means a[i] >= a[i+1] >= ... >= a[n-1].
    // Or, find the first index `i` from the right such that a[i] < a[i+1].
    // If no such `i` exists, the whole array is non-increasing.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now `a[i...n-1]` is a non-increasing suffix.
    // `i` is the first index of this suffix.
    // If `i` is 0, the whole array is non-increasing.

    // From this non-increasing suffix, find the rightmost index `j` such that a[j] is the start of a non-decreasing suffix.
    // This means a[j] <= a[j+1] <= ... <= a[n-1].
    // Or, find the first index `j` from the right such that a[j] > a[j+1].
    // We start searching from `i` (the start of the non-increasing suffix).
    // We are looking for the point where the array stops being non-decreasing from the right.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // Non-increasing suffix from right: [5, 3, 2] -> i = 4 (a[4]=5)
    // Now, from index i=4, we look for the first element from the right that breaks non-decreasing.
    // [5, 3, 2]
    // a[6]=2
    // a[5]=3, a[5] > a[6] is false (3 >= 2)
    // a[4]=5, a[4] > a[5] is true (5 > 3) -> j = 4
    // So, `j` is the first index from the right such that `a[j] > a[j+1]`.
    // This `j` must be less than or equal to `i`.
    int j = i;
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now `a[j...n-1]` is the candidate "good" suffix.
    // `j` is the length of the prefix to erase.

    std::cout << j << std::endl;
}

