int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    long long sum_r_val = (b - 1);
    sum_r_val = (sum_r_val * b) % MOD;

    // Modular inverse of 2 for division
    // MOD is 10^9 + 7, which is prime.
    // inv(2) = (MOD + 1) / 2
    long long inv2 = (MOD + 1) / 2;
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_k_b_plus_1 = b * (a * (a+1) / 2) + a
    long long sum_k_val = (a * (a + 1)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD;

    long long sum_k_b_plus_1_val = (b * sum_k_val) % MOD;
    sum_k_b_plus_1_val = (sum_k_b_plus_1_val + a) % MOD;

    // Total sum = (sum_r_val * sum_k_b_plus_1_val) % MOD
    long long total_sum = (sum_r_val * sum_k_b_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

