int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long val = (dq.empty() ? 0 : L[dq.back()]);
        L[i] = val + 1;
        dq.push_back(i);
    }

    dq.clear();
    std::vector<long long> R(n);
    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long val = (dq.empty() ? 0 : R[dq.back()]);
        R[i] = val + 1;
        dq.push_back(i);
    }

    long long max_k = 0;
    for (int i = 0; i < n; ++i) {
        max_k = std::max(max_k, std::min(h[i], std::min(L[i], R[i])));
    }

    std::cout << max_k << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1;
                n -= 1; // Opponent takes 1
            } else {
                // Check if N is a power of 2
                // A number is a power of 2 if (n & (n - 1)) == 0
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    chanek_coins += 1;
                    n -= 1;
                } else { // N is even but not a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        }
        // Opponent's turn (if n > 0)
        if (n > 0) {
            if (n % 2 != 0) {
                n -= 1;
            } else {
                if (n == 2) {
                    n -= 1;
                } else {
                    if ((n & (n - 1)) == 0) {
                        n -= 1;
                    } else {
                        n /= 2;
                    }
                }
            }
        }
    }
    return chanek_coins;
}

