#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance for the left half (jars 1 to n)
    // balance = (count of 1s) - (count of 2s)
    std::vector<int> left_balances(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_balances[i + 1] = left_balances[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate initial balance for the right half (jars n+1 to 2n)
    // balance = (count of 1s) - (count of 2s)
    // We iterate from right to left for the right half to simulate removing from the right.
    std::vector<int> right_balances(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_balances[i + 1] = right_balances[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the left to achieve a certain balance
    // map: balance_value -> jars_removed_from_left
    std::map<int, int> left_balance_to_removed_count;
    for (int k = 0; k <= n; ++k) { // k jars removed from left (0 to n)
        int current_balance = left_balances[n] - left_balances[k]; // Balance of remaining jars (k+1 to n)
        if (left_balance_to_removed_count.find(current_balance) == left_balance_to_removed_count.end()) {
            left_balance_to_removed_count[current_balance] = k;
        } else {
            left_balance_to_removed_count[current_balance] = std::min(left_balance_to_removed_count[current_balance], k);
        }
    }

    int min_total_removed = 2 * n; // Max possible jars to remove

    // Iterate through possible number of jars removed from the right
    for (int k = 0; k <= n; ++k) { // k jars removed from right (0 to n)
        int current_right_balance = right_balances[n] - right_balances[k]; // Balance of remaining jars (n+1 to 2n-k)

        // We need the total balance of remaining jars to be 0.
        // Let B_left_rem be balance of jars (k_left+1 to n)
        // Let B_right_rem be balance of jars (n+1 to 2n-k_right)
        // We need B_left_rem + B_right_rem = 0
        // So, B_left_rem = -B_right_rem

        int target_left_balance = -current_right_balance;

        if (left_balance_to_removed_count.count(target_left_balance)) {
            int removed_from_left = left_balance_to_removed_count[target_left_balance];
            min_total_removed = std::min(min_total_removed, removed_from_left + k);
        }
    }

    std::cout << min_total_removed << std::endl;
}

