    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    long long total_substrings = n * (n + 1) / 2;

    long long zeros = n - m;

    // To minimize substrings of all zeros, distribute zeros as evenly as possible.
    // This means placing '1's such that they break up the '0's into roughly equal segments.
    // There are m '1's. These '1's can create m+1 potential blocks of zeros (before the first '1',
    // between '1's, and after the last '1').
    // To minimize the sum of k*(k+1)/2 for blocks of zeros, we should use m+1 blocks if possible,
    // or fewer if zeros < m+1.
    // The optimal strategy is to place '1's such that the '0's are distributed into
    // m+1 segments (some of which might be empty).
    // However, the problem is about minimizing the sum of k*(k+1)/2.
    // This is achieved by making the lengths of zero blocks as equal as possible.
    // If we have 'm' ones, they divide the string into 'm+1' potential segments for zeros.
    // For example, _1_1_1_ (3 ones, 4 segments).
    // Let 'k' be the number of zeros in each of the 'm+1' segments.
    // We have 'zeros' total zeros.
    // We want to distribute 'zeros' into 'm+1' segments.
    // Let 'q' be the quotient and 'r' be the remainder when 'zeros' is divided by 'm+1'.
    // zeros = q * (m+1) + r
    // This means 'r' segments will have length 'q+1' and '(m+1) - r' segments will have length 'q'.
    // The number of zero-only substrings will be:
    // r * ((q+1) * (q+2) / 2) + ((m+1) - r) * (q * (q+1) / 2)

    long long num_blocks = m + 1;
    long long q = zeros / num_blocks;
    long long r = zeros % num_blocks;

    long long zero_substrings = r * (q + 1) * (q + 2) / 2 + (num_blocks - r) * q * (q + 1) / 2;

    return total_substrings - zero_substrings;
}

