        //   Now we have `A_j = 1`.
        //   `O_j ^ X_j = f_j(0)`.
        //   We can choose `O_j = 0`. Then `X_j = f_j(0)`.
        //   So if `f_j(0) != f_j(1)`: `A_j = 1`, `O_j = 0`, `X_j = f_j(0)`.
        //   Check:
        //     For `x_j=0`: `(0 & 1 | 0) ^ f_j(0) = 0 ^ f_j(0) = f_j(0)`. Correct.
        //     For `x_j=1`: `(1 & 1 | 0) ^ f_j(0) = 1 ^ f_j(0)`. This should be `f_j(1)`.
        //     Since `f_j(0) != f_j(1)`, `f_j(1) = 1 ^ f_j(0)`. Correct.

        // So, for each bit j:
        // `val_0_j = ((0 & a_j) | o_j) ^ c_j`
        // `val_1_j = ((1 & a_j) | o_j) ^ c_j`

        // If `val_0_j == val_1_j`:
        //   `A_j = 0`
        //   `O_j = val_0_j`
        //   `X_j = 0`
        // Else (`val_0_j != val_1_j`):
        //   `A_j = 1`
        //   `O_j = 0`
        //   `X_j = val_0_j`

        if (val_0_j == val_1_j) {
            // A_j = 0
            if (val_0_j == 1) {
                final_O |= (1 << j);
            }
            // X_j = 0
        } else { // val_0_j != val_1_j
            final_A |= (1 << j);
            // O_j = 0
            if (val_0_j == 1) {
                final_X |= (1 << j);
            }
        }
    }

    // Now we have final_A, final_O, final_X.
    // The program is (x & final_A) | final_O ^ final_X.
    // We need to output these operations.
    // The order matters for the output, but not for the final result.
    // The problem states "no more than 5 lines".
    // We have 3 constants. We can output them as:
    // & final_A
    // | final_O
    // ^ final_X
    // But we can optimize this. If a constant is 0, we can omit the operation.
    // For example, `x & 1023` is identity, `x | 0` is identity, `x ^ 0` is identity.

    // If final_A is 1023, `x & 1023` is `x`.
    // If final_O is 0, `x | 0` is `x`.
    // If final_X is 0, `x ^ 0` is `x`.

    // Let's check the actual values.
    // The problem states constants are 0 to 1023.
    // If final_A is 1023, it means all bits are passed through.
    // If final_A is 0, it means all bits are cleared.
    // If final_O is 1023, it means all bits are set.
    // If final_O is 0, it means no bits are set.
    // If final_X is 1023, it means all bits are flipped.
    // If final_X is 0, it means no bits are flipped.

    // The operations are `& A`, `| O`, `^ X`.
    // The order of these three operations can be arbitrary, as long as they are applied to the current value.
    // The problem implies a sequence of operations.
    // The standard form is `(x & A) | O ^ X`.
    // So we should output `& A`, then `| O`, then `^ X`.
    // We only output operations if their constant is not the identity constant.
    // For '&', identity is 1023.
    // For '|', identity is 0.
    // For '^', identity is 0.

    if (final_A != 1023) {
        result_ops.push_back({'&', final_A});
    }
    if (final_O != 0) {
        result_ops.push_back({'|', final_O});
    }
    if (final_X != 0) {
        result_ops.push_back({'^', final_X});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, or any positive number

    for (int k = 60; k >= 1; --k) { // Iterate from largest possible power of 2
        long long count_for_k = (1LL << k) - 1; // Number of subsequences for k elements
        while (X >= count_for_k) {
            result_array.push_back(current_val);
            X -= count_for_k;
            // Add k-1 more elements that are equal to current_val
            // but are far enough from current_val to not form valid subsequences with it
            // and far enough from each other to not form valid subsequences among themselves
            // but close enough to current_val to satisfy the condition if they are the only elements
            // This is achieved by making them current_val + d, current_val + 2d, etc.
            // However, the problem states that if max(s) - min(s) < d, it's valid.
            // If we add k-1 elements that are current_val + d, current_val + 2d, etc.
            // then max(s) - min(s) will be >= d for subsequences involving current_val and current_val + d.
            // The trick is to add k-1 elements that are all equal to current_val + d.
            // This makes them form 2^(k-1)-1 subsequences among themselves.
            // But we want to count 2^k-1 subsequences.
            // The strategy is to add k elements that are all equal to current_val.
            // This gives 2^k-1 subsequences.
            // But we need to make sure these k elements are distinct from previous groups.
            // The simplest way to achieve 2^k-1 subsequences is to add k elements that are all equal to current_val.
            // Then, for any subsequence of these k elements, max-min is 0.
            // To make them distinct from previous groups, we increment current_val by d+1.
            // This ensures that any subsequence containing elements from different groups will have max-min >= d+1.
            // So, we add k elements, all equal to current_val.
            // Then we increment current_val by d+1 for the next group.
            for (int i = 0; i < k - 1; ++i) {
                result_array.push_back(current_val);
            }
            current_val += d + 1;
        }
    }

    // Handle the remaining X, which must be 0 or 1
    if (X == 1) {
        result_array.push_back(current_val);
    } else if (X > 1) { // Should not happen with the current logic if X is correctly decomposed
        // This case implies an issue with the decomposition or X was too large for 60 bits
        // Given X <= 10^9, 2^30 is approx 10^9, so k=60 is more than enough.
        // If X is not 0 or 1 after the loop, it means it couldn't be formed.
        // However, the problem guarantees X can be formed by sum of 2^k-1.
        // The only remaining case is X=0, which means we've used all X.
        // If X=1, we add one more element.
        // If X=0, we are done.
    }

    if (result_array.empty() || result_array.size() > 10000) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zeros(n, 0); // left_zeros[i] = count of consecutive zeros ending at i
    std::vector<int> right_zeros(n, 0); // right_zeros[i] = count of consecutive zeros starting at i
    std::vector<int> left_ones(n, 0); // left_ones[i] = count of consecutive ones ending at i
    std::vector<int> right_ones(n, 0); // right_ones[i] = count of consecutive ones starting at i

    // Calculate left_zeros and left_ones
    if (a[0] == 0) {
        left_zeros[0] = 1;
    } else {
        left_ones[0] = 1;
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = left_zeros[i - 1] + 1;
            left_ones[i] = 0;
        } else {
            left_ones[i] = left_ones[i - 1] + 1;
            left_zeros[i] = 0;
        }
    }

    // Calculate right_zeros and right_ones
    if (a[n - 1] == 0) {
        right_zeros[n - 1] = 1;
    } else {
        right_ones[n - 1] = 1;
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = right_zeros[i + 1] + 1;
            right_ones[i] = 0;
        } else {
            right_ones[i] = right_ones[i + 1] + 1;
            right_zeros[i] = 0;
        }
    }

    int max_k = 0;
    std::vector<int> b = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0
            if (a[i - 1] == 1 && a[i + 1] == 1) { // 1 0 1 pattern
                // This 0 will turn into 1.
                // It's part of a 1-block that will expand.
                // The number of steps is min(length of 1s to left, length of 1s to right) + 1
                // length of 1s to left of i is left_ones[i-1]
                // length of 1s to right of i is right_ones[i+1]
                int k_val = std::min(left_ones[i - 1], right_ones[i + 1]) + 1;
                max_k = std::max(max_k, k_val);
                b[i] = 1; // In the final stable state, this will be 1
            }
        } else { // Current element is 1
            if (a[i - 1] == 0 && a[i + 1] == 0) { // 0 1 0 pattern
                // This 1 will turn into 0.
                // It's part of a 0-block that will expand.
                // The number of steps is min(length of 0s to left, length of 0s to right) + 1
                // length of 0s to left of i is left_zeros[i-1]
                // length of 0s to right of i is right_zeros[i+1]
                int k_val = std::min(left_zeros[i - 1], right_zeros[i + 1]) + 1;
                max_k = std::max(max_k, k_val);
                b[i] = 0; // In the final stable state, this will be 0
            }
        }
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Rule 1: If s[i] is '0', then w[i-x] (if exists) and w[i+x] (if exists) must be '0'.
    // This is a definitive assignment for w.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce the given s.
    // Rule 2: If s[i] is '1', then at least one of w[i-x] or w[i+x] must be '1'.
    // If this condition is not met for any s[i] == '1', then no such w exists.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            bool found_one = false;
            if (i - x >= 0 && w[i - x] == '1') {
                found_one = true;
            }
            if (i + x < n && w[i + x] == '1') {
                found_one = true;
            }

            if (!found_one) {
                std::cout << -1 << std::endl;
                return;
            }
        }
    }

    std::cout << w << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks vertices currently in the graph

    // Iterate backwards through the removal sequence
    // This means we are adding vertices one by one
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back

        active[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // Floyd-Warshall style: dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // Only consider active vertices for i, j, and k
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // Also update paths where k is an endpoint
        // dist[k][j] = min(dist[k][j], dist[k][i] + dist[i][j])
        // dist[i][k] = min(dist[i][k], dist[i][j] + dist[j][k])
        // This is implicitly handled by the triple loop if we iterate k first, then i, then j.
        // However, the standard Floyd-Warshall order is k (intermediate), then i, then j.
        // The above loop correctly updates paths using k as an intermediate for *existing* paths.
        // We also need to consider paths that might now be shorter because k is an endpoint.
        // The full Floyd-Warshall update for adding a vertex k is:
        // for i in active:
        //   for j in active:
        //     dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This is what the above loop does.
        // The initial dist[i][k] and dist[k][j] values are the direct edge weights or paths
        // that existed before k was added. When k is added, it can become an intermediate.
        // The crucial part is that when k is added, it can also be an endpoint.
        // The current `dist` matrix already contains direct edge weights for `k` to other nodes.
        // The triple loop `for i, for j, for k` (where k is the intermediate) is correct.
        // When we add vertex `k`, we need to update all `dist[i][j]` using `k` as an intermediate.
        // The `dist` matrix is being built up.
        // The order of loops for Floyd-Warshall is `k` (intermediate), then `i`, then `j`.
        // So, when `k` is the newly added vertex, we iterate `i` and `j` over all currently active vertices.
        // This correctly updates `dist[i][j]` using `k` as an intermediate.
        // It also updates `dist[i][k]` and `dist[k][j]` using other active vertices as intermediates.
        // Example: `dist[i][k] = min(dist[i][k], dist[i][p] + dist[p][k])` for `p` active.
        // This is covered by the `i, j` loops where `j` becomes `k`.

        // The standard Floyd-Warshall update for adding a vertex `k` is:
        // for i in active:
        //   for j in active:
        //     dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        //     dist[i][k] = min(dist[i][k], dist[i][j] + dist[j][k]) // This is important
        //     dist[k][j] = min(dist[k][j], dist[k][i] + dist[i][j]) // This is important
        // The current implementation of the triple loop:
        // for i in active:
        //   for j in active:
        //     if (dist[i][k] + dist[k][j] < dist[i][j]) dist[i][j] = dist[i][k] + dist[k][j];
        // This only updates paths *between* i and j using k.
        // It does not update paths *to* k or *from* k using other active vertices.
        // Let's refine the update for adding vertex `k`:
        // 1. Update paths involving `k` as an endpoint, using other active vertices as intermediates.
        //    For any active `i`:
        //      For any active `j`:
        //        dist[k][j] = min(dist[k][j], dist[k][i] + dist[i][j])
        //        dist[i][k] = min(dist[i][k], dist[i][j] + dist[j][k])
        // This needs to be done before `k` is used as an intermediate for `i` and `j`.
        // The simplest way to ensure all paths are correct is to run the full Floyd-Warshall step for `k`
        // as the intermediate, and ensure `dist[i][k]` and `dist[k][j]` are also updated.

        // Corrected update logic for adding vertex k:
        // First, update all paths involving k as an endpoint, using other active vertices as intermediates.
        // This ensures dist[i][k] and dist[k][j] are minimal before k is used as an intermediate.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                // Path from k to j via i
                if (dist[k][i] + dist[i][j] < dist[k][j]) {
                    dist[k][j] = dist[k][i] + dist[i][j];
                }
                // Path from i to k via j
                if (dist[i][j] + dist[j][k] < dist[i][k]) {
                    dist[i][k] = dist[i][j] + dist[j][k];
                }
            }
        }

        // Now, update all paths between any two active vertices i and j, using k as an intermediate.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before each step)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child goes to doctor, no longer in line

        long long current_v_cry = children[i].v;
        long long cumulative_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cumulative_d_cry from previous children who ran away
            children[j].p -= cumulative_d_cry;

            // Apply current_v_cry from the child in the doctor's office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j runs away
            if (children[j].p < 0) {
                children[j].in_line = false;
                cumulative_d_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // f values are only a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Two non-empty subsequences.
    // The minimum possible f value is a[0].value + a[1].value.
    // This occurs if a[0] and a[1] are in the same subsequence.
    // The maximum possible f value is max(a[n-1].value + a[n-2].value, a[n-1].value + a[0].value + h).
    // This occurs if a[n-1] and a[n-2] are in the same subsequence, OR
    // if a[n-1] and a[0] are in different subsequences.
    //
    // Consider a partition where a[0] is in S1, and a[1]...a[n-1] are in S2.
    // min_f: a[1].value + a[2].value (if n > 2, from S2)
    //        OR a[0].value + a[1].value + h (if a[0] in S1, a[1] in S2)
    // max_f: a[n-1].value + a[n-2].value (from S2)
    //        OR a[n-1].value + a[0].value + h (if a[n-1] in S2, a[0] in S1)
    //
    // The critical observation is that if we want to minimize max_f - min_f,
    // we should try to make the range of f values as small as possible.
    //
    // The smallest possible sum is a[0].value + a[1].value.
    // The largest possible sum is a[n-1].value + a[n-2].value.
    // The largest possible sum with h is a[n-1].value + a[n-0].value + h.
    //
    // If we put a[0] in S1 and all other elements in S2:
    // min_f = min(a[1].value + a[2].value (if n > 2), a[0].value + a[1].value + h)
    // max_f = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    //
    // Let's analyze the values:
    // V_same_min = a[0].value + a[1].value
    // V_same_max = a[n-1].value + a[n-2].value
    // V_diff_min = a[0].value + a[1].value + h
    // V_diff_max = a[n-1].value + a[n-0].value + h
    //
    // If we put a[0] in S1 and a[1]...a[n-1] in S2:
    // The values generated are:
    // 1. a[i] + a[j] for i,j in {1, ..., n-1} (from S2)
    //    Min: a[1].value + a[2].value (if n > 2)
    //    Max: a[n-1].value + a[n-2].value
    // 2. a[0].value + a[j].value + h for j in {1, ..., n-1} (S1-S2)
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-1].value + h
    //
    // So, for this partition:
    // min_f = a[0].value + a[1].value + h
    // max_f = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    //
    // Goodness = max_f - min_f
    //          = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) - (a[0].value + a[1].value + h)
    //          = std::max(a[n-1].value + a[n-2].value - (a[0].value + a[1].value + h), a[n-1].value - a[1].value)
    //
    // This is the goodness for the partition where a[0] is alone in S1.
    // Let's call this goodness2.
    long long goodness2;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    long long min_f_val_p2 = a[0].value + a[1].value + h;
    long long max_f_val_p2;
    if (n == 2) { // S2 only has a[1], no pairs within S2
        max_f_val_p2 = a[0].value + a[1].value + h;
    } else {
        max_f_val_p2 = std::max(a[n - 1].value + a[n - 2].value, a[0].value + a[n - 1].value + h);
    }
    goodness2 = max_f_val_p2 - min_f_val_p2;

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a(n);
    std::vector<long long> b(n, 0); // b_j = -min_j(A_j)

    // Step 1: Determine initial values for a_j based on type 2 operations
    // For each type 2 operation (l, r, m), we know that for all j in [l, r],
    // a_j + current_delta_j <= m.
    // This implies a_j <= m - current_delta_j.
    // To satisfy this for all type 2 operations, a_j must be less than or equal to
    // the minimum of (m - current_delta_j) over all type 2 operations that cover j.
    // We want to maximize a_j to make it easier to satisfy the max condition.
    // So, we initialize a_j to a very large value (effectively infinity)
    // and then take the minimum.
    // However, we don't know current_delta_j yet.
    // Let's define a_j = B_j - b_j, where B_j is the initial value and b_j is the
    // sum of d's applied to j by type 1 operations *before* any type 2 operation.
    // This is not quite right. Let's use the approach from the thought process.
    // We want to find initial values A_j.
    // Let A_j = x_j.
    // For each type 2 operation (l, r, m_i):
    // max_{k=l_i}^{r_i} (x_k + sum_of_d_before_this_op_for_k) = m_i
    // This implies x_k + sum_of_d_before_this_op_for_k <= m_i for all k in [l_i, r_i].
    // So, x_k <= m_i - sum_of_d_before_this_op_for_k.
    // Let's define `a[j]` as the initial value `A_j`.
    // Let `b[j]` be the sum of `d` values applied to `A_j` by type 1 operations
    // *that occur before any type 2 operation*. This is not useful.

    // Let's define `a[j]` as the initial value `A_j`.
    // We need to find `a[j]` such that `|a[j]| <= 10^9`.
    // For each type 2 operation `(l, r, m_i)`:
    // `max_{k=l_i}^{r_i} (a[k] + current_delta_k) = m_i`.
    // This implies `a[k] + current_delta_k <= m_i` for all `k` in `[l_i, r_i]`.
    // So, `a[k] <= m_i - current_delta_k`.
    // To satisfy all such inequalities, `a[k]` must be less than or equal to the minimum
    // of `(m_i - current_delta_k)` over all type 2 operations `i` that cover `k`.
    // Let `a[k]` be initialized to `m_i - current_delta_k` for some `i`.
    // We want to find the largest possible `a[k]` that satisfies all constraints.
    // Let `a[k]` be `m_i - current_delta_k` for some `i` where `m_i` is the maximum.
    // This is still not quite right.

    // The strategy is:
    // 1. For each type 2 operation (l, r, m_i), we know that for all j in [l, r],
    //    the initial value A_j must satisfy A_j <= m_i - (sum of d's applied to j *before* this operation).
    //    Let's denote `delta_j` as the sum of `d` values applied to `A_j` by type 1 operations
    //    *up to the current point in the sequence of operations*.
    //    Then for a type 2 operation `(l, r, m_i)`, we have `A_j + delta_j <= m_i` for `j` in `[l, r]`.
    //    This means `A_j <= m_i - delta_j`.
    //    We want to find the largest possible `A_j` that satisfies all these upper bounds.
    //    So, for each `j`, `A_j = min(m_i - delta_j)` over all type 2 operations `i` that cover `j`.
    //    To implement this, we can initialize `A_j` to a very large value (e.g., `2 * 10^9`)
    //    and then iterate through operations.
    //    When a type 1 operation `(l, r, d)` occurs, `delta_j` changes for `j` in `[l, r]`.
    //    When a type 2 operation `(l, r, m)` occurs, we update `A_j = min(A_j, m - delta_j)` for `j` in `[l, r]`.

    // Let's use `initial_a[j]` to store the value `A_j`.
    // Let `current_delta[j]` store the sum of `d` values applied to `A_j` so far.
    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());
    std::vector<long long> current_delta(n, 0);

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta[j] += op.val;
            }
        } else { // op.type == 2
            for (int j = op.l; j <= op.r; ++j) {
                initial_a[j] = std::min(initial_a[j], op.val - current_delta[j]);
            }
        }
    }

    // If any initial_a[j] is still max_long_long, it means it was not constrained by any type 2 operation.
    // We can set it to 0, or any value within bounds. Let's set it to 0.
    for (int j = 0; j < n; ++j) {
        if (initial_a[j] == std::numeric_limits<long long>::max()) {
            initial_a[j] = 0;
        }
    }

    // Step 2: Verify the constructed initial array
    // Simulate all operations with the constructed `initial_a` and check if type 2 operations match.
    std::vector<long long> simulated_a = initial_a;
    current_delta.assign(n, 0); // Reset current_delta for simulation

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                simulated_a[j] += op.val;
            }
        } else { // op.type == 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, simulated_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial_a
    for (int j = 0; j < n; ++j) {
        if (std::abs(initial_a[j]) > 1000000000LL) {
            // This case should ideally not be reached if the problem guarantees a solution
            // within 10^9. The bounds on m_i and d_i are such that initial_a[j]
            // should fit. m_i is up to 5*10^7, d_i up to 10^4. Max sum of d_i is 5000 * 10^4 = 5*10^7.
            // So m_i - current_delta_j can be around 5*10^7 - (-5*10^7) = 10^8.
            // This is well within 10^9.
            // If it's max_long_long, we set it to 0, which is also within bounds.
            // So this check is mostly for robustness, but shouldn't fail.
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> dp(m + 1, -1); // dp[i] = minimum head index required to cover p[0...i-1]
    dp[0] = -1; // Base case: 0 tracks covered, no head used (or head index -1)

    for (int i = 0; i < m; ++i) { // Iterate through target tracks p[i]
        if (dp[i] == -1) continue; // If p[0...i-1] cannot be covered, skip

        // Try to cover p[i] using a new head
        // Find the first head h[k] such that h[k] >= p[i] - T
        auto it_h_start = std::lower_bound(h.begin(), h.end(), p[i] - T);
        int k_start = std::distance(h.begin(), it_h_start);

        // We need a head with index >= dp[i] + 1
        // So, the actual starting head index to consider is max(dp[i] + 1, k_start)
        int current_head_idx = std::max((long long)dp[i] + 1, (long long)k_start);

        if (current_head_idx < n) { // If there's a head available
            // This head h[current_head_idx] can cover p[i]
            // The range covered by h[current_head_idx] is [h[current_head_idx] - T, h[current_head_idx] + T]
            // We need to find how many subsequent tracks p[j] can be covered by this head.
            // p[j] must be <= h[current_head_idx] + T
            auto it_p_end = std::upper_bound(p.begin() + i, p.end(), h[current_head_idx] + T);
            int j_end = std::distance(p.begin(), it_p_end); // p[j_end-1] is the last track covered

            // Update dp for all tracks covered by this head
            for (int j = i + 1; j <= j_end; ++j) {
                if (dp[j] == -1 || current_head_idx < dp[j]) {
                    dp[j] = current_head_idx;
                }
            }
        }
    }

    return dp[m] != -1;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10; // Max possible distance between p_m and h_1, or p_1 and h_n
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // The new string is s2s1.
    // We need s2s1 to be a palindrome and s2s1 != s.
    // If s2s1 is a palindrome, then s2s1 == reverse(s2s1).
    // Since s is a palindrome, s == reverse(s).
    // If s2s1 == s, then s2s1 is a palindrome.
    // So we are looking for a cut such that s2s1 is a palindrome AND s2s1 != s.
    // This means we need to find a cut point i (1 <= i < n) such that
    // s.substr(i) + s.substr(0, i) is a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // This means 3 pieces: s1, s2, s3.
    // s = s1s2s3.
    // We can reorder them.
    // The problem statement implies that if k=1 doesn't work, k=2 might.
    // The only case where k=1 doesn't work is if all possible rotations of s
    // that are palindromes are equal to s.
    // This happens if s consists of only one distinct character (e.g., "aaaaa")
    // or if s is a palindrome that, when rotated, always results in s itself
    // (e.g., "ababa" rotated by 2 is "baaba" which is not "ababa", but "ababa" rotated by 1 is "babaa").
    // For example, "qqqq" - any rotation is "qqqq".
    // "nolon" - rotations: "olon", "lon", "onol", "nolo". None are "nolon" and palindrome.
    // "otto" - rotations: "ttoo", "toot", "oot". "toot" is a palindrome and not "otto". So k=1.

    // If all characters in s are the same, e.g., "aaaaa", then no matter how you cut and reorder,
    // the resulting string will always be "aaaaa". In this case, it's impossible to get a new string.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 must work.
    // Why? Consider s = s_prefix + s_middle + s_suffix.
    // Since s is a palindrome, s_prefix = reverse(s_suffix).
    // Example: "nolon". n=5.
    // s_prefix = "no", s_middle = "l", s_suffix = "on".
    // We can cut it as "no" | "l" | "on".
    // Reorder to "on" | "l" | "no". This forms "onlno".
    // "onlno" is a palindrome and "onlno" != "nolon".
    // This requires 2 cuts.
    // This strategy works as long as s is not composed of all identical characters.
    // If s is a palindrome and not all characters are the same, then s must have at least two distinct characters.
    // Let s = c1 c2 ... c_k ... c2 c1.
    // If we take s_prefix = s[0], s_middle = s[1...n-2], s_suffix = s[n-1].
    // Then s_prefix = s[0], s_suffix = s[0] (since s is a palindrome).
    // This doesn't help much.
    // Consider s = s[0...i-1] | s[i...n-1-i] | s[n-i...n-1].
    // Let s_prefix = s.substr(0, i), s_middle = s.substr(i, n-2*i), s_suffix = s.substr(n-i).
    // Since s is a palindrome, s_prefix == reverse(s_suffix).
    // If we reorder to s_suffix + s_middle + s_prefix, this will be reverse(s_prefix) + s_middle + s_prefix.
    // This new string is a palindrome if s_middle is a palindrome.
    // And it will be different from s if s_prefix is not empty and s_prefix != reverse(s_prefix).
    // But s_prefix is not necessarily a palindrome.
    // The example "nolon" -> "no" | "l" | "on" -> "on" | "l" | "no" -> "onlno".
    // Here s_prefix = "no", s_middle = "l", s_suffix = "on".
    // "on" is reverse("no").
    // The new string is reverse(s_prefix) + s_middle + s_prefix.
    // This is a palindrome if s_middle is a palindrome.
    // For "nolon", s_middle = "l" is a palindrome.
    // The new string "onlno" is a palindrome.
    // This construction always yields a palindrome.
    // It will be different from s if s_prefix is not empty and s_prefix != reverse(s_prefix).
    // But s_prefix is not necessarily a palindrome.
    // The new string is `reverse(s_prefix) + s_middle + s_prefix`.
    // The original string is `s_prefix + s_middle + reverse(s_prefix)`.
    // These are different if `s_prefix != reverse(s_prefix)`.
    // If `s_prefix == reverse(s_prefix)` (i.e., `s_prefix` is a palindrome), then the new string is `s_prefix + s_middle + s_prefix`.
    // This is equal to `s` if `s_middle` is also a palindrome.
    //
    // The key insight for k=2 is that if s is a palindrome and not all characters are the same,
    // then there must exist at least one character `c` such that `s[0] != c`.
    // Since s is a palindrome, s[0] == s[n-1].
    // If we take s_prefix = s[0], s_middle = s[1...n-2], s_suffix = s[n-1].
    // This is not enough.
    //
    // Consider the string s. If it's not all the same character, then there must be some `s[i] != s[0]`.
    // Since s is a palindrome, s[i] == s[n-1-i].
    // If we cut s into `s[0...i-1]`, `s[i]`, `s[i+1...n-1-i-1]`, `s[n-1-i]`, `s[n-i...n-1]`.
    // This is getting too complicated.
    //
    // The simplest argument for k=2:
    // If s is a palindrome and not all characters are the same, then there exists an index `i` such that `s[i] != s[0]`.
    // Consider the cut `s[0]` | `s[1...n-2]` | `s[n-1]`.
    // Let `p1 = s[0]`, `p2 = s[1...n-2]`, `p3 = s[n-1]`.
    // Since `s` is a palindrome, `p1 == p3`.
    // We can reorder these pieces to `p3 + p2 + p1`.
    // This forms `s[n-1] + s[1...n-2] + s[0]`.
    // Since `s[n-1] == s[0]`, this new string is identical to `s`. This doesn't work.
    //
    // The example "nolon" -> "no" | "l" | "on" -> "onlno".
    // This is `s.substr(0,2)` | `s.substr(2,1)` | `s.substr(3,2)`.
    // Pieces are `s_prefix`, `s_middle`, `s_suffix`.
    // `s_prefix = "no"`, `s_middle = "l"`, `s_suffix = "on"`.
    // `s_suffix` is `reverse(s_prefix)`.
    // The new string is `s_suffix + s_middle + s_prefix`.
    // This is `reverse(s_prefix) + s_middle + s_prefix`.
    // This string is a palindrome if `s_middle` is a palindrome.
    // And it is different from `s` if `s_prefix != reverse(s_prefix)`.
    // No, this is not correct. `s_prefix` is "no", `reverse(s_prefix)` is "on".
    // The new string is "on" + "l" + "no" = "onlno". This is a palindrome.
    // The original string is "no" + "l" + "on" = "nolon". This is a palindrome.
    // These are different.
    // This construction works if we can find a `k` such that `s.substr(0, k)` is not a palindrome,
    // and `s.substr(k, n-2*k)` is a palindrome.
    // For "nolon", k=2. `s.substr(0,2)`="no" (not palindrome). `s.substr(2,1)`="l" (palindrome).
    // This construction always works for `k=2` if `s` is not all same characters.
    // We need to find an `i` such that `s.substr(0, i)` is not a palindrome.
    // If `s.substr(0, i)` is a palindrome for all `i < n/2`, then `s` must be of the form `aaaa...`.
    // For example, if `s = "abacaba"`.
    // `s.substr(0,1)` = "a" (palindrome).
    // `s.substr(0,2)` = "ab" (not palindrome).
    // So we can use `i=2`.
    // `s_prefix = "ab"`, `s_middle = "aca"`, `s_suffix = "aba"`.
    // `s_suffix` is `reverse(s_prefix)` is not true here. `s_suffix` is `s.substr(n-i)`.
    // `s_suffix` is `s.substr(5) = "ba"`.
    // `s_prefix = "ab"`, `s_middle = "aca"`, `s_suffix = "ba"`.
    // `s_suffix` is `reverse(s_prefix)`.
    // New string: `s_suffix + s_middle + s_prefix` = "ba" + "aca" + "ab" = "baacaab".
    // Is "baacaab" a palindrome? Yes.
    // Is "baacaab" != "abacaba"? Yes.
    // This works.
    // The condition for this to work is that `s_middle` (the middle part `s.substr(i, n-2*i)`) must be a palindrome.
    // Since `s` is a palindrome, `s.substr(i, n-2*i)` is always a palindrome.
    // The only remaining condition is that `s_prefix` is not empty and `s_prefix != reverse(s_prefix)`.
    // No, the new string is `reverse(s_prefix) + s_middle + s_prefix`.
    // This is a palindrome if `s_middle` is a palindrome.
    // `s_middle = s.substr(i, n - 2*i)`. Since `s` is a palindrome, any substring `s[j...k]` where `s[j...k]` is symmetric around the center of `s` is a palindrome.
    // `s_middle` is symmetric around the center of `s`, so `s_middle` is always a palindrome.
    // So `reverse(s_prefix) + s_middle + s_prefix` is always a palindrome.
    // We need this new string to be different from `s`.
    // `s = s_prefix + s_middle + reverse(s_prefix)`.
    // We need `reverse(s_prefix) + s_middle + s_prefix != s_prefix + s_middle + reverse(s_prefix)`.
    // This is true if `s_prefix != reverse(s_prefix)`.
    // So we need to find an `i` (1 <= i < n/2) such that `s.substr(0, i)` is not a palindrome.
    // If such an `i` exists, then `k=2` is the answer.
    // When does such an `i` NOT exist?
    // If `s.substr(0, i)` is a palindrome for all `1 <= i < n/2`.
    // Example: "aaaaa". `s.substr(0,1)`="a" (palindrome). `s.substr(0,2)`="aa" (palindrome).
    // In this case, `s` must be composed of all identical characters.
    // Example: "abacaba". `s.substr(0,1)`="a" (palindrome). `s.substr(0,2)`="ab" (not palindrome). So `i=2` works.
    //
    // So, if `s` is not composed of all identical characters, then there must be some `i` such that `s.substr(0, i)` is not a palindrome.
    // For such an `i`, we can use `s_prefix = s.substr(0, i)`, `s_middle = s.substr(i, n-2*i)`, `s_suffix = s.substr(n-i)`.
    // The pieces are `s_prefix`, `s_middle`, `s_suffix`.
    // Reorder to `s_suffix + s_middle + s_prefix`.
    // This is `reverse(s_prefix) + s_middle + s_prefix`.
    // This is a palindrome and different from `s`.
    // This construction uses 2 cuts.
    //
    // Therefore, if `k=1` doesn't work, and `s` is not all same characters, then `k=2` is the answer.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that s[l-1...r-1] contains a triple.
                                                // Initialize with n+1 (invalid r)

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through possible values of k.
        // The maximum value for k is such that x + 2k < n.
        // So, 2k < n - x, or k < (n - x) / 2.
        // Since k >= 1, we start k from 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x] == s[x + 2 * k]) {
                // Found a triple: s[x], s[x+k], s[x+2k]
                // The 1-based indices for this triple are x+1, x+k+1, x+2k+1.
                // The minimum l for this triple is x+1.
                // The minimum r for this triple is x+2k+1.
                // We need to update min_r_for_l[l] for all l from 1 to x+1.
                // For a fixed l, the smallest r that contains this triple is x+2k+1.
                // So, min_r_for_l[l] = min(min_r_for_l[l], x+2k+1).
                // This update needs to be done for l from 1 to x+1.
                // However, we can optimize this.
                // If we find a triple (x, k), it means any substring s[l..r] where l <= x+1 and r >= x+2k+1
                // contains this triple.
                // The smallest r for a given l is x+2k+1.
                // We want to find the smallest r for each l.
                // So, for l_idx from 1 to x+1, we update min_r_for_l[l_idx] = min(min_r_for_l[l_idx], x+2k+1).
                // This is equivalent to updating a range.
                // Since we are iterating x from left to right, and k from small to large,
                // x+2k+1 will generally increase.
                // The crucial observation is that for a fixed x, as k increases, x+2k+1 increases.
                // So, the first k that satisfies the condition for a given x will give the smallest x+2k+1.
                // This means we only need to consider the smallest k for each x.
                // The maximum k is 2. If k=1, x, x+1, x+2. If k=2, x, x+2, x+4.
                // If k=3, x, x+3, x+6.
                // The problem statement implies k can be any value.
                // However, the maximum distance between x and x+2k is 6.
                // If k > 3, then x+2k - x = 2k > 6.
                // If s[x] = s[x+k] = s[x+2k], then for any l <= x+1 and r >= x+2k+1, the pair (l,r) is counted.
                // The smallest r for such an l is x+2k+1.
                // So, for each l from 1 to x+1, we update min_r_for_l[l] with x+2k+1.
                // This is equivalent to:
                // min_r_for_l[x+1] = min(min_r_for_l[x+1], x+2k+1).
                // And then propagate this minimum to the left:
                // min_r_for_l[i] = min(min_r_for_l[i], min_r_for_l[i+1]) for i from x down to 1.
                // This propagation is done after the loop.

                // The maximum possible k is 3.
                // If k=1, we have s[x] = s[x+1] = s[x+2].
                // If k=2, we have s[x] = s[x+2] = s[x+4].
                // If k=3, we have s[x] = s[x+3] = s[x+6].
                // Any k > 3 would mean x+2k - x > 6.
                // If s[x] = s[x+k] = s[x+2k] for some k > 3, then it must be that
                // s[x] = s[x+1] = s[x+2] or s[x] = s[x+2] = s[x+4] or s[x] = s[x+3] = s[x+6]
                // must have occurred earlier or at the same x.
                // This is because if s[x] = s[x+k] = s[x+2k], then the substring s[x...x+2k] contains this pattern.
                // The length of this pattern is 2k+1.
                // If 2k+1 > 7 (i.e., k > 3), then it is guaranteed that there is a shorter pattern.
                // For example, if s[x] = s[x+4] = s[x+8], then the substring s[x...x+8] contains this.
                // But it also contains s[x...x+6] if s[x]=s[x+3]=s[x+6] or s[x...x+4] if s[x]=s[x+2]=s[x+4] etc.
                // This is a known property for "arithmetic progressions" in binary strings.
                // Any 3-term arithmetic progression of length > 7 must contain a shorter 3-term AP.
                // So we only need to check k=1, 2, 3.

                // Update min_r_for_l[x+1] (1-based index for l)
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 2 * k + 1);
            }
            if (k == 3) break; // Optimization: only need to check k=1, 2, 3
        }
    }

    // Propagate minimum r values from right to left.
    // If min_r_for_l[i] is valid, then min_r_for_l[i-1] must be at least as small as min_r_for_l[i].
    // This ensures that if a triple starts at or after i, it also covers i-1.
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long total_count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one triple starting at or after l
            // All r from min_r_for_l[l] to n will form a valid pair (l, r)
            total_count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_count << std::endl;

    return 0;
}

