    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // To maximize the binary number, we want to have as many '1's as possible,
    // followed by '0's.
    // A '1' is formed by "one" (o, n, e)
    // A '0' is formed by "zero" (z, e, r, o)

    // Count how many '1's can be formed
    // Each "one" requires one 'o', one 'n', one 'e'.
    int num_ones = count_n; // 'n' is unique to "one" among the letters 'o', 'n', 'e' for "one" and 'z', 'e', 'r', 'o' for "zero"
                            // 'n' is only used in "one". So the number of '1's is directly limited by count_n.

    // Count how many '0's can be formed
    // Each "zero" requires one 'z', one 'e', one 'r', one 'o'.
    int num_zeros = count_z; // 'z' is unique to "zero". So the number of '0's is directly limited by count_z.

    // The problem guarantees that it is possible to rearrange the letters
    // to form a sequence of "one"s and "zero"s.
    // This implies that the counts of 'e' and 'o' will be consistent.
    // For example, if we have X '1's and Y '0's:
    // Total 'e's needed = X (for "one") + Y (for "zero")
    // Total 'o's needed = X (for "one") + Y (for "zero")
    // Since num_ones = count_n and num_zeros = count_z,
    // the total 'e's available (count_e) must be equal to num_ones + num_zeros.
    // The total 'o's available (count_o) must be equal to num_ones + num_zeros.
    // The total 'r's available (count_r) must be equal to num_zeros.

    // Print all the '1's first
    bool first = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first) {
            std::cout << " ";
        }
        std::cout << 1;
        first = false;
    }

    // Then print all the '0's
    for (int i = 0; i < num_zeros; ++i) {
        if (!first) {
            std::cout << " ";
        }
        std::cout << 0;
        first = false;
    }
    std::cout << std::endl;

    return 0;
}

