        // k sticks for the torches themselves
        // k * y sticks for k coal
        // Total = k + k * y = k * (y + 1)
        long long total_sticks_needed = k * (y + 1);

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) additional sticks
        // using the first trade offer (1 stick -> x sticks).
        // Each such trade effectively increases our stick count by (x - 1).
        // Number of stick trades = ceil((total_sticks_needed - 1) / (x - 1))
        // Using integer division: (A + B - 1) / B for ceil(A/B)
        long long stick_trades = (total_sticks_needed - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = stick_trades (to get enough sticks) + k (to get k coal)
        long long total_trades = stick_trades + k;

        std::cout << total_trades << "\n";
    }
