            if (!has_minus_one) {
                possible = false;
                break;
            }
        }

        // Update flags for the next iteration (i-1)
        if (a[i] == 1) has_one = false;
        if (a[i] == -1) has_minus_one = false;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

