void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<bool> row_taken(n, false);
    std::vector<bool> col_taken(m, false);
    int initial_taken_count = 0;

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            int val;
            std::cin >> val;
            if (val == 1) {
                if (!row_taken[i]) {
                    row_taken[i] = true;
                    initial_taken_count++;
                }
                if (!col_taken[j]) {
                    col_taken[j] = true;
                    initial_taken_count++;
                }
            }
        }
    }

    int available_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_taken[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_taken[j]) {
            available_cols++;
        }
    }

    int moves_possible = std::min(available_rows, available_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

