int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration_per_post = total_sum / k;
    std::vector<int> s_values;
    long long current_post_duration = 0;
    int current_post_videos_count = 0;
    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_duration += a[i];
        current_post_videos_count++;

        if (current_post_duration > target_duration_per_post) {
            std::cout << "No\n";
            return 0;
        } else if (current_post_duration == target_duration_per_post) {
            s_values.push_back(current_post_videos_count);
            posts_formed++;
            current_post_duration = 0;
            current_post_videos_count = 0;
        }
    }

    if (posts_formed == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be covered by current_post_duration != 0 after loop
        // or posts_formed > k if target_duration_per_post was 0 (not possible with a_i >= 1)
        // or posts_formed < k if some posts couldn't be formed.
        // The logic above ensures current_post_duration is 0 if a post was completed.
        // If current_post_duration is not 0 here, it means the last segment didn't sum up to target_duration_per_post.
        // If current_post_duration is 0 but posts_formed != k, it means we either formed too few or too many.
        // Too many is impossible because we only increment posts_formed when current_post_duration == target_duration_per_post.
        // Too few means the total sum was not divisible by target_duration_per_post, which is checked at the beginning.
        // So, if we reach here, it implies an inconsistency, which means "No".
        std::cout << "No\n";
    }

    return 0;
}

