#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        // The frog starts at cell 0.
        // It needs to reach cell n+1.
        // It can only jump right from cell 0.
        // If it lands on cell i (1 <= i <= n) and s[i-1] is 'R', it can jump right.
        // If it lands on cell i (1 <= i <= n) and s[i-1] is 'L', it can jump left.

        // The key observation is that to reach n+1, the frog must always make progress to the right.
        // Jumps to the left are only useful if they allow the frog to bypass an 'R' cell
        // that would otherwise prevent it from reaching n+1 with the current 'd'.
        // However, the problem states that the frog can jump to any cell in the range.
        // If the frog is at cell `i` and `s[i-1]` is 'R', it can jump to `[i+1, min(n+1, i+d)]`.
        // If the frog is at cell `i` and `s[i-1]` is 'L', it can jump to `[max(0, i-d), i-1]`.

        // Consider the sequence of 'R' cells.
        // The frog must be able to jump from 0 to the first 'R' cell, or directly to n+1.
        // Then from that 'R' cell to the next 'R' cell, and so on, until it reaches n+1.
        // 'L' cells are effectively obstacles that prevent direct rightward movement from them.
        // If the frog lands on an 'L' cell, it must jump left. This means it must have
        // jumped over this 'L' cell from a previous 'R' cell (or 0).

        // The problem simplifies to finding the maximum distance between consecutive 'R' cells (including 0 and n+1).
        // Let's consider the positions of 'R' characters.
        // The frog starts at 0.
        // It needs to reach n+1.
        // If it's at cell `curr_pos`, it needs to jump to `next_pos`.
        // The maximum distance it needs to cover in a single rightward jump is `next_pos - curr_pos`.
        // The minimum `d` must be at least this maximum required jump distance.

        // Let's list all positions from which the frog can jump right:
        // 0 (initial position)
        // i, where s[i-1] == 'R' (for 1 <= i <= n)

        // We can imagine adding 'R' at index -1 (representing cell 0) and 'R' at index n (representing cell n+1).
        // The actual string indices are 0 to n-1, corresponding to cells 1 to n.
        // So, s[i] corresponds to cell i+1.

        // Let's track the last position from which a right jump was possible.
        // Initially, this is cell 0.
        int last_r_pos = 0;
        int max_gap = 0;

        for (int i = 0; i < n; ++i) {
            // s[i] corresponds to cell i+1
            if (s[i] == 'R') {
                // If we encounter an 'R' at cell i+1, it means we can jump from last_r_pos to i+1.
                // The distance is (i+1) - last_r_pos.
                // We need d to be at least this distance.
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1; // Update last_r_pos to the current 'R' cell
            }
        }

        // After iterating through the string, last_r_pos holds the position of the last 'R' cell.
        // The frog still needs to jump from last_r_pos to n+1.
        max_gap = std::max(max_gap, (n + 1) - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

