    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // Remaining students: (c - mid) coders, (m - mid) mathematicians, x no-specialization.
            // Total remaining students: (c - mid) + (m - mid) + x
            // Each team needs 3 members. 'mid' teams need 3 * 'mid' members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' more members from the remaining pool.
            // The remaining pool is (c - mid) + (m - mid) + x.
            // If this sum is >= mid, then we can form 'mid' teams.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_elements;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_elements.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            if (used_elements.count(q[i])) {
                // This should not happen if q is valid, as q_i must be distinct from previous p_j if it's a new max
                // and p_j are distinct. But as a safety check.
                possible = false;
                break;
            }
            p[i] = q[i];
            used_elements.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some unused value less than q_i
            // We need to find the smallest available number that is not used and is <= q_i.
            // To maximize chances of finding a solution, we should pick the smallest available number.
            // The numbers available are those from 1 to n that haven't been used yet.
            // We need to find an unused number x such that x < q_i.
            // The largest possible value for p_i in this case is q_i-1.
            // We can use a set of available numbers or iterate.
            // A more efficient way is to pre-populate a set of all numbers from 1 to n,
            // then remove used numbers.
            // However, we need to pick the smallest available number that is *not* q_i.
            // The numbers that are not used are in the range [1, n] \ used_elements.
            // We need to find the smallest x in this set such that x < q_i.
            // The problem statement implies we can pick *any* suitable permutation.
            // So, we can pick the smallest available number that is not q_i.
            // The numbers that are available for p_i are those in [1, n] that are not in used_elements.
            // We need to find the smallest such number that is also less than q_i.
            // Let's find the smallest number in [1, n] that is not in used_elements.
            // We can iterate from 1 upwards.
            // A more efficient way is to maintain a sorted list/set of available numbers.
            // Or, since we are looking for *any* solution, we can just pick the smallest available number.
            // The smallest available number must be less than q_i, otherwise q_i would be the new maximum.
            // If we pick the smallest available number, say `val`, and `val >= q_i`, then `max(q_{i-1}, val)` would be `val`.
            // But `q_i` is `q_{i-1}`, so `val` must be less than `q_i`.
            // So we need to find the smallest `x` such that `x` is not in `used_elements` and `x < q_i`.
            // The smallest available number is `*std::min_element(available_numbers.begin(), available_numbers.end())`.
            // A better approach: maintain a set of all numbers from 1 to n. Remove numbers as they are used.
            // When q_i == q_{i-1}, find the smallest number in the set that is less than q_i.
            // This is equivalent to finding the smallest number in the set.
            // If the smallest number in the set is >= q_i, then it's impossible.

            // Let's find the smallest number not yet used.
            int current_val = 1;
            while (used_elements.count(current_val)) {
                current_val++;
            }

            if (current_val >= q[i]) { // q[i] == q[i-1]
                possible = false;
                break;
            }
            p[i] = current_val;
            used_elements.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_stair_cost = 1; // Cost for n=1: 1
        long long n_val = 1; // Current n for which we calculate cost

        while (true) {
            if (x >= current_stair_cost) {
                x -= current_stair_cost;
                count++;
                // Calculate cost for the next staircase (n_next = 2*n_val + 1)
                // The cost for n_next is (n_next * (n_next + 1) / 2)
                // which is (2*n_val + 1) * (2*n_val + 2) / 2
                // = (2*n_val + 1) * (n_val + 1)
                // This can also be derived as:
                // cost(2n+1) = cost(n) + (n+1)^2 + (n+1)n
                // cost(2n+1) = cost(n) + (n+1)(2n+1)
                // current_stair_cost = n_val * (n_val + 1) / 2
                // next_stair_cost = (2*n_val + 1) * (2*n_val + 2) / 2
                //                 = (2*n_val + 1) * (n_val + 1)
                // The difference is (2*n_val + 1) * (n_val + 1) - n_val * (n_val + 1) / 2
                // This is not the recurrence for cost, but for the next n.
                // The recurrence for cost is:
                // C(n) = n(n+1)/2
                // C(2n+1) = (2n+1)(2n+2)/2 = (2n+1)(n+1)
                // The cost of the next staircase (with 2*n_val + 1 stairs) is:
                // (2*n_val + 1) * (n_val + 1)
                // This is the cost of the staircase with (2*n_val + 1) stairs.
                // The recurrence for the cost of the next staircase in the sequence 1, 3, 7, 15, ...
                // Let C_k be the cost of the k-th staircase in this sequence.
                // C_0 = 1 (for n=1)
                // C_1 = 6 (for n=3)
                // C_2 = 28 (for n=7)
                // The recurrence is C_{k+1} = C_k * 4 + (2^{k+1} + 1) * (2^{k+1} + 2) / 2 - (2^k + 1) * (2^k + 2) / 2
                // No, the recurrence is simpler:
                // The cost of a staircase with N stairs is N*(N+1)/2.
                // The sequence of N values is 1, 3, 7, 15, ... which is 2^k - 1 for k=1, 2, 3, ...
                // No, it's 2^k + 1 for k=0, 1, 2, ...
                // N_0 = 1
                // N_1 = 3
                // N_2 = 7
                // N_k = 2^(k+1) - 1
                // The cost for N_k is (2^(k+1) - 1) * (2^(k+1)) / 2
                // Let's use the recurrence for `current_stair_cost` directly.
                // If current_stair_cost is for n, then the next n is 2*n + 1.
                // The cost for n is n*(n+1)/2.
                // The cost for 2n+1 is (2n+1)*(2n+2)/2 = (2n+1)*(n+1).
                // So, if current_stair_cost = n*(n+1)/2, then n = (-1 + sqrt(1 + 8*current_stair_cost))/2.
                // This is too complex.
                // Let's use the recurrence:
                // n_val_new = 2 * n_val + 1
                // current_stair_cost_new = n_val_new * (n_val_new + 1) / 2
                // This can be simplified:
                // current_stair_cost_new = (2 * n_val + 1) * (2 * n_val + 2) / 2
                //                        = (2 * n_val + 1) * (n_val + 1)
                // This is the cost of the staircase with (2*n_val + 1) stairs.
                // We can also express this in terms of current_stair_cost:
                // current_stair_cost = n_val * (n_val + 1) / 2
                // (n_val + 1) = 2 * current_stair_cost / n_val
                // current_stair_cost_new = (2 * n_val + 1) * (n_val + 1)
                //                        = (2 * n_val + 1) * (2 * current_stair_cost / n_val)
                // This is not simpler.
                // Let's use the direct recurrence for current_stair_cost:
                // C_k = (2^(k+1)-1) * (2^(k+1))/2
                // C_0 = (2^1-1)*(2^1)/2 = 1*2/2 = 1
                // C_1 = (2^2-1)*(2^2)/2 = 3*4/2 = 6
                // C_2 = (2^3-1)*(2^3)/2 = 7*8/2 = 28
                // C_3 = (2^4-1)*(2^4)/2 = 15*16/2 = 120
                // The recurrence for C_k is C_{k+1} = (2*N_k + 1) * (N_k + 1) where N_k = 2^(k+1)-1
                // No, the recurrence for the cost itself is:
                // C_{k+1} = (2*N_k + 1) * (N_k + 1)
                // N_k = 2^(k+1)-1
                // N_{k+1} = 2^(k+2)-1 = 2*(2^(k+1)-1) + 1 = 2*N_k + 1
                // So, the cost for N_{k+1} is N_{k+1} * (N_{k+1} + 1) / 2
                // = (2*N_k + 1) * (2*N_k + 2) / 2
                // = (2*N_k + 1) * (N_k + 1)
                // We have current_stair_cost = N_k * (N_k + 1) / 2.
                // So, N_k = (-1 + sqrt(1 + 8 * current_stair_cost)) / 2.
                // This is too complex.
                // Let's use the recurrence for `n_val` and then calculate `current_stair_cost`.
                n_val = 2 * n_val + 1;
                // Check for overflow before multiplication
                if (n_val > 2000000000LL) { // n_val * (n_val + 1) / 2 could exceed LLONG_MAX
                                            // if n_val is around 3*10^9.
                                            // Max x is 10^18. Max cost is around 10^18.
                                            // n_val * (n_val + 1) / 2 <= 10^18
                                            // n_val^2 / 2 <= 10^18 => n_val^2 <= 2*10^18
                                            // n_val <= sqrt(2)*10^9 approx 1.4 * 10^9.
                                            // So n_val can go up to ~1.4 * 10^9.
                                            // 2 * n_val + 1 can be ~2.8 * 10^9.
                                            // (2.8 * 10^9) * (1.4 * 10^9) is too large.
                                            // The next cost is (2*n_val + 1) * (n_val + 1).
                                            // If n_val is 1.4 * 10^9, then (2*n_val + 1) is 2.8 * 10^9.
                                            // (n_val + 1) is 1.4 * 10^9.
                                            // Their product is (2.8 * 1.4) * 10^18 = 3.92 * 10^18.
                                            // This fits in long long.
                                            // The next cost is (2*n_val + 1) * (n_val + 1).
                                            // If n_val is 1, cost is 1. Next n_val is 3. Next cost is 3*4/2 = 6.
                                            // If n_val is 3, cost is 6. Next n_val is 7. Next cost is 7*8/2 = 28.
                                            // If n_val is 7, cost is 28. Next n_val is 15. Next cost is 15*16/2 = 120.
                                            // The recurrence for current_stair_cost is:
                                            // current_stair_cost_new = (2 * n_val + 1) * (n_val + 1)
                                            // This is the cost of the staircase with (2*n_val + 1) stairs.
                                            // This is the value we need to assign to current_stair_cost for the next iteration.
                                            // Let's check for overflow for (2 * n_val + 1) * (n_val + 1)
                                            // If n_val is around 1.4 * 10^9, then (n_val + 1) is also around 1.4 * 10^9.
                                            // (2 * n_val + 1) is around 2.8 * 10^9.
                                            // Product is around 3.92 * 10^18. This fits in long long.
                                            // However, if n_val is already large, say 2*10^9, then (2*n_val+1) is 4*10^9,
                                            // and (n_val+1) is 2*10^9. Their product is 8*10^18. This fits.
                                            // But if n_val is 3*10^9, then (2*n_val+1) is 6*10^9, (n_val+1) is 3*10^9.
                                            // Product is 18*10^18, which overflows.
                                            // So, we need to check if n_val is too large before calculating the next cost.
                                            // The maximum n_val for which n_val*(n_val+1)/2 <= 10^18 is approx 1.414 * 10^9.
                                            // So, if n_val exceeds this, the next cost will definitely exceed 10^18.
                                            // A safe upper bound for n_val to avoid overflow in (2*n_val+1)*(n_val+1)
                                            // is when (2*n_val+1)*(n_val+1) > LLONG_MAX.
                                            // (2*n_val+1)*(n_val+1) approx 2*n_val^2.
                                            // 2*n_val^2 > 9*10^18 => n_val^2 > 4.5*10^18 => n_val > 2.1*10^9.
                                            // So if n_val is already > 2*10^9, the next cost will overflow.
                                            // Let's use a slightly smaller threshold for safety.
                if (n_val > 1500000000LL) { // If n_val is already this large, the next cost will be > 10^18
                                            // and likely overflow long long.
                    break;
                }
                current_stair_cost = n_val * (n_val + 1) / 2;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

