    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences

    // Generate k distinct differences using numbers from 1 to k+1
    // The pattern is 1, k+1, 2, k, 3, k-1, ...
    // This generates differences k, k-1, k-2, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // For the remaining n - (k+1) elements, just append them in increasing order
    // starting from k+2. This will only introduce difference 1.
    // Example: if k=2, n=5. p[0]=1, p[1]=3, p[2]=2.
    // Next numbers are 4, 5. Append them: 1 3 2 4 5.
    // Differences: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1. Distinct: 1, 2. (k=2)
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
