#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Arrays of length 0, 1, 2 are always good.
                  // Length 0: empty array is good.
                  // Length 1: [x] -> c=[x] (non-decreasing).
                  // Length 2: [x, y] -> if x<=y, take x then y. if x>y, take y then x. (c=[x,y] or c=[y,x]).
                  // The problem states "array consisting of one element is good".
                  // For length 2, [x,y], we can always make it non-decreasing.
                  // E.g., if x <= y, take x, then y. c = [x, y].
                  // If x > y, take y, then x. c = [y, x].
                  // So any array of length <= 2 is good.
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This is the suffix that looks like `... x y z` where `x <= y <= z`.
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This is the suffix that looks like `... p q r` where `p >= q >= r`.
    // We start searching from `i-1` because `a[i...n-1]` is already non-decreasing.
    // We are looking for the "peak" or "valley" structure.
    // The structure of a good array suffix is `... decreasing part ... increasing part`.
    // The `i` we found above marks the start of the increasing part.
    // We need to find the start of the decreasing part.
    int j = i; // j starts where the increasing part starts.
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing, and a[i...n-1] is non-decreasing.
    // The suffix a[j...n-1] is a candidate for a good array.
    // The length of the prefix to erase is `j`.

    std::cout << j << std::endl;
}

