#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a specific box can be the final box
// `target_box_idx` is 0-indexed (0 for Box 1, 1 for Box 2, etc.)
bool can_be_final(long long A, long long B, long long C, long long D, int target_box_idx) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        return false;
    }
    if (total_toys == 1) {
        if (A == 1 && target_box_idx == 0) return true;
        if (B == 1 && target_box_idx == 1) return true;
        if (C == 1 && target_box_idx == 2) return true;
        if (D == 1 && target_box_idx == 3) return true;
        return false;
    }

    // Case 1: Final toy is in Box 1 (Negative, magnitude >= 1)
    if (target_box_idx == 0) {
        // To get a negative result, we need an odd number of negative factors.
        // To get magnitude >= 1, we need to be able to achieve it.
        // If there are any N1 or P1 toys, we can always make magnitude >= 1.
        // If all toys are N0/P0, we can only make magnitude >= 1 if we have 0 toys.
        // But we have total_toys > 1.
        // So if A+D > 0, we can always make magnitude >= 1.
        // If A+D == 0, then all initial toys are N0 or P0.
        // In this case, the product of any number of N0/P0 toys will always be in (-1, 1).
        // So if A+D == 0, we cannot end up in Box 1 or Box 4.
        if (A + D == 0) return false; // Cannot achieve magnitude >= 1

        // We need an odd number of negative factors.
        // The number of negative factors is A + B.
        // If A+B is odd, we can achieve a negative result.
        // If A+B is even, we need to introduce an odd number of negative factors.
        // This can be done by pairing two positive toys (P0*P0 or P0*P1 or P1*P1)
        // to create a positive toy, then pairing it with a negative toy.
        // Or, if we have an even number of negative toys, we can pair them up to make positive toys.
        // The parity of negative toys (A+B) determines the sign of the final product.
        // If (A+B) is odd, we can get a negative result.
        // If (A+B) is even, we can get a positive result.
        // So, if (A+B) is odd, Box 1 is possible.
        return (A + B) % 2 != 0;
    }

    // Case 2: Final toy is in Box 2 (Negative, magnitude < 1)
    if (target_box_idx == 1) {
        // To get a negative result, we need an odd number of negative factors.
        // To get magnitude < 1, we need to be able to achieve it.
        // If there are any N0 or P0 toys, we can always make magnitude < 1.
        // If all toys are N1/P1, we can only make magnitude < 1 if we have 0 toys.
        // But we have total_toys > 1.
        // So if B+C > 0, we can always make magnitude < 1.
        // If B+C == 0, then all initial toys are N1 or P1.
        // In this case, the product of any number of N1/P1 toys will always be in (-inf, -1] or [1, inf).
        // So if B+C == 0, we cannot end up in Box 2 or Box 3.
        if (B + C == 0) return false; // Cannot achieve magnitude < 1

        // We need an odd number of negative factors.
        // If (A+B) is odd, Box 2 is possible.
        return (A + B) % 2 != 0;
    }

    // Case 3: Final toy is in Box 3 (Positive, magnitude < 1)
    if (target_box_idx == 2) {
        // To get a positive result, we need an even number of negative factors.
        // To get magnitude < 1, we need to be able to achieve it.
        // If B+C == 0, we cannot achieve magnitude < 1.
        if (B + C == 0) return false;

        // We need an even number of negative factors.
        // If (A+B) is even, Box 3 is possible.
        return (A + B) % 2 == 0;
    }

    // Case 4: Final toy is in Box 4 (Positive, magnitude >= 1)
    if (target_box_idx == 3) {
        // To get a positive result, we need an even number of negative factors.
        // To get magnitude >= 1, we need to be able to achieve it.
        // If A+D == 0, we cannot achieve magnitude >= 1.
        if (A + D == 0) return false;

        // We need an even number of negative factors.
        // If (A+B) is even, Box 4 is possible.
        return (A + B) % 2 == 0;
    }

    return false; // Should not be reached
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::string result[4];
        for (int i = 0; i < 4; ++i) {
            if (can_be_final(A, B, C, D, i)) {
                result[i] = "Ya";
            } else {
                result[i] = "Tidak";
            }
        }
        std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;

    // Iterate through each point as the first point of a potential triplet
    for (int i = 0; i < n; ++i) {
        // Find the rightmost point 'k' such that x[k] - x[i] <= d
        // This means x[k] <= x[i] + d
        // std::upper_bound returns an iterator to the first element greater than x[i] + d.
        // We want elements less than or equal to x[i] + d, so we take the element before it.
        auto it = std::upper_bound(x.begin() + i + 1, x.end(), x[i] + d);

        // The index of the last valid point 'k' is (it - 1) - x.begin()
        // If it points to x.begin() + i + 1, it means no point satisfies the condition.
        // If it points to x.begin() + i + 1, then it - (x.begin() + i + 1) = 0.
        // The number of points in the range [i+1, k_idx] is k_idx - (i+1) + 1 = k_idx - i.

        // The number of points in the range (x[i], x[i]+d] is (it - x.begin()) - (i + 1).
        // Let's call this number 'm'. These are the candidates for the second and third points.
        // These points are at indices from i+1 up to (it - x.begin() - 1).

        long long m = (it - x.begin()) - (i + 1);

        // If there are at least two points available (m >= 2) after x[i]
        // that satisfy the distance condition, we can form triplets.
        // From these 'm' points, we need to choose 2 points to form the pair (x[j], x[k]).
        // The number of ways to choose 2 points from 'm' points is m * (m - 1) / 2.
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Operations for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Operations for elements to the left of the median
    // These elements must be <= s. If a[i] > s, we must decrease it to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Operations for elements to the right of the median
    // These elements must be >= s. If a[i] < s, we must increase it to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

