// Function to check if a sub-array is a permutation of its length
// This version uses a boolean array for efficiency
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int length) {
    if (length <= 0) return false; // A permutation must have positive length
    if (end_idx - start_idx + 1 != length) return false; // Length mismatch

    std::vector<bool> seen(length + 1, false);
    for (int i = start_idx; i <= end_idx; ++i) {
        if (arr[i] < 1 || arr[i] > length || seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute max values for prefixes and suffixes
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute prefix permutation checks
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[L] means a[0...L-1] is a perm of length L
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool possible_prefix = true;
    for (int l1 = 1; l1 <= n; ++l1) {
        int val = a[l1 - 1];
        if (!possible_prefix || val < 1 || val > l1 || seen_prefix[val]) {
            possible_prefix = false;
        } else {
            seen_prefix[val] = true;
            current_max_prefix = std::max(current_max_prefix, val);
            if (current_max_prefix == l1) { // All numbers from 1 to l1 seen, and max is l1
                is_prefix_perm[l1] = true;
            }
        }
    }

    // Precompute suffix permutation checks
    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[L] means a[n-L...n-1] is a perm of length L
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool possible_suffix = true;
    for (int l2 = 1; l2 <= n; ++l2) {
        int val = a[n - l2];
        if (!possible_suffix || val < 1 || val > l2 || seen_suffix[val]) {
            possible_suffix = false;
        } else {
            seen_suffix[val] = true;
            current_max_suffix = std::max(current_max_suffix, val);
            if (current_max_suffix == l2) { // All numbers from 1 to l2 seen, and max is l2
                is_suffix_perm[l2] = true;
            }
        }
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if p1 is a permutation of length l1
        // Condition 1: max element in p1 must be l1
        // Condition 2: all elements 1 to l1 must be present exactly once (checked by is_prefix_perm)
        bool p1_ok = (prefix_max[l1 - 1] == l1) && is_prefix_perm[l1];

        // Check if p2 is a permutation of length l2
        // Condition 1: max element in p2 must be l2
        // Condition 2: all elements 1 to l2 must be present exactly once (checked by is_suffix_perm)
        bool p2_ok = (suffix_max[l1] == l2) && is_suffix_perm[l2];

        if (p1_ok && p2_ok) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

