long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        // Mr. Chanek's turn
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2 || n == 4) { // Special cases for N=2, N=4
                chanek_coins += n / 2;
                n -= n / 2;
            } else if ((n / 2) % 2 != 0) { // N/2 is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N/2 is even
                chanek_coins += n / 2;
                n -= n / 2;
            }
        }

        if (n == 0) break;

        // Opponent's turn
        if (n % 2 != 0) { // N is odd
            n -= 1;
        } else { // N is even
            if (n == 2 || n == 4) { // Special cases for N=2, N=4
                n -= n / 2;
            } else if ((n / 2) % 2 != 0) { // N/2 is odd
                n -= 1;
            } else { // N/2 is even
                n -= n / 2;
            }
        }
    }
    return chanek_coins;
}

