}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    int initial_wins = 0;
    for (char c : s) {
        if (c == 'W') {
            initial_wins++;
        }
    }

    if (initial_wins + k >= n) { // Can make all games 'W'
        if (n == 0) return 0; // Should not happen based on constraints n >= 1
        return 2 * n - 1;
    }

    if (initial_wins == 0 && k == 0) { // All 'L's, no changes
        return 0;
    }

    // Calculate initial score
    int current_score = 0;
    if (s[0] == 'W') {
        current_score = 1;
    }
    for (int i = 1; i < n; ++i) {
        if (s[i] == 'W') {
            if (s[i - 1] == 'W') {
                current_score += 2;
            } else {
                current_score += 1;
            }
        }
    }

    // Find segments of 'L's between 'W's
    std::vector<int> l_segments;
    int first_w = -1;
    int last_w = -1;

    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (first_w == -1) {
                first_w = i;
            }
            last_w = i;
        }
    }

    if (first_w == -1) { // All 'L's initially
        if (k == 0) return 0;
        // Change k 'L's to 'W's.
        // The first 'W' gives 1 point.
        // The next k-1 'W's give 2 points each if they are consecutive.
        // Since we can choose any k 'L's, we can make them consecutive.
        return 2 * k - 1;
    }

    // Collect lengths of 'L' segments between 'W's
    int current_l_count = 0;
    for (int i = first_w + 1; i <= last_w; ++i) {
        if (s[i] == 'L') {
            current_l_count++;
        } else { // s[i] == 'W'
            if (current_l_count > 0) {
                l_segments.push_back(current_l_count);
            }
            current_l_count = 0;
        }
    }
    std::sort(l_segments.begin(), l_segments.end());

    // Fill 'L' segments between 'W's
    for (int segment_len : l_segments) {
        if (k >= segment_len) {
            k -= segment_len;
            current_score += 2 * segment_len + 1; // Each L becomes W, connecting two Ws, adds 2*len + 1
                                                   // (len L's become W's, each adds 2 points, plus 1 for connecting)
                                                   // More precisely, each L becomes W, adds 2 points.
                                                   // The W after the segment now gets 2 points instead of 1.
                                                   // So, 2*segment_len + 1.
                                                   // Example: W L W -> W W W. Score changes from (1+1) to (1+2+2). Diff = 3. segment_len=1. 2*1+1=3.
                                                   // Example: W L L W -> W W W W. Score changes from (1+1) to (1+2+2+2). Diff = 4. segment_len=2. 2*2+1=5.
                                                   // Wait, the score calculation is:
                                                   // W L W: 1 (for first W) + 0 (for L) + 1 (for second W) = 2
                                                   // W W W: 1 (for first W) + 2 (for second W) + 2 (for third W) = 5
                                                   // Difference is 3.
                                                   // The number of L's changed is `segment_len`. Each change costs 1 `k`.
                                                   // Each changed L becomes a W. This adds `segment_len` to `initial_wins`.
                                                   // Each changed L now contributes 2 points. So `2 * segment_len` points.
                                                   // Additionally, the W *after* this segment now gets 2 points instead of 1. This is +1 point.
                                                   // So, `2 * segment_len + 1` is correct.
        } else {
            break;
        }
    }

    // Use remaining k to change 'L's at the ends or remaining 'L's
    current_score += 2 * k; // Each remaining k changes an L to W. This W will be adjacent to another W (if possible) or start a new chain.
                            // If it's adjacent to a W, it adds 2 points.
                            // If it's not adjacent to a W, it adds 1 point.
                            // Since we prioritize connecting, any remaining k will be used to extend existing W chains or create new ones.
                            // If we have W...W L L L L, and k=2, we change two L's to W's: W...W W W L L.
                            // The two new W's each add 2 points. So 2*k.
                            // This is because we already accounted for the +1 bonus from connecting segments.
                            // Any remaining k will be used to convert L's to W's. Each such W will either extend a chain (2 points)
                            // or start a new chain (1 point). Since we want to maximize, we assume they extend chains.
                            // The `initial_wins + k` check at the beginning handles the case where we can make all 'W's.
                            // So here, we are always adding 'W's that are adjacent to other 'W's or creating new 'W's.
                            // If we have W...W L L L, and k=1, we get W...W W L L. The new W adds 2 points.
                            // If we have L L L W...W, and k=1, we get L L W W...W. The new W adds 2 points.
                            // If we have L L L, and k=1, we get L L W. The new W adds 1 point.
                            // The `initial_wins + k >= n` check handles the case where we can make all 'W's.
                            // If `initial_wins == 0` and `k > 0`, we already handled it.
                            // So, if we reach here, `initial_wins > 0`.
                            // Any remaining `k` changes will be used to convert `L`s to `W`s.
                            // Each such `W` will either be adjacent to an existing `W` (contributing 2 points)
                            // or it will be isolated (contributing 1 point).
                            // Since we want to maximize, we assume they are adjacent to existing `W`s.
                            // This means each of the `k` changes adds 2 points.
                            // This is because we've already filled all gaps between `W`s.
                            // So any remaining `k` will be used to extend the `W` chain at either end.
                            // For example, if we have `L L W W L L` and `k=2`.
                            // Initial score: `1+2=3`.
                            // `first_w=2`, `last_w=3`. No internal `L` segments.
                            // `k` is still 2.
                            // We change `L L W W L L` to `W W W W L L` (using 2 `k`s).
                            // Score becomes `1+2+2+2=7`.
                            // `current_score` was 3. `3 + 2*2 = 7`. This is correct.

    return current_score;
}

