                    // Let's re-evaluate.
                    // The operations are:
                    // 1. Swap a[i] and a[j], cost |i-j|.
                    // 2. Flip a[i], cost 1.
                    //
                    // We want to make a[k] == b[k] for all k.
                    //
                    // Consider positions where a[k] != b[k].
                    // Let P01 be the set of indices k where a[k]='0' and b[k]='1'.
                    // Let P10 be the set of indices k where a[k]='1' and b[k]='0'.
                    //
                    // To fix a position k in P01:
                    //   - Flip a[k]: cost 1. a[k] becomes '1', matches b[k].
                    //   - Swap a[k] with a[j]:
                    //     - If j is in P10: a[k] becomes '1', a[j] becomes '0'. Both fixed. Cost |k-j|.
                    //     - If j is not in P10: a[k] becomes '1', a[j] becomes '0'. a[k] fixed, a[j] now incorrect.
                    //       This is generally not optimal unless a[j] was '1' and b[j] was '1', and we needed a '0' at k.
                    //       This is too complex.
                    //
                    // The optimal strategy involves pairing up elements from P01 and P10 for swaps,
                    // and flipping the remaining ones.
                    //
                    // If we swap a[i] (from P01) with a[j] (from P10), both positions are fixed. Cost |i-j|.
                    // If we flip a[i] (from P01), cost 1.
                    // If we flip a[j] (from P10), cost 1.
                    //
                    // So, for each pair (i in P01, j in P10), we have two options:
                    // 1. Swap a[i] and a[j]. Cost |i-j|. Both fixed.
                    // 2. Flip a[i] and flip a[j]. Cost 1 + 1 = 2. Both fixed.
                    //
                    // We should choose the minimum of these two: min(|i-j|, 2).
                    // This is still not quite right. We can't just pick arbitrary pairs.
                    //
                    // Consider the total number of 0->1 changes needed (count01) and 1->0 changes needed (count10).
                    //
                    // If we have a 0->1 at index i and a 1->0 at index j, we can swap a[i] and a[j].
                    // This fixes both positions. Cost = |i-j|.
                    //
                    // If we have a 0->1 at index i, and no 1->0 to pair it with, we must flip a[i]. Cost = 1.
                    // Similarly for 1->0.
                    //
                    // The problem is to decide which 0->1 to pair with which 1->0.
                    // This is a minimum cost perfect matching problem if |P01| == |P10|.
                    // If |P01| != |P10|, then min(|P01|, |P10|) pairs can be formed, and the remaining | |P01| - |P10| | must be flipped.
                    //
                    // The crucial observation from similar problems (e.g., "Minimum Swaps to Make Strings Equal" on LeetCode)
                    // is that if you have a mismatch `xy` and `yx` (e.g., `a[i]=0, b[i]=1` and `a[j]=1, b[j]=0`),
                    // you can swap `a[i]` and `a[j]` to fix both. The cost is `|i-j|`.
                    //
                    // If you have `a[i]=0, b[i]=1` and `a[j]=0, b[j]=1`, you cannot fix both with a swap.
                    // If you have `a[i]=1, b[i]=0` and `a[j]=1, b[j]=0`, you cannot fix both with a swap.
                    //
                    // So, swaps are only useful between a 0->1 mismatch and a 1->0 mismatch.
                    //
                    // Let's track the counts of 0->1 and 1->0 mismatches.
                    //
                    // Iterate through the string:
                    // `zeros_to_ones_pending`: count of '0's in `a` that need to become '1's (i.e., `a[k]=0, b[k]=1`)
                    // `ones_to_zeros_pending`: count of '1's in `a` that need to become '0's (i.e., `a[k]=1, b[k]=0`)
                    //
                    // When we are at index `i`:
                    // If `a[i] == b[i]`, do nothing.
                    //
                    // If `a[i] = '0'` and `b[i] = '1'` (needs 0->1):
                    //   If `ones_to_zeros_pending > 0`:
                    //     We have a '1' that needs to be '0' somewhere before `i`, and a '0' that needs to be '1' at `i`.
                    //     We can perform a swap. The cost of this swap is 1.
                    //     This is because we can always find an adjacent pair of (0->1, 1->0) or (1->0, 0->1)
                    //     and fix them with a cost of 1.
                    //     This is the key insight.
                    //     No, this is not the key insight. The key insight is that if we have a 0->1 at index i and a 1->0 at index j,
                    //     we can fix both with a swap of cost |i-j|.
                    //     If we have a 0->1 at index i and a 1->0 at index i+1, we can swap a[i] and a[i+1] for cost 1.
                    //     This is the minimum cost for a swap.
                    //     So, if we have a 0->1 at index i, and we have a pending 1->0 from some previous index j,
                    //     we can fix both with a swap. The cost is |i-j|.
                    //     The problem is that we don't know j.
                    //
                    // Let's reconsider the example:
                    // 3
                    // 100
                    // 001
                    //
                    // i=0: a[0]=1, b[0]=0. Mismatch (1->0).
                    // i=1: a[1]=0, b[1]=0. Match.
                    // i=2: a[2]=0, b[2]=1. Mismatch (0->1).
                    //
                    // Mismatches:
                    // Index 0: 1->0
                    // Index 2: 0->1
                    //
                    // Option 1: Swap a[0] and a[2]. Cost |0-2|=2.
                    // a becomes "001". Done. Total cost 2.
                    //
                    // Option 2: Flip a[0]. Cost 1. a becomes "000".
                    // Now a[2]=0, b[2]=1. Flip a[2]. Cost 1. a becomes "001".
                    // Total cost 1+1=2.
                    //
                    // Both options give cost 2.
                    //
                    // Example 2:
                    // 4
                    // 0101
                    // 0011
                    //
                    // i=0: a[0]=0, b[0]=0. Match.
                    // i=1: a[1]=1, b[1]=0. Mismatch (1->0).
                    // i=2: a[2]=0, b[2]=1. Mismatch (0->1).
                    // i=3: a[3]=1, b[3]=1. Match.
                    //
                    // Mismatches:
                    // Index 1: 1->0
                    // Index 2: 0->1
                    //
                    // Option 1: Swap a[1] and a[2]. Cost |1-2|=1.
                    // a becomes "0011". Done. Total cost 1.
                    //
                    // Option 2: Flip a[1]. Cost 1. a becomes "0001".
                    // Now a[2]=0, b[2]=1. Flip a[2]. Cost 1. a becomes "0011".
                    // Total cost 1+1=2.
                    //
                    // Minimum cost is 1.
                    //
                    // This suggests that if we have a 1->0 at index i and a 0->1 at index i+1, we should swap them for cost 1.
                    // This is a greedy approach.
                    //
                    // Let's try this greedy approach:
                    // Iterate `i` from `0` to `n-2`.
                    // If `a[i] != b[i]` AND `a[i+1] != b[i+1]` AND `a[i] == b[i+1]` AND `a[i+1] == b[i]`:
                    //   This means `a[i]` needs to become `a[i+1]`'s current value, and `a[i+1]` needs to become `a[i]`'s current value.
                    //   Specifically, if `a[i]=0, b[i]=1` and `a[i+1]=1, b[i+1]=0`, then `a[i]` needs to be '1' and `a[i+1]` needs to be '0'.
                    //   Swapping `a[i]` and `a[i+1]` fixes both. Cost is `|i - (i+1)| = 1`.
                    //   Increment total cost by 1.
                    //   Mark `i` and `i+1` as fixed (e.g., change `a[i]` and `a[i+1]` to `b[i]` and `b[i+1]`).
                    //   Advance `i` by 1 (since `i+1` is also processed).
                    //
                    // After this pass, any remaining mismatches must be fixed by flips. Each flip costs 1.
                    //
                    // Let's trace this greedy strategy:
                    // Example 1:
                    // n=3
                    // a="100"
                    // b="001"
                    // cost = 0
                    //
                    // i=0:
                    // a[0]=1, b[0]=0. Mismatch.
                    // a[1]=0, b[1]=0. Match.
                    // Not the pattern `a[i]!=b[i]` AND `a[i+1]!=b[i+1]` AND `a[i]==b[i+1]` AND `a[i+1]==b[i]`.
                    //
                    // i=1:
                    // a[1]=0, b[1]=0. Match.
                    //
                    // Loop ends.
                    //
                    // Now count remaining mismatches:
                    // i=0: a[0]=1, b[0]=0. Mismatch. Cost += 1.
                    // i=1: a[1]=0, b[1]=0. Match.
                    // i=2: a[2]=0, b[2]=1. Mismatch. Cost += 1.
                    // Total cost = 2. This matches the example.
                    //
                    // Example 2:
                    // n=4
                    // a="0101"
                    // b="0011"
                    // cost = 0
                    //
                    // i=0:
                    // a[0]=0, b[0]=0. Match.
                    //
                    // i=1:
                    // a[1]=1, b[1]=0. Mismatch.
                    // a[2]=0, b[2]=1. Mismatch.
                    // Check pattern:
                    // a[1]!=b[1] (1!=0) - true
                    // a[2]!=b[2] (0!=1) - true
                    // a[1]==b[2] (1==1) - true
                    // a[2]==b[1] (0==0) - true
                    // All true! This is the pattern for an adjacent swap.
                    // Cost += 1. (cost becomes 1)
                    // Mark a[1] and a[2] as fixed.
                    // For simplicity, we can modify `a` in place or use a boolean array `fixed`.
                    // Let's modify `a` for now: `a[1]` becomes `b[1]` ('0'), `a[2]` becomes `b[2]` ('1').
                    // `a` is now "0011".
                    // Advance `i` by 1. So `i` becomes 2. Loop will then go to `i=3`.
                    //
                    // i=3: Loop condition `i < n-1` (3 < 3) is false. Loop ends.
                    //
                    // Now count remaining mismatches:
                    // `a` is "0011", `b` is "0011". No mismatches.
                    // Total cost = 1. This matches the example.
                    //
                    // This greedy strategy seems to work for both examples.
                    // Why is this optimal?
                    // An adjacent swap costs 1. A flip costs 1.
                    // If we have `a[i]=0, b[i]=1` and `a[i+1]=1, b[i+1]=0`, we can swap `a[i]` and `a[i+1]` for cost 1.
                    // This fixes two positions for cost 1.
                    // If we instead flipped `a[i]` and `a[i+1]`, it would cost 1+1=2.
                    // So, an adjacent swap is always better than two flips for this specific pattern.
                    //
                    // What if we have `a[i]=0, b[i]=1` and `a[j]=1, b[j]=0` where `|i-j| > 1`?
                    // E.g., `a="001", b="100"`.
                    // i=0: a[0]=0, b[0]=1 (0->1)
                    // i=1: a[1]=0, b[1]=0 (match)
                    // i=2: a[2]=1, b[2]=0 (1->0)
                    //
                    // Greedy pass:
                    // i=0: a[0]=0, b[0]=1. a[1]=0, b[1]=0. No adjacent swap.
                    // i=1: a[1]=0, b[1]=0. Match.
                    // Loop ends.
                    //
                    // Remaining mismatches:
                    // i=0: a[0]=0, b[0]=1. Flip. Cost += 1.
                    // i=2: a[2]=1, b[2]=0. Flip. Cost += 1.
                    // Total cost = 2.
                    //
                    // Alternative: Swap a[0] and a[2]. Cost |0-2|=2.
                    // a becomes "100". Done. Total cost 2.
                    //
                    // In this case, the greedy strategy (two flips) gives the same cost as the non-adjacent swap.
                    // This suggests that if an adjacent swap is not possible, two flips are as good as a non-adjacent swap.
                    //
                    // This greedy strategy seems correct.
                    //
                    // Implementation:
                    // Iterate `i` from `0` to `n-2`.
                    // If `a[i] != b[i]` and `a[i+1] != b[i+1]` and `a[i] != a[i+1]` (which implies `a[i] == b[i+1]` and `a[i+1] == b[i]`):
                    //   cost += 1;
                    //   i++; // Skip next character as it's also fixed.
                    //
                    // After the loop, iterate `i` from `0` to `n-1`.
                    // If `a[i] != b[i]`:
                    //   cost += 1;
                    //
                    // This is the most straightforward and likely correct approach.

    for (int i = 0; i < n - 1; ++i) {
        if (a[i] != b[i] && a[i+1] != b[i+1] && a[i] != a[i+1]) {
            // This condition means:
            // 1. a[i] != b[i] (mismatch at i)
            // 2. a[i+1] != b[i+1] (mismatch at i+1)
            // 3. a[i] != a[i+1] (the bits are different, e.g., '0' and '1')
            //
            // If a[i] != a[i+1], then one is '0' and the other is '1'.
            // Case 1: a[i]='0', a[i+1]='1'.
            //   Since a[i]!=b[i], b[i] must be '1'.
            //   Since a[i+1]!=b[i+1], b[i+1] must be '0'.
            //   So we have (a[i]=0, b[i]=1) and (a[i+1]=1, b[i+1]=0).
            //   Swapping a[i] and a[i+1] makes a[i]='1' and a[i+1]='0'. Both are fixed. Cost = 1.
            // Case 2: a[i]='1', a[i+1]='0'.
            //   Since a[i]!=b[i], b[i] must be '0'.
            //   Since a[i+1]!=b[i+1], b[i+1] must be '1'.
            //   So we have (a[i]=1, b[i]=0) and (a[i+1]=0, b[i+1]=1).
            //   Swapping a[i] and a[i+1] makes a[i]='0' and a[i+1]='1'. Both are fixed. Cost = 1.
            //
            // In both cases, an adjacent swap fixes two mismatches for a cost of 1.
            // This is the most efficient operation.
            cost += 1;
            i++; // Skip the next character as it's also fixed by this operation.
        }
    }

    // After the greedy adjacent swaps, any remaining mismatches must be fixed by flips.
    // Each flip costs 1.
    for (int i = 0; i < n; ++i) {
        // We need to re-check a[i] != b[i] because the string 'a' was not actually modified.
        // The `i++` in the previous loop effectively skipped positions that were "fixed".
        // So, we just need to count the remaining mismatches.
        // The positions that were part of an adjacent swap are effectively fixed and won't be counted here.
        // For example, if i=1 and i+1=2 were swapped, the loop `i++` makes `i` become 2.
        // The next iteration starts with `i=3`. So `i=1` and `i=2` are skipped in this final count.
        // This is correct.
        if (a[i] != b[i]) {
            cost += 1;
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends with w_i = 1 get the largest available numbers, contributing 2 * a_i
    // These are the k_ones largest numbers.
    // Since w is sorted, w_i = 1 friends are at the beginning of sorted w.
    // We iterate from the largest elements of 'a' for these friends.
    int a_ptr_max = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_max];
            a_ptr_max--;
        } else {
            // All remaining friends have w_i > 1.
            // They will get one largest number and one smallest number.
            // The largest numbers are already assigned to friends with w_i=1 or will be assigned to these friends.
            // The smallest numbers are assigned to these friends.
            // Break here as w is sorted, so all subsequent w[i] will also be > 1.
            break;
        }
    }

    // Friends with w_i > 1.
    // These friends get one largest available number and one smallest available number.
    // To maximize sum, give the largest remaining 'a' values as max_val,
    // and the smallest remaining 'a' values as min_val.
    // The largest remaining 'a' values are from a_ptr_max downwards.
    // The smallest remaining 'a' values are from a_ptr_min upwards.
    int a_ptr_min = 0;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_max]; // Max value for this friend
            a_ptr_max--;
            total_happiness += a[a_ptr_min]; // Min value for this friend
            a_ptr_min += (w[i] - 1); // Consume w[i]-1 smallest values for this friend
        }
    }

    std::cout << total_happiness << std::endl;
}

