    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum, X = current_xor_sum
    // We want S' = 2X'
    // S' = S + b1 + b2 + b3
    // X' = X ^ b1 ^ b2 ^ b3

    // Strategy: Append at most 3 elements.
    // It's always possible to append 2 elements.
    // Let's try to append two elements: b1, b2.
    // We want (S + b1 + b2) = 2 * (X ^ b1 ^ b2)

    // Consider appending two elements: X and S+X.
    // New XOR sum: X' = X ^ X ^ (S+X) = S+X
    // New sum: S' = S + X + (S+X) = 2S + 2X
    // Condition: S' = 2X'
    // (2S + 2X) = 2 * (S+X)
    // This is always true!
    // So, we can always append X and S+X.
    // The problem states that appended elements are non-negative.
    // X is always non-negative.
    // S is sum of non-negative numbers, so S is non-negative.
    // Thus S+X is non-negative.
    // This strategy always works and uses 2 elements.

    // The problem asks to output 0 elements if the array is already good.
    // So, first check if it's already good.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
