int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can be paired with any 'a's to its left.
            // Each such 'a' will eventually move past this 'b'.
            // The number of operations this 'b' contributes is equal to the current count of 'a's.
            // After this 'b' is processed (conceptually, as 'a's move past it),
            // it effectively doubles the number of 'a's that will be available
            // for 'b's further to the left.
            // This is because each 'a' that moves past this 'b' generates a new 'b'.
            // So, for each 'a' that moves past this 'b', it's like we have an 'a'
            // and a new 'b' (from the operation) available for 'b's further left.
            // This means the 'a' count effectively doubles for the next 'b' to its left.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's available
            // for 'b's further to its left.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
