void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
    // This is the only way to definitively set characters in w to '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce the given s.
    // For each s[i], check if it can be '1' based on our w.
    // If s[i] is '1' but our w cannot make it '1', then no such w exists.
    for (int i = 0; i < n; ++i) {
        bool can_be_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            can_be_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            can_be_one = true;
        }

        if ((s[i] == '1' && !can_be_one) || (s[i] == '0' && can_be_one)) {
            // If s[i] is '1' but w cannot make it '1', then it's impossible.
            // If s[i] is '0' but w *can* make it '1', then it's impossible.
            // The second condition (s[i] == '0' && can_be_one) should ideally not happen
            // if our logic for setting w[j] to '0' was correct.
            // Specifically, if s[i] was '0', we set w[i-x] and w[i+x] to '0'.
            // So, can_be_one would be false. This check primarily catches the first case.
            std::cout << -1 << std::endl;
            return;
        }
    }

    std::cout << w << std::endl;
}

