        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>
#include <numeric>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    std::vector<long long> prime_factors_q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    for (long long factor_q : prime_factors_q) {
        long long current_p = p;
        while (current_p % factor_q == 0) {
            current_p /= factor_q;
        }
        // current_p is now p with all factors of factor_q removed.
        // This current_p is a divisor of original p.
        // current_p is not divisible by factor_q, hence not divisible by q.
        // We want the largest such current_p.
        // If current_p is not divisible by q, it's a candidate.
        // If current_p is still divisible by q, it means q has other prime factors.
        // The problem statement guarantees an answer exists.
        // The logic is: we are looking for a divisor x of p such that x is not divisible by q.
        // If p is divisible by q, we must remove some factors from p.
        // To maximize x, we should remove as few factors as possible.
        // Specifically, we must remove enough factors such that x is no longer divisible by q.
        // If q = q1^a1 * q2^a2 * ... * qk^ak, then x is not divisible by q if for at least one i,
        // the exponent of qi in x's prime factorization is less than ai.
        //
        // Consider p_prime = p / (factor_q^k) where factor_q^k is the highest power of factor_q that divides p.
        // This p_prime is a divisor of p.
        // This p_prime is not divisible by factor_q.
        // Therefore, p_prime is not divisible by q (since q is divisible by factor_q).
        // So, p_prime is a valid candidate for x. We want the maximum such p_prime.
        // We iterate over all distinct prime factors of q. For each prime factor `f` of `q`,
        // we find the largest divisor of `p` that is not divisible by `f`.
        // This divisor is `p` divided by all occurrences of `f` in `p`.
        // Let this be `p_reduced_by_f`.
        // `p_reduced_by_f` is a divisor of `p`.
        // `p_reduced_by_f` is not divisible by `f`.
        // Since `f` is a prime factor of `q`, `p_reduced_by_f` cannot be divisible by `q`.
        // So `p_reduced_by_f` is a valid candidate for `x`.
        // We want the maximum among all such `p_reduced_by_f` for distinct prime factors `f` of `q`.
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

