#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::vector<char> current_s1;
        std::vector<char> current_s2;
        bool current_possible = true;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < pivot_digit) {
                result[i] = '1';
                current_s1.push_back(s[i]);
            } else if (digit > pivot_digit) {
                result[i] = '2';
                current_s2.push_back(s[i]);
            } else { // digit == pivot_digit
                // Try to assign '2' first, then '1'
                // This greedy choice ensures that if there are multiple pivot_digits,
                // the ones that come earlier in the original string are more likely to be '1'
                // and later ones are more likely to be '2', which helps maintain sorted order.
                // Specifically, we want to find the *first* occurrence of pivot_digit
                // that we assign '2' to. All pivot_digits before it are '1', all after are '2'.
                // This is handled by the `first_pivot_for_2_idx` logic.
            }
        }

        // Check if current_s1 and current_s2 are sorted
        for (size_t i = 0; i + 1 < current_s1.size(); ++i) {
            if (current_s1[i] > current_s1[i+1]) {
                current_possible = false;
                break;
            }
        }
        if (!current_possible) continue;

        for (size_t i = 0; i + 1 < current_s2.size(); ++i) {
            if (current_s2[i] > current_s2[i+1]) {
                current_possible = false;
                break;
            }
        }
        if (!current_possible) continue;

        // Now handle digits equal to pivot_digit
        // Find the split point for pivot_digit
        int first_pivot_for_2_idx = -1;
        for (int i = n - 1; i >= 0; --i) {
            if (s[i] - '0' == pivot_digit) {
                first_pivot_for_2_idx = i;
            } else if (s[i] - '0' < pivot_digit) {
                // All digits < pivot_digit must be '1'.
                // If we encounter a digit < pivot_digit AFTER a pivot_digit assigned to '2',
                // then it's impossible.
                if (first_pivot_for_2_idx != -1) {
                    current_possible = false;
                    break;
                }
            }
        }
        if (!current_possible) continue;

        // If no pivot_digit exists, or all pivot_digits are assigned to '1' (first_pivot_for_2_idx == -1)
        // then all pivot_digits are '1'.
        // If all pivot_digits are assigned to '2' (first_pivot_for_2_idx == 0 and all s[i] == pivot_digit),
        // then all pivot_digits are '2'.
        // The logic below handles this correctly.

        std::vector<char> final_s1_chars;
        std::vector<char> final_s2_chars;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < pivot_digit) {
                result[i] = '1';
                final_s1_chars.push_back(s[i]);
            } else if (digit > pivot_digit) {
                result[i] = '2';
                final_s2_chars.push_back(s[i]);
            } else { // digit == pivot_digit
                if (first_pivot_for_2_idx == -1) { // No pivot_digit assigned to '2'
                    result[i] = '1';
                    final_s1_chars.push_back(s[i]);
                } else if (i < first_pivot_for_2_idx) {
                    result[i] = '1';
                    final_s1_chars.push_back(s[i]);
                } else { // i >= first_pivot_for_2_idx
                    result[i] = '2';
                    final_s2_chars.push_back(s[i]);
                }
            }
        }

        // Final check for sortedness
        for (size_t i = 0; i + 1 < final_s1_chars.size(); ++i) {
            if (final_s1_chars[i] > final_s1_chars[i+1]) {
                current_possible = false;
                break;
            }
        }
        if (!current_possible) continue;

        for (size_t i = 0; i + 1 < final_s2_chars.size(); ++i) {
            if (final_s2_chars[i] > final_s2_chars[i+1]) {
                current_possible = false;
                break;
            }
        }
        if (!current_possible) continue;

        if (!final_s1_chars.empty() && !final_s2_chars.empty()) {
            if (final_s1_chars.back() > final_s2_chars.front()) {
                current_possible = false;
            }
        }

        if (current_possible) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
