int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int consecutive_pairs_in_target = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Calculate operations for this chain
        // Each chain of length m has m-1 direct nestings.
        // To disassemble a chain of length m, it takes m-1 "get out" operations.
        // To assemble a chain of length m, it takes m-1 "put in" operations.
        // The total number of dolls is n.
        // The total number of "put in" operations needed for the final chain is n-1.
        // The total number of "get out" operations needed is (n-1) - (number of existing correct nestings).
        // The problem asks for minimum time.
        //
        // Let's count how many pairs (x, x+1) are already correctly nested in the initial chains.
        // If a chain is a_1, a_2, ..., a_m, it means a_1 is in a_2, a_2 is in a_3, ..., a_{m-1} is in a_m.
        // We are interested in pairs (j, j+1) where j is nested in j+1.
        //
        // For each chain, we iterate through its elements.
        // If chain[j] is 1, then it's the start of the target sequence.
        // We count how many consecutive elements from 1 onwards are present in this chain.
        // E.g., if chain is 1, 2, 3, 7, then (1,2) and (2,3) are correct.
        // If chain is 2, 5, then no correct pairs starting from 1.

        if (m > 0 && chain[0] == 1) {
            int current_expected = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    consecutive_pairs_in_target++; // This counts 'current_expected' itself, not the pair.
                                                    // If chain is 1,2,3, this counts 1, then 2, then 3.
                                                    // The number of pairs (x, x+1) is one less than this count.
                    current_expected++;
                } else {
                    break;
                }
            }
        }
    }

    // The number of dolls that are part of the initial correct prefix (1, 2, ..., X) is `consecutive_pairs_in_target`.
    // For example, if `consecutive_pairs_in_target` is 3, it means dolls 1, 2, 3 are correctly nested as 1->2->3.
    // This means we have 2 correct pairs (1,2) and (2,3).
    // These `consecutive_pairs_in_target - 1` nestings do not need to be disassembled or reassembled.

    // Total dolls to be moved (disassembled and reassembled) are `n - consecutive_pairs_in_target`.
    // Each such doll needs one "get out" operation (if it's nested) and one "put in" operation.
    // So, `2 * (n - consecutive_pairs_in_target)` operations.

    // However, this is not quite right. Let's re-evaluate.
    // Total operations = (total "get out" operations) + (total "put in" operations).

    // Total "put in" operations required for the final chain 1->2->...->n is `n-1`.
    // Of these `n-1` required "put in" operations, `consecutive_pairs_in_target - 1` are already satisfied.
    // So, `(n-1) - (consecutive_pairs_in_target - 1)` new "put in" operations are needed.
    // This simplifies to `n - consecutive_pairs_in_target` new "put in" operations.

    // Now, consider "get out" operations.
    // Any doll `x` that is not part of the `1->2->...->consecutive_pairs_in_target` prefix,
    // and is currently nested in some `y`, must be taken out.
    // Also, any doll `x` that is part of the `1->2->...->consecutive_pairs_in_target` prefix,
    // but is nested in `y` where `y != x+1` (this shouldn't happen if it's part of the prefix),
    // or `y` is not part of the prefix, must be taken out.

    // Let's use the formula derived from the problem analysis:
    // Total operations = (n - 1) + (n - 1) - 2 * (consecutive_pairs_in_target - 1)
    // This is (total "put in" operations for final chain) + (total "get out" operations for dolls not in final chain)
    // The `n-1` is the number of "put in" operations to form the final chain.
    // The `n-1` is the number of "get out" operations to break all existing nestings.
    // We save 2 operations (one "get out", one "put in") for each pair (i, i+1) that is already correctly nested.
    // The number of such pairs is `consecutive_pairs_in_target - 1`.

    // So, total_operations = (n-1) + (n-1) - 2 * (consecutive_pairs_in_target - 1)
    // total_operations = 2 * (n-1) - 2 * (consecutive_pairs_in_target - 1)
    // total_operations = 2 * (n - 1 - (consecutive_pairs_in_target - 1))
    // total_operations = 2 * (n - consecutive_pairs_in_target)

    // Example 1: n=3, k=2. Chains: (1,2), (3).
    // consecutive_pairs_in_target:
    // Chain (1,2): chain[0]=1, current_expected=1. counts 1. current_expected=2.
    //              chain[1]=2, current_expected=2. counts 2. current_expected=3.
    //              consecutive_pairs_in_target = 2.
    // Chain (3): chain[0]=3, current_expected=1. Not 1. Break.
    // Final consecutive_pairs_in_target = 2.
    // Operations = 2 * (3 - 2) = 2 * 1 = 2.
    // Wait, example output is 1. What's wrong?

    // The problem states: "In one second, you can perform one of the two following operations:
    // 1. Having a matryoshka a that isn't nested in any other matryoshka and a matryoshka b, such that b doesn't contain any other matryoshka and is not nested in any other matryoshka, you may put a in b;
    // 2. Having a matryoshka a directly contained in matryoshka b, such that b is not nested in any other matryoshka, you may get a out of b."

    // Let's re-think the operations.
    // To form 1->2->3:
    // Initial: (1->2), (3)
    // We need to put (1->2) into (3).
    // Doll (1->2) is not nested in anything. Doll (3) doesn't contain anything and is not nested in anything.
    // So, we can directly put (1->2) into (3). This is 1 operation.
    // This means the formula `2 * (n - consecutive_pairs_in_target)` is incorrect.

    // The `consecutive_pairs_in_target` variable counts the number of dolls in the prefix 1, 2, ..., X.
    // If `consecutive_pairs_in_target` is `X`, it means dolls 1, 2, ..., X are already correctly nested as 1->2->...->X.
    // This forms one "block" that is already in the target configuration.
    // We need to extend this block to `n`.
    // This means we need to put `X` into `X+1`, then `X+1` into `X+2`, ..., `n-1` into `n`.
    // This requires `n - X` "put in" operations.

    // What about "get out" operations?
    // All dolls from `X+1` to `n` are currently in some chains, but not in the target configuration.
    // Each of these `n - X` dolls (from `X+1` to `n`) must eventually be available to be nested.
    // If doll `i` (where `i > X`) is currently nested in `j`, it must be taken out.
    // If doll `i` (where `i > X`) currently contains `j`, then `j` must be taken out of `i`.

    // The total number of dolls is `n`.
    // The number of dolls that are part of the `1->2->...->X` prefix is `X`.
    // The number of dolls that are NOT part of this prefix is `n - X`.

    // Each of these `n - X` dolls must be "freed" from any current nesting.
    // If a doll `d` is nested in `d+1` (and `d+1` is not part of the prefix), this is a "bad" nesting.
    // If a doll `d` is nested in `d+k` (k > 1), this is a "bad" nesting.

    // Let's count the number of "bad" nestings.
    // A nesting `a` in `b` is "bad" if `b != a+1` OR `a` is not part of the `1->...->X` prefix.
    // The total number of initial nestings is `n - k`. (Each chain of length `m_i` has `m_i-1` nestings. Sum of `m_i-1` over `k` chains is `(sum m_i) - k = n - k`).
    // The number of "good" nestings is `consecutive_pairs_in_target - 1`.
    // So, the number of "bad" nestings is `(n - k) - (consecutive_pairs_in_target - 1)`.
    // Each "bad" nesting requires one "get out" operation.
    // So, `(n - k) - (consecutive_pairs_in_target - 1)` "get out" operations.

    // The number of "put in" operations needed is `n - consecutive_pairs_in_target`.
    // This is because we need to put `X` into `X+1`, `X+1` into `X+2`, ..., `n-1` into `n`.
    // This is `(n-1) - (X-1)` operations, which is `n-X`.

    // Total operations = (number of "get out" operations) + (number of "put in" operations)
    // Total operations = `((n - k) - (consecutive_pairs_in_target - 1))` + `(n - consecutive_pairs_in_target)`
    // Total operations = `n - k - consecutive_pairs_in_target + 1 + n - consecutive_pairs_in_target`
    // Total operations = `2*n - k - 2*consecutive_pairs_in_target + 1`

    // Let's test this formula with Example 1: n=3, k=2. consecutive_pairs_in_target = 2.
    // Total operations = `2*3 - 2 - 2*2 + 1`
    // = `6 - 2 - 4 + 1`
    // = `4 - 4 + 1`
    // = `1`. This matches the example output!

    // Let's test with Example 2: n=7, k=3.
    // Chains: (1,3,7), (2,5), (4,6)
    // consecutive_pairs_in_target:
    // Chain (1,3,7): chain[0]=1, current_expected=1. counts 1. current_expected=2.
    //                chain[1]=3, current_expected=2. Not 2. Break.
    //                consecutive_pairs_in_target = 1.
    // Chain (2,5): chain[0]=2, current_expected=1. Not 1. Break.
    // Chain (4,6): chain[0]=4, current_expected=1. Not 1. Break.
    // Final consecutive_pairs_in_target = 1. (Only doll 1 is part of the prefix 1->...->X)

    // Total operations = `2*n - k - 2*consecutive_pairs_in_target + 1`
    // = `2*7 - 3 - 2*1 + 1`
    // = `14 - 3 - 2 + 1`
    // = `11 - 2 + 1`
    // = `9 + 1`
    // = `10`. This matches the example output!

    // The formula seems correct.
    // `consecutive_pairs_in_target` is the length of the longest prefix `1, 2, ..., X` that is already correctly formed and nested.
    // If `consecutive_pairs_in_target` is 0, it means doll 1 is not the first element of any chain, or there are no chains.
    // If `consecutive_pairs_in_target` is 1, it means doll 1 is the first element of some chain, but doll 2 is not nested in it.

    // The number of "get out" operations:
    // We have `n` dolls. `k` chains. Total `n-k` existing direct nestings.
    // `consecutive_pairs_in_target - 1` of these are "good" nestings (e.g., 1 in 2, 2 in 3, ..., X-1 in X).
    // The remaining `(n-k) - (consecutive_pairs_in_target - 1)` nestings must be broken. Each takes 1 second.
    // This is the number of "get out" operations.

    // The number of "put in" operations:
    // We need to form `n-1` direct nestings in the final chain (1 in 2, 2 in 3, ..., n-1 in n).
    // `consecutive_pairs_in_target - 1` of these are already formed.
    // So, we need to perform `(n-1) - (consecutive_pairs_in_target - 1)` new "put in" operations.
    // This simplifies to `n - consecutive_pairs_in_target` "put in" operations.

    // Total operations = `((n - k) - (consecutive_pairs_in_target - 1))` + `(n - consecutive_pairs_in_target)`
    // = `n - k - consecutive_pairs_in_target + 1 + n - consecutive_pairs_in_target`
    // = `2*n - k - 2*consecutive_pairs_in_target + 1`

    // This formula holds.

    total_operations = (long long)2 * n - k - (long long)2 * consecutive_pairs_in_target + 1;

    std::cout << total_operations << std::endl;

    return 0;
}

