            if (f2 == 0) { // Cannot move up, so target Y must be <= current Y
                max_y = std::min(max_y, y);
            }
            if (f3 == 0) { // Cannot move right, so target X must be <= current X
                max_x = std::min(max_x, x);
            }
            if (f4 == 0) { // Cannot move down, so target Y must be >= current Y
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a point exists, one exists within [-10^5, 10^5].
            // Our calculated min_x, max_x, min_y, max_y might be outside this range
            // if all robots have very restrictive movement.
            // However, any point within [min_x, max_x] and [min_y, max_y] is valid.
            // We can just pick min_x and min_y, and they will be within the guaranteed range
            // if a solution exists.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    long long sum_r_val;
    if (b == 1) { // If b=1, then r must be 0, but r must be != 0. So no nice integers.
        sum_r_val = 0;
    } else {
        sum_r_val = (b - 1);
        sum_r_val = (sum_r_val % MOD * (b % MOD)) % MOD;
        // We need to divide by 2. This is equivalent to multiplying by modular inverse of 2.
        // Modular inverse of 2 modulo 10^9+7 is (10^9+8)/2 = 500000004.
        long long inv2 = 500000004;
        sum_r_val = (sum_r_val * inv2) % MOD;
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // sum_k_term = b * sum_{k=1 to a} k + a
    // sum_k_term = b * (a * (a+1) / 2) + a

    long long sum_k_val;
    long long sum_k_1_to_a; // sum_{k=1 to a} k = a * (a+1) / 2
    sum_k_1_to_a = (a % MOD * ((a + 1) % MOD)) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2
    sum_k_1_to_a = (sum_k_1_to_a * inv2) % MOD;

    long long term_b_times_sum_k = (b % MOD * sum_k_1_to_a) % MOD;
    long long term_a = a % MOD;

    sum_k_val = (term_b_times_sum_k + term_a) % MOD;

    // Total sum = sum_r_val * sum_k_val
    long long total_sum = (sum_r_val * sum_k_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

