#include <iostream>
#include <algorithm> // For std::abs, std::max, std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n <= abs_m for simpler logic
        if (abs_n > abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k is less than the minimum required moves
        // Minimum moves to reach (abs_n, abs_m) is abs_m (by making abs_n diagonal moves and abs_m - abs_n straight moves)
        if (k < abs_m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k and abs_m have different parity
        // If k and abs_m have different parity, we need to make an odd number of "wasted" moves.
        // A wasted move pair (e.g., (1,0) then (-1,0)) changes coordinates by (0,0) in 2 moves.
        // A wasted move pair (e.g., (1,0) then (0,1)) changes coordinates by (1,1) in 2 moves.
        // A wasted move pair (e.g., (1,0) then (1,0)) changes coordinates by (2,0) in 2 moves.
        // The parity of (x+y) changes with each move.
        // Start (0,0), sum = 0 (even).
        // After k moves, target (n,m), sum = n+m.
        // If k is even, (n+m) must be even.
        // If k is odd, (n+m) must be odd.
        // This is equivalent to (k % 2) == ((abs_n + abs_m) % 2).
        // Or, more simply, (k - abs_m) must be even.
        // If (k - abs_m) is odd, it's impossible to reach.
        if ((k - abs_m) % 2 != 0) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 3: Possible to reach. Maximize diagonal moves.
        // We have k moves.
        // We need at least abs_m moves to cover the larger coordinate.
        // The remaining moves are k - abs_m. These must be used in pairs to not change the parity of the final position relative to the number of moves.
        // Each pair of remaining moves can be used to increase diagonal moves.
        // For example, if we are at (x,y) and need to reach (N,M), and we have an extra 2 moves:
        // We can do (1,1) then (-1,-1) -> 2 diagonal moves, net change (0,0).
        // Or (1,0) then (0,1) -> 0 diagonal moves, net change (1,1).
        // Or (1,0) then (-1,0) -> 0 diagonal moves, net change (0,0).
        //
        // The strategy to maximize diagonal moves is to make as many diagonal moves as possible.
        // We can make abs_n diagonal moves to cover the smaller coordinate.
        // Then we have abs_m - abs_n moves remaining to cover the larger coordinate. These must be straight moves.
        // Total moves so far: abs_n (diagonal) + (abs_m - abs_n) (straight) = abs_m moves.
        // Number of diagonal moves so far: abs_n.
        //
        // We have k - abs_m moves remaining. These moves must be used in pairs that effectively cancel out or maintain the target.
        // Each pair of moves can be used to increase the diagonal count by 2.
        // For example, if we are at (x,y) and need to reach (N,M), and we have an extra 2 moves:
        // We can make a diagonal move (e.g., (1,1)) and then an anti-diagonal move (e.g., (-1,-1)).
        // This uses 2 moves, results in 2 diagonal moves, and brings us back to (x,y).
        // So, each pair of (k - abs_m) moves can contribute 2 diagonal moves.
        // The number of such pairs is (k - abs_m) / 2.
        // So, these pairs contribute 2 * ((k - abs_m) / 2) = (k - abs_m) diagonal moves.
        //
        // Total diagonal moves = (initial abs_n diagonal moves) + (k - abs_m) additional diagonal moves.
        // Result = abs_n + (k - abs_m).
        // This simplifies to k - (abs_m - abs_n).
        //
        // Let's verify this.
        // We make abs_n diagonal moves. This brings us to (abs_n, abs_n).
        // We make abs_m - abs_n straight moves in the y-direction. This brings us to (abs_n, abs_m).
        // Total moves used: abs_n + (abs_m - abs_n) = abs_m.
        // Total diagonal moves: abs_n.
        // Remaining moves: k - abs_m.
        // These remaining moves must be used in pairs that don't change the final position.
        // The best way to do this for maximizing diagonal moves is to use a diagonal move and then an opposite diagonal move.
        // E.g., (1,1) then (-1,-1). This uses 2 moves and adds 2 diagonal moves.
        // So, (k - abs_m) moves can add (k - abs_m) diagonal moves.
        // Total diagonal moves = abs_n + (k - abs_m).
        // This is equivalent to k - (abs_m - abs_n).

        std::cout << k - (abs_m - abs_n) << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_val = (dq.empty() ? 0 : L[dq.back()]);
        long long prev_idx_val = (dq.empty() ? 0 : h[dq.back()]);

        L[i] = std::min(h[i], prev_val + (i - (dq.empty() ? -1 : dq.back())));
        dq.push_back(i);
    }

    dq.clear();
    std::vector<long long> R(n);
    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_val = (dq.empty() ? 0 : R[dq.back()]);
        long long prev_idx_val = (dq.empty() ? 0 : h[dq.back()]);

        R[i] = std::min(h[i], prev_val + ((dq.empty() ? n : dq.back()) - i));
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

