#include <iostream>
#include <algorithm>

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    long long total_substrings = n * (n + 1) / 2;

    long long num_zeros = n - m;

    // To minimize the number of substrings consisting only of zeros,
    // we need to distribute the zeros as evenly as possible into m+1 blocks.
    // The '1's act as separators. m '1's create m+1 potential blocks of zeros.
    // For example, "0010100" has m=2, n=7. Zeros = 5. Blocks: 00, 0, 00.
    // The number of blocks of zeros is m+1.
    // Let k be the number of zeros in each block.
    // We have num_zeros zeros to distribute into m+1 blocks.
    // Let q = num_zeros / (m + 1) be the quotient (average number of zeros per block).
    // Let r = num_zeros % (m + 1) be the remainder.
    // This means r blocks will have (q + 1) zeros, and (m + 1 - r) blocks will have q zeros.

    long long q = num_zeros / (m + 1);
    long long r = num_zeros % (m + 1);

    long long substrings_from_zeros = 0;

    // r blocks of size (q + 1)
    if (q + 1 > 0) { // Only count if block size is positive
        substrings_from_zeros += r * (q + 1) * (q + 2) / 2;
    }

    // (m + 1 - r) blocks of size q
    if (q > 0) { // Only count if block size is positive
        substrings_from_zeros += (m + 1 - r) * q * (q + 1) / 2;
    }

    return total_substrings - substrings_from_zeros;
}

