}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total difference
    int initial_diff = 0;
    for (int x : a) {
        if (x == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // If initial_diff is 0, no jars need to be eaten.
    if (initial_diff == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Precompute prefix sums for the left side (jars 1 to n)
    // diff_L[i] = (count of 1s) - (count of 2s) in jars 1 to i
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Precompute suffix sums for the right side (jars n+1 to 2n)
    // diff_R[i] = (count of 1s) - (count of 2s) in jars i to 2n
    // We'll store this as diff_R_from_n_plus_1[k] = (count of 1s) - (count of 2s) in jars n+1 to n+k
    std::vector<int> diff_R_from_n_plus_1(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R_from_n_plus_1[i + 1] = diff_R_from_n_plus_1[i] + (a[n + i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left to achieve a certain difference
    // key: difference, value: number of jars eaten from left (n - remaining_left_jars)
    std::map<int, int> left_diff_to_eaten_count;
    for (int k_L = 0; k_L <= n; ++k_L) { // k_L is number of jars eaten from left
        // Remaining jars on left are 1 to n-k_L. Their difference is diff_L[n-k_L].
        int current_left_diff = diff_L[n - k_L];
        if (left_diff_to_eaten_count.find(current_left_diff) == left_diff_to_eaten_count.end()) {
            left_diff_to_eaten_count[current_left_diff] = k_L;
        } else {
            // We want minimum k_L for a given diff, so update if current k_L is smaller
            left_diff_to_eaten_count[current_left_diff] = std::min(left_diff_to_eaten_count[current_left_diff], k_L);
        }
    }

    int min_eaten_jars = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars eaten from the right (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        // Remaining jars on right are n+k_R+1 to 2n.
        // Their difference is diff_R_from_n_plus_1[n] - diff_R_from_n_plus_1[k_R].
        int current_right_diff = diff_R_from_n_plus_1[n] - diff_R_from_n_plus_1[k_R];

        // We need total_diff = current_left_diff + current_right_diff = 0
        // So, current_left_diff = -current_right_diff
        int target_left_diff = -current_right_diff;

        if (left_diff_to_eaten_count.count(target_left_diff)) {
            int k_L = left_diff_to_eaten_count[target_left_diff];
            min_eaten_jars = std::min(min_eaten_jars, k_L + k_R);
        }
    }

    std::cout << min_eaten_jars << std::endl;
}

