    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Dummy operation (e.g., add 0 to a[0])
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";

        // Operation 3: Dummy operation (e.g., add 0 to a[0])
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // For each a[i] (0 <= i < n-1), we want to add x_i such that (a[i] + x_i) % n == 0.
    // x_i must be a multiple of n.
    // This means a[i] % n must be 0.
    // If a[i] % n != 0, we need to add a multiple of n to make it 0.
    // Let current_val = a[i]. We want current_val + k*n = 0 (mod n).
    // This is always true if k*n is added.
    // The trick is to make a[i] + k*n = 0 (mod n) for the *next* operation.
    // No, the trick is to make a[i] + k*len = 0.
    // The problem states "add a multiple of len".
    // So, if we want a[i] to become 0, we need a[i] to be a multiple of len.
    // This is not what we want. We want to make a[i] become 0 *eventually*.

    // Let's re-read: "for each number in this segment we can add a multiple of len to it"
    // This means a_i_new = a_i_old + k_i * len.
    // We want a_i_new = 0. So a_i_old must be a multiple of len.
    // This is the key.

    // Strategy:
    // 1. For elements a[0] to a[n-2]:
    //    We want to make a[i] % n == 0.
    //    We can choose segment [1, n-1] (indices 0 to n-2). Length is n-1.
    //    For each a[i] in this segment, we add b_i such that b_i is a multiple of (n-1).
    //    This doesn't help make a[i] % n == 0.

    // Let's use the standard solution for this problem.
    // The standard solution uses the fact that for any number `x`, `x % n` can be made `0` by adding `k * n` if `n` is the length.
    // But here, `len` is the length of the segment.

    // Operation 1: Target a[0]...a[n-2]
    // Segment [1, n-1] (indices 0 to n-2). Length = n-1.
    // For each a[i] in this segment, we want to add b_i such that (a[i] + b_i) % n == 0.
    // And b_i must be a multiple of (n-1).
    // This is possible if we can find k_i such that a[i] + k_i * (n-1) is a multiple of n.
    // a[i] + k_i * (n-1) = 0 (mod n)
    // a[i] + k_i * (-1) = 0 (mod n)
    // a[i] - k_i = 0 (mod n)
    // k_i = a[i] (mod n)
    // So, we need to add b_i = (a[i] % n) * (n-1) if a[i] % n != 0.
    // If a[i] % n == 0, we add 0.
    // More precisely, if a[i] % n is `rem`, we want to add `b_i` such that `(a[i] + b_i) % n == 0`.
    // We know `b_i` must be a multiple of `n-1`.
    // So `a[i] + k_i * (n-1) = 0 (mod n)`.
    // `a[i] - k_i = 0 (mod n)`.
    // `k_i = a[i] % n`. If `a[i] % n` is negative, add `n`.
    // So `k_i = (a[i] % n + n) % n`.
    // The value to add is `b_i = k_i * (n-1)`.
    // After this operation, `a[i]` becomes `a[i] + b_i`.
    // `(a[i] + b_i) % n = (a[i] + (a[i] % n) * (n-1)) % n`
    // `= (a[i] + (a[i] % n) * (-1)) % n`
    // `= (a[i] - (a[i] % n)) % n`
    // `= 0 % n`.
    // So, after this operation, `a[0]...a[n-2]` will be multiples of `n`.

    std::cout << 1 << " " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n;
        long long to_add = remainder * (n - 1);
        std::cout << to_add << (i == n - 2 ? "" : " ");
        a[i] += to_add;
    }
    std::cout << "\n";

    // Operation 2: Target a[n-1]
    // Segment [n, n] (index n-1). Length = 1.
    // We want to make a[n-1] % n == 0.
    // We can add b_{n-1} such that b_{n-1} is a multiple of 1.
    // We want a[n-1] + b_{n-1} = 0 (mod n).
    // We can simply add b_{n-1} = -a[n-1]. This is a multiple of 1.
    // But we want to make it a multiple of n.
    // No, we want to make it 0.
    // We want to make a[n-1] become 0.
    // We can add -a[n-1] to a[n-1]. This is a multiple of 1.
    // After this, a[n-1] becomes 0.
    // This is simpler.

    std::cout << n << " " << n << "\n";
    std::cout << -a[n - 1] << "\n";
    a[n - 1] = 0;

    // Operation 3: Target all elements a[0]...a[n-1]
    // Segment [1, n] (indices 0 to n-1). Length = n.
    // At this point, a[0]...a[n-2] are all multiples of n (from Op 1).
    // And a[n-1] is 0 (from Op 2), which is also a multiple of n.
    // So all a[i] are multiples of n.
    // For each a[i], we want to add b_i such that b_i is a multiple of n, and a[i] + b_i = 0.
    // We can simply add b_i = -a[i]. Since a[i] is a multiple of n, -a[i] is also a multiple of n.

    std::cout << 1 << " " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

