    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal (i.e., addition)
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = removal_order[k_idx]; // The vertex being "added" back

        active_vertices[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate node
        // This is the core of Floyd-Warshall, but applied incrementally
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue; // Only consider active 'i'
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue; // Only consider active 'j'

                // Path i -> k -> j
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // After adding vertex k and updating all paths,
        // calculate the sum of shortest paths between all *currently active* pairs.
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself

                // Only sum if a path exists (dist[i][j] != -1 if using -1 for infinity)
                // Given constraints a_ij >= 1, a_ii = 0, all paths will have positive length
                // and all pairs of distinct vertices have an edge, so paths always exist.
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first step to last)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, subsequent values will be current_val + d + 1

    while (X > 0) {
        long long k = 0;
        // Find largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        if (X == 1) { // Special case for X=1, 2^0-1 = 0, but we need 1 element
            k = 1;
        } else {
            k = std::floor(std::log2(X + 1));
            // Ensure 2^k - 1 does not exceed X
            if ((1LL << k) - 1 > X) {
                k--;
            }
            // Ensure k is at least 1 if X > 0
            if (k == 0 && X > 0) {
                k = 1;
            }
        }

        // If k is 0, it means X is 0, but loop condition is X > 0.
        // If X=1, k=1. If X=2, k=1. If X=3, k=2.
        // The smallest k for X > 0 is 1.
        // If X=1, k=1. (2^1-1 = 1)
        // If X=2, k=1. (2^1-1 = 1)
        // If X=3, k=2. (2^2-1 = 3)

        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }
        X -= ((1LL << k) - 1);
        current_val += (d + 1);
    }

    if (result_array.size() > 10000) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current_and, current_or, current_xor
    // These represent the combined effect of all operations so far.
    // For an input 'x', the current value would be ((x & current_and) | current_or) ^ current_xor
    // Initially, x is unchanged, so:
    // x & 1023 (all bits 0-9 are 1) -> x
    // x | 0 -> x
    // x ^ 0 -> x
    int current_and = 1023; // All bits 0-9 are 1
    int current_or = 0;     // All bits 0-9 are 0
    int current_xor = 0;    // All bits 0-9 are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            // New operation: `& val`
            // Current state: `((x & current_and) | current_or) ^ current_xor`
            // After `& val`: `(((x & current_and) | current_or) ^ current_xor) & val`
            // This is equivalent to:
            // `(x & current_and & val)`
            // `| (current_or & val)`
            // `^ (current_xor & val)`
            // So, update current_and, current_or, current_xor:
            current_and &= val;
            current_or &= val;
            current_xor &= val;
        } else if (op_char == '|') {
            // New operation: `| val`
            // Current state: `((x & current_and) | current_or) ^ current_xor`
            // After `| val`: `(((x & current_and) | current_or) ^ current_xor) | val`
            // This is equivalent to:
            // `(x & current_and)`
            // `| (current_or | val)`
            // `^ (current_xor & (~val))`
            // So, update current_and, current_or, current_xor:
            current_or |= val;
            current_xor &= ~val; // Bits set in val become 0 in current_xor
            current_and |= val; // Bits set in val become 1 in current_and
        } else if (op_char == '^') {
            // New operation: `^ val`
            // Current state: `((x & current_and) | current_or) ^ current_xor`
            // After `^ val`: `(((x & current_and) | current_or) ^ current_xor) ^ val`
            // This is equivalent to:
            // `(x & current_and)`
            // `| (current_or ^ val)`
            // `^ (current_xor ^ val)`
            // So, update current_and, current_or, current_xor:
            current_xor ^= val;
        }
    }

    // Now we have the combined effect: `((x & current_and) | current_or) ^ current_xor`
    // We need to represent this with at most 5 operations.
    // The maximum value for constants is 1023 (10 bits).
    // Let's determine the final state of each bit for input 0 and input 1.
    // For an input bit `b` (0 or 1), the output bit `b'` is:
    // `((b & current_and_bit) | current_or_bit) ^ current_xor_bit`

    // Let's find the final values for an input of 0 and 1023 (all 1s).
    // For input 0: `((0 & current_and) | current_or) ^ current_xor` = `(0 | current_or) ^ current_xor` = `current_or ^ current_xor`
    int val_for_0 = current_or ^ current_xor;

    // For input 1023 (all 1s): `((1023 & current_and) | current_or) ^ current_xor` = `(current_and | current_or) ^ current_xor`
    int val_for_1023 = (current_and | current_or) ^ current_xor;

    std::vector<std::pair<char, int>> result_ops;

    // The goal is to find A, B, C such that `((x & A) | B) ^ C` is equivalent.
    // We can derive A, B, C from `val_for_0` and `val_for_1023`.
    // Let's consider each bit position `j` from 0 to 9.
    // Let `b_j` be the `j`-th bit of `x`.
    // Let `a_j`, `o_j`, `x_j` be the `j`-th bits of `current_and`, `current_or`, `current_xor`.
    // Output bit `y_j = ((b_j & a_j) | o_j) ^ x_j`.

    // If `b_j = 0`: `y_j = (0 | o_j) ^ x_j = o_j ^ x_j`. This is the `j`-th bit of `val_for_0`.
    // If `b_j = 1`: `y_j = (a_j | o_j) ^ x_j`. This is the `j`-th bit of `val_for_1023`.

    // We want to find `A_j`, `B_j`, `C_j` for the simplified form `((b_j & A_j) | B_j) ^ C_j`.
    // From `val_for_0` and `val_for_1023`, we can determine `A_j`, `B_j`, `C_j`.
    // Let `f_0 = (val_for_0 >> j) & 1` and `f_1 = (val_for_1023 >> j) & 1`.
    //
    // Case 1: `f_0 = 0, f_1 = 0`
    //   Input 0 -> 0, Input 1 -> 0.
    //   This means `((b_j & A_j) | B_j) ^ C_j` should always be 0.
    //   Possible: `& 0` (A_j=0, B_j=0, C_j=0) or `^ B_j` where B_j is 0.
    //   Simplest: `& 0` (A_j=0, B_j=0, C_j=0)
    //
    // Case 2: `f_0 = 0, f_1 = 1`
    //   Input 0 -> 0, Input 1 -> 1.
    //   This means `((b_j & A_j) | B_j) ^ C_j` should be `b_j`.
    //   Possible: `& 1` (A_j=1, B_j=0, C_j=0)
    //
    // Case 3: `f_0 = 1, f_1 = 0`
    //   Input 0 -> 1, Input 1 -> 0.
    //   This means `((b_j & A_j) | B_j) ^ C_j` should be `~b_j`.
    //   Possible: `^ 1` (A_j=1, B_j=0, C_j=1)
    //
    // Case 4: `f_0 = 1, f_1 = 1`
    //   Input 0 -> 1, Input 1 -> 1.
    //   This means `((b_j & A_j) | B_j) ^ C_j` should always be 1.
    //   Possible: `| 1` (A_j=1, B_j=1, C_j=0)

    // We can construct the final A, B, C values bit by bit.
    int final_A = 0; // For '&' operation
    int final_B = 0; // For '|' operation
    int final_C = 0; // For '^' operation

    for (int j = 0; j < 10; ++j) {
        int f0_bit = (val_for_0 >> j) & 1;
        int f1_bit = (val_for_1023 >> j) & 1;

        if (f0_bit == 0 && f1_bit == 0) {
            // Output is always 0. Equivalent to `& 0` for this bit.
            // A_j = 0, B_j = 0, C_j = 0
            // No change to final_B, final_C. Set A_j to 0.
            // final_A already initialized to 0, so no need to set bit.
        } else if (f0_bit == 0 && f1_bit == 1) {
            // Output is `x_j`. Equivalent to `& 1` for this bit.
            // A_j = 1, B_j = 0, C_j = 0
            final_A |= (1 << j);
        } else if (f0_bit == 1 && f1_bit == 0) {
            // Output is `~x_j`. Equivalent to `^ 1` for this bit.
            // A_j = 1, B_j = 0, C_j = 1
            final_A |= (1 << j);
            final_C |= (1 << j);
        } else { // f0_bit == 1 && f1_bit == 1
            // Output is always 1. Equivalent to `| 1` for this bit.
            // A_j = 1, B_j = 1, C_j = 0
            final_A |= (1 << j); // This is actually not needed for |1, but it doesn't hurt.
                                 // The `| B_j` will force it to 1 regardless of `x & A_j`.
            final_B |= (1 << j);
        }
    }

    // The operations are: `& final_A`, `| final_B`, `^ final_C`
    // The order matters. The combined effect is `((x & final_A) | final_B) ^ final_C`.
    // We need to output these operations if their constant is non-zero.
    if (final_A != 1023) { // If final_A is 1023, it means `& 1023` which is a no-op for 0-1023 range.
        result_ops.push_back({'&', final_A});
    }
    if (final_B != 0) {
        result_ops.push_back({'|', final_B});
    }
    if (final_C != 0) {
        result_ops.push_back({'^', final_C});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // max_val[j] stores the maximum possible value for A_0[j]
    // Initialize with a very large value (effectively infinity)
    std::vector<long long> max_val(n, std::numeric_limits<long long>::max());

    // current_delta[j] stores the sum of 'd' values applied to A_0[j]
    // up to the current point in the reverse pass.
    std::vector<long long> current_delta(n, 0);

    // Iterate operations in reverse to determine constraints on A_0
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (increase by d),
            // then for elements in [l, r], their initial value A_0[j]
            // effectively needs to be 'd' less to compensate for this operation
            // when we consider the state *before* this operation.
            // So, we subtract d from current_delta for this range.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // If it's a type 2 operation (max = m),
            // then for all j in [l, r], A_0[j] + current_delta[j] <= m.
            // This implies A_0[j] <= m - current_delta[j].
            // We update max_val[j] with this new upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val[j] = std::min(max_val[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // The initial array A_0 is now determined by max_val.
    // We choose A_0[j] = max_val[j] to maximize our chances of satisfying constraints.
    // If max_val[j] is still std::numeric_limits<long long>::max(), it means
    // there was no upper bound constraint for A_0[j]. We can pick 0, or any value
    // within the |a_i| <= 10^9 range. Let's pick 0.
    // However, the problem states |a_i| <= 10^9.
    // If max_val[j] is greater than 10^9, we should cap it at 10^9.
    // If max_val[j] is less than -10^9, it's an issue.
    // Let's just use max_val[j] directly, as it's derived from constraints.
    // If it exceeds 10^9 or is less than -10^9, it will be caught by the final check.
    std::vector<long long> a0(n);
    for (int j = 0; j < n; ++j) {
        if (max_val[j] == std::numeric_limits<long long>::max()) {
            a0[j] = 0; // Default for unconstrained elements
        } else {
            a0[j] = max_val[j];
        }
    }

    // Verify the solution by replaying all operations
    std::vector<long long> current_a = a0;
    current_delta.assign(n, 0); // Reset current_delta for forward pass

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
                current_delta[j] += ops[i].val; // Keep track of total delta for A_0
            }
        } else { // ops[i].type == 2
            long long max_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_in_range = std::max(max_in_range, current_a[j]);
            }
            if (max_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check initial array elements for absolute value constraint
    for (int j = 0; j < n; ++j) {
        if (a0[j] > 1000000000LL || a0[j] < -1000000000LL) {
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << a0[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        // Child i goes to the doctor
        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_cry_effect = children[i].v;
        long long total_d_cry_effect = 0;

        // Apply v_i cry effect and d_j chain reaction
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry_effect from previous children who ran away
            if (total_d_cry_effect > 0) {
                children[j].p -= total_d_cry_effect;
            }

            // Apply v_i cry effect
            if (current_v_cry_effect > 0) {
                children[j].p -= current_v_cry_effect;
                current_v_cry_effect--;
            }

            // Check for chain reaction
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // In this case, all pairs (a_i, a_j) are in the same subsequence.
    // f(a_i, a_j) = a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: At least one element in S1 and at least one in S2.
    // This means there will be pairs (a_i, a_j) with f = a_i + a_j + h.
    // The minimum possible value for f is a[0].value + a[1].value (if a[0] and a[1] are in the same subsequence).
    // The maximum possible value for f is a[n-1].value + a[n-2].value + h (if a[n-1] and a[n-2] are in different subsequences).
    // Or it could be a[n-1].value + a[n-2].value (if a[n-1] and a[n-2] are in the same subsequence).
    // Or it could be a[n-1].value + a[0].value + h (if a[n-1] and a[0] are in different subsequences).

    // Let's consider a specific partition: a[0] in S1, and all other elements a[1]...a[n-1] in S2.
    // This is a common strategy for minimizing range when h is large.
    // min_f:
    //   - a[1].value + a[2].value (if n >= 3, from S2)
    //   - a[0].value + a[1].value + h (from S1 and S2)
    //   So, min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h) if n >= 3.
    //   If n=2, min_f = a[0].value + a[1].value + h.
    // max_f:
    //   - a[n-1].value + a[n-2].value (from S2)
    //   - a[0].value + a[n-1].value + h (from S1 and S2)
    //   So, max_f = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) if n >= 3.
    //   If n=2, max_f = a[0].value + a[1].value + h.

    // The minimum possible value of f is always at least a[0].value + a[1].value.
    // The maximum possible value of f is always at most a[n-1].value + a[n-2].value + h.
    // The range of values for f is [min_f, max_f].
    // The goodness is max_f - min_f.

    // Consider the partition where a[0] is in S1, and a[1]...a[n-1] are in S2.
    // min_f_val:
    //   - If n=2: a[0].value + a[1].value + h (only one pair, different subsequences)
    //   - If n > 2: min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // max_f_val:
    //   - If n=2: a[0].value + a[1].value + h
    //   - If n > 2: max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)

    long long min_f_val_case2, max_f_val_case2;
    if (n == 2) {
        min_f_val_case2 = a[0].value + a[1].value + h;
        max_f_val_case2 = a[0].value + a[1].value + h;
    } else {
        min_f_val_case2 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        max_f_val_case2 = std::max(a[n - 1].value + a[n - 2].value, a[0].value + a[n - 1].value + h);
    }
    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // dp[i] will store the maximum 'r' such that the substring s[i...r-1]
    // does not contain any bad triplet.
    // Or, more precisely, dp[i] stores the smallest 'r_prime' such that
    // s[i...r_prime-1] contains a bad triplet.
    // If no bad triplet starts at or after i, dp[i] can be n+1.
    // We want to find the smallest r_prime >= i + 2k for some x, k.
    // Let's define dp[i] as the minimum ending index (0-based) of a bad triplet
    // that starts at or after index i. If no such triplet exists, dp[i] = n.
    // So, for a given l (0-based), any r (0-based) such that l <= r < dp[l]
    // will form a "good" pair (l, r).
    // The number of such r's for a given l is dp[l] - l.
    // The problem uses 1-based indexing for l, r.
    // Let's use 0-based indexing for dp array and string.
    // dp[i] = minimum (x + 2k - 1) such that x >= i and s[x] = s[x+k] = s[x+2k].
    // If no such triplet exists starting at or after i, dp[i] = n.

    std::vector<int> dp(n + 1); // dp[i] stores the minimum r_idx (0-based) for a bad triplet starting at or after i
                               // If no such triplet, dp[i] = n.
    dp[n] = n; // Base case: no triplets can start at or after index n.

    for (int i = n - 1; i >= 0; --i) {
        dp[i] = dp[i + 1]; // Inherit from the next index

        // Check for triplets starting at i
        // k can be 1 or 2 for small k values.
        // For k=1: s[i], s[i+1], s[i+2]
        if (i + 2 < n && s[i] == s[i+1] && s[i+1] == s[i+2]) {
            dp[i] = std::min(dp[i], i + 2);
        }
        // For k=2: s[i], s[i+2], s[i+4]
        if (i + 4 < n && s[i] == s[i+2] && s[i+2] == s[i+4]) {
            dp[i] = std::min(dp[i], i + 4);
        }
        // For k=3: s[i], s[i+3], s[i+6]
        if (i + 6 < n && s[i] == s[i+3] && s[i+3] == s[i+6]) {
            dp[i] = std::min(dp[i], i + 6);
        }
        // For k=4: s[i], s[i+4], s[i+8]
        if (i + 8 < n && s[i] == s[i+4] && s[i+4] == s[i+8]) {
            dp[i] = std::min(dp[i], i + 8);
        }
        // For k=5: s[i], s[i+5], s[i+10]
        if (i + 10 < n && s[i] == s[i+5] && s[i+5] == s[i+10]) {
            dp[i] = std::min(dp[i], i + 10);
        }
        // For k=6: s[i], s[i+6], s[i+12]
        if (i + 12 < n && s[i] == s[i+6] && s[i+6] == s[i+12]) {
            dp[i] = std::min(dp[i], i + 12);
        }
    }

    for (int l = 0; l < n; ++l) {
        // For each starting index l (0-based),
        // any r (0-based) such that l <= r < dp[l] forms a "bad" pair (l, r)
        // in the sense that it does NOT contain a bad triplet.
        // The number of such r's is dp[l] - l.
        // These are the pairs we want to subtract from total_pairs.
        bad_pairs += (dp[l] - l);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into s[0...i-1] and s[i...N-1].
    // We can form s' = s[i...N-1] + s[0...i-1].
    // We need s' to be a palindrome and s' != s.
    for (int i = 1; i < n; ++i) { // i is the cut point, 0 < i < N
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 didn't work, we need to check k=2.
    // This means 3 pieces.
    // The problem statement implies that if k=1 doesn't work,
    // but a solution exists, it must be k=2.
    // This is because any string can be cut into N pieces (each character)
    // and reordered to form a palindrome if the character counts allow.
    // However, the constraint is that the pieces are substrings of the original.
    //
    // Consider the structure of a palindrome s.
    // If s consists of only one distinct character (e.g., "aaaaa"),
    // then any reordering of its substrings will result in the same string,
    // which is also "aaaaa". In this case, it's impossible to get s' != s.
    //
    // Let's check if s consists of only one distinct character.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 must be the answer.
    // Why?
    // Consider s = s_0 s_1 ... s_{N-1}.
    // Since s is a palindrome, s_0 = s_{N-1}, s_1 = s_{N-2}, etc.
    // If not all characters are the same, there must be at least two distinct characters.
    //
    // If N is odd, say N = 2m + 1.
    // s = s_0 ... s_{m-1} s_m s_{m-1} ... s_0.
    // Consider cutting s into three pieces:
    // P1 = s[0...m-1]
    // P2 = s[m]
    // P3 = s[m+1...N-1] = s[m+1...2m]
    // Note that P3 is the reverse of P1.
    // So P1 = s_0 ... s_{m-1}
    // P2 = s_m
    // P3 = s_{m-1} ... s_0
    //
    // We can reorder them as P3 + P2 + P1.
    // This forms s' = (s_{m-1} ... s_0) + (s_m) + (s_0 ... s_{m-1}).
    // This s' is a palindrome.
    // Is s' != s?
    // s = (s_0 ... s_{m-1}) + (s_m) + (s_{m-1} ... s_0)
    // s' = (s_{m-1} ... s_0) + (s_m) + (s_0 ... s_{m-1})
    // If s' == s, then (s_0 ... s_{m-1}) must be equal to (s_{m-1} ... s_0).
    // This means s[0...m-1] must be a palindrome.
    //
    // If N is even, say N = 2m.
    // s = s_0 ... s_{m-1} s_{m-1} ... s_0.
    // Consider cutting s into three pieces:
    // P1 = s[0...m-1]
    // P2 = "" (empty string, effectively 2 cuts at the same point, or 2 cuts very close)
    // P3 = s[m...N-1]
    // This is not quite right for 3 pieces.
    //
    // A simpler argument for k=2:
    // If s is not all same characters, then s[0...N/2 - 1] is not all same characters.
    // (If s[0...N/2 - 1] were all same, say 'a', then s would be 'a...a' because it's a palindrome).
    // So there exists some `j < N/2` such that `s[j] != s[0]`.
    //
    // Consider the string `s_prefix = s.substr(0, n/2)`.
    // If `s_prefix` is not a palindrome, then `s_prefix + s_suffix` (where `s_suffix` is `s.substr(n/2)`)
    // can be rearranged.
    //
    // The problem statement guarantees that if k=1 doesn't work, and it's not "Impossible", then k=2.
    // The "Impossible" case is handled by checking `all_same_char`.
    // If `s` is a palindrome and not all characters are the same, then `s` must contain at least two distinct characters.
    // For example, `s = "abacaba"`. `n=7`. `n/2 = 3`.
    // `s[0...2] = "aba"`. This is a palindrome.
    // `s[3] = 'c'`.
    // `s[4...6] = "aba"`.
    //
    // If `s` is not all same characters, then `s.substr(0, n-1)` is not all same characters.
    // Consider `s_prime = s.substr(1) + s[0]`.
    // This is a cyclic shift. If `s_prime` is a palindrome and `s_prime != s`, then `k=1`.
    //
    // The problem statement implies that if `k=1` fails and it's not "Impossible", then `k=2`.
    // This is a common pattern in competitive programming problems where the minimum `k` is asked.
    // If `k=1` fails, and the "Impossible" case (all same characters) is handled, then `k=2` is the answer.
    // This is because we can always make two cuts to achieve a different palindrome if the string is not monochromatic.
    // For example, cut `s` into `s[0]`, `s[1...N-2]`, `s[N-1]`.
    // Since `s` is a palindrome, `s[0] == s[N-1]`.
    // We can reorder them as `s[N-1] + s[1...N-2] + s[0]`. This is `s`.
    //
    // A different strategy for k=2:
    // Cut `s` into `s[0...i-1]`, `s[i...j-1]`, `s[j...N-1]`.
    //
    // The simplest argument for k=2 if k=1 fails and not all chars are same:
    // If `s` is a palindrome and not all characters are the same, then `s` must have at least two distinct characters.
    // For example, `s = "abacaba"`.
    // `k=1` check:
    // `bacabaa` (not pal)
    // `acabaab` (not pal)
    // `cabaaba` (not pal)
    // `abaacab` (not pal)
    // `baacaba` (not pal)
    // `aacabab` (not pal)
    //
    // `s = "nolon"`. `n=5`.
    // `k=1` check:
    // `olon` + `n` = `olonn` (not pal)
    // `lon` + `no` = `lonno` (not pal)
    // `on` + `nol` = `onnol` (not pal)
    // `n` + `nolo` = `nnolo` (not pal)
    // So `k=1` fails.
    // `nolon` is not all same chars. So output `2`.
    // Example solution for `nolon`: `no|l|on` -> `on|l|no`. This is `k=2`.
    //
    // `s = "otto"`. `n=4`.
    // `k=1` check:
    // `tto` + `o` = `ttoo` (not pal)
    // `to` + `ot` = `toot` (is pal, `toot != otto`). So `k=1`.
    //
    // `s = "qqqq"`. `n=4`.
    // `k=1` check:
    // `qqq` + `q` = `qqqq` (is pal, but `qqqq == qqqq`).
    // `qq` + `qq` = `qqqq` (is pal, but `qqqq == qqqq`).
    // `q` + `qqq` = `qqqq` (is pal, but `qqqq == qqqq`).
    // So `k=1` fails.
    // `qqqq` is all same chars. So output `Impossible`.
    //
    // `s = "kinnikkinnik"`. `n=12`.
    // `k=1` check:
    // `innikkinnikk` + `k` (not pal)
    // ...
    // `nik` + `kinnikkin` = `nikkinnikkin` (is pal, `nikkinnikkin != kinnikkinnik`). So `k=1`.

    // If we reach here, it means k=1 failed.
    // And we've already checked for the "Impossible" case (all same characters).
    // Therefore, the answer must be 2.
    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long head_reach_left = current_h - T;
        long long head_reach_right = current_h + T;

        // Find the first target track that this head can potentially cover
        // It must be within [head_reach_left, head_reach_right]
        // And it must be greater than or equal to the current p[p_idx]

        // If current_h is already to the right of p[p_idx] + T, this head is too far right for p[p_idx]
        // and potentially for many subsequent p's.
        // We need to find the first p[k] such that p[k] <= head_reach_right.
        // And then check if it can be covered.

        // If p[p_idx] is already to the right of head_reach_right, this head cannot cover p[p_idx]
        // and cannot cover any subsequent p's. So this head is useless for current p_idx.
        // We need to find a head that can cover p[p_idx].
        // The current head can only cover tracks in [current_h - T, current_h + T].
        // If p[p_idx] > current_h + T, this head cannot cover p[p_idx].
        // If p[p_idx] < current_h - T, this head cannot cover p[p_idx].

        // The strategy is: for each head, cover as many *uncovered* tracks as possible, starting from the leftmost uncovered track.
        // If the current head h[h_idx] cannot cover p[p_idx], we move to the next head.
        // If it can, we use it to cover p[p_idx] and all subsequent tracks it can reach.

        if (p[p_idx] > head_reach_right) {
            // This head is too far left to cover p[p_idx]
            // It means current_h + T < p[p_idx].
            // This head cannot cover p[p_idx] or any tracks to its right.
            // So we continue to the next head.
            continue;
        }

        // At this point, p[p_idx] <= head_reach_right.
        // This head *might* be able to cover p[p_idx].
        // We need to determine the effective range this head can cover, considering p[p_idx].

        long long effective_left_bound;
        long long effective_right_bound;

        if (current_h >= p[p_idx]) {
            // Head is at or to the right of p[p_idx].
            // It can move left to cover p[p_idx].
            // The leftmost track it can cover is max(p[p_idx], current_h - T).
            // The rightmost track it can cover is current_h + T.
            // The time taken to reach p[p_idx] is current_h - p[p_idx].
            // Remaining time for rightward movement is T - (current_h - p[p_idx]).
            // So it can cover up to p[p_idx] + (T - (current_h - p[p_idx])) = 2*p[p_idx] - current_h + T.
            // This is equivalent to saying it covers [p[p_idx], p[p_idx] + (T - (current_h - p[p_idx]))]
            // The rightmost point it can reach is p[p_idx] + (T - (current_h - p[p_idx]))
            // This is equivalent to current_h + T - 2*(current_h - p[p_idx]) if it moves left to p[p_idx] and then right.
            // No, this is simpler: if it covers p[p_idx], it can cover any track in [p[p_idx], p[p_idx] + (T - (current_h - p[p_idx]))].
            // The rightmost track it can cover is p[p_idx] + (T - (current_h - p[p_idx])).
            // This is the maximum rightward reach *after* covering p[p_idx].
            effective_right_bound = p[p_idx] + (T - (current_h - p[p_idx]));
        } else { // current_h < p[p_idx]
            // Head is to the left of p[p_idx].
            // It can move right to cover p[p_idx].
            // The time taken to reach p[p_idx] is p[p_idx] - current_h.
            // Remaining time for leftward movement is T - (p[p_idx] - current_h).
            // So it can cover down to p[p_idx] - (T - (p[p_idx] - current_h)) = 2*p[p_idx] - current_h - T.
            // This is equivalent to saying it covers [p[p_idx] - (T - (p[p_idx] - current_h)), p[p_idx]].
            // The rightmost point it can reach is current_h + T.
            effective_right_bound = current_h + T;
        }

        // Now, advance p_idx as long as p[p_idx] is within the effective_right_bound
        while (p_idx < m && p[p_idx] <= effective_right_bound) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p and h is 10^10.
                                    // Max T could be 10^10.
                                    // If p[0] = 1, h[0] = 10^10, T = 10^10 - 1.
                                    // If p[m-1] = 10^10, h[n-1] = 1, T = 10^10 - 1.
                                    // Max value for p_i or h_i is 10^10.
                                    // So max T could be around 10^10.
                                    // 2 * 10^10 is a safe upper bound.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_fixed(n); // a_fixed[0] is unused, a_fixed[1]...a_fixed[n-1] store a_2...a_n
    for (int i = 1; i < n; ++i) {
        std::cin >> a_fixed[i];
    }

    std::vector<long long> dp_val(n + 1, 0); // dp_val[i] stores the total y accumulated when starting at x=i and moving to x=i+a[i]
    std::vector<int> dp_next_x(n + 1, 0); // dp_next_x[i] stores the next x position after the first jump from x=i

    // Iterate backwards from n to 1 to fill DP tables
    for (int i = n; i >= 1; --i) {
        long long current_a_val;
        // For the DP calculation, we need a_i.
        // If i is the initial x (which is 1 for the problem's a_1),
        // then a_1 is varied. But for DP, we are considering a fixed a_i.
        // The problem states a_2...a_n are fixed.
        // So, for i >= 2, a_i is a_fixed[i-1].
        // For i = 1, this DP state is not directly used for the initial a_1,
        // but rather for subsequent jumps where x might become 1.
        // In the context of the problem, a_1 is the value we are testing.
        // However, the DP is for general a_x.
        // Let's assume a_i is the value at index i in the sequence.
        // For i >= 2, a_i is a_fixed[i-1].
        // For i = 1, we can't use a_fixed[0] as it's not given.
        // But the DP state for x=1 will only be reached if a_1 is fixed.
        // The problem is about varying a_1.
        // Let's re-evaluate: dp_val[i] and dp_next_x[i] are for a fixed sequence a_1, ..., a_n.
        // The problem asks to vary a_1.
        // So, for each query (a_1 = k), we need to compute.
        // The DP approach is useful if a_1 is fixed.
        // The only way to use DP is if the value of a_1 doesn't affect the DP states for x >= 2.
        // This is true. dp_val[i] and dp_next_x[i] for i >= 2 depend only on a_2, ..., a_n.

        // For i >= 2, a_i is a_fixed[i-1]
        // For i = 1, this DP state is not directly used for the initial a_1,
        // but rather for subsequent jumps where x might become 1.
        // However, the problem states x starts at 1.
        // The DP states are for when x is *currently* i.
        // So, for i >= 2, current_a_val = a_fixed[i-1].
        // For i = 1, this DP state is not directly used for the initial a_1,
        // as a_1 is varied.
        // Let's compute DP for i from n down to 2.
        // The DP for i=1 will be computed on the fly for each query.

        if (i == 1) continue; // Skip i=1 for precomputation, as a_1 varies.

        current_a_val = a_fixed[i-1]; // a_fixed is 0-indexed, a_fixed[0] unused, a_fixed[1] is a_2, etc.

        long long next_x_after_first_jump = i + current_a_val;
        long long next_x_after_second_jump = i + current_a_val - current_a_val; // This is just i

        if (next_x_after_first_jump <= 0 || next_x_after_first_jump > n) {
            // Terminates after first jump (x = x + a_x)
            dp_val[i] = current_a_val;
            dp_next_x[i] = 0; // Sentinel for termination
        } else {
            // x becomes next_x_after_first_jump. Then y increases by a_x, x decreases by a_x.
            // The new x is i.
            // So, from i, we jump to i + a_i, then back to i.
            // The total y accumulated in this pair of steps is 2 * a_i.
            // The next x to consider is i.
            // This forms a cycle if i is not a terminal state.
            // This means if we land back on i, and i is not a terminal state, it's an infinite loop.
            // The problem states: "The program increases both x and y by a value equal to a_x simultaneously."
            // "The program now increases y by a_x while decreasing x by a_x."
            // "The program executes steps 2 and 3 (first step 2, then step 3) repeatedly until it terminates"
            // This means:
            // (x, y) -> (x+a_x, y+a_x) -> (x+a_x-a_x, y+a_x+a_x) = (x, y+2*a_x)
            // So, from (x, y), we go to (x, y+2*a_x). This is an infinite loop if x is not a terminal state.
            // This interpretation is different from the sample.
            // Sample 1: i=3, a_1=3, a_2=4, a_3=1.
            // x=1, y=0. a_1=3.
            // Step 2: x=1+3=4, y=0+3=3. (x=4, y=3)
            // Step 3: x=4-a_4. But a_4 is not defined.
            // The problem states: "If, after any step, x <= 0 or x > n, the program immediately terminates."
            // So, if x becomes 4, and n=3, it terminates.
            // The sample output for i=3 is 8.
            // This means the interpretation of "a_x" in step 3 is the *original* a_x from step 2.
            // Let's re-read: "The program increases both x and y by a value equal to a_x simultaneously."
            // "The program now increases y by a_x while decreasing x by a_x."
            // This implies a_x is evaluated *once* at the beginning of the pair of steps.
            // Let current_x be the x value at the start of a pair of steps.
            // Let val = a[current_x].
            // Step 2: x_new = current_x + val, y_new = current_y + val.
            // Check termination: if x_new <= 0 or x_new > n, terminate. Result is y_new.
            // Step 3: x_final = x_new - val, y_final = y_new + val.
            // Check termination: if x_final <= 0 or x_final > n, terminate. Result is y_final.
            // If not terminated, the next iteration starts with (x_final, y_final).

            // Let's re-do DP based on this interpretation.
            // dp_val[i] = total y accumulated from starting at x=i until termination.
            // dp_next_x[i] = the x value where the next pair of steps starts.
            // If dp_next_x[i] == 0, it means termination.

            // For current x = i, let val = a_i.
            // First jump: x_after_step2 = i + val. y_accumulated_step2 = val.
            // If x_after_step2 <= 0 or x_after_step2 > n:
            //   dp_val[i] = val
            //   dp_next_x[i] = 0 (terminates)
            // Else (x_after_step2 is valid):
            //   Second jump: x_after_step3 = x_after_step2 - val = i. y_accumulated_step3 = val.
            //   Total y for this pair of steps = 2 * val.
            //   If x_after_step3 <= 0 or x_after_step3 > n:
            //     dp_val[i] = 2 * val
            //     dp_next_x[i] = 0 (terminates)
