        if (memo_state[current_x] == 1) {
            return -1; // Cycle detected
        }
        if (memo_state[current_x] == 2) {
            return memo_val[current_x]; // Already computed
        }

        memo_state[current_x] = 1; // Mark as visiting

        long long val_at_current_x = a_full_for_dp[current_x];

        // Step 2: x = current_x + val_at_current_x, y += val_at_current_x
        long long y_accum = val_at_current_x;
        int x_after_step2 = current_x + val_at_current_x;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            memo_state[current_x] = 2;
            memo_val[current_x] = y_accum;
            return y_accum;
        }

