        if (x_after_step3 <= 0 || x_after_step3 > n) {
            std::cout << y_total << "\n";
            continue;
        }

        // If x_after_step3 is 1, it's an infinite loop because we are back to the start with the same a_1.
        if (x_after_step3 == 1) {
            std::cout << -1 << "\n";
            continue;
        }

        // Otherwise, x_after_step3 is >= 2. We can use the precomputed DP value.
        long long res_from_dp = memo_val[x_after_step3];
        if (res_from_dp == -1) {
            std::cout << -1 << "\n";
        } else {
