#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Calculate the cost of the next nice staircase.
            // A nice staircase with k stairs costs k * (k + 1) / 2 cells.
            // The sequence of k for nice staircases is 1, 3, 7, 15, ... which is 2^i - 1.
            // So, the cost for the i-th nice staircase (where k = 2^i - 1) is (2^i - 1) * (2^i) / 2.
            // Let's use the direct formula for the cost of a nice staircase with k stairs.
            // The k here is the number of stairs, not the index i.
            // The sequence of k values for nice staircases is 1, 3, 7, 15, 31, ...
            // This is k_i = 2^(i+1) - 1 for i = 0, 1, 2, ...
            // The cost for a staircase with k stairs is k * (k + 1) / 2.
            // For k=1, cost = 1*(2)/2 = 1.
            // For k=3, cost = 3*(4)/2 = 6.
            // For k=7, cost = 7*(8)/2 = 28.
            // For k=15, cost = 15*(16)/2 = 120.
            // For k=31, cost = 31*(32)/2 = 496.

            long long cost_of_next_staircase = k * (k + 1) / 2;

            if (current_cost + cost_of_next_staircase <= x) {
                current_cost += cost_of_next_staircase;
                count++;
                // Update k for the next nice staircase.
                // The next k is 2*k + 1.
                // If current k is 1, next is 3.
                // If current k is 3, next is 7.
                // If current k is 7, next is 15.
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is strictly greater than q_{i-1}, then p_i must be q_i.
            // This is because q_i is the new maximum.
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i must be a new maximum.
                // But as a safety check.
                possible = false;
                break;
            }
            p[i] = q[i];
            used_numbers.insert(q[i]);
        } else { // q_i == q_{i-1}
            // If q_i is equal to q_{i-1}, then p_i must be some value
            // less than or equal to q_i (which is q_{i-1}) and not yet used.
            // To maximize chances, pick the smallest available unused number.
            int current_max_val = q[i];
            int next_available = 1;
            while (used_numbers.count(next_available)) {
                next_available++;
            }

            if (next_available > current_max_val) {
                // If the smallest available number is greater than current_max_val,
                // then we cannot place a number that doesn't change the prefix maximum.
                possible = false;
                break;
            }
            p[i] = next_available;
            used_numbers.insert(next_available);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        // Final check: ensure all numbers from 1 to n are used exactly once.
        // This is implicitly handled by the logic if `possible` is true,
        // as we always pick distinct numbers and `next_available` will eventually
        // cover all numbers up to `n` if `n` distinct numbers are needed.
        // The problem guarantees `q` is valid for *some* permutation,
        // so if our greedy choice leads to a valid construction, it's fine.
        // The only way it could be impossible is if `next_available > current_max_val`.

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

