        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining students (no specialization): x
            // Total remaining students: (c - mid) + (m - mid) + x
            // Each team needs 3 members. 'mid' members are already assigned (1 coder, 1 math).
            // So, each team needs 1 more member.
            // Total additional members needed: mid
            // These additional members can come from remaining coders, mathematicians, or no-spec students.
            // Total available for additional members: (c - mid) + (m - mid) + x
            if (mid <= c && mid <= m && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
