int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we will use to generate k distinct differences

    // Generate k distinct differences using numbers from 1 to k+1
    // The pattern is 1, k+1, 2, k, 3, k-1, ...
    // This generates differences: k, k-1, k-2, ..., 1
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // For the remaining n - (k+1) elements, just append them in increasing order
    // starting from the next available number.
    // The next available number is 'left' (which is (k+1)/2 + 1 if k+1 is odd, or k/2 + 1 if k+1 is even)
    // or 'right' (which is (k+1)/2 if k+1 is odd, or k/2 + 1 if k+1 is even)
    // More simply, the numbers used so far are 1, ..., k+1.
    // So the next number to use is k+2.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

