// Function to check if a sub-array is a permutation of 1 to len
// This version uses a frequency array and checks max value
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0
    if (start_idx + len > arr.size()) return false; // Out of bounds

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max prefix values and check for prefix permutations
    std::vector<int> prefix_max(n);
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[k] is true if a[0...k-1] is a perm of 1..k
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max_prefix = 0;
    bool current_prefix_valid = true;

    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val <= 0 || val > n || seen_prefix[val]) {
            current_prefix_valid = false;
        } else {
            seen_prefix[val] = true;
        }
        if (val > current_max_prefix) {
            current_max_prefix = val;
        }
        prefix_max[i] = current_max_prefix;

        if (current_prefix_valid && current_max_prefix == (i + 1)) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Precompute max suffix values and check for suffix permutations
    std::vector<int> suffix_max(n);
    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[k] is true if a[n-k...n-1] is a perm of 1..k
    std::vector<bool> seen_suffix(n + 1, false);
    int current_max_suffix = 0;
    bool current_suffix_valid = true;

    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        if (val <= 0 || val > n || seen_suffix[val]) {
            current_suffix_valid = false;
        } else {
            seen_suffix[val] = true;
        }
        if (val > current_max_suffix) {
            current_max_suffix = val;
        }
        suffix_max[i] = current_max_suffix;

        if (current_suffix_valid && current_max_suffix == (n - i)) {
            is_suffix_perm[n - i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 goes from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if first l1 elements form a permutation of 1 to l1
        // Check if last l2 elements form a permutation of 1 to l2
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

