#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int wins_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins_count++;
                if (i > 0 && s[i - 1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (wins_count == 0) { // All L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + (k - 1) * 2 << "\n"; // Change k L's to W's. First W is 1 point, others are 2.
            }
            continue;
        }

        // If there are already wins, we want to fill gaps between W's and extend W sequences.
        // Find the first and last 'W'
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) first_w = i;
                last_w = i;
            }
        }

        // Gaps between W's
        std::vector<int> gaps;
        int current_gap = 0;
        bool in_gap = false;
        for (int i = first_w + 1; i < last_w; ++i) {
            if (s[i] == 'L') {
                current_gap++;
                in_gap = true;
            } else { // s[i] == 'W'
                if (in_gap) {
                    gaps.push_back(current_gap);
                    current_gap = 0;
                    in_gap = false;
                }
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int current_k = k;
        int max_score = initial_score;

        // Fill internal gaps
        for (int gap_len : gaps) {
            if (current_k >= gap_len) {
                current_k -= gap_len;
                max_score += gap_len * 2 + 1; // Each L becomes W, adds 2 points. The first L in a gap connects two Ws, adding 1 extra point.
                                              // Example: W L L W -> W W W W. 2 L's changed. Score increases by 2*2 + 1 = 5.
                                              // Original: W(1) L(0) L(0) W(1) -> 2 points.
                                              // New: W(1) W(2) W(2) W(2) -> 7 points. Increase 5.
                                              // Each L changed to W adds 2 points. The first L changed in a gap connects two Ws, giving an additional 1 point.
                                              // So, gap_len * 2 + 1.
            } else {
                max_score += current_k * 2; // Can't fill the whole gap, just change some L's to W's. Each adds 2 points.
                current_k = 0;
                break;
            }
        }

        // Extend from ends
        if (current_k > 0) {
            // Extend from left (before first_w)
            max_score += std::min(current_k, first_w) * 2;
            current_k -= std::min(current_k, first_w);

            // Extend from right (after last_w)
            if (current_k > 0) {
                max_score += std::min(current_k, n - 1 - last_w) * 2;
            }
        }

        std::cout << max_score << "\n";
    }
    return 0;
}

