#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    int k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends with w_i = 1: they get one number, happiness is 2 * number.
    // To maximize, give them the largest available numbers.
    // These are the k largest numbers from 'a'.
    // These friends are at the end of the sorted 'w' array.
    int a_ptr_end = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_end];
            a_ptr_end--;
        } else {
            // Since w is sorted, all remaining w[i] will be > 1.
            // Break and handle them in the next loop.
            break;
        }
    }

    // Friends with w_i > 1: they get w_i numbers. Happiness is max + min.
    // To maximize, give them the largest available numbers as their max.
    // These are the remaining largest numbers from 'a'.
    // The friends with w_i > 1 are at the beginning of the sorted 'w' array.
    // We iterate from the smallest w_i > 1 to largest w_i > 1.
    // The largest w_i values will consume more numbers, so they should get the smallest available numbers as their min.
    // The smallest w_i values will consume fewer numbers, so they should get larger available numbers as their min.
    // This is why we iterate w from smallest to largest.

    int a_ptr_start = 0;
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            // This friend gets one of the remaining largest numbers as their max.
            total_happiness += a[a_ptr_end];
            a_ptr_end--;

            // This friend gets one of the remaining smallest numbers as their min.
            // They need to consume w[i] - 1 additional numbers.
            // These w[i] - 1 numbers will be taken from the smallest available numbers.
            // The smallest number they receive will be a[a_ptr_start].
            total_happiness += a[a_ptr_start];
            a_ptr_start += (w[i] - 1);
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long turn = 0; // 0 for Chanek, 1 for Opponent

    while (n > 0) {
        if (turn == 0) { // Chanek's turn
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1. Opponent gets to play on N-1.
                // If N-1 is odd, opponent takes 1. N-2.
                // If N-1 is even, this path is not taken as N is even.
                // This path is always N-1 odd. Opponent takes 1.
                // Chanek gets 1 + (coins from N-2)

                // Option 2: Take N/2 coins
                // Remaining N/2. Opponent gets to play on N/2.
                // Chanek gets N/2 + (coins from N/2)

                // If N is a power of 2 (and N > 2), say N = 2^k (k > 1)
                // Option 1: Take 1. N becomes 2^k - 1 (odd).
                //   Opponent takes 1. N becomes 2^k - 2 (even).
                //   Chanek gets 1 + (coins from 2^k - 2)
                // Option 2: Take N/2. N becomes 2^(k-1).
                //   Chanek gets N/2 + (coins from 2^(k-1))
                // In this case, taking N/2 is always better for Chanek.
                // Example: N=4.
                //   Take 1: Chanek 1. N=3. Opponent takes 1. N=2. Chanek 1+1=2. N=1. Opponent takes 1. Total: C=2, O=2.
                //   Take N/2=2: Chanek 2. N=2. Opponent takes 1. N=1. Chanek 2+1=3. N=0. Total: C=3, O=1.
                // Chanek takes N/2.

                // If N is even but not a power of 2, say N = 2^k * M where M is odd and M > 1.
                // Example: N=6.
                //   Take 1: Chanek 1. N=5. Opponent takes 1. N=4. Chanek 1+2=3. N=2. Opponent takes 1. N=1. Chanek 3+1=4. N=0. Total: C=4, O=2.
                //   Take N/2=3: Chanek 3. N=3. Opponent takes 1. N=2. Chanek 3+1=4. N=1. Opponent takes 1. N=0. Total: C=4, O=2.
                // In this case, both options lead to the same result for Chanek.
                // The problem states "maximize the number of coins they have".
                // If N is even, and N/2 is odd (i.e., N = 2 * odd_number), then taking N/2 is good.
                // If N is even, and N/2 is even (i.e., N = 4 * any_number), then taking N/2 leads to an even number for opponent.
                // The strategy is: if N is even, and N/2 is odd, take N/2.
                // Otherwise (N is even, and N/2 is even, i.e., N is a multiple of 4), take 1.
                // This is because if N is a multiple of 4, taking N/2 leaves N/2 (which is even) for the opponent.
                // The opponent will then also have the option to take N/4.
                // If N is even, and N/2 is odd, taking N/2 leaves an odd number for the opponent, forcing them to take 1.

                // Let's re-evaluate the optimal strategy for Chanek when N is even.
                // If N is even:
                // Option A: Take 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2 (even).
                //   Chanek gets 1 + (coins from N-2 if Chanek plays optimally from N-2)
                // Option B: Take N/2. Remaining N/2.
                //   Chanek gets N/2 + (coins from N/2 if Chanek plays optimally from N/2)

                // Consider the total coins taken by Chanek and Opponent.
                // The game ends when N=0. Total coins taken is N_initial.
                // Let C(N) be the coins Chanek gets if starting with N.
                // Let O(N) be the coins Opponent gets if starting with N.
                // C(N) + O(N) = N_initial.
                // Chanek wants to maximize C(N). Opponent wants to maximize O(N).
                // This is equivalent to Chanek maximizing C(N) and Opponent minimizing C(N).

                // If N is even:
                // If Chanek takes 1: Chanek gets 1. Remaining N-1. Opponent plays on N-1.
                //   Opponent gets C(N-1) from N-1. Chanek gets O(N-1) from N-1.
                //   Total for Chanek: 1 + O(N-1).
                // If Chanek takes N/2: Chanek gets N/2. Remaining N/2. Opponent plays on N/2.
                //   Opponent gets C(N/2) from N/2. Chanek gets O(N/2) from N/2.
                //   Total for Chanek: N/2 + O(N/2).

                // This is a minimax problem.
                // Let's trace the logic from the examples.
                // N=5: C takes 1 (C=1, N=4). O takes N/2=2 (O=2, N=2). C takes N/2=1 (C=1+1=2, N=1). O takes 1 (O=2+1=3, N=0). C=2, O=3.
                // N=6: C takes N/2=3 (C=3, N=3). O takes 1 (O=1, N=2). C takes N/2=1 (C=3+1=4, N=1). O takes 1 (O=1+1=2, N=0). C=4, O=2.

                // The strategy for Chanek when N is even:
                // If N is a power of 2 (N = 2^k, k >= 1):
                //   Chanek takes N/2. This leaves N/2 (another power of 2) for the opponent.
                //   This continues until N=2. Chanek takes 1. Opponent takes 1.
                //   Example N=4: C takes 2 (N=2). O takes 1 (N=1). C takes 1 (N=0). C=3, O=1.
                //   Example N=8: C takes 4 (N=4). O takes 2 (N=2). C takes 1 (N=1). O takes 1 (N=0). C=5, O=3.
                //   In general, for N=2^k, Chanek takes N/2, then N/4, ..., until N=2.
                //   Then Chanek takes 1, Opponent takes 1.
                //   Chanek gets (N/2 + N/8 + N/32 + ...) + 1.
                //   Opponent gets (N/4 + N/16 + N/64 + ...) + 1.
                //   This is (N/2 + N/4 + N/8 + ... + 1) / 2 + 1/2.
                //   Sum of geometric series N/2 + N/4 + ... + 1 = N-1.
                //   Chanek gets (N-1)/2 + 1. Opponent gets (N-1)/2 + 1.
                //   This is wrong. Let's re-evaluate.
                //   N=2^k.
                //   C takes 2^(k-1). N=2^(k-1).
                //   O takes 2^(k-2). N=2^(k-2).
                //   C takes 2^(k-3). N=2^(k-3).
                //   ...
                //   If k is odd: C takes 2^0=1. N=2^0=1. O takes 1. N=0.
                //   Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^0.
                //   Opponent gets 2^(k-2) + 2^(k-4) + ... + 2^1 + 1.
                //   If k is even: C takes 2^1=2. N=2^1=2. O takes 1. N=1. C takes 1. N=0.
                //   Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^1 + 1.
                //   Opponent gets 2^(k-2) + 2^(k-4) + ... + 2^0.
                //   This is complicated.

                // Let's simplify the optimal strategy.
                // If N is odd, Chanek must take 1. N becomes even.
                // If N is even:
                //   If N/2 is odd (i.e., N = 2 * (odd number)):
                //     Chanek takes N/2. N becomes odd. Opponent must take 1.
                //     This seems like a good move for Chanek, as it forces opponent to take 1.
                //   If N/2 is even (i.e., N = 4 * (any number)):
                //     Chanek takes N/2. N becomes even. Opponent can also take N/4.
                //     In this case, taking 1 might be better.
                //     If Chanek takes 1, N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                //     This leaves an even number for Chanek on the next turn.

                // The core idea is that if N is even, and N/2 is odd, taking N/2 is always optimal for the current player.
                // Because it leaves an odd number for the opponent, forcing them to take 1.
                // If N is even, and N/2 is even (N is a multiple of 4), then taking N/2 leaves an even number for the opponent.
                // In this case, taking 1 might be better, as it leaves N-1 (odd) for the opponent, forcing them to take 1.
                // So, if N is a multiple of 4, Chanek takes 1.
                // If N is even, but not a multiple of 4 (i.e., N = 2 * odd), Chanek takes N/2.

                if (n % 4 == 0) { // N is a multiple of 4
                    chanek_coins += 1;
                    n -= 1;
                } else { // N is even, but not a multiple of 4 (N = 2 * odd)
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1;
            } else { // N is even
                if (n % 4 == 0) { // N is a multiple of 4
                    n -= 1;
                } else { // N is even, but not a multiple of 4 (N = 2 * odd)
                    n /= 2;
                }
            }
        }
        turn = 1 - turn; // Switch turn
    }
    return chanek_coins;
}

