#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // Condition: current_sum = 2 * current_xor_sum
    // If already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
        return;
    }

    // We need to append at most 3 elements.
    // Let's try to append 2 elements.
    // We want to find b1, b2 such that:
    // (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)

    // Strategy:
    // 1. Append current_xor_sum.
    //    New sum: S' = current_sum + current_xor_sum
    //    New XOR sum: X' = current_xor_sum ^ current_xor_sum = 0
    //    Condition: S' = 2 * X'  =>  current_sum + current_xor_sum = 2 * 0 = 0
    //    This only works if current_sum and current_xor_sum are both 0, which means all initial elements were 0.
    //    If they are not both 0, this doesn't make it good.

    // Let's try to make the XOR sum 0.
    // Append b1 = current_xor_sum.
    // New sum: S_1 = current_sum + current_xor_sum
    // New XOR sum: X_1 = current_xor_sum ^ current_xor_sum = 0
    // Now we need S_1 = 2 * X_1, which means S_1 = 0.
    // If S_1 is not 0, we need to append b2 such that:
    // (S_1 + b2) = 2 * (X_1 ^ b2)
    // (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2)
    // (current_sum + current_xor_sum + b2) = 2 * b2
    // current_sum + current_xor_sum = b2

    // So, we can append two elements:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum
    // Let's verify this:
    // New total sum: S_final = current_sum + b1 + b2
    //                          = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //                          = 2 * (current_sum + current_xor_sum)
    // New total XOR sum: X_final = current_xor_sum ^ b1 ^ b2
    //                              = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //                              = 0 ^ (current_sum + current_xor_sum)
    //                              = current_sum + current_xor_sum
    // Check condition: S_final = 2 * X_final
    //                  2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This holds true.

    // The problem states that appended elements must be non-negative.
    // Since initial a_i are non-negative, current_sum is non-negative.
    // current_xor_sum is also non-negative.
    // So b1 = current_xor_sum is non-negative.
    // And b2 = current_sum + current_xor_sum is non-negative.
    // This strategy always works and uses 2 elements.

    std::cout << 2 << "\n";
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << "\n";
}

