void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w_candidate(n, '1');

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w_candidate[i - x] = '0';
            }
            if (i + x < n) {
                w_candidate[i + x] = '0';
            }
        }
    }

    std::string s_reconstructed(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w_candidate[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w_candidate[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_reconstructed[i] = '1';
        }
    }

    if (s_reconstructed == s) {
        std::cout << w_candidate << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

