#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b' (or 'b's generated from it).
            // This 'b' will effectively "absorb" all 'a's to its left
            // that haven't been absorbed by 'b's further to the right.
            // The number of 'a's currently "active" to its left is `count_a`.
            // Each such 'a' will cause an "ab" -> "bba" operation.
            // This 'b' itself will be involved in `count_a` operations.
            // After these operations, this 'b' effectively moves past all `count_a` 'a's.
            // The `count_a` 'a's are still there, but now to the right of this 'b'.
            // The `count_a` operations also generate `count_a` new 'b's.
            // These new 'b's are effectively to the left of the original 'a's.
            // So, the number of 'a's that can interact with subsequent 'b's (to the left)
            // effectively doubles for each 'b' encountered.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now "active"
            // and can interact with any 'b's to its left.
            // Increment the count of active 'a's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

