int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int max_count = std::max({count_x, count_y, count_z});
        int min_count = std::min({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_disassemble_operations = 0;
    int correct_sequences = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (chain[0] == 1) { // This chain starts with 1
            correct_sequences++; // This chain is a candidate for being the main correct sequence
            for (int j = 0; j < m - 1; ++j) {
                if (chain[j+1] == chain[j] + 1) {
                    correct_sequences++;
                } else {
                    // The sequence 1 -> 2 -> ... -> X is broken here.
                    // All subsequent dolls in this chain are not part of the correct 1->2->... sequence.
                    // They need to be disassembled.
                    total_disassemble_operations += (m - 1 - j);
                    break; 
                }
            }
        } else {
            // This chain does not start with 1. All dolls in it need to be disassembled.
            // A chain of length m has m-1 nesting operations.
            // To disassemble it completely, we need m-1 operations.
            total_disassemble_operations += (m - 1);
        }
    }

    // Total operations = (disassemble all incorrect parts) + (assemble remaining parts)
    // Disassemble:
    // Each doll that is not part of the 1->2->...->N sequence needs to be taken out.
    // The `total_disassemble_operations` already counts the operations to break up chains
    // that are not part of the 1->2->... sequence, or parts of the 1->2->... sequence that are broken.
    // This is equivalent to (N - 1) - (number of correct adjacent pairs) operations.
    // The number of correct adjacent pairs is `correct_sequences - 1` (since `correct_sequences` counts 1->2, 2->3, etc., and also the initial '1').
    // So, `correct_sequences` is actually the count of `i` such that `i` is nested in `i+1` AND `i` is part of the initial chain.
    // If `chain[0] == 1`, then `correct_sequences` starts at 1 for the doll '1' itself.
    // Then for each `chain[j+1] == chain[j] + 1`, it increments.
    // So, `correct_sequences` is the length of the longest prefix `1 -> 2 -> ... -> X` that exists in the initial configuration.
    // For example, if we have `1 -> 2 -> 4`, `correct_sequences` would be 2 (for 1 and 2).
    // The number of correct direct nestings is `correct_sequences - 1`.
    // The number of dolls that are part of this correct prefix is `correct_sequences`.

    // Total dolls N. Total target nestings N-1.
    // Number of nestings that are already correct: `correct_sequences - 1`.
    // Number of nestings that need to be performed: `(N - 1) - (correct_sequences - 1) = N - correct_sequences`.
    // Each of these `N - correct_sequences` nestings costs 1 second.

    // Total operations = (disassemble operations) + (assemble operations)
    // Disassemble operations:
    // Each chain that is not the main chain (i.e., doesn't start with 1) needs to be fully disassembled.
    // This costs `m-1` operations for a chain of length `m`.
    // For the chain that starts with 1, if it's `1 -> 2 -> ... -> X -> Y -> ...`,
    // the part `Y -> ...` needs to be disassembled. This costs `(m - (X's index + 1))` operations.
    // This is exactly what `total_disassemble_operations` calculates.

    // The total number of dolls is N.
    // The number of dolls that are part of the `1 -> 2 -> ... -> X` correct prefix is `correct_sequences`.
    // These `correct_sequences` dolls are already correctly nested relative to each other.
    // The remaining `N - correct_sequences` dolls need to be assembled into this chain.
    // Each assembly operation costs 1 second. So, `N - correct_sequences` assembly operations.

    // Total operations = `total_disassemble_operations` + `(N - correct_sequences)`

    long long result = total_disassemble_operations + (n - correct_sequences);
    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        char last_c1 = '0'; // Last digit colored 1
        char last_c2 = (char)('0' + pivot_digit); // Last digit colored 2 (from S1 part)

        bool possible_pivot = true;
        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < (char)('0' + pivot_digit)) {
                // Must be color 1
                if (current_digit < last_c1) {
                    possible_pivot = false;
                    break;
                }
                result[i] = '1';
                last_c1 = current_digit;
            } else if (current_digit > (char)('0' + pivot_digit)) {
                // Must be color 2
                if (current_digit < last_c2) {
                    possible_pivot = false;
                    break;
                }
                result[i] = '2';
                last_c2 = current_digit;
            } else { // current_digit == pivot_digit
                // Can be either color 1 or color 2
                // Prefer color 2 if it maintains non-decreasing order for S2
                if (current_digit >= last_c2) {
                    result[i] = '2';
                    last_c2 = current_digit;
                } else if (current_digit >= last_c1) { // Otherwise, try color 1
                    result[i] = '1';
                    last_c1 = current_digit;
                } else { // Cannot place in either
                    possible_pivot = false;
                    break;
                }
            }
        }

        if (possible_pivot) {
            found_solution = true;
            std::cout << result << "\n";
            break;
        }
    }

    if (!found_solution) {
        std::cout << "-\n";
    }
}

