#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to perform division by 2.
    // If b is even, b/2 is integer.
    // If b is odd, (b-1)/2 is integer.
    // (b-1) * b is always even, so (b-1)*b/2 is always an integer.
    // We need to compute this modulo MOD.
    // (X * Y / 2) % MOD = (X % MOD * Y % MOD * inv(2) % MOD) % MOD
    // inv(2) modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004
    long long inv2 = 500000004;

    long long sum_r_term1 = (b - 1) % MOD;
    long long sum_r_term2 = b % MOD;
    long long sum_r = (sum_r_term1 * sum_r_term2) % MOD;
    sum_r = (sum_r * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_{k=1 to a} k = a * (a + 1) / 2
    // sum_{k=1 to a} 1 = a
    // So, sum_k_b_plus_1 = b * a * (a + 1) / 2 + a

    long long sum_k_term1 = a % MOD;
    long long sum_k_term2 = (a + 1) % MOD;
    long long sum_k = (sum_k_term1 * sum_k_term2) % MOD;
    sum_k = (sum_k * inv2) % MOD;

    long long sum_k_b_plus_1_part1 = (b % MOD * sum_k) % MOD;
    long long sum_k_b_plus_1_part2 = a % MOD;
    long long sum_k_b_plus_1 = (sum_k_b_plus_1_part1 + sum_k_b_plus_1_part2) % MOD;

    // Total sum S = sum_r * sum_k_b_plus_1
    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        std::string s;
        std::cin >> s;
        int countL = 0;
        int countR = 0;
        int countU = 0;
        int countD = 0;

        for (char c : s) {
            if (c == 'L') {
                countL++;
            } else if (c == 'R') {
                countR++;
            } else if (c == 'U') {
                countU++;
            } else if (c == 'D') {
                countD++;
            }
        }

        int horizontal_moves = std::min(countL, countR);
        int vertical_moves = std::min(countU, countD);

        if (horizontal_moves == 0 && vertical_moves == 0) {
            std::cout << 0 << "\n\n";
        } else if (horizontal_moves == 0) { // Only vertical moves possible
            std::cout << 2 << "\nUD\n";
        } else if (vertical_moves == 0) { // Only horizontal moves possible
            std::cout << 2 << "\nLR\n";
        } else {
            std::cout << 2 * (horizontal_moves + vertical_moves) << "\n";
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'L';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'U';
            }
            for (int i = 0; i < horizontal_moves; ++i) {
                std::cout << 'R';
            }
            for (int i = 0; i < vertical_moves; ++i) {
                std::cout << 'D';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> left_dist(n);
    left_dist[0] = 1;
    for (int i = 1; i < n; ++i) {
        left_dist[i] = std::min(h[i], left_dist[i - 1] + 1);
    }

    std::vector<long long> right_dist(n);
    right_dist[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        right_dist[i] = std::min(h[i], right_dist[i + 1] + 1);
    }

    long long max_min_dist = 0;
    for (int i = 0; i < n; ++i) {
        max_min_dist = std::max(max_min_dist, std::min(left_dist[i], right_dist[i]));
    }

    std::cout << max_min_dist << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_idx = i;
        int block_end_idx = std::min(n, i + k);

        // Fill this block in decreasing order
        // The values to fill are from current_val down to current_val - (block_end_idx - block_start_idx) + 1
        for (int j = block_end_idx - 1; j >= block_start_idx; --j) {
            p[j] = current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0; // What 0 becomes after all operations
    int current_val_1 = 1023; // What 1023 becomes after all operations

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_val_0 &= val;
            current_val_1 &= val;
        } else if (op_char == '|') {
            current_val_0 |= val;
            current_val_1 |= val;
        } else if (op_char == '^') {
            current_val_0 ^= val;
            current_val_1 ^= val;
        }
    }

    int final_and_mask = 1023; // Represents the 'A' in (x & A) | B ^ C
    int final_or_mask = 0;    // Represents the 'B' in (x & A) | B ^ C
    int final_xor_mask = 0;   // Represents the 'C' in (x & A) | B ^ C

    for (int bit = 0; bit < 10; ++bit) {
        int bit_mask = (1 << bit);
        bool bit_0_becomes_0 = ((current_val_0 & bit_mask) == 0);
        bool bit_1_becomes_0 = ((current_val_1 & bit_mask) == 0);

        if (bit_0_becomes_0 && bit_1_becomes_0) {
            // Both 0 and 1 become 0 for this bit.
            // This means the bit is forced to 0.
            // (x & 0) | 0 ^ 0 = 0
            // (x & 1) | 0 ^ 1 = 0 (if x=1)
            // To achieve this: final_and_mask &= ~bit_mask; final_or_mask &= ~bit_mask;
            // Or simply: final_and_mask &= ~bit_mask;
            final_and_mask &= ~bit_mask; // Force this bit to 0 regardless of input
            final_or_mask &= ~bit_mask; // Ensure OR doesn't set it to 1
            final_xor_mask &= ~bit_mask; // Ensure XOR doesn't flip it to 1
        } else if (!bit_0_becomes_0 && !bit_1_becomes_0) {
            // Both 0 and 1 become 1 for this bit.
            // This means the bit is forced to 1.
            // (x & 0) | 1 ^ 0 = 1
            // (x & 1) | 1 ^ 0 = 1
            // To achieve this: final_or_mask |= bit_mask;
            final_and_mask |= bit_mask; // Ensure AND doesn't clear it
            final_or_mask |= bit_mask; // Force this bit to 1
            final_xor_mask &= ~bit_mask; // Ensure XOR doesn't flip it to 0
        } else if (bit_0_becomes_0 && !bit_1_becomes_0) {
            // 0 becomes 0, 1 becomes 1.
            // This means the bit is unchanged.
            // (x & 1) | 0 ^ 0 = x
            // To achieve this: final_and_mask |= bit_mask;
            final_and_mask |= bit_mask; // Keep this bit as is
            final_or_mask &= ~bit_mask; // Ensure OR doesn't set it to 1
            final_xor_mask &= ~bit_mask; // Ensure XOR doesn't flip it
        } else { // !bit_0_becomes_0 && bit_1_becomes_0
            // 0 becomes 1, 1 becomes 0.
            // This means the bit is flipped.
            // (x & 1) | 0 ^ 1 = ~x
            // To achieve this: final_xor_mask |= bit_mask;
            final_and_mask |= bit_mask; // Keep this bit as is
            final_or_mask &= ~bit_mask; // Ensure OR doesn't set it to 1
            final_xor_mask |= bit_mask; // Flip this bit
        }
    }

    std::vector<std::pair<char, int>> simplified_ops;
    if (final_and_mask != 1023) { // If any bit is forced to 0
        simplified_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit is forced to 1
        simplified_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit is flipped
        simplified_ops.push_back({'^', final_xor_mask});
    }

    std::cout << simplified_ops.size() << "\n";
    for (const auto& op : simplified_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
