int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Dummy operation (e.g., add 0 to a[0])
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";

        // Operation 3: Dummy operation (e.g., add 0 to a[0])
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // Select segment [1, n-1] (0-indexed: [0, n-2])
    // For each a[i] in this segment, add (n - (a[i] % n)) % n * n
    // This makes a[i] a multiple of n.
    // The length of this segment is n-1.
    // We need to add a multiple of (n-1).
    // This strategy is flawed. The problem states "add a multiple of len".
    // The strategy should be:
    // For each a[i], we want to add x_i such that (a[i] + x_i) % n == 0.
    // And x_i must be a multiple of len.
    // This is tricky.

    // Let's use the standard trick for n > 1.
    // Operation 1: Make a[0]...a[n-2] multiples of n.
    // Segment: [1, n-1] (0-indexed: [0, n-2])
    // Length: n-1
    std::cout << 1 << " " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n; // Ensure positive remainder
        long long to_add = remainder * (n - 1); // This is a multiple of (n-1)
        // We want a[i] + x_i to be a multiple of n.
        // a[i] + x_i = k*n
        // x_i = k*n - a[i]
        // x_i must be a multiple of (n-1).
        // Let's try to make a[i] become a multiple of n.
        // We need to add (n - (a[i] % n)) % n to a[i] to make it a multiple of n.
        // Let this value be `val_to_add`.
        // We need `val_to_add` to be a multiple of `n-1`.
        // This is not directly possible.

        // The standard solution for this problem type:
        // Operation 1: For elements a[0]...a[n-2]
        // Select segment [1, n-1] (0-indexed: [0, n-2])
        // Length is n-1.
        // For each a[i], we want to add x_i such that (a[i] + x_i) % n == 0.
        // And x_i must be a multiple of (n-1).
        // Let a[i] = q*n + r, where 0 <= r < n.
        // We want to add x_i such that a[i] + x_i = k*n.
        // So x_i = k*n - a[i].
        // We need x_i to be a multiple of (n-1).
        // Consider a[i] * (n-1).
        // (a[i] * (n-1)) % n = (a[i] * (-1)) % n = (-a[i]) % n.
        // So if we add a[i] * (n-1) to a[i], it becomes a[i] + a[i]*(n-1) = a[i]*n.
        // This is a multiple of n.
        // And a[i]*(n-1) is a multiple of (n-1).
        // So, for each a[i] in [0, n-2], add a[i]*(n-1).
        // This makes a[i] become a[i]*n.
        // Then, in the next step, we can make it 0.
        long long add_val = a[i] * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // Operation 2: For the last element a[n-1]
    // Select segment [n, n] (0-indexed: [n-1, n-1])
    // Length is 1.
    // Add -a[n-1] to a[n-1]. This is a multiple of 1.
    std::cout << n << " " << n << "\n";
    std::cout << -a[n - 1] << "\n";
    a[n - 1] = 0;

    // Operation 3: For all elements a[0]...a[n-1]
    // Select segment [1, n] (0-indexed: [0, n-1])
    // Length is n.
    // At this point, a[0]...a[n-2] are all multiples of n (specifically, a[i]*n).
    // a[n-1] is 0.
    // For each a[i], add -a[i]. Since a[i] is a multiple of n, -a[i] is also a multiple of n.
    std::cout << 1 << " " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m by swapping if necessary.
        // This simplifies calculations as we can always assume n is the larger coordinate.
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: k is less than the minimum number of moves required to reach (n, m).
        // The minimum number of moves is max(n, m) because each move can change
        // at most one coordinate by 1, or both by 1 (diagonal).
        // So, to cover a distance of n in x and m in y, we need at least max(n, m) moves.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Calculate the maximum number of diagonal moves possible.
        // We can make 'm' diagonal moves to reach (m, m) or (-m, -m) etc.
        // After 'm' diagonal moves, we are at (n-m, 0) or similar, effectively.
        // The remaining k - m moves must cover the remaining distance n - m.
        // These remaining moves can be straight or diagonal.

        long long ans;
        long long diff = n - m;

        // If n and m have the same parity, and k has the same parity as n (and m).
        // This means (n % 2 == m % 2) and (k % 2 == n % 2).
        // Or equivalently, (n - m) is even, and (k - n) is even.
        if (diff % 2 == 0 && (k - n) % 2 == 0) {
            // In this case, we can reach (n, m) in exactly n moves using m diagonal moves
            // and n-m straight moves.
            // The remaining k - n moves must be used to "waste" moves without changing
            // the final position. This can be done by moving back and forth.
            // Each pair of such moves (e.g., (1,0) then (-1,0)) takes 2 moves and
            // results in 0 net change in position.
            // These "wasted" moves can be diagonal or straight. To maximize diagonal moves,
            // we prefer diagonal for these too.
            // So, we use n moves to reach (n, m).
            // The remaining k - n moves are even. We can use (k - n) / 2 pairs of moves.
            // Each pair can be two diagonal moves (e.g., (1,1) then (-1,-1)) or two straight moves.
            // Since we want to maximize diagonal moves, we assume these are diagonal.
            // So, total diagonal moves = m (to cover min(n,m) distance) + (k - n) (for wasting moves).
            ans = m + (k - n);
        }
        // If n and m have different parities, and k has the same parity as n (and m).
        // This means (n % 2 != m % 2) and (k % 2 == n % 2).
        // Or equivalently, (n - m) is odd, and (k - n) is even.
        // This scenario is impossible.
        // Consider the parity of (x+y).
        // A diagonal move changes (x+y) by 0, 2, or -2 (parity of x+y remains same).
        // A straight move changes (x+y) by 1 or -1 (parity of x+y flips).
        // To reach (n,m) from (0,0) in k moves:
        // (n+m) % 2 must be equal to (k % 2) if all moves were straight.
        // (n+m) % 2 must be equal to (k % 2) if all moves were diagonal.
        // This is not a simple parity argument.
        // Let's use the parity of coordinates.
        // (x_final - x_initial) % 2 = (sum of dx_i) % 2
        // (y_final - y_initial) % 2 = (sum of dy_i) % 2
        // n % 2 = (number of moves changing x parity) % 2
        // m % 2 = (number of moves changing y parity) % 2
        // Let D be diagonal moves, S_x be straight horizontal, S_y be straight vertical.
        // D + S_x + S_y = k
        // n % 2 = (D + S_x) % 2
        // m % 2 = (D + S_y) % 2
        // Summing these: (n + m) % 2 = (2D + S_x + S_y) % 2 = (S_x + S_y) % 2
        // Also, k = D + S_x + S_y.
        // So, (n + m) % 2 = (k - D) % 2.
        // This means (n + m) and (k - D) must have the same parity.
        // (n + m) % 2 == (k - D) % 2
        // (n + m) % 2 == (k % 2 - D % 2 + 2) % 2
        // (n + m + D) % 2 == k % 2

        // Let's re-evaluate the parity condition.
        // The parity of (x+y) changes with straight moves, but not with diagonal moves.
        // Initial (0,0) has (x+y) % 2 = 0.
        // After k moves, we are at (n,m).
        // Let S be the number of straight moves.
        // The parity of (n+m) must be equal to S % 2.
        // We know k = D + S. So S = k - D.
        // Thus, (n+m) % 2 must be equal to (k - D) % 2.
        // This means (n+m) and (k-D) must have the same parity.

        // If (n - m) is odd:
        // This means n and m have different parities.
        // (n + m) is odd.
        // If k has the same parity as n (and thus different from m),
        // then (k - n) is even.
        // This implies that k and n have the same parity.
        // If n and m have different parities, then (n+m) is odd.
        // If k and n have the same parity, then k and m have different parities.
        // So (k-m) is odd.
        //
        // Consider the case where (n-m) is odd.
        // This means n and m have different parities.
        // If k has the same parity as n, then k and m have different parities.
        // Example: (2,1), k=3. n=2, m=1. diff=1 (odd). k=3.
        // (n+m) = 3 (odd).
        // If we make k moves, and (k - (n+m)) is odd, then it's impossible.
        //
        // The condition for impossibility is when (k - n) is odd.
        // This means k and n have different parities.
        // If n and m have the same parity, and k has different parity from n (and m).
        // (n - m) is even. (k - n) is odd.
        // Example: (2,2), k=4. n=2, m=2. diff=0 (even). k=4. (k-n)=2 (even). ans = 2 + (4-2) = 4.
        // Example: (2,2), k=3. n=2, m=2. diff=0 (even). k=3. (k-n)=1 (odd).
        // In this case, we need to make one extra straight move to adjust parity.
        // We use m diagonal moves. Remaining distance n-m.
        // We use n-m straight moves. Total n moves.
        // Remaining k-n moves. If (k-n) is odd, we can't just do pairs of moves.
        // We need to "waste" an odd number of moves.
        // This means we must use one more straight move than usual.
        // So, instead of m diagonal moves, we use m-1 diagonal moves and 1 straight move.
        // This changes the parity of the remaining distance.
        //
        // Let's simplify:
        // We need to reach (n, m) in k moves.
        // The maximum number of diagonal moves is achieved by making as many diagonal moves as possible.
        // This is min(n, m) = m.
        // After m diagonal moves, we are at (n-m, 0) (or (0, n-m) if m was larger).
        // We have used m moves. Remaining moves: k - m.
        // Remaining distance: n - m.
        // We need to cover n - m distance using k - m moves.
        // The minimum moves to cover n - m distance is n - m.
        // So, we use n - m straight moves. Total moves so far: m + (n - m) = n.
        // Remaining moves: k - n.
        // Remaining distance: 0.
        // We need to make k - n moves without changing the position.
        // These k - n moves must be an even number, because each pair of moves (e.g., (1,0) then (-1,0))
        // results in no net change and uses 2 moves.
        // If (k - n) is odd, it's impossible to end at (n,m) if we only use moves that preserve parity.
        //
        // What if (k - n) is odd?
        // This means k and n have different parities.
        // If n and m have the same parity, then (n-m) is even.
        // If k and n have different parities, then k and m also have different parities.
        // In this case, we cannot reach (n,m) in k moves if we only use diagonal moves and straight moves
        // that preserve the parity of (x+y) or (x-y) in a specific way.
        //
        // Let's consider the parity of n and m.
        // If n and m have different parities (i.e., (n-m) is odd):
        // We need to make an odd number of straight moves to adjust the parity difference.
        // We can make m-1 diagonal moves. This takes m-1 moves.
        // We are at (n-(m-1), 1) or similar.
        // Then we make one straight move (e.g., (0,1) or (1,0)).
        // This takes 1 move. Total m moves.
        // Now we are at (n-m, 0) or (n-m+1, 1) etc.
        // This is getting complicated.

        // Simpler parity check:
        // The parity of (x+y) changes if and only if a straight move is made.
        // The parity of (x+y) does not change if a diagonal move is made.
        // Start at (0,0), (x+y) is even.
        // To reach (n,m), (n+m) must have the same parity as the number of straight moves.
        // Let S be the number of straight moves.
        // (n+m) % 2 == S % 2.
        // We know D + S = k. So S = k - D.
        // (n+m) % 2 == (k - D) % 2.
        // This means (n+m) and (k-D) must have the same parity.
        // Or, (n+m+D) and k must have the same parity.

        // Let's consider the parity of n and m directly.
        // If n and m have the same parity (n % 2 == m % 2):
        //   This means (n-m) is even.
        //   If k has the same parity as n (and m): (k % 2 == n % 2)
        //     Then (k-n) is even.
        //     We can reach (n,m) in n moves (m diagonal, n-m straight).
        //     Remaining k-n moves are even. We can use (k-n)/2 pairs of moves.
        //     Each pair can be two diagonal moves (e.g., (1,1) then (-1,-1)).
        //     So, total diagonal moves = m + (k-n).
        //   If k has a different parity from n (and m): (k % 2 != n % 2)
        //     Then (k-n) is odd.
        //     We cannot reach (n,m) in k moves if we only use moves that preserve parity.
        //     We need to "waste" an odd number of moves.
        //     This means we must use one more straight move than usual.
        //     Instead of m diagonal moves, we use m-1 diagonal moves and 1 straight move.
        //     This changes the parity of the remaining distance.
        //     This is equivalent to saying we use n-1 moves to reach (n-1, m) or (n, m-1)
        //     and then one more move to reach (n,m).
        //     If (k-n) is odd, we must use one less diagonal move and one more straight move.
        //     This means we use m-1 diagonal moves, and (n-m+1) straight moves to reach (n,m).
        //     Total moves = (m-1) + (n-m+1) = n.
        //     Remaining k-n moves. Since (k-n) is odd, we can't just add pairs of moves.
        //     This implies that we must have used one less diagonal move in the initial phase.
        //     So, we use m-1 diagonal moves.
        //     Then we have n-(m-1) = n-m+1 distance to cover in x, and 0 in y.
        //     We use n-m+1 straight moves.
        //     Total moves = (m-1) + (n-m+1) = n.
        //     Remaining k-n moves. Since (k-n) is odd, we can't just add pairs of moves.
        //     This means we must have used one less diagonal move in the initial phase.
