long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    // Total number of substrings in a string of length n is n*(n+1)/2
    long long total_substrings = n * (n + 1) / 2;

    // Number of zeros is n - m
    long long num_zeros = n - m;

    // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
    // This is achieved by distributing the '0's as evenly as possible among the '1's.
    // There are m '1's. These '1's divide the string into m+1 potential blocks of '0's.
    // For example, _1_1_1_ (3 '1's, 4 blocks of '0's)
    // We want to make the lengths of these blocks of '0's as equal as possible.

    // Number of blocks of zeros that will have length floor(num_zeros / (m+1))
    // and number of blocks that will have length ceil(num_zeros / (m+1)).
    // Let k be the number of '1's, so k = m.
    // The number of blocks of zeros is m+1.
    // Let q = num_zeros / (m+1) (integer division)
    // Let r = num_zeros % (m+1)
    // This means r blocks will have length q+1, and (m+1-r) blocks will have length q.

    long long num_blocks = m + 1;
    long long q = num_zeros / num_blocks; // Base length for zero blocks
    long long r = num_zeros % num_blocks; // Number of blocks with length q+1

    long long sum_zero_substrings = 0;

    // r blocks of length q+1
    if (q + 1 > 0) { // Only add if block length is positive
        sum_zero_substrings += r * (q + 1) * (q + 2) / 2;
    }

    // (num_blocks - r) blocks of length q
    if (q > 0) { // Only add if block length is positive
        sum_zero_substrings += (num_blocks - r) * q * (q + 1) / 2;
    }

    return total_substrings - sum_zero_substrings;
}

