#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total counts
    int total_s = 0;
    int total_b = 0;
    for (int x : a) {
        if (x == 1) {
            total_s++;
        } else {
            total_b++;
        }
    }

    // Precompute prefix sums for the left half (jars 1 to n)
    // diff_left[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // This is for jars 1 to k.
    // We are interested in jars *eaten* from the left.
    // If k jars are eaten from the left, jars a[0]...a[k-1] are gone.
    // The remaining jars are a[k]...a[2n-1].
    // The balance of jars *eaten* from the left:
    // Let L_s[k] be count of 1s in a[0...k-1]
    // Let L_b[k] be count of 2s in a[0...k-1]
    // L_diff[k] = L_s[k] - L_b[k]
    std::vector<int> L_diff(n + 1, 0);
    int current_s = 0;
    int current_b = 0;
    for (int k = 0; k < n; ++k) {
        if (a[k] == 1) {
            current_s++;
        } else {
            current_b++;
        }
        L_diff[k + 1] = current_s - current_b;
    }

    // Precompute suffix sums for the right half (jars n+1 to 2n)
    // diff_right[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // This is for jars 2n-k+1 to 2n.
    // If k jars are eaten from the right, jars a[2n-k]...a[2n-1] are gone.
    // The remaining jars are a[0]...a[2n-k-1].
    // The balance of jars *eaten* from the right:
    // Let R_s[k] be count of 1s in a[2n-k...2n-1]
    // Let R_b[k] be count of 2s in a[2n-k...2n-1]
    // R_diff[k] = R_s[k] - R_b[k]
    std::vector<int> R_diff(n + 1, 0);
    current_s = 0;
    current_b = 0;
    for (int k = 0; k < n; ++k) {
        if (a[2 * n - 1 - k] == 1) {
            current_s++;
        } else {
            current_b++;
        }
        R_diff[k + 1] = current_s - current_b;
    }

    // Map to store the minimum number of jars eaten from the right (j)
    // for a given R_diff[j] value.
    // R_diff_val -> min_j
    std::map<int, int> right_diff_to_j;
    for (int j = 0; j <= n; ++j) {
        int diff_val = R_diff[j];
        if (right_diff_to_j.find(diff_val) == right_diff_to_j.end()) {
            right_diff_to_j[diff_val] = j;
        } else {
            right_diff_to_j[diff_val] = std::min(right_diff_to_j[diff_val], j);
        }
    }

    int min_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible number of jars eaten from the left (i)
    for (int i = 0; i <= n; ++i) {
        // The target difference for the remaining jars is 0.
        // Initial total difference: total_s - total_b
        // Difference from left eaten jars: L_diff[i]
        // Difference from right eaten jars: R_diff[j]
        // The difference of remaining jars is:
        // (total_s - L_s[i] - R_s[j]) - (total_b - L_b[i] - R_b[j])
        // = (total_s - total_b) - (L_s[i] - L_b[i]) - (R_s[j] - R_b[j])
        // = (total_s - total_b) - L_diff[i] - R_diff[j]
        // We want this to be 0.
        // So, we need R_diff[j] = (total_s - total_b) - L_diff[i]
        int target_R_diff = (total_s - total_b) - L_diff[i];

        if (right_diff_to_j.count(target_R_diff)) {
            int j = right_diff_to_j[target_R_diff];
            min_eaten = std::min(min_eaten, i + j);
        }
    }

    std::cout << min_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

