    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (no internal elements to smooth)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> current_seq = a;
    std::vector<int> next_seq(n);
    int steps = 0;

    // Find the first 0-1 or 1-0 transition
    int first_transition_idx = -1;
    for (int i = 0; i < n - 1; ++i) {
        if (current_seq[i] != current_seq[i+1]) {
            first_transition_idx = i;
            break;
        }
    }

    // If no transitions, sequence is all 0s or all 1s, already stable
    if (first_transition_idx == -1) {
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Find the last 0-1 or 1-0 transition
    int last_transition_idx = -1;
    for (int i = n - 2; i >= 0; --i) {
        if (current_seq[i] != current_seq[i+1]) {
            last_transition_idx = i;
            break;
        }
    }

    // Calculate max_steps based on the transitions
    // The number of steps is limited by the distance from the ends to the nearest transition
    // or half the distance between the first and last transition.
    // Specifically, it's ceil( (last_transition_idx - first_transition_idx) / 2.0 )
    // plus 1 if the first/last elements are different from their neighbors.
    // A simpler bound is (n-1)/2, but we can be more precise.
    // The maximum number of steps for a sequence of length N is roughly N/2.
    // For N=500,000, this is 250,000.
    // We can use a more precise bound: max_steps = max(first_transition_idx, n - 1 - (last_transition_idx + 1))
    // This is the distance from an end to the nearest "stable" block.
    // Or, more simply, the maximum number of steps is bounded by n/2.
    // The actual number of steps is related to the "width" of the changing region.
    // The number of steps is at most (last_transition_idx - first_transition_idx + 1) / 2.
    // Let's use a generous bound like n to be safe, or even n/2.
    // The maximum number of steps is actually (last_transition_idx - first_transition_idx + 1) / 2.
    // Example: 01010 (n=5). first_trans=0, last_trans=3. (3-0+1)/2 = 2. Correct.
    // Example: 0011 (n=4). first_trans=1, last_trans=1. (1-1+1)/2 = 0. Correct.
    // Example: 000111 (n=6). first_trans=2, last_trans=2. (2-2+1)/2 = 0. Correct.
    // Example: 01110 (n=5). first_trans=0, last_trans=3. (3-0+1)/2 = 2.
    // 01110 -> 01110 (stable) -> 0 steps.
    // My formula is for the "width" of the unstable region.
    // The actual number of steps is the maximum of:
    // 1. The number of steps for the first block to stabilize: first_transition_idx + 1 if a[0] != a[first_transition_idx+1]
    // 2. The number of steps for the last block to stabilize: n - (last_transition_idx + 1) if a[n-1] != a[last_transition_idx]
    // 3. The number of steps for the middle part to stabilize.
    // The maximum number of steps is actually `(last_transition_idx - first_transition_idx + 1) / 2`
    // if the sequence is of the form 0...01...10...0 or 1...10...01...1.
    // For 01010, first_trans=0, last_trans=3. (3-0+1)/2 = 2.
    // For 01110, first_trans=0, last_trans=3. (3-0+1)/2 = 2. But it's 0 steps.
    // The formula is for the maximum possible steps for a sequence of alternating values.
    // The actual number of steps is bounded by `n/2`. Let's use `n` as a safe upper bound for the loop.
    // The problem statement guarantees that if it stabilizes, it does so in a finite number of steps.
    // The maximum number of steps is actually `(n-1)/2`.
    // For N=500,000, this is 249,999.
    // A loop for `n` iterations is fine.

    for (int k = 0; k < n; ++k) { // Max steps is bounded by n/2, so n iterations is safe.
        if (!apply_median_smoothing(current_seq, next_seq)) {
            break; // Sequence became stable
        }
        steps++;
    }

    // Check for non-stability (oscillating sequences)
    // An oscillating sequence would be something like 010101...
    // However, for 0s and 1s, the median filter tends to "flatten" sequences.
    // It's known that for 0/1 sequences, the median filter always converges to a stable state.
    // The only stable sequences are blocks of 0s and 1s, e.g., 000111, 00000, 11111.
    // A sequence like 010101... will eventually become 000000... or 111111...
    // The problem statement implies that it *might* not become stable, but for 0/1 sequences, it always does.
    // So, we don't need to output -1. The loop will always break.

    std::cout << steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, 0); // b_j = -min_delta_j
    std::vector<long long> initial_a(n, 0); // This will store the reconstructed initial array

    // Initialize b_j based on type 2 operations
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::max(b[j], -ops[i].val);
            }
        }
    }

    // Calculate initial_a_j = -b_j
    for (int j = 0; j < n; ++j) {
        initial_a[j] = -b[j];
    }

    // Verify the solution
    std::vector<long long> current_a = initial_a;
    std::vector<long long> delta_prefix_sum(n + 1, 0); // Stores sum of d's for current_a

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Apply delta to current_a for verification
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
            // Update delta_prefix_sum for future type 2 operations
            delta_prefix_sum[ops[i].l] += ops[i].val;
            delta_prefix_sum[ops[i].r + 1] -= ops[i].val;
        } else { // type == 2
            long long max_val = std::numeric_limits<long long>::min();
            long long current_delta_sum = 0;
            for (int j = 0; j < n; ++j) {
                current_delta_sum += delta_prefix_sum[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    max_val = std::max(max_val, initial_a[j] + current_delta_sum);
                }
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * max(a_i) * 2, which is 2*10^5 * 10^9 * 2 = 4*10^14.
// x can be up to n, so int is fine for x.

// Using a global or static array for 'a' to avoid passing it around and for potential memoization.
// Since 'a[1]' changes for each query, we can't fully memoize 'a' itself.
// However, the values a[2]...a[n] are constant.
// We can precompute results for states (x, parity) where x > 1.
// The parity matters because the operations are (x+a[x], y+a[x]) then (x-a[x], y+a[x]).
// If we land on x with a certain parity, the next step depends on that parity.
// Let's define state as (current_x, current_y, is_step2_next).
// This is too complex. The problem states "step 2, then step 3".
// So, if we are at (x, y), the next state is always (x', y') after step 2, then (x'', y'') after step 3.
// The sequence is fixed: (x,y) -> (x+a[x], y+a[x]) -> (x+a[x]-a[x+a[x]], y+a[x]+a[x+a[x]]).
// This means the state is just (x, y).

// Let's define dp[x][parity] as the pair (final_x_change, final_y_change) if starting from x
// and the next operation is 'parity' (0 for step 2, 1 for step 3).
// This is not quite right. The problem is about the total y value.
// Let dp[x] store the total y accumulated and the final x value if starting from x.
// dp[x] = {final_x, total_y_added_from_this_x_onwards}
// This is a standard dynamic programming approach on a graph where nodes are x values.
// The transitions are:
// From x, first step 2: x_new = x + a[x], y_add1 = a[x]
// Then step 3: x_final = x_new - a[x_new], y_add2 = a[x_new]
// Total y added in one cycle: a[x] + a[x_new]
// Final x after one cycle: x_new - a[x_new]

// We need to compute this for each starting i (which becomes a[1]).
// The values a[2]...a[n] are fixed.
// So, we can compute dp values for x from 2 to n.
// dp[x] = {final_x, total_y}
// If x + a[x] > n or x + a[x] <= 0, then the program terminates after step 2.
//   Result: {x + a[x], a[x]}
// Else, let x_next = x + a[x].
//   If x_next - a[x_next] > n or x_next - a[x_next] <= 0, then terminates after step 3.
//     Result: {x_next - a[x_next], a[x] + a[x_next]}
//   Else, let x_final = x_next - a[x_next].
//     Result: {dp[x_final].final_x, a[x] + a[x_next] + dp[x_final].total_y}

// This is a recursive definition. We can compute it iteratively from n down to 2.
// dp[x] will store a pair: {final_x_after_termination, total_y_accumulated_from_x_onwards}.
// If it never terminates, we can use a special value like -1 for final_x.

struct Result {
    long long final_x; // The x value when it terminates. If -1, it means infinite loop.
    long long total_y; // The total y accumulated from this point until termination.
};

std::vector<long long> a_values;
std::vector<Result> dp;
std::vector<bool> visited; // To detect cycles for x >= 2
std::vector<bool> in_recursion_stack; // To detect cycles during DP calculation

int N;

Result calculate_dp(int current_x) {
    if (current_x <= 0 || current_x > N) {
        return {current_x, 0}; // Base case: already terminated
    }

    if (visited[current_x]) {
        if (in_recursion_stack[current_x]) {
            // Cycle detected, this path leads to infinite loop
            return {-1, -1};
        }
        // Already computed
        return dp[current_x];
    }

    visited[current_x] = true;
    in_recursion_stack[current_x] = true;

    long long val_ax = a_values[current_x];

    // Step 2: x = x + a[x], y = y + a[x]
    long long x_after_step2 = current_x + val_ax;
    long long y_added_step2 = val_ax;

    if (x_after_step2 <= 0 || x_after_step2 > N) {
        in_recursion_stack[current_x] = false;
        return dp[current_x] = {x_after_step2, y_added_step2};
    }

    long long val_ax_after_step2 = a_values[x_after_step2];

    // Step 3: y = y + a[x_after_step2], x = x_after_step2 - a[x_after_step2]
    long long x_after_step3 = x_after_step2 - val_ax_after_step2;
    long long y_added_step3 = val_ax_after_step2;

    // Recursively calculate for the next state
    Result next_result = calculate_dp(x_after_step3);

    in_recursion_stack[current_x] = false;

    if (next_result.final_x == -1) {
        // Infinite loop detected further down the path
        return dp[current_x] = {-1, -1};
    } else {
        return dp[current_x] = {next_result.final_x, y_added_step2 + y_added_step3 + next_result.total_y};
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_values.resize(N + 1);
    dp.resize(N + 1);
    visited.resize(N + 1, false);
    in_recursion_stack.resize(N + 1, false);

    for (int i = 2; i <= N; ++i) {
        std::cin >> a_values[i];
    }

    // Precompute DP for x from 2 to N
    // This is done by calling calculate_dp for each x from 2 to N.
    // The recursive calls will fill the dp table.
    for (int i = 2; i <= N; ++i) {
        if (!visited[i]) {
            calculate_dp(i);
        }
    }

    // Now, for each query i (1 to N-1), set a_values[1] = i and run the simulation.
    for (int i = 1; i < N; ++i) {
        a_values[1] = i;

        long long current_x = 1;
        long long current_y = 0;

        long long val_ax = a_values[current_x];

        // Step 2: x = x + a[x], y = y + a[x]
        long long x_after_step2 = current_x + val_ax;
        long long y_added_step2 = val_ax;

        if (x_after_step2 <= 0 || x_after_step2 > N) {
            std::cout << y_added_step2 << "\n";
            continue;
        }

        long long val_ax_after_step2 = a_values[x_after_step2];

        // Step 3: y = y + a[x_after_step2], x = x_after_step2 - a[x_after_step2]
        long long x_after_step3 = x_after_step2 - val_ax_after_step2;
        long long y_added_step3 = val_ax_after_step2;

        // Now, we are at x_after_step3 with y_added_step2 + y_added_step3 accumulated.
        // We can use the precomputed DP table for x_after_step3.
        Result res = calculate_dp(x_after_step3); // This will use the precomputed values for x >= 2

        if (res.final_x == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << y_added_step2 + y_added_step3 + res.total_y << "\n";
        }
    }

    return 0;
}

