        //         if (!active[j]) continue;
        //         // Path i -> k -> j
        //         if (dist[i][k] + dist[k][j] < dist[i][j]) {
        //             dist[i][j] = dist[i][k] + dist[k][j];
        //         }
        //     }
        // }
        // This is not enough. It only considers paths where `k` is the *only* intermediate.
        //
        // The correct way is to apply the Floyd-Warshall update for `k` as the intermediate,
        // and then for all *other* active vertices as intermediates, considering paths involving `k`.
        //
        // The most straightforward way to implement the reverse Floyd-Warshall is:
        // For each `k` (from `x[n-1]` down to `x[0]`):
        //   Mark `k` as active.
        //   For each `i` (0 to n-1):
        //     For each `j` (0 to n-1):
        //       `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        //   Calculate sum over *only* active vertices.
        //
        // This is what the code currently does. Let's trace it.
        // `k` is `x[k_idx]`.
        // `active[k] = true`.
        //
        // The first triple loop:
        // for (int i = 0; i < n; ++i) {
        //     if (!active[i]) continue; // This is wrong. `i` can be `k` or any other active vertex.
        //     for (int j = 0; j < n; ++j) {
        //         if (!active[j]) continue; // This is wrong. `j` can be `k` or any other active vertex.
        //         // This loop structure means `i` and `j` are *already* active.
        //         // It updates `dist[i][j]` using `k` as an intermediate.
        //         // This is correct for paths between *already active* vertices.
        //         // But what about paths like `i -> k` or `k -> j`?
        //         // Or `k -> i -> j`?
        //     }
        // }
        //
        // The standard Floyd-Warshall update for a new intermediate `k_node`:
        // for (int i = 0; i < n; ++i) {
        //     for (int j = 0; j < n; ++j) {
        //         dist[i][j] = std::min(dist[i][j], dist[i][k_node] + dist[k_node][j]);
        //     }
        // }
        // This updates all pairs `(i, j)` using `k_node` as an intermediate.
        // This is the correct step for adding `k_node` to the set of allowed intermediates.
        //
        // After this, `dist` matrix contains shortest paths between *all* pairs `(i, j)`
        // using only intermediate vertices from the set `{x[n-1], x[n-2], ..., x[k_idx]}`.
        //
        // So, the first triple loop should be:
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
        // This updates all paths using `k` as an intermediate.
        // This is the standard Floyd-Warshall step for `k`.
        //
        // Now, calculate the sum for *only* the currently active vertices.
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were calculated)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child goes to doctor

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children who left
            children[j].p -= accumulated_d_cry;

            // Apply v_cry from the child currently in the doctor's office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_d_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Option 1: All elements in one subsequence (e.g., subsequence 1)
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Option 2: a_1 and a_n are in different subsequences.
    // This implies that f(a_1, a_n) = a_1 + a_n + h.
    // To minimize max_f - min_f, we want to make min_f as large as possible
    // and max_f as small as possible.
    // The smallest possible value for f is a_1 + a_2.
    // The largest possible value for f is a_{n-1} + a_n + h.
    // However, if a_1 and a_n are in different subsequences, then a_1 + a_n + h is one of the values.
    // If a_1 and a_2 are in the same subsequence, then a_1 + a_2 is one of the values.
    // If a_{n-1} and a_n are in the same subsequence, then a_{n-1} + a_n is one of the values.
    //
    // Consider the partition where a_1 is in subseq 1, and all other elements are in subseq 2.
    // min_f:
    //   - If n=2: a_1 and a_2 are different. min_f = a_1 + a_2 + h. max_f = a_1 + a_2 + h. Goodness = 0.
    //   - If n > 2:
    //     - a_1 is in subseq 1.
    //     - a_2, ..., a_n are in subseq 2.
    //     - Pairs within subseq 1: None (only a_1).
    //     - Pairs within subseq 2: (a_2, a_3), ..., (a_{n-1}, a_n). Smallest is a_2 + a_3.
    //     - Pairs across subsequences: (a_1, a_2), ..., (a_1, a_n). Smallest is a_1 + a_2 + h.
    //     So, min_f = std::min(a_2 + a_3, a_1 + a_2 + h) if n > 2.
    //     If n=2, min_f = a_1 + a_2 + h.
    // max_f:
    //   - If n=2: a_1 + a_2 + h.
    //   - If n > 2:
    //     - Pairs within subseq 2: (a_2, a_3), ..., (a_{n-1}, a_n). Largest is a_{n-1} + a_n.
    //     - Pairs across subsequences: (a_1, a_2), ..., (a_1, a_n). Largest is a_1 + a_n + h.
    //     So, max_f = std::max(a_{n-1} + a_n, a_1 + a_n + h) if n > 2.
    //     If n=2, max_f = a_1 + a_2 + h.
    //
    // Let's simplify.
    // The critical values are:
    // A = a_1 + a_2
    // B = a_{n-1} + a_n
    // C = a_1 + a_n + h
    //
    // If we put a_1 in subseq 1 and all others in subseq 2:
    // min_f = min(a_1 + a_2 + h, a_2 + a_3) (if n > 2, else a_1 + a_2 + h)
    // max_f = max(a_1 + a_n + h, a_{n-1} + a_n) (if n > 2, else a_1 + a_2 + h)
    //
    // The values of f are:
    //   - a_i + a_j for i, j >= 2 (same subsequence)
    //   - a_1 + a_k + h for k >= 2 (different subsequences)
    //
    // So, min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value); (if n > 2)
    // max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value); (if n > 2)
    //
    // If n=2: min_f = a_1 + a_2 + h, max_f = a_1 + a_2 + h. Goodness = 0.
    // This is covered by the general case if we define elements[2] as elements[1] for min_f calculation.
    //
    // Let's consider the specific partition: a_1 in subseq 1, a_2, ..., a_n in subseq 2.
    // The minimum possible sum is elements[0].value + elements[1].value.
    // The maximum possible sum is elements[n-1].value + elements[n-2].value.
    //
    // The actual values of f are:
    //   - elements[i].value + elements[j].value for 1 <= i < j <= n-1 (indices in sorted array)
    //   - elements[0].value + elements[k].value + h for 1 <= k <= n-1
    //
    // So, min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    // max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    //
    // This is the partition where elements[0] is in group 1, and elements[1]...elements[n-1] are in group 2.
    //
    // The minimum value of f will be:
    //   - elements[0].value + elements[1].value + h (from (a_1, a_2) across groups)
    //   - elements[1].value + elements[2].value (from (a_2, a_3) within group 2, if n >= 3)
    // So, min_f_val = elements[0].value + elements[1].value + h;
    // if (n >= 3) {
    //     min_f_val = std::min(min_f_val, elements[1].value + elements[2].value);
    // }
    //
    // The maximum value of f will be:
    //   - elements[0].value + elements[n-1].value + h (from (a_1, a_n) across groups)
    //   - elements[n-2].value + elements[n-1].value (from (a_{n-1}, a_n) within group 2, if n >= 3)
    // So, max_f_val = elements[0].value + elements[n-1].value + h;
    // if (n >= 3) {
    //     max_f_val = std::max(max_f_val, elements[n-2].value + elements[n-1].value);
    // }
    //
    // Goodness for this partition: max_f_val - min_f_val.
    //
    // Let's consider the specific case where a_1 is in group 1, and a_2, ..., a_n are in group 2.
    // The minimum value of f is `min(a_1 + a_2 + h, a_2 + a_3)` (if n >= 3, else `a_1 + a_2 + h`).
    // The maximum value of f is `max(a_1 + a_n + h, a_{n-1} + a_n)` (if n >= 3, else `a_1 + a_2 + h`).
    //
    // Let's denote `a_i` as `elements[i-1].value` for simplicity.
    //
    // min_f_val_2 = a_1 + a_2 + h;
    // if (n >= 3) {
    //     min_f_val_2 = std::min(min_f_val_2, a_2 + a_3);
    // }
    //
    // max_f_val_2 = a_1 + a_n + h;
    // if (n >= 3) {
    //     max_f_val_2 = std::max(max_f_val_2, a_{n-1} + a_n);
    // }
    //
    // Goodness2 = max_f_val_2 - min_f_val_2;

    long long min_f_val_2;
    long long max_f_val_2;

    if (n == 2) {
        min_f_val_2 = elements[0].value + elements[1].value + h;
        max_f_val_2 = elements[0].value + elements[1].value + h;
    } else {
        min_f_val_2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
        max_f_val_2 = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
    }
    long long goodness2 = max_f_val_2 - min_f_val_2;

    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    if (n < 3) { // Minimum length for any triplet is 3 (x, x+1, x+2)
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that [l, r] contains a valid triplet.
                                                // Initialize with n+1, meaning no such r found yet.

    // Iterate through all possible starting positions x (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through all possible common differences k
        // The maximum possible k is such that x + 2k < n.
        // So 2k < n - x, or k < (n - x) / 2.
        // Since k must be at least 1, we start k from 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a valid triplet (x, x+k, x+2k)
                // The 0-indexed range is [x, x+2k].
                // The 1-indexed range is [x+1, x+2k+1].
                // So, for any l_1-based from 1 to x+1, this triplet is contained if r_1-based >= x+2k+1.
                // We want to update min_r_for_l[l_1] with x+2k+1.
                // Since we are iterating x from left to right, and k from small to large,
                // x+2k+1 will be increasing.
                // For a fixed x, as k increases, x+2k+1 increases.
                // For a fixed k, as x increases, x+2k+1 increases.
                // This means the first triplet found for a given l will have the smallest r.

                // The triplet starts at 0-indexed x.
                // The triplet ends at 0-indexed x + 2k.
                // This triplet covers all 1-indexed ranges [l, r] where 1 <= l <= x+1 and x+2k+1 <= r <= n.

                // We need to update min_r_for_l[l_1] for l_1 from 1 to x+1.
                // The minimum r_1 for these l_1 values is x+2k+1.
                // Since we want the *minimum* r for each l, we use std::min.
                // However, because we iterate x and k in increasing order,
                // x+2k+1 is always increasing.
                // So, for a given l_1, the first time we find a triplet that starts at or before l_1,
                // its end point x+2k+1 will be the smallest possible r_1 for that l_1.
                // We can optimize this by only updating min_r_for_l[x+1] (the 1-indexed start of the triplet).
                // The value min_r_for_l[l] for l < x+1 will be propagated later.

                // The current triplet is [x, x+2k] (0-indexed).
                // Its 1-indexed start is x+1, its 1-indexed end is x+2k+1.
                // This triplet makes any range [l, r] valid if l <= x+1 and r >= x+2k+1.
                // We are interested in the smallest r for each l.
                // So, for l = x+1, the smallest r is x+2k+1.
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 2 * k + 1);
            }
        }
    }

    // Propagate the minimum r values.
    // If min_r_for_l[l] is R, it means for the range [l, R], there's a valid triplet.
    // Then for range [l-1, R], there's also a valid triplet (the same one).
    // So min_r_for_l[l-1] must be at most min_r_for_l[l].
    // We iterate from n down to 2 (1-indexed l).
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long total_valid_pairs = 0;
    // Now, for each l (1-indexed), min_r_for_l[l] stores the smallest r (1-indexed)
    // such that the range [l, r] contains a valid triplet.
    // If min_r_for_l[l] is n+1, it means no such r exists for this l.
    // Otherwise, for this l, any r from min_r_for_l[l] to n will form a valid pair [l, r].
    // The number of such r values is n - min_r_for_l[l] + 1.
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If a valid r exists for this l
            total_valid_pairs += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_valid_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=1: One cut, two pieces.
    // Try all possible cut positions.
    for (int i = 1; i < n; ++i) {
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string new_s = s_suffix + s_prefix;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts, three pieces.
    // The problem statement implies that if k=1 doesn't work,
    // we should check k=2.
    // For k=2, we can always achieve a new palindrome if not all characters are the same.
    // Consider cutting s into s[0], s[1...N-2], s[N-1].
    // Since s is a palindrome, s[0] == s[N-1].
    // If we swap s[0] and s[N-1], we get s[N-1] + s[1...N-2] + s[0].
    // This is s[0] + s[1...N-2] + s[N-1], which is s.
    // This specific rearrangement doesn't work.

    // However, the problem states "cut the paper minimum number of times k,
    // so they got k+1 pieces of paper with substrings of the initial string,
    // and then unite those pieces together to get a new string."
    // This means we can take any substring as a piece.
    // For k=2, we can cut s into s[0], s[1...N-1], and then rearrange.
    // Or s[0...N-2], s[N-1].
    // This is effectively the same as k=1.

    // The example "nolon" -> 2 cuts, "on|l|no" from "no|l|on".
    // This means "no", "l", "on" are the pieces.
    // Original: s = "nolon"
    // Pieces: P1="no", P2="l", P3="on"
    // Rearrangement: P3 + P2 + P1 = "on" + "l" + "no" = "onlno"
    // "onlno" is a palindrome and "onlno" != "nolon".
    // This is a valid solution for k=2.

    // The only case where k=2 might be needed is if all characters in s are the same,
    // or if s is of the form "ababa" where a single cut doesn't work.
    // If all characters in s are the same (e.g., "qqqq"), then any rearrangement of its
    // substrings will result in the same string "qqqq".
    // In this case, it's impossible to form a new string.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Consider s = "abacaba" (N=7).
        // s[0] = 'a', s[1] = 'b', s[2] = 'a', s[3] = 'c', s[4] = 'a', s[5] = 'b', s[6] = 'a'
        // If we cut s into s[0], s[1...N-2], s[N-1].
        // Pieces: P1 = s[0], P2 = s.substr(1, N-2), P3 = s[N-1].
        // Since s is a palindrome, s[0] == s[N-1].
        // P1 = 'a', P2 = "bacab", P3 = 'a'.
        // Rearrangement P3 + P2 + P1 = 'a' + "bacab" + 'a' = "abacaba" (which is s).
        // This specific rearrangement doesn't work.

        // However, if not all characters are the same, and s is a palindrome,
        // then s must have at least two distinct characters.
        // For example, "nolon". 'n' and 'o' are different.
        // If N is odd, the middle character is unique.
        // If N is even, there's no unique middle character.
        // If s is a palindrome and not all characters are the same,
        // then s.substr(0, N-1) is not a palindrome (unless N=1).
        // Example: "nolon". s.substr(0, 4) = "nolo". Not a palindrome.
        // Example: "otto". s.substr(0, 3) = "ott". Not a palindrome.
        // Example: "kinnikkinnik". s.substr(0, 11) = "kinnikkinnik". Not a palindrome.

        // The logic for k=2 is that if s is a palindrome and not all characters are the same,
        // then s.substr(0, N-1) is not a palindrome.
        // If s.substr(0, N-1) is not a palindrome, then we can cut s into
        // s.substr(0, N-1) and s[N-1].
        // Let P1 = s.substr(0, N-1) and P2 = s[N-1].
        // We can rearrange them as P2 + P1.
        // This is s[N-1] + s.substr(0, N-1).
        // This is a single cut. We already checked this.

        // The problem is asking for the minimum k.
        // If k=1 doesn't work, and not all characters are the same,
        // then k=2 is the answer.
        // Why? Consider the string s.
        // If s is a palindrome and not all characters are the same,
        // then s must contain at least two distinct characters.
        // For example, "abacaba".
        // We can cut it into three pieces: s[0], s.substr(1, N-2), s[N-1].
        // P1 = s[0], P2 = s.substr(1, N-2), P3 = s[N-1].
        // Since s is a palindrome, P1 == P3.
