void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_s(k, '?'); // Stores the determined characters for s[0...k-1] based on s[i] == s[i+k] property

    bool possible = true;

    // Step 1: Propagate constraints s[i] == s[i+k]
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            if (fixed_s[i % k] == '?') {
                fixed_s[i % k] = s[i];
            } else if (fixed_s[i % k] != s[i]) {
                possible = false; // Conflict detected
                break;
            }
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Check if the first k characters can form a k/2, k/2 balance
    int zeros = 0;
    int ones = 0;
    int q_marks = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_s[i] == '0') {
            zeros++;
        } else if (fixed_s[i] == '1') {
            ones++;
        } else { // fixed_s[i] == '?'
            q_marks++;
        }
    }

    if (zeros > k / 2 || ones > k / 2) {
        possible = false; // Too many 0s or 1s already
    } else {
        // We need to fill (k/2 - zeros) '0's and (k/2 - ones) '1's using q_marks
        // The remaining q_marks can be filled arbitrarily, but we only care if we have enough
        // q_marks to satisfy the counts.
        // (k/2 - zeros) + (k/2 - ones) = k - (zeros + ones)
        // This sum must be <= q_marks
        if (k - (zeros + ones) > q_marks) {
            // This condition is actually equivalent to (k/2 - zeros) > q_marks - (k/2 - ones)
            // or (k/2 - ones) > q_marks - (k/2 - zeros)
            // which means we don't have enough '?' to satisfy both counts.
            // A simpler way: if (zeros + ones + q_marks) != k, it's an issue, but it's always k.
            // The actual check is if we have enough '?' to make up the difference.
            // We need k/2 zeros. We have 'zeros'. We need (k/2 - zeros) more.
            // We need k/2 ones. We have 'ones'. We need (k/2 - ones) more.
            // Total needed from '?' is (k/2 - zeros) + (k/2 - ones).
            // If this sum is greater than q_marks, it's impossible.
            // (k/2 - zeros) + (k/2 - ones) = k - (zeros + ones).
            // If k - (zeros + ones) > q_marks, then it's impossible.
            // This is equivalent to k > zeros + ones + q_marks, which is impossible since zeros + ones + q_marks = k.
            // The actual check is simpler:
            // If zeros > k/2 or ones > k/2, it's impossible (already handled).
            // Otherwise, we can always fill the '?'s.
            // We need k/2 zeros. We have 'zeros'. We need (k/2 - zeros) more.
            // We need k/2 ones. We have 'ones'. We need (k/2 - ones) more.
            // The number of '?'s we need to use is (k/2 - zeros) + (k/2 - ones).
            // This sum is k - (zeros + ones).
            // Since q_marks = k - (zeros + ones), we always have exactly enough '?'s to fill the required 0s and 1s.
            // So, if zeros <= k/2 and ones <= k/2, it's always possible.
            // The only constraint is that the number of '?'s must be non-negative, which it is.
            // This means the check `zeros > k/2 || ones > k/2` is sufficient.
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

