    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic works because if p[i] is not n, then max_val_in_row = max_{j!=i} min(p[i], p[j])
        // must be p[i] itself (if there is some p[j] > p[i]) or some p[j] < p[i].
        // But since p is a permutation of 1..n, there must be some p[j] > p[i] if p[i] < n.
        // So max_{j!=i} min(p[i], p[j]) = p[i].
        // If p[i] = n, then max_{j!=i} min(n, p[j]) = max_{j!=i} p[j] = n-1.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
