int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = -1; // Represents the last 'R' cell or the starting cell 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is 0, it means the frog is at cell 0.
                             // So, we can initialize it to -1 to represent cell 0.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The gap is from the previous 'R' (or 0) to the current 'R'.
                // The length of the segment of 'L's (or empty space) is (i - last_r_pos - 1).
                // The distance needed to jump over this segment is (i - last_r_pos).
                // For example, if last_r_pos = 0, i = 3, s[0]='R', s[1]='L', s[2]='L', s[3]='R'.
                // The gap is between cell 0 and cell 3.
                // The cells are 0, 1, 2, 3.
                // We need to jump from 0 to 3. The distance is 3.
                // i - last_r_pos = 3 - 0 = 3.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' cell
        // to the target cell n+1.
        // If last_r_pos is -1, it means there were no 'R's in the string.
        // In this case, the frog must jump from cell 0 to cell n+1 directly.
        // The distance is (n+1 - 0) = n+1.
        // If last_r_pos is not -1, it means the last 'R' was at last_r_pos.
        // The frog needs to jump from last_r_pos to n+1.
        // The distance is (n+1 - last_r_pos).
        max_gap = std::max(max_gap, n + 1 - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

