void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;

    // p_1 must be q_1
    p[0] = q[0];
    used_values.insert(q[0]);

    // For subsequent elements
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is strictly greater than q_{i-1}, then p_i must be q_i
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q is valid, as q_i are distinct when increasing
                // But as a safety check, if q_i was already used, it's impossible.
                // However, q_i > q_{i-1} implies q_i is a new maximum, so it must be a new value.
                // The only way it could be used is if q_i was q_j for some j < i and q_j was also a new max.
                // This is impossible because q_i > q_{i-1} >= q_j.
                // So this check is technically redundant for valid q.
            }
            used_values.insert(q[i]);
        } else { // q_i == q_{i-1}
            // If q_i equals q_{i-1}, then p_i must be some value x < q_i
            // and x must not have been used yet.
            // To maximize chances of finding a solution, we should pick the smallest available unused value.
            // This is because larger values might be needed for later q_j == q_{j-1} cases.
            // However, the problem asks for *any* possible permutation.
            // A simpler greedy approach is to pick the largest available unused value less than q_i.
            // Let's try to pick the largest available value that is less than q_i.
            // This is equivalent to picking values from n down to 1, skipping those already used.
            // We need to find an unused value `x` such that `x < q_i`.
            // The values that are *not* in `used_values` are candidates.
            // We need to find the largest candidate `x` such that `x < q_i`.
            // A `std::set` of available numbers can help.
            // Let's populate a set of all numbers from 1 to n initially.
            // Then remove numbers as they are used.
            // For q_i == q_{i-1}, we need to find an unused number `x` such that `x < q_i`.
            // The largest such `x` is `q_i - 1` if it's available, then `q_i - 2`, etc.
            // Or, we can maintain a set of available numbers and pick the largest one less than q_i.
            // Let's use a `std::set` of available numbers.
        }
    }

    // Re-think the strategy for q_i == q_{i-1}
    // We have already filled p_i for all i where q_i > q_{i-1}.
    // These values are q_0, q_k1, q_k2, ... where q_k_j are the distinct prefix maximums.
    // All these values are distinct and are part of p.
    // The remaining positions p_i (where q_i == q_{i-1}) need to be filled with unused numbers.
    // These unused numbers must be less than or equal to q_i (which is q_{i-1}).
    // To ensure a valid permutation, we should use numbers from 1 to n that haven't been used yet.
    // Let's collect all numbers from 1 to n that are not in `used_values`.
    std::vector<int> available_numbers;
    for (int j = 1; j <= n; ++j) {
        if (used_values.find(j) == used_values.end()) {
            available_numbers.push_back(j);
        }
    }

    // Sort available numbers in descending order to pick largest first.
    // This is a common strategy for "any valid permutation" problems to simplify logic.
    std::sort(available_numbers.rbegin(), available_numbers.rend());

    int available_idx = 0;
    for (int i = 1; i < n; ++i) {
        if (q[i] == q[i-1]) {
            // We need to fill p[i] with an available number.
            // This number must be <= q[i].
            // Since we are picking from `available_numbers` in descending order,
            // the first one we pick must be <= q[i].
            // If `available_numbers[available_idx]` is greater than `q[i]`,
            // then it's impossible to find a valid `p_i` for this position.
            // Because all subsequent available numbers will be even smaller.
            if (available_idx >= available_numbers.size() || available_numbers[available_idx] > q[i]) {
                std::cout << -1 << "\n";
                return;
            }
            p[i] = available_numbers[available_idx];
            available_idx++;
        }
    }

    // Final check: all numbers 1 to n must be used exactly once.
    // The construction ensures this if `available_numbers` is correctly populated and used.
    // Also, all p_i must be distinct and within [1, n].
    // The construction ensures this.
    // The only remaining condition is that p_i <= q_i for all i.
    // For q_i > q_{i-1}, p_i = q_i, so p_i <= q_i holds.
    // For q_i = q_{i-1}, we picked p_i from `available_numbers` such that p_i <= q_i.
    // So this condition holds.

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

