void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, current_min_idx and current_max_idx are both pos[1].
        // The range is [pos[1], pos[1]]. Length is 1. Min is 1, Max is 1.
        // This is a permutation of {1}.

        // For m > 1, we need to expand the current range [current_min_idx, current_max_idx]
        // to include 'm'.
        // The number 'm' is at pos[m].
        // We need to update current_min_idx and current_max_idx to cover the range
        // from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // forms a permutation of 1...m.
        // Condition 1: The length of the segment must be m.
        // Condition 2: The minimum value in the segment must be 1.
        // Condition 3: The maximum value in the segment must be m.
        // Conditions 2 and 3 are implicitly handled by how current_min_idx and current_max_idx
        // are updated. They always span from the position of 1 to the position of m,
        // covering all numbers from 1 to m.
        // So, we only need to check the length.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

