int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int count01 = 0; // a[i] = '0', b[i] = '1'
    int count10 = 0; // a[i] = '1', b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                if (count10 > 0) { // Found a '1' in a where b wants '0'
                    cost += 1; // Swap a[i] and a[j] where a[j]='1', b[j]='0'. Cost is 1.
                    count10--; // One '10' pair resolved
                } else {
                    count01++; // No '10' pair to resolve, add to '01' count
                }
            } else { // a[i] = '1', b[i] = '0'
                if (count01 > 0) { // Found a '0' in a where b wants '1'
                    cost += 1; // Swap a[i] and a[j] where a[j]='0', b[j]='1'. Cost is 1.
                    count01--; // One '01' pair resolved
                } else {
                    count10++; // No '01' pair to resolve, add to '10' count
                }
            }
        }
    }

    // After all possible swaps of adjacent differing types,
    // any remaining '01' or '10' positions must be fixed by flips.
    // Each remaining '01' needs a flip.
    // Each remaining '10' needs a flip.
    // The total number of remaining differing positions is count01 + count10.
    // Each flip costs 1.
    cost += (long long)(count01 + count10);

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
