int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] - x[i] > d or right_ptr reaches end
        // The condition x[right_ptr] <= x[i] + d is equivalent to x[right_ptr] - x[i] <= d
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }
        // At this point, all points from x[i] to x[right_ptr - 1] satisfy the distance condition with x[i].
        // We need to choose two more points, x[j] and x[k], such that i < j < k <= right_ptr - 1.
        // The number of available points to choose from (excluding x[i]) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = (long long)right_ptr - 1 - i;

        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

