    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak"; // Box 1: (-inf, -1]
    std::string ans2 = "Tidak"; // Box 2: (-1, 0)
    std::string ans3 = "Tidak"; // Box 3: (0, 1)
    std::string ans4 = "Tidak"; // Box 4: [1, inf)

    if (total_toys == 1) {
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Case 1: Final product is positive
    // This requires an even number of negative factors.
    // The number of negative factors is A + B.
    // If A + B is even, it's possible to get a positive product.
    if ((a + b) % 2 == 0) {
        // Can it be in Box 3 (0, 1)?
        // Requires positive product, magnitude < 1.
        // This is possible if there's at least one toy with magnitude < 1 (B or C)
        // OR if A=0 and D=0 (all toys have magnitude < 1).
        // If A=0 and D=0, then all toys are from B and C.
        // If B+C > 0, then it's possible to get magnitude < 1.
        // If A=0, D=0, and B+C > 0, then (B+C) toys are all magnitude < 1.
        // The product of any number of such toys will have magnitude < 1.
        // So if A=0, D=0, B+C > 0, and (A+B)%2==0 (which means B%2==0), then Box 3 is possible.
        // More generally, if we have any B or C toys, we can make the magnitude < 1.
        // If we have only A and D toys, and A+D > 0, then we can't guarantee magnitude < 1.
        // We need at least one toy from B or C to ensure we can make the magnitude < 1.
        // If B+C > 0, we can always make the magnitude < 1.
        // If B+C == 0, then all toys are from A and D.
        // If A+B is even, and B=0, then A is even.
        // If A is even, and B=0, C=0, then all toys are from A and D.
        // If A=0, B=0, C=0, D>0, then (A+B)%2==0 is true. Product is D toys.
        // If D>0, product is >= 1. So Box 3 is not possible.
        // If A>0, B=0, C=0, D=0, then A is even. Product is A toys.
        // If A>0, product is >= 1. So Box 3 is not possible.
        // So, Box 3 is possible if (B > 0 || C > 0) OR (A == 0 && D == 0 && B == 0 && C == 0) which is total_toys == 0, but total_toys > 0.
        // So, Box 3 is possible if (B > 0 || C > 0).
        if (b > 0 || c > 0) {
            ans3 = "Ya";
        } else { // Only A and D toys
            // If A+D > 0, and A+B is even (so A is even), then product is positive.
            // All toys have magnitude >= 1. Product will have magnitude >= 1.
            // So Box 3 is not possible.
        }

        // Can it be in Box 4 [1, inf)?
        // Requires positive product, magnitude >= 1.
        // This is possible if there's at least one toy with magnitude >= 1 (A or D)
        // OR if all toys are from B and C, and we can make the magnitude >= 1.
        // If A+D > 0, then it's possible to get magnitude >= 1.
        // If A+D == 0, then all toys are from B and C.
        // If B+C > 0, then all toys have magnitude < 1. Product will have magnitude < 1.
        // So Box 4 is not possible.
        // So, Box 4 is possible if (A > 0 || D > 0).
        if (a > 0 || d > 0) {
            ans4 = "Ya";
        } else { // Only B and C toys
            // If B+C > 0, and A+B is even (so B is even), then product is positive.
            // All toys have magnitude < 1. Product will have magnitude < 1.
            // So Box 4 is not possible.
        }
    }

    // Case 2: Final product is negative
    // This requires an odd number of negative factors.
    // The number of negative factors is A + B.
    // If A + B is odd, it's possible to get a negative product.
    if ((a + b) % 2 == 1) {
        // Can it be in Box 2 (-1, 0)?
        // Requires negative product, magnitude < 1.
        // This is possible if there's at least one toy with magnitude < 1 (B or C).
        // If B+C > 0, we can always make the magnitude < 1.
        // If B+C == 0, then all toys are from A and D.
        // If A+D > 0, and A+B is odd (so A is odd), then product is negative.
        // All toys have magnitude >= 1. Product will have magnitude >= 1.
        // So Box 2 is not possible.
        // So, Box 2 is possible if (B > 0 || C > 0).
        if (b > 0 || c > 0) {
            ans2 = "Ya";
        } else { // Only A and D toys
            // If A+D > 0, and A+B is odd (so A is odd), then product is negative.
            // All toys have magnitude >= 1. Product will have magnitude >= 1.
            // So Box 2 is not possible.
        }

        // Can it be in Box 1 (-inf, -1]?
        // Requires negative product, magnitude >= 1.
        // This is possible if there's at least one toy with magnitude >= 1 (A or D).
        // If A+D > 0, we can always make the magnitude >= 1.
        // If A+D == 0, then all toys are from B and C.
        // If B+C > 0, and A+B is odd (so B is odd), then product is negative.
        // All toys have magnitude < 1. Product will have magnitude < 1.
        // So Box 1 is not possible.
        // So, Box 1 is possible if (A > 0 || D > 0).
        if (a > 0 || d > 0) {
            ans1 = "Ya";
        } else { // Only B and C toys
            // If B+C > 0, and A+B is odd (so B is odd), then product is negative.
            // All toys have magnitude < 1. Product will have magnitude < 1.
            // So Box 1 is not possible.
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

