#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is always optimal for current player
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd, opponent will get an odd number next turn
                    // If Chanek takes N/2, opponent faces odd N/2. Opponent takes 1.
                    // If Chanek takes 1, opponent faces even N-1. Opponent takes (N-1)/2.
                    // Chanek wants to minimize opponent's gain.
                    // If Chanek takes N/2, opponent gets 1. Chanek gets N/2.
                    // If Chanek takes 1, opponent gets (N-1)/2. Chanek gets 1.
                    // Since N/2 is odd, N is 2 * odd.
                    // Example: N=6. N/2=3 (odd).
                    //   Chanek takes 3. N=3. Chanek has 3. Opponent faces 3. Opponent takes 1. N=2. Opponent has 1.
                    //   Chanek takes 1. N=5. Chanek has 1. Opponent faces 5. Opponent takes 1. N=4. Opponent has 1.
                    // In this scenario, taking N/2 is better for Chanek.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even, opponent will get an even number next turn
                    // If Chanek takes N/2, opponent faces even N/2. Opponent takes N/4.
                    // If Chanek takes 1, opponent faces odd N-1. Opponent takes 1.
                    // Chanek wants to minimize opponent's gain.
                    // If Chanek takes N/2, opponent gets N/4. Chanek gets N/2.
                    // If Chanek takes 1, opponent gets 1. Chanek gets 1.
                    // Chanek should take 1 to minimize opponent's gain (1 vs N/4).
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) {
                    opponent_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

