    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int win_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                win_count++;
                if (i > 0 && s[i - 1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (win_count == 0) { // All 'L's
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // Change k 'L's to 'W's.
                // The first 'W' gives 1 point.
                // The next k-1 'W's give 2 points each.
                // Total: 1 + 2*(k-1) = 2k - 1.
                // If k=1, score is 1.
                std::cout << std::max(0, 2 * k - 1) << "\n";
            }
            continue;
        }

        // If there are already wins, we want to fill gaps between wins.
        // Find the first and last 'W'.
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        // Gaps between 'W's
        std::vector<int> gaps;
        int current_gap = 0;
        for (int i = first_w + 1; i <= last_w; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int score_increase = 0;
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                score_increase += 2 * gap_len + 1; // Each L becomes W, connecting two Ws.
                                                   // gap_len L's become W's.
                                                   // Each of these gap_len W's gets 2 points.
                                                   // The W after the gap was getting 1 point (because previous was L).
                                                   // Now it gets 2 points. So +1 for that W.
                                                   // Total: 2*gap_len + 1.
            } else {
                score_increase += 2 * k; // Can only fill k L's. Each gives 2 points.
                k = 0;
                break;
            }
        }

        // Remaining k can be used to convert 'L's before first 'W' or after last 'W'.
        // Each such 'L' converted to 'W' adds 2 points (as it extends a streak).
        // The first 'W' in such a new streak would add 1 point, but we are extending existing streaks.
        // If we convert an 'L' before first_w, it becomes part of a streak ending at first_w.
        // If we convert an 'L' after last_w, it becomes part of a streak starting at last_w.
        // Each such conversion adds 2 points.
        // The only exception is if we convert an 'L' adjacent to an existing 'W' and that 'W' was getting 1 point.
        // For example, L W W. If we change L to W, it becomes W W W.
        // The original W W was 1+2=3. Now W W W is 1+2+2=5. Increase is 2.
        // Example: W L L. If we change L to W, it becomes W W L.
        // Original W L L was 1+0+0=1. Now W W L is 1+2+0=3. Increase is 2.
        // So, each remaining k can add 2 points.
        score_increase += 2 * k;

        std::cout << initial_score + score_increase << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a subarray is a permutation
// `arr` is the input array
// `start` is the starting index (inclusive)
// `end` is the ending index (exclusive)
// `length` is the expected length of the permutation (end - start)
bool is_permutation(const std::vector<int>& arr, int start, int end, int length) {
    if (length <= 0) { // A permutation must have positive length
        return false;
    }
    if (end - start != length) { // Length mismatch
        return false;
    }

    std::vector<bool> seen(length + 1, false); // Use 1-based indexing for values 1 to length
    int max_val = 0;

    for (int i = start; i < end; ++i) {
        int val = arr[i];
        if (val < 1 || val > length) { // Value out of range [1, length]
            return false;
        }
        if (seen[val]) { // Duplicate value
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // All values from 1 to length must be present exactly once.
    // We've checked for duplicates and range.
    // If max_val is not equal to length, it means some number is missing.
    // Example: [1, 3] for length 3. max_val=3, but 2 is missing.
    // The `seen` array check is more robust.
    for (int i = 1; i <= length; ++i) {
        if (!seen[i]) {
            return false;
        }
    }

    return true;
}

// Optimized check for permutation using prefix/suffix properties
// This function precomputes properties for all possible prefixes and suffixes
// `n` is the total length of the array `a`
// `a` is the input array
// `is_prefix_perm[i]` will be true if `a[0...i-1]` is a permutation of length `i`
// `is_suffix_perm[i]` will be true if `a[i...n-1]` is a permutation of length `n-i`
void precompute_permutation_checks(int n, const std::vector<int>& a,
                                   std::vector<bool>& is_prefix_perm,
                                   std::vector<bool>& is_suffix_perm) {
    is_prefix_perm.assign(n + 1, false);
    is_suffix_perm.assign(n + 1, false);

    // Check prefixes
    std::vector<bool> seen_prefix(n + 1, false); // Max possible value is n-1, but length can be n.
                                                 // Use n+1 for 1-based indexing up to n.
    int max_val_prefix = 0;
    bool current_prefix_valid = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        int current_length = i + 1;

        if (!current_prefix_valid || val < 1 || val > current_length || seen_prefix[val]) {
            current_prefix_valid = false;
        } else {
            seen_prefix[val] = true;
            if (val > max_val_prefix) {
                max_val_prefix = val;
            }
            if (max_val_prefix == current_length) { // If max value seen so far equals current length,
                                                    // and no duplicates/out-of-range, it's a permutation.
                is_prefix_perm[current_length] = true;
            }
        }
    }

    // Check suffixes
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool current_suffix_valid = true;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        int current_length = n - i;

        if (!current_suffix_valid || val < 1 || val > current_length || seen_suffix[val]) {
            current_suffix_valid = false;
        } else {
            seen_suffix[val] = true;
            if (val > max_val_suffix) {
                max_val_suffix = val;
            }
            if (max_val_suffix == current_length) {
                is_suffix_perm[i] = true; // i is the starting index of the suffix
            }
        }
    }
}


void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm;
    std::vector<bool> is_suffix_perm;
    precompute_permutation_checks(n, a, is_prefix_perm, is_suffix_perm);

    std::vector<std::pair<int, int>> solutions;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1 (inclusive)
    // If l1 = n, p1 would be length n, p2 length 0 (not allowed)
    // If l1 = 0, p1 would be length 0, p2 length n (not allowed)
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        // Check if a[0...l1-1] is a permutation of length l1
        // And if a[l1...n-1] is a permutation of length l2
        if (is_prefix_perm[l1] && is_suffix_perm[l1]) {
            solutions.push_back({l1, l2});
        }
    }

    std::cout << solutions.size() << "\n";
    for (const auto& p : solutions) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

