#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // The condition is sum = 2 * xor_sum
    // If current_sum = 2 * current_xor_sum, we don't need to append anything.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
        return;
    }

    // We need to append at most 3 elements.
    // Let's try to append 2 elements.
    // We want to find b1, b2 such that:
    // (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)

    // A common strategy for these problems is to make the XOR sum equal to the sum.
    // If we append X and 0, the XOR sum becomes current_xor_sum ^ X.
    // The sum becomes current_sum + X.
    // We want current_sum + X = 2 * (current_xor_sum ^ X).

    // Let's try to append two numbers: current_xor_sum and current_sum + current_xor_sum.
    // This is a known trick for similar problems.
    // Let X = current_xor_sum.
    // Let S = current_sum.
    // We append X and S+X.
    // New XOR sum: X_new = X ^ X ^ (S+X) = S+X
    // New sum: S_new = S + X + (S+X) = 2S + 2X
    // Check condition: S_new = 2 * X_new
    // 2S + 2X = 2 * (S+X)
    // This is always true.

    // So, we can always append two elements: current_xor_sum and current_sum + current_xor_sum.
    // These elements are non-negative since current_sum and current_xor_sum are non-negative.
    // The maximum value for current_sum is 10^5 * 10^9 = 10^14.
    // The maximum value for current_xor_sum is around 2^30 (since a_i <= 10^9).
    // So current_sum + current_xor_sum can be up to 10^14 + 2^30, which fits in long long.

    std::cout << 2 << "\n";
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
}

