int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1000000007;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually need to pass this 'b'.
            // Each 'a' to its left will generate a new 'b' when passing this 'b'.
            // So, the number of 'a's that need to pass this 'b' doubles.
            // The 'count_a' represents the number of 'a's that are currently
            // "active" and need to pass subsequent 'b's.
            // When an 'a' passes a 'b', it effectively becomes two 'a's for future 'b's.
            // This is equivalent to saying that each 'a' currently in 'count_a'
            // will generate a new 'a' (conceptually, as it moves past 'b' and
            // the original 'a' remains to the right of the new 'b').
            // So, the number of 'a's that need to pass future 'b's doubles.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' needs to pass
            // all the 'b's that have been accumulated in 'count_a'.
            // Each 'a' passing a 'b' is one step.
            // So, this 'a' contributes 'count_a' steps.
            total_steps = (total_steps + count_a) % mod;
            // After this 'a' has passed all 'count_a' 'b's, it itself
            // becomes an 'a' that needs to be passed by 'b's further left,
            // or it needs to pass 'b's further right.
            // So, we increment 'count_a' by 1 to include this 'a' for future 'b's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

