    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will be the s generated from our w
    for (int i = 0; i < n; ++i) {
        bool found_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            found_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            found_one = true;
        }
        if (found_one) {
            s_prime[i] = '1';
        }
    }

    if (s_prime == s) {
