#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int consecutive_correct_pairs = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Calculate operations for this chain
        // Each chain starts with m-1 "put" operations to form it.
        // To disassemble, it takes m-1 "get out" operations.
        // So, m-1 operations to disassemble.
        total_operations += (m - 1);

        // Check for consecutive correct pairs (j -> j+1)
        // If the chain starts with 1, then 1->2, 2->3, etc. are "correctly" formed.
        // These don't need to be disassembled and reassembled.
        if (chain[0] == 1) {
            int current_consecutive = 0;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == j + 1) {
                    current_consecutive++;
                } else {
                    break;
                }
            }
            consecutive_correct_pairs = current_consecutive;
        }
    }

    // The total operations calculated so far is the sum of (m_i - 1) for all chains.
    // This represents the cost to disassemble all chains into individual dolls.
    // total_operations = sum(m_i - 1) = sum(m_i) - k = n - k.

    // Now, we need to assemble the final chain 1 -> 2 -> ... -> n.
    // This requires n-1 "put" operations.
    // So, initial total operations = (n - k) + (n - 1).

    // However, if there's a prefix 1 -> 2 -> ... -> C in the first chain,
    // these C-1 connections are already correct and don't need to be disassembled
    // and reassembled.
    // Each such correct connection (j -> j+1) saves 2 operations:
    // 1 "get out" operation (part of m_i - 1)
    // 1 "put" operation (part of n - 1)
    // So, for 'consecutive_correct_pairs' dolls (1 to C), there are C-1 correct connections.
    // Each of these C-1 connections saves 2 operations.
    // The number of saved operations is 2 * (consecutive_correct_pairs - 1).
    // Note: if consecutive_correct_pairs is 0 or 1, then C-1 is 0, saving 0 operations.

    // The total number of operations is:
    // (n - k)  // Disassemble all chains
    // + (n - 1) // Assemble the final chain
    // - 2 * (consecutive_correct_pairs - 1) // Savings from already correct prefix

    // Let's re-evaluate:
    // Total "put" operations needed for final chain: n-1.
    // Total "get out" operations needed to free up dolls:
    // For each chain, m_i-1 "get out" operations are needed to break it down.
    // Sum of (m_i-1) over all chains = (sum m_i) - k = n - k.
    // So, initial total = (n-1) + (n-k).

    // If we have a prefix 1 -> 2 -> ... -> C, these C dolls form C-1 correct connections.
    // These C-1 connections do not need to be disassembled.
    // So, we save (C-1) "get out" operations from the initial chain's disassembly.
    // And these C-1 connections do not need to be re-assembled.
    // So, we save (C-1) "put" operations from the final assembly.
    // Total saved operations = (C-1) + (C-1) = 2 * (C-1).
    // Here, C is `consecutive_correct_pairs`.

    total_operations = (long long)(n - k) + (n - 1);
    if (consecutive_correct_pairs > 0) { // Only apply savings if chain 1 starts with 1
        total_operations -= 2LL * (consecutive_correct_pairs - 1);
    }

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends with w_i = 1: they get one number, happiness is 2 * number.
    // To maximize, give them the largest available numbers.
    // These are the k_ones largest numbers from 'a'.
    // Since w is sorted, w[0]...w[count_ones-1] will be 1s.
    int a_ptr_max = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_max];
            a_ptr_max--;
        } else {
            // All remaining w_i are > 1, so we can break.
            // This loop processes w_i in descending order.
            // w[k-1], w[k-2], ..., w[0]
            // If w[i] is not 1, then w[i-1], w[i-2], ... will also not be 1 (or will be 1s that were already processed).
            // This is incorrect. w is sorted ascending.
            // So w[0], w[1], ..., w[count_ones-1] are 1s.
            // w[count_ones], ..., w[k-1] are > 1.
            // Let's re-think the loop for w_i = 1.
            // The largest 'a' values should go to friends with w_i=1.
            // So, iterate w from right to left.
            // If w[i] == 1, assign a[a_ptr_max] to it.
            // If w[i] > 1, assign a[a_ptr_max] as max, and a[a_ptr_min] as min.
            // This means we need to separate the processing.
            break; // All remaining w[i] are > 1
        }
    }

    // Friends with w_i > 1: they get w_i numbers. Happiness is max_val + min_val.
    // To maximize, give them the largest available number as max_val.
    // And the smallest available number as min_val.
    // The numbers in between don't matter for happiness.
    // We have already used some largest numbers for w_i = 1 friends.
    // The remaining largest numbers are from a_ptr_max down to 0.
    // The remaining smallest numbers are from a_ptr_min up to a_ptr_max.

    // Let's re-sort w in descending order to process friends with w_i > 1 first.
    // This ensures that friends who need more numbers (and thus have a larger w_i)
    // get their 'max' from the largest available numbers.
    // No, this is not correct. The largest w_i values should get their max from the largest available numbers.
    // The smallest w_i values (that are > 1) should get their min from the smallest available numbers.

    // Correct strategy:
    // 1. Sort 'a' in ascending order.
    // 2. Sort 'w' in ascending order.
    // 3. Friends with w_i = 1: These friends contribute 2 * (some_value) to happiness.
    //    To maximize, these 'some_value's should be the largest available numbers.
    //    So, iterate through 'w' from right to left. If w[i] == 1, assign a[a_ptr_max] to this friend.
    //    Decrement a_ptr_max.
    // 4. Friends with w_i > 1: These friends contribute max_val + min_val to happiness.
    //    To maximize, their max_val should be the largest available numbers.
    //    Their min_val should be the smallest available numbers.
    //    The largest available numbers are from a_ptr_max downwards.
    //    The smallest available numbers are from a_ptr_min upwards.
    //    Iterate through 'w' from left to right (for w_i > 1).
    //    For each such friend, assign a[a_ptr_max] as their max_val.
    //    Then, assign a[a_ptr_min] as their min_val.
    //    Then, skip w_i - 2 numbers from the smallest end (a_ptr_min += w_i - 1).
    //    Decrement a_ptr_max.

    // Reset pointers and total_happiness for the correct approach.
    total_happiness = 0;
    a_ptr_max = n - 1;
    int a_ptr_min = 0;

    // Process friends with w_i = 1 first (from largest 'a' values)
    // These are the 'k_ones' friends with w_i = 1.
    // They should get the largest 'k_ones' numbers from 'a'.
    // Since 'w' is sorted ascending, the 1s are at the beginning.
    // But we want to give them the largest 'a' values, so we iterate 'w' from right to left.
    // This means we process friends with w_i=1 first, but they take from the largest 'a' values.
    // The friends with w_i > 1 will take from the remaining largest 'a' values.
    // This is still confusing. Let's be explicit.

    // Separate w into two groups: w_ones (w_i = 1) and w_others (w_i > 1).
    std::vector<int> w_ones;
    std::vector<int> w_others;
    for (int val : w) {
        if (val == 1) {
            w_ones.push_back(val);
        } else {
            w_others.push_back(val);
        }
    }

    // Sort w_others in descending order. This is crucial.
    // Friends who need more numbers (larger w_i) should consume more of the 'middle' numbers,
    // leaving the smallest available numbers for friends who need fewer numbers (smaller w_i).
    std::sort(w_others.rbegin(), w_others.rend());

    // First, assign the largest available numbers to friends with w_i = 1.
    // Each such friend gets 2 * (largest available number).
    for (int i = 0; i < w_ones.size(); ++i) {
        total_happiness += 2 * a[a_ptr_max];
        a_ptr_max--;
    }

    // Now, process friends with w_i > 1.
    // Each such friend gets a[a_ptr_max] as their max_val.
    // And a[a_ptr_min] as their min_val.
    // They also consume w_i - 2 numbers from the smallest end.
    for (int val : w_others) {
        total_happiness += a[a_ptr_max]; // Max value for this friend
        a_ptr_max--;
        total_happiness += a[a_ptr_min]; // Min value for this friend
        a_ptr_min += (val - 1); // Consume val-1 numbers from the smallest end (including the one used as min_val)
                                // The min_val itself is a[a_ptr_min].
                                // So we need to advance a_ptr_min by (val - 1) positions.
                                // Example: w_i = 3. Takes a[a_ptr_min], a[a_ptr_min+1], a[a_ptr_min+2].
                                // min is a[a_ptr_min]. We need to advance a_ptr_min to a_ptr_min+3.
                                // So, a_ptr_min += 3. This is a_ptr_min += val.
                                // No, the problem states "w_i integers".
                                // If w_i = 3, we take a[a_ptr_min], a[a_ptr_min+1], a[a_ptr_min+2].
                                // The min is a[a_ptr_min]. The next available smallest is a[a_ptr_min+3].
                                // So, a_ptr_min should be incremented by w_i.
                                // The current a_ptr_min is used. So we need to advance it by (val - 1) more positions.
                                // So, a_ptr_min += (val - 1).
    }

    std::cout << total_happiness << std::endl;
}

