// Function to get prime factors of a number
// Returns a vector of pairs: {prime_factor, exponent}
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x % q != 0.
        // x must be a divisor of p.
        // This means we need to remove some prime factors from p such that x is no longer divisible by q.
        // To maximize x, we should remove the minimum necessary factors.

        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);
        long long max_x = 1;

        for (const auto& factor_pair : q_factors) {
            long long prime_factor = factor_pair.first;
            // int q_exponent = factor_pair.second; // Not directly needed, we just need the prime factor

            // Calculate the highest power of prime_factor that divides p
            long long temp_p = p;
            int p_exponent = 0;
            while (temp_p > 0 && temp_p % prime_factor == 0) {
                temp_p /= prime_factor;
                p_exponent++;
            }

            // Calculate the highest power of prime_factor that divides q
            long long temp_q = q;
            int q_exponent = 0;
            while (temp_q > 0 && temp_q % prime_factor == 0) {
                temp_q /= prime_factor;
                q_exponent++;
            }

            // If p is divisible by q, then p_exponent >= q_exponent for all prime factors of q.
            // To make x not divisible by q, we must reduce the exponent of at least one prime_factor
            // in x to be less than its exponent in q.
            // The largest x will be p / (prime_factor ^ (q_exponent - 1 + 1)) = p / (prime_factor ^ q_exponent)
            // This ensures that the exponent of prime_factor in x is p_exponent - q_exponent,
            // which is less than q_exponent.
            // More precisely, we want to make the exponent of prime_factor in x be p_exponent - k,
            // where p_exponent - k < q_exponent. The smallest k that achieves this is k = p_exponent - (q_exponent - 1).
            // So we divide p by prime_factor ^ (p_exponent - (q_exponent - 1)).
            // This is equivalent to p / (prime_factor ^ (p_exponent - q_exponent + 1)).
            // This is the smallest factor we can remove from p related to this prime_factor to make x not divisible by q.

            long long current_x = p;
            for(int i = 0; i < q_exponent; ++i) { // Divide by prime_factor q_exponent times
                current_x /= prime_factor;
            }
            // Now current_x has p_exponent - q_exponent power of prime_factor.
            // If p_exponent - q_exponent < q_exponent, then current_x is not divisible by q.
            // But we need to ensure that current_x is not divisible by q.
            // The simplest way to ensure x is not divisible by q is to remove enough factors of prime_factor
            // from p such that the resulting x has an exponent of prime_factor that is less than q_exponent.
            // The largest such x would be p / (prime_factor ^ (q_exponent - 1 + 1)) = p / (prime_factor ^ q_exponent).
            // No, this is wrong. We need to remove just enough factors of prime_factor from p such that
            // the resulting x has an exponent of prime_factor that is less than q_exponent.
            // The largest such x would be p / (prime_factor ^ (p_exponent - (q_exponent - 1)))
            // which simplifies to p / (prime_factor ^ (p_exponent - q_exponent + 1)).

            long long divisor_to_remove = 1;
            for (int i = 0; i < p_exponent - q_exponent + 1; ++i) {
                divisor_to_remove *= prime_factor;
            }
            max_x = std::max(max_x, p / divisor_to_remove);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for counts of 'x', 'y', 'z'
    // counts[0][i] = count of 'x' in s[0...i-1]
    // counts[1][i] = count of 'y' in s[0...i-1]
    // counts[2][i] = count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;
        // Adjust to 0-indexed
        --l; 
        // r is already exclusive for prefix sums, so it's fine

        int len = r - l;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = counts[0][r] - counts[0][l];
        int count_y = counts[1][r] - counts[1][l];
        int count_z = counts[2][r] - counts[2][l];

        // The condition for infinite loop is that for any 3-character substring,
        // it's a permutation of 'x', 'y', 'z' AND it's one of the forbidden ones.
        // This implies that all 3-character substrings must be permutations of 'x', 'y', 'z'.
        // If the counts of 'x', 'y', 'z' in the entire substring s[l...r-1] are too different,
        // it's impossible for all 3-character substrings to be permutations of 'x', 'y', 'z'.
        // Specifically, if the difference between the max and min count of any character
        // in a window of 3 is greater than 1, then there must be a non-forbidden permutation
        // or a substring that is not a permutation of 'x', 'y', 'z'.
        // For the algorithm to run infinitely, it must be possible to always find a 3-char substring
        // that is a permutation of 'x', 'y', 'z' and is one of the forbidden ones.
        // This implies that the counts of 'x', 'y', 'z' in the entire substring s[l...r-1]
        // must be "balanced" enough such that any 3-char window can be a permutation of 'x', 'y', 'z'.
        // The most balanced counts are when they differ by at most 1.
        // E.g., (3,3,3), (3,3,4), (3,4,4), (4,4,4) are balanced.
        // (3,3,5) is not balanced enough, because if you have 5 'z's and 3 'x's,
        // you can't always form 'xyz' permutations.
        // The condition for termination is that the counts of 'x', 'y', 'z' in the substring
        // s[l...r-1] are "unbalanced" enough.
        // If max_count - min_count > 1, then it's guaranteed to terminate.
        // Why? Consider the counts of 'x', 'y', 'z' in any 3-character window.
        // If max_count - min_count > 1 for the whole substring, say count_x = C_x, count_y = C_y, count_z = C_z.
        // Assume C_x is the minimum and C_z is the maximum, and C_z - C_x > 1.
        // This means there are at least two more 'z's than 'x's.
        // If we take any 3-character substring, its counts (c_x, c_y, c_z) must satisfy c_x + c_y + c_z = 3.
        // If c_x, c_y, c_z are all 1, it's a permutation of 'xyz'.
        // If they are not all 1, e.g., (2,1,0) or (3,0,0), then it's not a permutation of 'xyz'.
        // The algorithm terminates if it finds a substring that is NOT a permutation of 'xyz'
        // OR if it finds a permutation of 'xyz' that is "xyz", "yzx", or "zxy".
        // The algorithm runs infinitely if ALL 3-character substrings are "zyx", "xzy", or "yxz".
        // This implies that all 3-character substrings must be permutations of 'x', 'y', 'z'.
        // If the total counts (count_x, count_y, count_z) differ by more than 1,
        // it's impossible for all 3-character substrings to be permutations of 'x', 'y', 'z'.
        // For example, if counts are (3,3,5) for a length 11 string.
        // If we have a window of 3, say s[i..i+2].
        // If we slide this window, the counts of 'x', 'y', 'z' in the window change by at most 1 for each character.
        // If the overall counts are (C_x, C_y, C_z) such that max(C_x, C_y, C_z) - min(C_x, C_y, C_z) > 1,
        // then it's impossible for all 3-character substrings to be permutations of 'x', 'y', 'z'.
        // This is because if all 3-character substrings were permutations of 'x', 'y', 'z',
        // then the counts of 'x', 'y', 'z' in the entire string would have to be very close.
        // Specifically, if all 3-character substrings are permutations of 'x', 'y', 'z',
        // then the counts of 'x', 'y', 'z' in the entire string must differ by at most 1.
        // Proof: Assume max_count - min_count > 1. WLOG, let count_x be min and count_z be max.
        // So count_z >= count_x + 2.
        // Consider the string s[l...r-1].
        // If we remove all 'x's, 'y's, 'z's in groups of (1,1,1), we are left with some remainder.
        // If count_z >= count_x + 2, then there must be some point where we have 'z's without enough 'x's.
        // This implies that there must be a 3-character substring that is not a permutation of 'x', 'y', 'z'.
        // For example, if we have "zzz" or "zzy" or "zzx", these are not permutations of 'x', 'y', 'z'.
        // If such a substring exists, the algorithm will find it and rearrange it.
        // After rearrangement, it might become "xyz", "yzx", or "zxy", which are not forbidden.
        // So, if max_count - min_count > 1, the algorithm terminates.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count > 1) {
            std::cout << "YES\n";
        } else {
            // If max_count - min_count <= 1, it means the counts are balanced (e.g., (3,3,3), (3,3,4), (3,4,4)).
            // In this case, it is possible that all 3-character substrings are permutations of 'x', 'y', 'z'.
            // And it is possible that all such permutations are the forbidden ones ("zyx", "xzy", "yxz").
            // If this happens, the algorithm will run infinitely.
            // Example: "zyxzyxzyx" - counts are balanced, and all 3-char substrings are "zyx".
            // Example: "xzyxzyxzy" - counts are balanced, and all 3-char substrings are "xzy".
            // Example: "yxzyxzyxz" - counts are balanced, and all 3-char substrings are "yxz".
            // In these cases, the algorithm runs infinitely.
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
