void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_pattern(k, '?');

    // Step 1: Propagate known characters based on s[i] == s[i+k]
    for (int i = 0; i < n; ++i) {
        char current_char = s[i];
        int pattern_idx = i % k;

        if (current_char != '?') {
            if (fixed_pattern[pattern_idx] == '?') {
                fixed_pattern[pattern_idx] = current_char;
            } else if (fixed_pattern[pattern_idx] != current_char) {
                // Conflict: s[i] and s[j] (where i % k == j % k) are different
                // and both are non-'?'
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Apply the fixed pattern to the string s
    // and check for conflicts
    for (int i = 0; i < n; ++i) {
        int pattern_idx = i % k;
        if (s[i] == '?') {
            s[i] = fixed_pattern[pattern_idx];
        } else if (fixed_pattern[pattern_idx] != '?' && s[i] != fixed_pattern[pattern_idx]) {
            // This case should ideally be caught in Step 1, but as a safeguard
            std::cout << "NO\n";
            return;
        }
    }

    // Step 3: Check if the first k characters can form a k-balanced substring
    int zeros = 0;
    int ones = 0;
    int question_marks = 0;

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            zeros++;
        } else if (s[i] == '1') {
            ones++;
        } else { // s[i] == '?'
            question_marks++;
        }
    }

    int required_zeros = k / 2;
    int required_ones = k / 2;

    if (zeros > required_zeros || ones > required_ones) {
        std::cout << "NO\n";
        return;
    }

    // We need to fill (required_zeros - zeros) '0's and (required_ones - ones) '1's
    // using the available '?'s.
    // The total number of '?'s must be exactly (required_zeros - zeros) + (required_ones - ones).
    if (question_marks != (required_zeros - zeros) + (required_ones - ones)) {
        // This condition should always be true if zeros <= required_zeros and ones <= required_ones
        // because question_marks = k - zeros - ones, and required_zeros + required_ones = k.
        // So, k - zeros - ones = k - (zeros + ones)
        // and (required_zeros - zeros) + (required_ones - ones) = (required_zeros + required_ones) - (zeros + ones) = k - (zeros + ones).
        // This check is redundant but harmless.
    }

    std::cout << "YES\n";
}

