#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int k = 0; k <= 9; ++k) {
        std::vector<int> colors(n);
        bool possible_k = true;

        int last1 = -1; // Last digit colored 1
        int first2 = -1; // First digit colored 2

        for (int i = 0; i < n; ++i) {
            if (d[i] < k) {
                colors[i] = 1;
                if (d[i] < last1) { // Check non-decreasing for color 1
                    possible_k = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > k) {
                colors[i] = 2;
                if (d[i] < first2) { // Check non-decreasing for color 2
                    possible_k = false;
                    break;
                }
                first2 = d[i];
            } else { // d[i] == k
                // If we've already started color 2 (i.e., first2 is not -1),
                // then this 'k' must be colored 2 to maintain non-decreasing order for color 2.
                // If we haven't started color 2 yet, we can color it 1.
                // This greedy choice ensures that if there's a 'k' that must be 2, it is.
                // Otherwise, we prefer 1 to keep last1 as small as possible.
                if (first2 != -1) { // If we've already seen a digit > k, this k must be color 2
                    colors[i] = 2;
                    // No need to check d[i] < first2 here, as d[i] == k and first2 >= k
                    // (first2 is the smallest digit > k seen so far, or k itself if it was colored 2)
                    // If first2 was a digit > k, then k < first2, so it's fine.
                    // If first2 was a k, then k == first2, so it's fine.
                } else { // We haven't seen any digit > k yet, so this k can be color 1
                    colors[i] = 1;
                    if (d[i] < last1) { // Check non-decreasing for color 1
                        possible_k = false;
                        break;
                    }
                    last1 = d[i];
                }
            }
        }

        if (!possible_k) {
            continue;
        }

        // Now, for digits equal to k that were initially colored 1,
        // we need to check if they can be moved to color 2 to satisfy the overall condition.
        // The overall condition is last_digit_of_S1 <= first_digit_of_S2.
        // We want to find the largest possible last_digit_of_S1 and smallest possible first_digit_of_S2.
        // The current construction makes last1 as large as possible (among digits < k or k colored 1)
        // and first2 as small as possible (among digits > k or k colored 2).
        // We need to ensure that all digits colored 1 are <= all digits colored 2.
        // This means the largest digit colored 1 must be <= the smallest digit colored 2.

        // Let's re-evaluate the coloring for d[i] == k.
        // All d[i] < k are 1. All d[i] > k are 2.
        // For d[i] == k:
        // We want to find a split point `p` such that d[0...p-1] == k are 1, and d[p...n-1] == k are 2.
        // This is equivalent to finding the first `k` that should be colored 2.
        // All `k`s before that are 1, all `k`s after that are 2.

        std::vector<int> final_colors(n);
        int split_k_idx = -1; // Index of the first 'k' that will be colored 2.
                              // If all 'k's are 1, this remains -1.
                              // If all 'k's are 2, this is the index of the first 'k'.

        // Find the first 'k' that must be colored 2 to maintain non-decreasing order for color 2.
        // Or, if no 'k' is forced to be 2, find the last 'k' that can be colored 1.
        // This is tricky. Let's try a simpler approach.

        // For a given k, we have:
        // d_i < k -> color 1
        // d_i > k -> color 2
        // d_i = k -> can be 1 or 2.
        // We need to find a threshold index `idx_k_split`.
        // All d_i = k with i < idx_k_split are color 1.
        // All d_i = k with i >= idx_k_split are color 2.
        // If no d_i = k, idx_k_split can be 0 or n.
        // If all d_i = k are color 1, idx_k_split = n.
        // If all d_i = k are color 2, idx_k_split = 0.

        // Let's try to find the optimal `idx_k_split` for the current `k`.
        // We iterate through all possible `idx_k_split` values.
        // `idx_k_split` can be from 0 to `n`.
        // `idx_k_split` represents the first index where a digit `k` is colored 2.
        // All `k`s before `idx_k_split` are 1, all `k`s at or after `idx_k_split` are 2.

        bool found_solution_for_k = false;

        // The split point for digits equal to k can be anywhere.
        // We can iterate through all possible positions for the "first k to be colored 2".
        // This means we try to color all k's up to index `j` as 1, and all k's from `j` onwards as 2.
        // `j` can range from 0 to `n`.
        // If `j=0`, all k's are 2. If `j=n`, all k's are 1.

        for (int j = 0; j <= n; ++j) { // j is the first index where d[j] == k is colored 2
            std::vector<int> current_colors(n);
            int current_last1 = -1;
            int current_first2 = -1;
            bool current_possible = true;

            for (int i = 0; i < n; ++i) {
                if (d[i] < k) {
                    current_colors[i] = 1;
                    if (d[i] < current_last1) { current_possible = false; break; }
                    current_last1 = d[i];
                } else if (d[i] > k) {
                    current_colors[i] = 2;
                    if (d[i] < current_first2) { current_possible = false; break; }
                    current_first2 = d[i];
                } else { // d[i] == k
                    if (i < j) { // This 'k' is colored 1
                        current_colors[i] = 1;
                        if (d[i] < current_last1) { current_possible = false; break; }
                        current_last1 = d[i];
                    } else { // This 'k' is colored 2
                        current_colors[i] = 2;
                        if (d[i] < current_first2) { current_possible = false; break; }
                        current_first2 = d[i];
                    }
                }
            }

            if (!current_possible) {
                continue;
            }

            // Final check: last digit of S1 <= first digit of S2
            // Find the actual last digit of S1 and first digit of S2 from current_colors
            int actual_last1 = -1;
            for (int i = 0; i < n; ++i) {
                if (current_colors[i] == 1) {
                    actual_last1 = d[i];
                }
            }

            int actual_first2 = 10; // Larger than any digit
            for (int i = 0; i < n; ++i) {
                if (current_colors[i] == 2) {
                    actual_first2 = d[i];
                    break; // Found the first one
                }
            }

            if (actual_last1 <= actual_first2) {
                for (int i = 0; i < n; ++i) {
                    std::cout << current_colors[i];
                }
                std::cout << "\n";
                found_solution_for_k = true;
                break; // Found a valid coloring for this k
            }
        }

        if (found_solution_for_k) {
            return; // Found a solution for some k, print and exit
        }
    }

    std::cout << "-\n"; // No solution found
}

