int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum_r = sum_{r=1}^{b-1} r = (b-1) * b / 2
    // We need to calculate this modulo MOD.
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to divide by 2. Since MOD is prime and > 2, we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9+7 is (10^9+7 + 1) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = (b - 1) % MOD;
    sum_r_term = (sum_r_term * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum_k_term = sum_{k=1}^{a} (k * b + 1)
    // Sum_k_term = sum_{k=1}^{a} (k * b) + sum_{k=1}^{a} 1
    // Sum_k_term = b * sum_{k=1}^{a} k + a
    // Sum_k_term = b * (a * (a+1) / 2) + a

    long long sum_k_val = (a % MOD);
    sum_k_val = (sum_k_val * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD; // This is sum_{k=1}^{a} k modulo MOD

    long long sum_k_b_term = (b % MOD);
    sum_k_b_term = (sum_k_b_term * sum_k_val) % MOD;

    long long sum_1_term = (a % MOD);

    long long total_sum_k_term = (sum_k_b_term + sum_1_term) % MOD;

    long long final_answer = (sum_r_term * total_sum_k_term) % MOD;

    std::cout << final_answer << std::endl;

    return 0;
}

