        left_max[i] = std::min(left_max[i], h[i] - 1);
    }

    right_max[n - 1] = 0;
    for (int i = n - 2; i >= 0; --i) {
        right_max[i] = std::max(0LL, right_max[i + 1] + 1);
        right_max[i] = std::min(right_max[i], h[i] - 1);
    }

    long long max_k = 0;
    for (int i = 0; i < n; ++i) {
        long long k_val = std::min({h[i] - 1, left_max[i], right_max[i]});
        max_k = std::max(max_k, k_val);
    }

