#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_left[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // k jars removed from left means jars a[0...k-1] are removed.
    // The balance of these k jars is diff_left[k].
    std::vector<int> diff_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_left[i + 1] = diff_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_right[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // k jars removed from right means jars a[2n-k...2n-1] are removed.
    // The balance of these k jars is diff_right[k].
    std::vector<int> diff_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_right[i + 1] = diff_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Calculate the total balance of all 2n jars
    int total_balance = 0;
    for (int x : a) {
        total_balance += (x == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the right to achieve a certain balance
    // map: balance_value -> min_jars_removed_from_right
    std::map<int, int> right_balance_to_jars_removed;
    for (int k = 0; k <= n; ++k) {
        int current_right_balance = diff_right[k];
        if (right_balance_to_jars_removed.find(current_right_balance) == right_balance_to_jars_removed.end()) {
            right_balance_to_jars_removed[current_right_balance] = k;
        }
    }

    int min_jars_removed = 2 * n; // Initialize with max possible

    // Iterate through all possible numbers of jars removed from the left (0 to n)
    for (int k_left = 0; k_left <= n; ++k_left) {
        int current_left_balance = diff_left[k_left];

        // The remaining jars (after removing k_left from left and k_right from right)
        // should have a balance of 0.
        // This means: total_balance - current_left_balance - current_right_balance = 0
        // So, current_right_balance must be equal to total_balance - current_left_balance
        int target_right_balance = total_balance - current_left_balance;

        if (right_balance_to_jars_removed.count(target_right_balance)) {
            int k_right = right_balance_to_jars_removed[target_right_balance];
            min_jars_removed = std::min(min_jars_removed, k_left + k_right);
        }
    }

    std::cout << min_jars_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    // Total number of substrings in a string of length n
    long long total_substrings = n * (n + 1) / 2;

    // Number of zeros
    long long num_zeros = n - m;

    // To maximize f(s), we need to minimize the number of substrings consisting only of '0's.
    // This is achieved by distributing the '0's as evenly as possible among the 'm+1' gaps
    // created by the 'm' ones.
    // The 'm' ones divide the string into m+1 potential blocks of zeros.
    // For example, if s = "0010100", n=7, m=2. Zeros = 5. Gaps = m+1 = 3.
    // We want to make the lengths of zero blocks as small as possible.
    // The lengths of zero blocks are k1, k2, ..., k_{m+1}.
    // Sum of k_i = num_zeros.
    // Number of zero-only substrings = sum(k_i * (k_i + 1) / 2).
    // This sum is minimized when k_i are as close to each other as possible.

    // Distribute num_zeros among m+1 blocks.
    // Each block gets at least 'base_len' zeros.
    long long base_len = num_zeros / (m + 1);
    // 'remainder' blocks get one additional zero.
    long long remainder = num_zeros % (m + 1);

    // Number of blocks with length base_len + 1
    long long blocks_long = remainder;
    // Number of blocks with length base_len
    long long blocks_short = (m + 1) - remainder;

    // Calculate the number of substrings consisting only of '0's
    long long zero_only_substrings = 0;

    // Contribution from blocks of length base_len
    zero_only_substrings += blocks_short * (base_len * (base_len + 1) / 2);

    // Contribution from blocks of length base_len + 1
    long long long_len = base_len + 1;
    zero_only_substrings += blocks_long * (long_len * (long_len + 1) / 2);

    // The maximum value of f(s) is total_substrings - minimum_zero_only_substrings
    return total_substrings - zero_only_substrings;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two values:
    // val0: what 0 becomes after all operations
    // val1: what 1023 becomes after all operations
    // We use 0 and 1023 because they cover all possible bit states.
    // For any bit position j:
    // The j-th bit of 0 is 0.
    // The j-th bit of 1023 is 1.
    int val0 = 0;
    int val1023 = 1023;

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val0 &= x;
            val1023 &= x;
        } else if (op_char == '|') {
            val0 |= x;
            val1023 |= x;
        } else if (op_char == '^') {
            val0 ^= x;
            val1023 ^= x;
        }
    }

    // Now, for each bit position j (0 to 9):
    // Let x_j be the j-th bit of the input.
    // Let f(x_j) be the j-th bit of the final result.
    // We know f(0) (j-th bit of val0) and f(1) (j-th bit of val1023).
    //
    // Case 1: f(0) = 0, f(1) = 0  =>  f(x_j) = 0 for all x_j. This means the bit is always 0.
    // Case 2: f(0) = 0, f(1) = 1  =>  f(x_j) = x_j for all x_j. This means the bit is unchanged.
    // Case 3: f(0) = 1, f(1) = 0  =>  f(x_j) = 1 - x_j for all x_j. This means the bit is flipped.
    // Case 4: f(0) = 1, f(1) = 1  =>  f(x_j) = 1 for all x_j. This means the bit is always 1.

    // We can represent these transformations using a combination of AND, OR, XOR.
    // Let the simplified program be:
    // (input & AND_mask) | OR_mask ^ XOR_mask
    //
    // Initialize masks:
    // AND_mask: initially all 1s (1023), bits will be set to 0 if they must become 0.
    // OR_mask: initially all 0s (0), bits will be set to 1 if they must become 1.
    // XOR_mask: initially all 0s (0), bits will be set to 1 if they must be flipped.
    int final_and_mask = 1023; // All bits can pass through
    int final_or_mask = 0;    // No bits are forced to 1
    int final_xor_mask = 0;   // No bits are flipped

    for (int j = 0; j < 10; ++j) {
        int bit_val0 = (val0 >> j) & 1;
        int bit_val1023 = (val1023 >> j) & 1;

        if (bit_val0 == 0 && bit_val1023 == 0) {
            // Case 1: f(x_j) = 0.
            // To achieve this: (x_j & 0) | 0 ^ 0 = 0.
            // So, set j-th bit of AND_mask to 0.
            final_and_mask &= ~(1 << j);
        } else if (bit_val0 == 0 && bit_val1023 == 1) {
            // Case 2: f(x_j) = x_j.
            // To achieve this: (x_j & 1) | 0 ^ 0 = x_j.
            // No change needed for masks for this bit.
        } else if (bit_val0 == 1 && bit_val1023 == 0) {
            // Case 3: f(x_j) = 1 - x_j.
            // To achieve this: (x_j & 1) | 0 ^ 1 = 1 - x_j.
            // So, set j-th bit of XOR_mask to 1.
            final_xor_mask |= (1 << j);
        } else if (bit_val0 == 1 && bit_val1023 == 1) {
            // Case 4: f(x_j) = 1.
            // To achieve this: (x_j & 1) | 1 ^ 0 = 1.
            // So, set j-th bit of OR_mask to 1.
            final_or_mask |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> simplified_ops;
    if (final_and_mask != 1023) { // If any bit was forced to 0
        simplified_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit was forced to 1
        simplified_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit was flipped
        simplified_ops.push_back({'^', final_xor_mask});
    }

    std::cout << simplified_ops.size() << "\n";
    for (const auto& op : simplified_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

