int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Dummy operation (e.g., add 0 to a[0])
        std::cout << "1 1\n";
        std::cout << "0\n";

        // Operation 3: Another dummy operation
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Make all elements except the last one divisible by n.
    // For each a[i] (0 <= i < n-1), we want a[i] + x * n to be 0.
    // This means a[i] + x * n = 0 (mod n).
    // So, a[i] = 0 (mod n).
    // We can achieve this by adding (n - (a[i] % n)) % n * n to a[i].
    // The segment is [1, n-1]. Length is n-1.
    // We need to add a multiple of (n-1).
    // This is not the strategy.

    // Strategy:
    // 1. For elements a[0] to a[n-2]:
    //    Add a multiple of n to each a[i] such that a[i] becomes 0 (mod n).
    //    Specifically, add (n - (a[i] % n)) % n * n.
    //    This makes a[i] divisible by n.
    //    The segment is [1, n-1]. Length is n-1.
    //    This operation is not valid because we need to add a multiple of (n-1), not n.

    // Correct strategy:
    // Operation 1: For elements a[0] to a[n-2], make them divisible by n.
    // Segment [1, n-1]. Length is n-1.
    // For each a[i] (0 <= i < n-1), we want to add b_i such that b_i is a multiple of (n-1)
    // AND a[i] + b_i is a multiple of n.
    // Let a[i]' = a[i] + b_i. We want a[i]' % n == 0.
    // We know that gcd(n, n-1) = 1.
    // This means for any target value T, we can find b_i such that b_i is a multiple of (n-1)
    // and a[i] + b_i = T (mod n).
    // Specifically, we want a[i] + b_i = 0 (mod n).
    // So b_i = -a[i] (mod n).
    // Since gcd(n, n-1) = 1, there exists an integer k such that k * (n-1) = -a[i] (mod n).
    // We can find k by solving k * (n-1) = -a[i] + m * n for some integer m.
    // k * (n-1) % n = (-a[i] % n + n) % n.
    // k * (-1) % n = (-a[i] % n + n) % n.
    // -k % n = (-a[i] % n + n) % n.
    // k % n = (a[i] % n + n) % n.
    // Let rem = (a[i] % n + n) % n. We need k % n = rem.
    // So we can choose k = rem.
    // Then b_i = rem * (n-1).
    // After this operation, a[i] becomes a[i] + rem * (n-1).
    // This new value is a[i] + rem * (n-1) = a[i] + rem * (-1) (mod n) = a[i] - rem (mod n).
    // Since rem = a[i] % n, a[i] - rem is 0 (mod n).
    // So, after this operation, a[i] (for 0 <= i < n-1) will be divisible by n.

    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long rem = (a[i] % n + n) % n;
        long long add_val = rem * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // Operation 2: For the last element a[n-1], make it divisible by n.
    // Segment [n, n]. Length is 1.
    // We can add any integer. We want to add b_{n-1} such that a[n-1] + b_{n-1} is 0 (mod n).
    // We can add (n - (a[n-1] % n)) % n * n.
    // This makes a[n-1] divisible by n.
    // This is not the strategy.

    // Correct strategy for Operation 2:
    // For the last element a[n-1], make it divisible by n.
    // Segment [n, n]. Length is 1.
    // We want a[n-1] + b_{n-1} = 0 (mod n).
    // We can add b_{n-1} = (n - (a[n-1] % n)) % n * n.
    // This makes a[n-1] divisible by n.
    // This is not the strategy.

    // The strategy is simpler:
    // 1. For elements a[0] to a[n-1]:
    //    Add a multiple of n to each a[i] such that a[i] becomes 0 (mod n).
    //    Specifically, add (n - (a[i] % n)) % n * n.
    //    This makes a[i] divisible by n.
    //    The segment is [1, n]. Length is n.
    //    This is the first operation.
    //    After this, all a[i] are divisible by n.
    //    Then, in the second operation, for each a[i], add -a[i].
    //    This is not 3 operations.

    // The standard solution for this problem:
    // 1. For elements a[0] to a[n-2]:
    //    Add a multiple of (n-1) to each a[i] such that a[i] becomes 0 (mod n).
    //    As derived above, for each a[i], add `rem * (n-1)` where `rem = (a[i] % n + n) % n`.
    //    After this, a[i] (for 0 <= i < n-1) is divisible by n.
    //    The segment is [1, n-1].
    //    This is what I implemented above.

    // 2. For the last element a[n-1]:
    //    Add a multiple of 1 to a[n-1] such that a[n-1] becomes 0 (mod n).
    //    Segment [n, n]. Length is 1.
    //    Add `rem * 1` where `rem = (a[n-1] % n + n) % n`.
    //    After this, a[n-1] is divisible by n.
    //    Now all elements a[0]...a[n-1] are divisible by n.

    std::cout << n << " " << n << "\n";
    long long rem_last = (a[n - 1] % n + n) % n;
    long long add_val_last = rem_last * 1; // Length is 1
    std::cout << add_val_last << "\n";
    a[n - 1] += add_val_last;

    // 3. For all elements a[0] to a[n-1]:
    //    All a[i] are now divisible by n.
    //    Segment [1, n]. Length is n.
    //    For each a[i], add -a[i]. Since a[i] is divisible by n, -a[i] is also divisible by n.
    //    So we can add -a[i] to each a[i].
    //    This makes all elements zero.

    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // Convert to 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal (i.e., addition)
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" back

        active_vertices[k] = true; // Mark vertex k as active

        // Update shortest paths using vertex k as an intermediate
        // This is the Floyd-Warshall step
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // After updating with k, check all pairs of currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j]) {
                        if (i != j) { // Sum only for distinct pairs
                            current_sum += dist[i][j];
                        }
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were collected)
