#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, then add d, 2d, 3d, etc.

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // Since X can be up to 10^9, X+1 can be up to 10^9+1.
        // log2(10^9+1) is approximately log2(2^30) = 30.
        // So k will be at most around 29-30.
        // We can iterate k from 1 to 60 (max possible for long long)
        // or use bit manipulation.
        // A simple loop is fine given k is small.
        for (int i = 1; i <= 60; ++i) { // Max k for 2^k-1 to fit in long long is 62 (2^62-1)
            if ((1LL << i) - 1 <= X) {
                k = i;
            } else {
                break;
            }
        }

        // Add k copies of current_val to the array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the count of subsequences formed by these k elements
        X -= ((1LL << k) - 1);

        // Increment current_val for the next block of elements
        // The next block's elements must be at least d greater than the current block's max element
        // to ensure no subsequences span across blocks.
        // current_val + d is a safe choice.
        current_val += d;

        // Ensure current_val does not exceed 10^18.
        // If current_val becomes too large, it means we can't construct the array.
        // However, with X up to 10^9, k is at most ~30.
        // The number of blocks will be at most ~30 (if X is sum of 2^k-1 for distinct k).
        // So current_val will be roughly 1 + 30 * d.
        // If d is 10^9, current_val could be 1 + 30 * 10^9 = 3 * 10^10, which is fine.
        // If d is 1, current_val is small.
        // The total number of elements is sum of k's. Max k is ~30. Max blocks is ~30.
        // Total elements ~ 30 * 30 = 900, well within 10^4.
        // The maximum value of current_val will be roughly 1 + (number of blocks) * d.
        // Max number of blocks is about 60 (if X is sum of 2^0, 2^1, ..., 2^59).
        // So max current_val is 1 + 60 * 10^9 = 6 * 10^10, which is < 10^18.
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

