struct Child {
    long long v, d, p;
    int original_index;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_index);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_v_effect = children[i].v;
        long long accumulated_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_effect from previous dropouts
            if (accumulated_d_effect > 0) {
                children[j].p -= accumulated_d_effect;
            }

            // Apply current_v_effect from child i's cry
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Check if child j drops out
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_d_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * max(a_i) which is 2*10^5 * 10^9 = 2*10^14.

// This function calculates the result for a given starting a_1 value.
// It uses memoization (dynamic programming) to store results for intermediate states (x, parity).
// The 'parity' indicates whether the current step is an 'add' (0) or 'subtract' (1) operation.
// This is crucial because the value of a_x depends on the current x, and the next x depends on the operation.
// The state (x, parity) uniquely determines the subsequent path and accumulated y.
long long solve(int current_x, int parity, int n, const std::vector<long long>& a,
                std::vector<std::vector<long long>>& memo,
                std::vector<std::vector<bool>>& visited) {

    // Check for termination conditions
    if (current_x <= 0 || current_x > n) {
        return 0; // Base case: program terminates, no further y added.
    }

    // Check if this state has been visited in the current path (cycle detection)
    if (visited[current_x][parity]) {
        return -1; // Cycle detected, program does not terminate.
    }

    // Check if this state has been computed before
    if (memo[current_x][parity] != -2) { // -2 indicates not computed
        return memo[current_x][parity];
    }

    // Mark current state as visited for cycle detection
    visited[current_x][parity] = true;

    long long val_at_x = a[current_x - 1]; // Get a_x (using 0-based indexing for vector a)
    long long result;

    if (parity == 0) { // Step 2: x = x + a_x, y = y + a_x
        int next_x = current_x + val_at_x;
        long long next_y_contribution = solve(next_x, 1, n, a, memo, visited); // Next step is 'subtract'
        if (next_y_contribution == -1) {
            result = -1; // Propagate non-termination
        } else {
            result = val_at_x + next_y_contribution;
        }
    } else { // parity == 1, Step 3: y = y + a_x, x = x - a_x
        int next_x = current_x - val_at_x;
        long long next_y_contribution = solve(next_x, 0, n, a, memo, visited); // Next step is 'add'
        if (next_y_contribution == -1) {
            result = -1; // Propagate non-termination
        } else {
            result = val_at_x + next_y_contribution;
        }
    }

    // Unmark current state as visited (for other paths)
    visited[current_x][parity] = false;

    // Store and return the result
    memo[current_x][parity] = result;
    return result;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n); // a[0] will be set for each run, a[1]...a[n-1] are fixed
    for (int i = 1; i < n; ++i) {
        std::cin >> a[i];
    }

    // Memoization table: memo[x][parity] stores the accumulated y from state (x, parity)
    // Initialize with -2 to indicate not computed. -1 is for non-termination.
    std::vector<std::vector<long long>> memo(n + 1, std::vector<long long>(2, -2));
    // Visited table for cycle detection in the current DFS path
    std::vector<std::vector<bool>> visited(n + 1, std::vector<bool>(2, false));

    for (int i = 1; i < n; ++i) {
        a[0] = i; // Set a_1 for the current run

        // Clear memoization and visited tables for each new a_1.
        // This is because the values in 'a' (specifically a[0]) change,
        // invalidating previous memoized results.
        for (int j = 0; j <= n; ++j) {
            memo[j][0] = -2;
            memo[j][1] = -2;
            visited[j][0] = false;
            visited[j][1] = false;
        }

        // Start the simulation from x=1, y=0. The first operation is 'add' (parity 0).
        // The initial y is 0, so we just need the result from solve(1, 0, ...)
        long long result = solve(1, 0, n, a, memo, visited);
        std::cout << result << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a_upper_bound[i] to a very large value (effectively infinity)
    // This represents the upper bound for A_0[i]
    std::vector<long long> initial_a_upper_bound(n, std::numeric_limits<long long>::max());

    // Calculate the total delta applied to each element up to the point of each query operation.
    // This is done by iterating through operations in reverse.
    // For each element i, we need to know the sum of 'd' values that would be applied
    // to it if we were to apply all type 1 operations *after* a specific query.
    // This is equivalent to finding the maximum possible A_0[i] for each i.

    // current_delta_prefix_sum[k] stores the sum of d values for ranges [0, k]
    // that are applied *after* the current operation being processed (in reverse).
    // This allows us to efficiently calculate the total delta for any element j.
    std::vector<long long> current_delta_prefix_sum(n + 1, 0);

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (increase by d),
            // this 'd' value will affect elements in [l, r] for all subsequent operations (in forward time).
            // In reverse time, this means we need to add 'd' to our current_delta_prefix_sum
            // for the range [l, r].
            current_delta_prefix_sum[ops[i].l] += ops[i].val;
            current_delta_prefix_sum[ops[i].r + 1] -= ops[i].val;
        } else { // ops[i].type == 2
            // If it's a type 2 operation (query max m),
            // for each element j in [l, r], its initial value A_0[j] plus the total delta
            // applied *after* this query (which is what current_delta_prefix_sum represents)
            // must be less than or equal to m.
            // So, A_0[j] + (sum of d's applied after this query) <= m
            // A_0[j] <= m - (sum of d's applied after this query)

            // Calculate the actual delta for each element j in [l, r]
            // by summing up current_delta_prefix_sum.
            long long current_delta_for_j = 0;
            for (int j = 0; j < n; ++j) {
                current_delta_for_j += current_delta_prefix_sum[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    initial_a_upper_bound[j] = std::min(initial_a_upper_bound[j], ops[i].val - current_delta_for_j);
                }
            }
        }
    }

    // Now we have the upper bounds for each A_0[i].
    // We can choose A_0[i] = initial_a_upper_bound[i] as a candidate solution.
    // Let's verify this candidate solution.
    std::vector<long long> a_candidate = initial_a_upper_bound;

    // Simulate the operations with a_candidate
    std::vector<long long> current_a = a_candidate;
    std::vector<long long> diff_array(n + 1, 0); // For efficient range updates

    for (const auto& op : ops) {
        if (op.type == 1) {
            diff_array[op.l] += op.val;
            diff_array[op.r + 1] -= op.val;
        } else { // op.type == 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            long long current_diff_sum = 0;
            for (int j = 0; j < n; ++j) {
                current_diff_sum += diff_array[j];
                if (j >= op.l && j <= op.r) {
                    max_val_in_range = std::max(max_val_in_range, a_candidate[j] + current_diff_sum);
                }
            }
            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial array elements
    for (int i = 0; i < n; ++i) {
        if (std::abs(a_candidate[i]) > 1000000000LL) {
            // This case should ideally not be hit if the problem constraints are well-defined
            // and a solution exists within the given bounds.
            // The problem states "all numbers in his array didn't exceed 10^9 in their absolute value"
            // which implies the initial array elements.
            // If our derived a_candidate[i] exceeds this, it means no such initial array exists.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_candidate[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

