int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, m;
        std::cin >> n >> m;
        std::vector<bool> row_occupied(n, false);
        std::vector<bool> col_occupied(m, false);
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                int cell_val;
                std::cin >> cell_val;
                if (cell_val == 1) {
                    row_occupied[i] = true;
                    col_occupied[j] = true;
                }
            }
        }

        int available_rows = 0;
        for (int i = 0; i < n; ++i) {
            if (!row_occupied[i]) {
                available_rows++;
            }
        }

        int available_cols = 0;
        for (int j = 0; j < m; ++j) {
            if (!col_occupied[j]) {
                available_cols++;
            }
        }

        int moves_possible = std::min(available_rows, available_cols);

        if (moves_possible % 2 == 1) {
            std::cout << "Ashish\n";
        } else {
            std::cout << "Vivek\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n && p_idx < m; ++h_idx) {
        long long current_h = h[h_idx];
        long long min_reach = current_h - T;
        long long max_reach = current_h + T;

        // If the current head cannot reach the current target track p[p_idx],
        // then this head is useless for p[p_idx] and subsequent tracks.
        // We need to move to the next head.
        if (max_reach < p[p_idx]) {
            continue;
        }

        // The current head can reach p[p_idx].
        // Now, find how many tracks this head can cover.
        // It can cover all tracks p[k] such that p[k] is within [min_reach, max_reach].
        // Also, if p[k] is to the left of current_h, the head can move left to cover it.
        // If p[k] is to the right of current_h, the head can move right to cover it.
        // The total distance covered by a head is T.
        // If a head moves left to cover p[p_idx], its rightmost reach is current_h + (T - (current_h - p[p_idx])) = p[p_idx] + T.
        // If a head moves right to cover p[p_idx], its leftmost reach is current_h - (T - (p[p_idx] - current_h)) = p[p_idx] - T.
        // This is not quite right. The head can cover a contiguous segment of length T+1.
        // If it covers p[p_idx], it can cover [p[p_idx], p[p_idx] + T] or [p[p_idx] - T, p[p_idx]].
        // The total range covered by a head starting at `current_h` in `T` time is `[current_h - T, current_h + T]`.
        // If `p[p_idx]` is within this range, the head can reach it.
        // To maximize the number of tracks covered by this head, we should try to cover `p[p_idx]` and then extend as far right as possible.
        // The head can cover a segment of length `T` starting from `p[p_idx]`.
        // The head is at `current_h`. It needs to reach `p[p_idx]`. This takes `abs(current_h - p[p_idx])` time.
        // Remaining time: `T_rem = T - abs(current_h - p[p_idx])`.
        // With `T_rem` time, it can extend its coverage.
        // If `current_h <= p[p_idx]`, the head moves right to `p[p_idx]`. It can then continue right up to `p[p_idx] + T_rem`.
        // If `current_h > p[p_idx]`, the head moves left to `p[p_idx]`. It can then continue right up to `p[p_idx] + T_rem`.
        // So, the rightmost point it can cover is `p[p_idx] + T - abs(current_h - p[p_idx])`.
        long long current_head_max_coverage_right = p[p_idx] + (T - std::abs(current_h - p[p_idx]));

        while (p_idx < m && p[p_idx] <= current_head_max_coverage_right) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between tracks is 10^10.
                                    // A head might need to move from 1 to 10^10, so 10^10 is a safe upper bound.
                                    // 2 * 10^10 is a very safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
