void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<bool> row_taken(n, false);
    std::vector<bool> col_taken(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            int val;
            std::cin >> val;
            if (val == 1) {
                row_taken[i] = true;
                col_taken[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_taken[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_taken[j]) {
            available_cols++;
        }
    }

    int moves = std::min(available_rows, available_cols);

    if (moves % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

