#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_r_pos = -1; // Represents the last position where an 'R' was encountered, or -1 for cell 0.

        // Iterate through the string s (cells 1 to n)
        // s[i] corresponds to cell i+1
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at cell i+1,
                // the distance from the previous 'R' (or cell 0) to this 'R'
                // is (i+1) - (last_r_pos + 1) + 1 = i - last_r_pos.
                // This is the length of the segment of 'L's plus one for the 'R' itself.
                // Example: 0 R L L R
                // last_r_pos = -1 (cell 0)
                // i = 0, s[0] = 'R' (cell 1). Current segment length is 1 - (-1) = 2.
                // max_dist = max(0, 2) = 2. last_r_pos = 0.
                // i = 1, s[1] = 'L'
                // i = 2, s[2] = 'L'
                // i = 3, s[3] = 'R' (cell 4). Current segment length is 4 - 1 = 3.
                // max_dist = max(2, 3) = 3. last_r_pos = 3.
                max_dist = std::max(max_dist, (i + 1) - (last_r_pos + 1) + 1);
                last_r_pos = i;
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R'
        // (or cell 0 if no 'R's) to cell n+1.
        // The distance is (n+1) - (last_r_pos + 1) + 1 = n - last_r_pos.
        // Example: LLL, n=3. last_r_pos = -1. max_dist = max(0, 3 - (-1)) = max(0, 4) = 4.
        // Example: RRR, n=3. last_r_pos = 2. max_dist = max(1, 3 - 2) = max(1, 1) = 1.
        max_dist = std::max(max_dist, (int)s.length() - last_r_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

