                // If a[i] != b[i], then b[i] is the opposite of a[i].
                // If a[i+1] != b[i+1], then b[i+1] is the opposite of a[i+1].
                // So, if a[i] != a[i+1], then b[i] must be a[i+1] and b[i+1] must be a[i].
                // Example: a="01", b="10". a[0]!=b[0], a[1]!=b[1], a[0]!=a[1]. Swap a[0],a[1] -> "10". Cost 1.
                cost += 1; // Cost of swap |(i+1) - i| = 1
                i += 2;    // Both positions i and i+1 are resolved
            } else {
                // No adjacent swap possible or beneficial.
                // Must flip a[i].
                cost += 1; // Cost of flip
                i += 1;    // Position i is resolved
            }
        } else {
            // No mismatch at index i, move to the next position
            i += 1;
        }
    }

    std::cout << cost << std::endl;

    return 0;
}

