    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // (n-1)/2 for 0-indexed array

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually change it for subsequent checks

    // 2. Ensure elements to the left of median are <= s
    // These are elements at indices 0 to median_idx - 1
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // These are elements at indices median_idx + 1 to n - 1
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

