int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long total_count = 0;
    int right_ptr = 0; // This will be 'k' in the explanation, but it's the rightmost point of the window

    for (int i = 0; i < n; ++i) { // 'i' is the leftmost point of the window
        // Expand the window to the right as much as possible
        // such that x[right_ptr] - x[i] <= d
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[i] to x[right_ptr-1] satisfy the condition with x[i].
        // The number of points in this valid range (inclusive) is (right_ptr - 1) - i + 1 = right_ptr - i.
        // Let m = right_ptr - i be the number of points in the current valid window [x[i], ..., x[right_ptr-1]].
        // We need to choose 2 more points from the remaining m-1 points (excluding x[i]).
        // The number of ways to choose 2 points from m-1 points is C(m-1, 2).
        // C(m-1, 2) = (m-1) * (m-2) / 2.

        long long m = right_ptr - i;
        if (m >= 3) { // We need at least 3 points in the window to form a triplet
            total_count += (m - 1) * (m - 2) / 2;
        }
    }

    std::cout << total_count << std::endl;

    return 0;
}

