// Function to determine if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: Negative, Large magnitude (NL)
    // Final toy must be NL.
    // This means the final product must be negative and its magnitude >= 1.

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // The initial number of negative toys is A + B.
    // If A + B is even, we need to make an odd number of negative toys from positive ones, which is impossible.
    // So, if A + B is even, we must have an odd number of negative toys initially.
    // If A + B is odd, we can end up with a negative toy.

    // Case 2: Final product has magnitude >= 1.
    // This requires at least one initial toy with magnitude >= 1 (from A or D)
    // OR a sequence of multiplications that eventually produces a magnitude >= 1.
    // If all initial toys have magnitude < 1 (B and C only), then the final product will always have magnitude < 1.
    // So, if A + D == 0, Box 1 cannot be the special box.

    if (A + D == 0) { // All initial toys have magnitude < 1
        return false;
    }

    // If A + B is odd, we can always end up with a negative product.
    // If A + B is even, we can only end up with a negative product if we can make an odd number of negative toys.
    // This is only possible if we start with an odd number of negative toys.
    // So, if A + B is even, the final product will be positive.
    // Thus, if A + B is even, Box 1 cannot be the special box.
    if ((A + B) % 2 == 0) {
        return false;
    }

    // If A + B is odd and A + D > 0, it's possible.
    // We can always arrange multiplications to keep a large magnitude if one exists.
    // For example, if we have a toy from A or D, we can multiply it last with a toy that has the desired sign.
    // If we have a toy from A or D, we can always ensure the final magnitude is >= 1.
    // We just need to ensure the sign is negative.
    // If A+B is odd, we can always make the final sign negative.
    // If A+D > 0, we can always make the final magnitude >= 1.
    return true;
}

// Function to determine if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: Negative, Small magnitude (NS)
    // Final toy must be NS.
    // This means the final product must be negative and its magnitude < 1.

    // Case 1: Final product is negative.
    // Requires an odd number of negative factors.
    if ((A + B) % 2 == 0) { // If initial negative count is even, final product is positive.
        return false;
    }

    // Case 2: Final product has magnitude < 1.
    // This requires that we can make the final product's magnitude < 1.
    // If A + D == 0, all initial toys have magnitude < 1, so the final product will always have magnitude < 1.
    // In this case, if A+B is odd, Box 2 is possible.
    if (A + D == 0) {
        return true;
    }

    // If A + D > 0, we have at least one toy with magnitude >= 1.
    // To get a final magnitude < 1, we need to be able to "reduce" the magnitude.
    // This requires at least one toy with magnitude < 1 (from B or C).
    // If B + C == 0, and A + D > 0, then all toys have magnitude >= 1.
    // In this scenario, the final product will always have magnitude >= 1.
    // So, if B + C == 0, Box 2 is not possible.
    if (B + C == 0) {
        return false;
    }

    // If A + B is odd, A + D > 0, and B + C > 0:
    // We have negative toys (odd count), large magnitude toys, and small magnitude toys.
    // We can always achieve a negative sign.
    // We can always achieve a small magnitude by multiplying a large magnitude toy with a small magnitude toy.
    // For example, multiply all toys from A and D together. Then multiply all toys from B and C together.
    // Then multiply the two resulting toys.
    // Or, more simply, take one toy from B or C, and multiply it with the rest of the toys.
    // The product of all other toys can be arbitrarily large or small, but multiplying by a small magnitude toy (e.g., 0.1)
    // can always bring the final product's magnitude below 1.
    return true;
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: Positive, Small magnitude (PS)
    // Final toy must be PS.
    // This means the final product must be positive and its magnitude < 1.

    // Case 1: Final product is positive.
    // Requires an even number of negative factors.
    if ((A + B) % 2 != 0) { // If initial negative count is odd, final product is negative.
        return false;
    }

    // Case 2: Final product has magnitude < 1.
    // Similar to Box 2, if A + D == 0, all initial toys have magnitude < 1, so final product will always have magnitude < 1.
    // In this case, if A+B is even, Box 3 is possible.
    if (A + D == 0) {
        return true;
    }

    // If A + D > 0, we have at least one toy with magnitude >= 1.
    // To get a final magnitude < 1, we need at least one toy with magnitude < 1 (from B or C).
    // If B + C == 0, and A + D > 0, then all toys have magnitude >= 1.
    // In this scenario, the final product will always have magnitude >= 1.
    // So, if B + C == 0, Box 3 is not possible.
    if (B + C == 0) {
        return false;
    }

    // If A + B is even, A + D > 0, and B + C > 0:
    // We have positive toys (even negative count), large magnitude toys, and small magnitude toys.
    // We can always achieve a positive sign.
    // We can always achieve a small magnitude.
    return true;
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: Positive, Large magnitude (PL)
    // Final toy must be PL.
    // This means the final product must be positive and its magnitude >= 1.

    // Case 1: Final product is positive.
    // Requires an even number of negative factors.
    if ((A + B) % 2 != 0) { // If initial negative count is odd, final product is negative.
        return false;
    }

    // Case 2: Final product has magnitude >= 1.
    // This requires at least one initial toy with magnitude >= 1 (from A or D).
    // If A + D == 0, all initial toys have magnitude < 1, so the final product will always have magnitude < 1.
    // So, if A + D == 0, Box 4 cannot be the special box.
    if (A + D == 0) {
        return false;
    }

    // If A + B is even and A + D > 0, it's possible.
    // We can always arrange multiplications to keep a large magnitude if one exists.
    // We just need to ensure the sign is positive.
    // If A+B is even, we can always make the final sign positive.
    // If A+D > 0, we can always make the final magnitude >= 1.
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        // Total number of toys
        long long total_toys = A + B + C + D;

        // If only one toy, that toy is the super toy.
        // The rules for multiplication don't apply.
        if (total_toys == 1) {
            std::cout << (A == 1 ? "Ya" : "Tidak") << " "
                      << (B == 1 ? "Ya" : "Tidak") << " "
                      << (C == 1 ? "Ya" : "Tidak") << " "
                      << (D == 1 ? "Ya" : "Tidak") << "\n";
        } else {
            std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " "
                      << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " "
                      << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " "
                      << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << "\n";
        }
    }
    return 0;
}

