// Function to check if a sub-array is a permutation
// It checks if all numbers from 1 to 'len' are present exactly once.
// This is done by checking if the maximum element is 'len' and if all elements are distinct.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len; // All numbers from 1 to len must be present, and max must be len.
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute max prefix values
    std::vector<int> max_prefix(n);
    max_prefix[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = std::max(max_prefix[i - 1], a[i]);
    }

    // Precompute max suffix values
    std::vector<int> max_suffix(n);
    max_suffix[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i + 1], a[i]);
    }

    // Precompute distinct counts for prefixes
    std::vector<int> distinct_prefix_count(n);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_distinct_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (!seen_prefix[a[i]]) {
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        distinct_prefix_count[i] = current_distinct_prefix;
    }

    // Precompute distinct counts for suffixes
    std::vector<int> distinct_suffix_count(n);
    std::vector<bool> seen_suffix(n + 1, false);
    int current_distinct_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (!seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        distinct_suffix_count[i] = current_distinct_suffix;
    }

    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;

        // Check conditions for p1 (first l1 elements)
        // 1. Max element in p1 must be l1
        // 2. Number of distinct elements in p1 must be l1
        bool p1_is_perm = (max_prefix[l1 - 1] == l1) && (distinct_prefix_count[l1 - 1] == l1);

        // Check conditions for p2 (last l2 elements)
        // 1. Max element in p2 must be l2
        // 2. Number of distinct elements in p2 must be l2
        bool p2_is_perm = (max_suffix[l1] == l2) && (distinct_suffix_count[l1] == l2);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

