int calculate_score(int n, const std::string& s) {
    if (n == 0) return 0;
    int current_score = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (i > 0 && s[i - 1] == 'W') {
                current_score += 2;
            } else {
                current_score += 1;
            }
        }
    }
    return current_score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            if (n == 0) { // Edge case for n=0, though constraints say n>=1
                std::cout << 0 << "\n";
            } else if (n == 1) {
                std::cout << 1 << "\n";
            } else {
                std::cout << 1 + (n - 1) * 2 << "\n";
            }
            continue;
        }

        if (initial_wins == 0 && k == 0) { // All L's, no changes
            std::cout << 0 << "\n";
            continue;
        }

        // If k > 0 and initial_wins == 0, we must change at least one L to W.
        // The best strategy is to change the first L to W to get 1 point,
        // then use remaining k-1 changes to extend it.
        // This is covered by the general logic below.

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        if (first_W == -1) { // All L's initially
            if (k > 0) { // Can change at least one L to W
                std::cout << 1 + (k - 1) * 2 << "\n"; // Change first L to W (1 pt), then k-1 more (2 pts each)
            } else { // k=0, all L's
                std::cout << 0 << "\n";
            }
            continue;
        }

        // Collect gaps between W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int current_score = calculate_score(n, s);
        int changes_made = 0;

        // Fill internal gaps
        for (int gap_len : gaps) {
            if (changes_made + gap_len <= k) {
                current_score += gap_len * 2 + 1; // Each L becomes W (2 pts), plus 1 for connecting two Ws
                changes_made += gap_len;
            } else {
                current_score += (k - changes_made) * 2; // Fill partially
                changes_made = k;
                break;
            }
        }

        // Fill prefix L's
        if (changes_made < k) {
            int prefix_L_count = first_W;
            int can_change = std::min(k - changes_made, prefix_L_count);
            current_score += can_change * 2;
            changes_made += can_change;
        }

        // Fill suffix L's
        if (changes_made < k) {
            int suffix_L_count = n - 1 - last_W;
            int can_change = std::min(k - changes_made, suffix_L_count);
            current_score += can_change * 2;
            changes_made += can_change;
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

