void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    long long current_sum = 0;
    long long current_xor_sum = 0;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        current_sum += a[i];
        current_xor_sum ^= a[i];
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        // We need to append elements.
        // Let S_new = current_sum + b1 + b2
        // Let X_new = current_xor_sum ^ b1 ^ b2
        // We want S_new = 2 * X_new

        // Strategy: Append two elements.
        // Let b1 = current_xor_sum
        // Let b2 = current_sum + current_xor_sum
        // This strategy is based on the observation that if we append X and S+X,
        // the new XOR sum becomes X_old ^ X_old ^ (S_old + X_old) = S_old + X_old.
        // The new sum becomes S_old + X_old + (S_old + X_old) = 2 * (S_old + X_old).
        // So, S_new = 2 * X_new.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << std::endl;
        std::cout << b1 << " " << b2 << std::endl;
    }
}

