int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int consecutive_count = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (chain[0] == 1) { // This chain starts with 1
            consecutive_count = 1;
            for (int j = 1; j < m; ++j) {
                if (chain[j] == chain[j - 1] + 1) {
                    consecutive_count++;
                } else {
                    break; // Sequence 1, 2, ..., consecutive_count is broken
                }
            }
        }
    }

    // Operations to break existing chains:
    // Each chain of length m_i requires m_i - 1 unnesting operations to break it into m_i individual dolls.
    // Total dolls = n. Total chains = k.
    // Total unnesting operations needed to break all chains into individual dolls: n - k.
    // This is because each chain of length m_i has m_i-1 nesting relationships.
    // Sum of (m_i - 1) for all k chains = (sum of m_i) - k = n - k.
    total_operations += (n - k);

    // Operations to form the target chain:
    // The target chain 1 -> 2 -> ... -> n requires n - 1 nesting operations.
    // We have already identified a prefix 1 -> 2 -> ... -> consecutive_count that is already formed.
    // So, we don't need to perform nesting operations for these consecutive_count - 1 pairs.
    // The number of nesting operations saved is (consecutive_count - 1).
    // The number of nesting operations still needed is (n - 1) - (consecutive_count - 1) = n - consecutive_count.
    total_operations += (n - consecutive_count);

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    int k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Handle friends with w_i = 1 first
    // These friends get 2 * largest available numbers
    // They should get the k largest numbers from 'a'
    // Since w is sorted, w[0]...w[k-1] are the smallest w_i values.
    // The friends with w_i = 1 should get the largest numbers.
    // So, we iterate w from largest to smallest.
    // The friends with w_i = 1 will be at the end of the sorted w array.

    int a_ptr_large = n - 1; // Pointer to the largest available number in 'a'

    // Friends with w_i = 1
    // These are the friends with w_i = 1. They should get the largest numbers.
    // Since w is sorted ascending, these are at the end of the w array.
    // We iterate w from k-1 down to 0.
    // If w[i] == 1, this friend gets a[a_ptr_large] and happiness is 2 * a[a_ptr_large].
    // Then a_ptr_large decrements.

    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_large];
            a_ptr_large--;
        } else {
            // All remaining w[i] will be > 1 because w is sorted.
            // We can break here as we've processed all w_i = 1.
            // Or, more robustly, just let the loop continue and the next block handle them.
            // For clarity, let's break and handle the rest in a separate loop.
            break; 
        }
    }

    // Handle friends with w_i > 1
    // These friends get one largest available number (as max_val) and one smallest available number (as min_val).
    // The remaining w_i - 2 numbers don't affect happiness.
    // The largest available numbers are already taken by w_i=1 friends or will be taken by these friends.
    // The smallest available numbers are taken by these friends.

    // The friends with w_i > 1 should get the remaining largest numbers as their max_val.
    // These are the remaining elements from a_ptr_large down to 0.
    // The friends with w_i > 1 should get the smallest numbers as their min_val.
    // These are elements from a_ptr_small up.

    // We iterate through w from smallest w_i to largest w_i.
    // The smallest w_i (that are > 1) should get the smallest numbers from 'a' as their min_val.
    // The largest w_i (that are > 1) should get the largest numbers from 'a' as their max_val.
    // This is already handled by the a_ptr_large.

    int a_ptr_small = 0; // Pointer to the smallest available number in 'a'

    // Iterate through w from smallest to largest.
    // These are the friends with w_i > 1.
    // They will take one number from the largest available (a_ptr_large) and one from the smallest available (a_ptr_small).
    // The w_i - 2 numbers in between are taken from a_ptr_small + 1 up to a_ptr_small + (w_i - 2).

    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_large]; // Max value for this friend
            total_happiness += a[a_ptr_small]; // Min value for this friend

            a_ptr_large--; // This largest number is used
            a_ptr_small += (w[i] - 1); // This smallest number is used, plus w[i]-2 intermediate numbers
                                       // So, a_ptr_small moves w[i]-1 positions forward.
        }
    }

    std::cout << total_happiness << std::endl;
}

