// Function to get prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // We want the largest such x.
        // This means we need to remove "just enough" factors from p to make it not divisible by q.

        std::vector<long long> q_prime_factors = get_prime_factors(q);
        long long max_x = 0;

        for (long long factor : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q
            // or until current_p is no longer divisible by 'factor'.
            // The goal is to find the largest divisor of p that is not divisible by q.
            // If p is divisible by q, we must reduce p.
            // We try reducing p by removing factors of 'factor' one by one.
            // For each prime factor 'f' of q, we find the largest 'p / f^k' such that 'p / f^k' is not divisible by q.
            // This 'p / f^k' is a candidate for max_x.

            // Calculate the highest power of 'factor' that divides q
            long long q_temp = q;
            long long q_factor_power = 1;
            while (q_temp > 0 && q_temp % factor == 0) {
                q_factor_power *= factor;
                q_temp /= factor;
            }

            // Now, we need to find the largest x = p / (factor^k) such that x % q != 0.
            // This means we need to remove enough factors of 'factor' from p such that
            // the remaining number is not divisible by q.
            // The smallest number of 'factor's to remove from p to make it not divisible by q
            // is such that the power of 'factor' in x is less than the power of 'factor' in q.
            // If p is divisible by q, then p has at least as many factors of 'factor' as q.
            // We want to remove just enough 'factor's from p.
            // The number of 'factor's to remove is (power of 'factor' in p) - (power of 'factor' in q) + 1.
            // Or more simply, divide p by 'factor' until p is no longer divisible by q.

            long long temp_x = p;
            while (temp_x % q == 0) {
                temp_x /= factor;
            }
            max_x = std::max(max_x, temp_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

