#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate constraints based on s[i] == s[i+k]
    // For each i, s[i] must be equal to s[i+k], s[i+2k], etc.
    // This means all characters at indices i, i+k, i+2k, ... must be the same.
    // We can iterate through the first k characters and determine the required character
    // for each "k-chain".
    for (int i = 0; i < k; ++i) {
        char required_char = '?';
        for (int j = i; j < n; j += k) {
            if (s[j] != '?') {
                if (required_char == '?') {
                    required_char = s[j];
                } else if (required_char != s[j]) {
                    // Conflict: s[j] is '0' but required_char is '1', or vice versa.
                    // Impossible to make k-balanced.
                    std::cout << "NO\n";
                    return;
                }
            }
        }
        // If a required_char was found, update all '?' in this k-chain.
        if (required_char != '?') {
            for (int j = i; j < n; j += k) {
                s[j] = required_char;
            }
        }
    }

    // Step 2: Check if the first k characters can form a k-balanced substring.
    // After propagation, the first k characters s[0...k-1] are either '0', '1', or '?'.
    // We need to count '0's, '1's, and '?'s in s[0...k-1].
    int zeros = 0;
    int ones = 0;
    int questions = 0;
    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            zeros++;
        } else if (s[i] == '1') {
            ones++;
        } else {
            questions++;
        }
    }

    // We need k/2 zeros and k/2 ones in the first k characters.
    // The number of '0's must be <= k/2.
    // The number of '1's must be <= k/2.
    // The remaining '?'s must be able to fill the gaps.
    if (zeros > k / 2 || ones > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // The number of '?'s that must become '0' is (k/2 - zeros).
    // The number of '?'s that must become '1' is (k/2 - ones).
    // The sum of these must be equal to the total number of '?'s.
    if ((k / 2 - zeros) + (k / 2 - ones) == questions) {
        std::cout << "YES\n";
    } else {
        // This case should ideally be covered by the previous checks,
        // but as a safeguard, if the counts don't add up, it's impossible.
        // For example, if zeros=0, ones=0, questions=k, then (k/2 - 0) + (k/2 - 0) = k == questions. YES.
        // If zeros=k/2, ones=0, questions=k/2, then (k/2 - k/2) + (k/2 - 0) = k/2 == questions. YES.
        // If zeros=k/2-1, ones=k/2-1, questions=2, then (1) + (1) = 2 == questions. YES.
        // This condition is implicitly true if zeros <= k/2 and ones <= k/2,
        // because zeros + ones + questions = k, and we need zeros_final + ones_final = k.
        // zeros_final = zeros + q0, ones_final = ones + q1, where q0+q1 = questions.
        // We need zeros + q0 = k/2 and ones + q1 = k/2.
        // q0 = k/2 - zeros, q1 = k/2 - ones.
        // So, (k/2 - zeros) + (k/2 - ones) must equal questions.
        // This is equivalent to k - (zeros + ones) == questions.
        // Since zeros + ones + questions = k, this is always true if zeros <= k/2 and ones <= k/2.
        // So, the previous two checks (zeros > k/2 || ones > k/2) are sufficient.
        // This else branch should theoretically not be reached if the logic is sound.
        std::cout << "NO\n"; // Fallback, though likely redundant.
    }
}

