int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> d(n);
    std::deque<int> q;

    // Initialize d_i with min(h_i, i+1, n-i)
    // This is the distance from the "outer" boundaries (left, right, bottom)
    for (int i = 0; i < n; ++i) {
        d[i] = std::min({h[i], (long long)i + 1, (long long)n - i});
        q.push_back(i);
    }

    // Propagate minimums from left to right
    // d[i] cannot be more than d[i-1] + 1
    for (int i = 1; i < n; ++i) {
        d[i] = std::min(d[i], d[i - 1] + 1);
    }

    // Propagate minimums from right to left
    // d[i] cannot be more than d[i+1] + 1
    for (int i = n - 2; i >= 0; --i) {
        d[i] = std::min(d[i], d[i + 1] + 1);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, d[i]);
    }

    std::cout << max_ops << std::endl;

    return 0;
}

