#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_diff = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Calculate prefix sums for the left part (jars 1 to n)
    // diff_L[k] = (count of 1s - count of 2s) in jars 1 to k
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            diff_L[i + 1] = diff_L[i] + 1;
        } else {
            diff_L[i + 1] = diff_L[i] - 1;
        }
    }

    // Calculate suffix sums for the right part (jars n+1 to 2n)
    // diff_R[k] = (count of 1s - count of 2s) in jars k to 2n
    // We store this as a map from diff value to the number of jars removed from the right.
    // The number of jars removed from the right is (2n - k + 1).
    // Or, more simply, diff_R[k] is the diff for the first k jars from the right.
    // So, diff_R[0] is for 0 jars removed from right (all 2n-n jars kept)
    // diff_R[1] is for 1 jar removed from right (2n-n-1 jars kept)
    // ...
    // diff_R[k] is for k jars removed from right.
    std::map<int, int> right_diff_to_removed_count;
    right_diff_to_removed_count[0] = 0; // If 0 jars are removed from the right, diff is 0.

    int current_right_diff = 0;
    for (int i = 2 * n - 1; i >= n; --i) {
        if (a[i] == 1) {
            current_right_diff++;
        } else {
            current_right_diff--;
        }
        // The number of jars removed from the right is (2n - 1 - i + 1) = 2n - i.
        // This is the count of jars from index i to 2n-1.
        // The number of jars removed from the right is (2n - (i+1) + 1) = 2n - i.
        // If we remove 1 jar (a[2n-1]), then current_right_diff is for a[2n-1].
        // The number of jars removed is 1.
        // If we remove k jars from the right, the diff is for those k jars.
        // The index of the k-th jar from the right is 2n-k.
        // The number of jars removed is (2n - (i+1) + 1) = 2n - i.
        // Let's rephrase: current_right_diff is the diff of jars a[i]...a[2n-1].
        // The number of jars removed from the right is (2n - i).
        // We want to store the diff for `k` jars removed from the right.
        // These `k` jars are a[2n-k]...a[2n-1].
        // So, `current_right_diff` is the diff for `2n-i` jars.
        // We map `current_right_diff` to `2n-i`.
        right_diff_to_removed_count[current_right_diff] = (2 * n - i);
    }

    int min_removed = 2 * n; // Max possible jars to remove

    // Iterate through all possible numbers of jars removed from the left (0 to n)
    for (int k_left = 0; k_left <= n; ++k_left) {
        // diff_L[k_left] is the diff of the k_left jars removed from the left (jars 1 to k_left).
        // The remaining jars from the left part have a diff of (diff_L[n] - diff_L[k_left]).
        // The total initial diff is `initial_diff`.
        // If we remove `k_left` jars from the left, and `k_right` jars from the right,
        // the remaining jars have a total diff of `initial_diff - diff_L[k_left] - diff_R_removed_k_right`.
        // We want this total diff to be 0.
        // So, `initial_diff - diff_L[k_left] - diff_R_removed_k_right = 0`.
        // This means `diff_R_removed_k_right = initial_diff - diff_L[k_left]`.

        int target_right_diff = initial_diff - diff_L[k_left];

        if (right_diff_to_removed_count.count(target_right_diff)) {
            int k_right = right_diff_to_removed_count[target_right_diff];
            min_removed = std::min(min_removed, k_left + k_right);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits 0-9 are 1
    int current_or_mask = 0;    // All bits 0-9 are 0
    int current_xor_mask = 0;   // All bits 0-9 are 0

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    // Now we have the final state for an input of 0 (current_or_mask)
    // and an input of 1023 (current_and_mask ^ current_xor_mask)
    // Let's determine the equivalent operations.

    // For each bit position i (0 to 9):
    // Let x_i be the i-th bit of the input.
    // Let a_i be the i-th bit of current_and_mask.
    // Let o_i be the i-th bit of current_or_mask.
    // Let xor_i be the i-th bit of current_xor_mask.

    // If input bit is 0: final bit is o_i.
    // If input bit is 1: final bit is (a_i ^ xor_i).

    // We want to find A, O, X such that:
    // (0 & A | O) ^ X = o_i
    // (1 & A | O) ^ X = (a_i ^ xor_i)

    // This simplifies to:
    // (O_i) ^ X_i = o_i
    // (A_i | O_i) ^ X_i = (a_i ^ xor_i)

    // Let's find the combined A, O, X for all bits.
    int final_A = 1023; // Represents the AND constant
    int final_O = 0;    // Represents the OR constant
    int final_X = 0;    // Represents the XOR constant

    for (int i = 0; i < 10; ++i) {
        int bit_mask = (1 << i);
        int o_i = (current_or_mask & bit_mask) >> i;
        int a_i_xor_xor_i = ((current_and_mask ^ current_xor_mask) & bit_mask) >> i;

        // Case 1: If input bit is 0, output is o_i.
        // Case 2: If input bit is 1, output is a_i_xor_xor_i.

        // We need to find A_i, O_i, X_i such that:
        // (0 & A_i | O_i) ^ X_i = o_i  => O_i ^ X_i = o_i
        // (1 & A_i | O_i) ^ X_i = a_i_xor_xor_i => (A_i | O_i) ^ X_i = a_i_xor_xor_i

        // Let's analyze the 4 possible (o_i, a_i_xor_xor_i) pairs:
        if (o_i == 0 && a_i_xor_xor_i == 0) {
            // Input 0 -> 0, Input 1 -> 0
            // This means the bit is always 0, regardless of input.
            // (x & 0) | 0 ^ 0 = 0
            // So, A_i = 0, O_i = 0, X_i = 0
            final_A &= ~bit_mask; // Set A_i to 0
            // O_i remains 0
            // X_i remains 0
        } else if (o_i == 0 && a_i_xor_xor_i == 1) {
            // Input 0 -> 0, Input 1 -> 1
            // This means the bit is unchanged.
            // (x & 1) | 0 ^ 0 = x
            // So, A_i = 1, O_i = 0, X_i = 0
            // A_i remains 1
            // O_i remains 0
            // X_i remains 0
        } else if (o_i == 1 && a_i_xor_xor_i == 0) {
            // Input 0 -> 1, Input 1 -> 0
            // This means the bit is flipped.
            // (x & 1) | 0 ^ 1 = ~x
            // So, A_i = 1, O_i = 0, X_i = 1
            // A_i remains 1
            // O_i remains 0
            final_X |= bit_mask; // Set X_i to 1
        } else { // o_i == 1 && a_i_xor_xor_i == 1
            // Input 0 -> 1, Input 1 -> 1
            // This means the bit is always 1, regardless of input.
            // (x & 0) | 1 ^ 0 = 1
            // So, A_i = 0, O_i = 1, X_i = 0
            final_A &= ~bit_mask; // Set A_i to 0
            final_O |= bit_mask;  // Set O_i to 1
            // X_i remains 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If any bit of A is 0, we need an AND operation
        result_ops.push_back({'&', final_A});
    }
    if (final_O != 0) { // If any bit of O is 1, we need an OR operation
        result_ops.push_back({'|', final_O});
    }
    if (final_X != 0) { // If any bit of X is 1, we need an XOR operation
        result_ops.push_back({'^', final_X});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m ones are present, they divide the string into m+1 potential blocks of zeros.
        // To minimize the number of zero-only substrings, we distribute zeros as evenly as possible.
        // Let k be the number of zeros in each of the 'm+1' blocks.
        // There will be 'rem' blocks with (k+1) zeros and (m+1-rem) blocks with k zeros.
        // k = num_zeros / (m + 1)
        // rem = num_zeros % (m + 1)

        long long k = num_zeros / (m + 1);
        long long rem = num_zeros % (m + 1);

        // Number of blocks with (k+1) zeros
        long long blocks_k_plus_1 = rem;
        // Number of blocks with k zeros
        long long blocks_k = (m + 1) - rem;

        // Calculate the number of zero-only substrings from these blocks
        long long zero_only_substrings = 0;
        if (k > 0) {
            zero_only_substrings += blocks_k * k * (k + 1) / 2;
        }
        if (k + 1 > 0) { // This condition is always true if rem > 0 and k >= 0
            zero_only_substrings += blocks_k_plus_1 * (k + 1) * (k + 2) / 2;
        }

        // The maximum f(s) is total_substrings - minimum_zero_only_substrings
        long long max_f_s = total_substrings - zero_only_substrings;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> deletion_order(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> deletion_order[i];
        deletion_order[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process deletions in reverse order, effectively adding vertices
    for (int step = n - 1; step >= 0; --step) {
        int k = deletion_order[step]; // The vertex being "added" in this step
        active_vertices[k] = true;

        // Update shortest paths using k as an intermediate vertex
        // This is the core Floyd-Warshall step
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After updating with k, also update paths between existing active vertices
        // using k as an intermediate. This is crucial because k might connect
        // two previously active vertices more efficiently.
        // The previous loop already did this for all i,j.
        // Now, we need to ensure all pairs of currently active vertices are updated
        // using any other currently active vertex as an intermediate.
        // Since we are adding vertices one by one, and updating dist[i][j] for all i,j
        // using the newly added vertex k, the dist matrix will always contain
        // shortest paths considering all vertices up to k.
        // So, we just need to sum up for currently active vertices.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j]) {
                        current_sum += dist[i][j];
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, before x_2, ..., before x_n)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

