    //    This is a multiple of n.
    //    So for 0 <= i < n-1, we add ((a[i] % n + n) % n) * (n-1) to a[i].

    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        long long rem = (a[i] % n + n) % n;
        long long add_val = rem * (n - 1); // This is a multiple of (n-1)
        // No, this is not a multiple of n.
