    //    Segment [1, n]. Length = n.
    //    For each a[i], we want to add b_i such that b_i is a multiple of n, and a[i] + b_i = 0.
    //    This is possible because a[i] is already a multiple of n.
    //    So b_i = -a[i].

    // Let's refine this strategy for n > 1:

    // Operation 1: For elements a[0]...a[n-2]
    // Segment: [1, n-1] (1-indexed)
    // Length: n-1
    // For each a[i] (0 <= i < n-1), we want to add b_i such that b_i is a multiple of (n-1)
    // and a[i] + b_i becomes a multiple of n.
    // Let current_a_i = a[i].
    // We need to find b_i = m * (n-1) such that (current_a_i + b_i) % n == 0.
    // (current_a_i + m * (n-1)) % n == 0
    // (current_a_i - m) % n == 0
    // So m % n == current_a_i % n.
    // Let m = (current_a_i % n + n) % n.
    // Then b_i = m * (n-1).
    // This b_i is a multiple of (n-1).
    // And current_a_i + b_i will be a multiple of n.

    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long rem = (a[i] % n + n) % n; // a[i] mod n, always non-negative
        long long add_val = rem * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val; // Update a[i]
    }
    std::cout << "\n";

    // Operation 2: For element a[n-1]
    // Segment: [n, n] (1-indexed)
    // Length: 1
    // We want to add b_{n-1} such that b_{n-1} is a multiple of 1, and a[n-1] + b_{n-1} becomes 0.
    // This is always possible: b_{n-1} = -a[n-1].
    std::cout << n << " " << n << "\n";
    std::cout << -a[n - 1] << "\n";
    a[n - 1] = 0; // Update a[n-1]

    // Operation 3: For all elements a[0]...a[n-1]
    // Segment: [1, n] (1-indexed)
    // Length: n
    // Now, a[0]...a[n-2] are all multiples of n (from Op 1).
    // And a[n-1] is 0 (from Op 2), which is also a multiple of n.
    // So all a[i] are multiples of n.
    // For each a[i], we want to add b_i such that b_i is a multiple of n, and a[i] + b_i = 0.
    // This is possible: b_i = -a[i]. Since a[i] is a multiple of n, -a[i] is also a multiple of n.
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones(n, -1); // Stores the index of the nearest 1 to the left (inclusive)
    std::vector<int> right_ones(n, -1); // Stores the index of the nearest 1 to the right (inclusive)

    int last_one = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            last_one = i;
        }
        left_ones[i] = last_one;
    }

    last_one = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            last_one = i;
        }
        right_ones[i] = last_one;
    }

    int max_dist = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int dist_left = (left_ones[i] == -1) ? n : (i - left_ones[i]);
            int dist_right = (right_ones[i] == -1) ? n : (right_ones[i] - i);
            max_dist = std::max(max_dist, std::min(dist_left, dist_right));
        }
    }

    int k = (max_dist + 1) / 2;

    std::vector<int> final_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) {
            int dist_left = (left_ones[i] == -1) ? n : (i - left_ones[i]);
            int dist_right = (right_ones[i] == -1) ? n : (right_ones[i] - i);

            if (dist_left <= k && dist_right <= k) {
                // This 0 is between two 1s, and both are within k steps.
                // It will become 1.
                final_a[i] = 1;
            } else if (dist_left <= k && dist_right > k) {
                // This 0 is closer to a 1 on the left, and far from any 1 on the right.
                // It will become 0.
                final_a[i] = 0;
            } else if (dist_left > k && dist_right <= k) {
                // This 0 is closer to a 1 on the right, and far from any 1 on the left.
                // It will become 0.
                final_a[i] = 0;
            } else { // dist_left > k && dist_right > k
                // This 0 is far from any 1 on both sides.
                // It will become 0.
                final_a[i] = 0;
            }
        }
    }

    std::cout << k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

