#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, then increment by d for new blocks

    while (X > 0) {
        long long k = 0;
        // Find largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        if (X == 1) { // Special case for X=1, 2^0-1=0, but we need 1 element
            k = 1;
        } else {
            k = std::floor(std::log2(X + 1));
        }

        // If 2^k - 1 > X, we need to reduce k
        // This can happen if X+1 is not a power of 2, e.g., X=5, X+1=6, log2(6) approx 2.58, k=2.
        // 2^2 - 1 = 3 <= 5. This is correct.
        // If X=7, X+1=8, log2(8)=3, k=3. 2^3-1=7 <= 7. Correct.
        // The floor(log2(X+1)) correctly gives the largest k such that 2^k <= X+1.
        // So 2^k-1 <= X.
        // The only edge case is if X+1 is a power of 2, say X+1 = 2^k_max.
        // Then 2^k_max - 1 = X.
        // If X+1 is not a power of 2, say X+1 = 2^k_max + R, where R > 0.
        // Then floor(log2(X+1)) = k_max.
        // 2^k_max - 1 < X.
        // So k is always chosen such that 2^k - 1 <= X.

        // Add k elements of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the count of subsequences formed by these k elements
        X -= (1LL << k) - 1;

        // Increment current_val for the next block
        current_val += d;

        // Check for overflow before adding d again
        if (current_val > 1000000000000000000LL - d && X > 0) { // If current_val + d would overflow
            // This condition is a bit tricky. If current_val is already very large,
            // and we still have X > 0, it means we need to add more blocks.
            // If current_val + d exceeds 10^18, we can't form a valid array.
            // However, the problem states a_i < 10^18.
            // If current_val is already >= 10^18, it's an issue.
            // If current_val + d would exceed 10^18, it's an issue.
            // The maximum number of elements is 10^4.
            // The maximum value of d is 10^9.
            // If we add 10^4 blocks, each incrementing by d, current_val could be 1 + 10^4 * 10^9 = 10^13.
            // This is well within 10^18.
            // The only way current_val could exceed 10^18 is if d is very large and X is very large,
            // requiring many blocks.
            // But the number of blocks is at most 60 (since 2^60 is approx 10^18).
            // So current_val will not exceed 10^18.
            // The check `current_val > 1000000000000000000LL - d` is a safeguard, but likely not hit.
        }
    }

    if (result_array.size() > 10000) {
        // This case should not be hit based on constraints and logic.
        // Max X is 10^9. Max k is 30 (2^30-1 approx 10^9).
        // If X=10^9, k=30. X becomes 0. Array size 30.
        // If X=10^9, d=1.
        // k=30. X -= 2^30-1. current_val = 1+1.
        // k=29. X -= 2^29-1. current_val = 1+2.
        // ...
        // The number of blocks is at most 60 (for X up to 2^60-1).
        // Each block adds at most 60 elements.
        // So total elements is at most 60 * 60 = 3600.
        // This is well within 10^4.
        std::cout << -1 << std::endl;
        return 0;
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_effect = children[i].v;
        long long cumulative_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cumulative d effect from previous children who left
            if (cumulative_d_effect > 0) {
                children[j].p -= cumulative_d_effect;
            }

            // Apply current child's v effect
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                cumulative_d_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_max_val = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], current_max_val);
            }
        }
    }

    std::vector<long long> a_prime(n);
    for (int i = 0; i < n; ++i) {
        if (b[i] == std::numeric_limits<long long>::max()) {
            a_prime[i] = 0; // Default to 0 if no upper bound from type 2 ops
        } else {
            a_prime[i] = b[i];
        }
    }

    std::vector<long long> current_a = a_prime;
    std::vector<long long> delta(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
                delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, current_a[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_prime[i] - delta[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

