// Using long long for y to prevent overflow, as a_i can be up to 10^9 and n up to 2*10^5.
// In the worst case, y could be n * max(a_i) * 2, which is 2*10^5 * 10^9 * 2 = 4*10^14.
// x can be up to n, so int is fine for x.

// Using a global or static array for 'a' to avoid passing it around and for potential memoization.
// Since 'a[1]' changes for each query, we can't fully memoize 'a' itself.
// However, the values a[2]...a[n] are constant.
// We can precompute results for states (x, parity) where x > 1.
// The parity matters because the operations are (x+a[x], y+a[x]) then (x-a[x], y+a[x]).
// If we land on x with a certain parity, the next step depends on that parity.
// Let's define state as (current_x, current_y, is_step2_next).
// This is too complex. The problem states "step 2, then step 3".
// So, if we are at (x, y), the next state is always (x', y') after step 2, then (x'', y'') after step 3.
// The sequence is fixed: (x,y) -> (x+a[x], y+a[x]) -> (x+a[x]-a[x+a[x]], y+a[x]+a[x+a[x]]).
// This means the state is just (x, y).

// Let's define dp[x][parity] as the pair (final_x_change, final_y_change) if starting from x
// and the next operation is 'parity' (0 for step 2, 1 for step 3).
// This is not quite right. The problem is about the total y value.
// Let dp[x] store the total y accumulated and the final x value if starting from x.
// dp[x] = {final_x, total_y_added_from_this_x_onwards}
// This is a standard dynamic programming approach on a graph where nodes are x values.
// The transitions are:
// From x, first step 2: x_new = x + a[x], y_add1 = a[x]
// Then step 3: x_final = x_new - a[x_new], y_add2 = a[x_new]
// Total y added in one cycle: a[x] + a[x_new]
// Final x after one cycle: x_new - a[x_new]

// We need to compute this for each starting i (which becomes a[1]).
// The values a[2]...a[n] are fixed.
// So, we can compute dp values for x from 2 to n.
// dp[x] = {final_x, total_y}
// If x + a[x] > n or x + a[x] <= 0, then the program terminates after step 2.
//   Result: {x + a[x], a[x]}
// Else, let x_next = x + a[x].
//   If x_next - a[x_next] > n or x_next - a[x_next] <= 0, then terminates after step 3.
//     Result: {x_next - a[x_next], a[x] + a[x_next]}
//   Else, let x_final = x_next - a[x_next].
//     Result: {dp[x_final].final_x, a[x] + a[x_next] + dp[x_final].total_y}

// This is a recursive definition. We can compute it iteratively from n down to 2.
// dp[x] will store a pair: {final_x_after_termination, total_y_accumulated_from_x_onwards}.
// If it never terminates, we can use a special value like -1 for final_x.

struct Result {
    long long final_x; // The x value when it terminates. If -1, it means infinite loop.
    long long total_y; // The total y accumulated from this point until termination.
};

std::vector<long long> a_values;
std::vector<Result> dp;
std::vector<bool> visited; // To detect cycles for x >= 2
std::vector<bool> in_recursion_stack; // To detect cycles during DP calculation

int N;

Result calculate_dp(int current_x) {
    if (current_x <= 0 || current_x > N) {
        return {current_x, 0}; // Base case: already terminated
    }

    if (visited[current_x]) {
        if (in_recursion_stack[current_x]) {
            // Cycle detected, this path leads to infinite loop
            return {-1, -1};
        }
        // Already computed
        return dp[current_x];
    }

    visited[current_x] = true;
    in_recursion_stack[current_x] = true;

    long long val_ax = a_values[current_x];

    // Step 2: x = x + a[x], y = y + a[x]
    long long x_after_step2 = current_x + val_ax;
    long long y_added_step2 = val_ax;

    if (x_after_step2 <= 0 || x_after_step2 > N) {
        in_recursion_stack[current_x] = false;
        return dp[current_x] = {x_after_step2, y_added_step2};
    }

    long long val_ax_after_step2 = a_values[x_after_step2];

    // Step 3: y = y + a[x_after_step2], x = x_after_step2 - a[x_after_step2]
    long long x_after_step3 = x_after_step2 - val_ax_after_step2;
    long long y_added_step3 = val_ax_after_step2;

    // Recursively calculate for the next state
    Result next_result = calculate_dp(x_after_step3);

    in_recursion_stack[current_x] = false;

    if (next_result.final_x == -1) {
        // Infinite loop detected further down the path
        return dp[current_x] = {-1, -1};
    } else {
        return dp[current_x] = {next_result.final_x, y_added_step2 + y_added_step3 + next_result.total_y};
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_values.resize(N + 1);
    dp.resize(N + 1);
    visited.resize(N + 1, false);
    in_recursion_stack.resize(N + 1, false);

    for (int i = 2; i <= N; ++i) {
        std::cin >> a_values[i];
    }

    // Precompute DP for x from 2 to N
    // This is done by calling calculate_dp for each x from 2 to N.
    // The recursive calls will fill the dp table.
    for (int i = 2; i <= N; ++i) {
        if (!visited[i]) {
            calculate_dp(i);
        }
    }

    // Now, for each query i (1 to N-1), set a_values[1] = i and run the simulation.
    for (int i = 1; i < N; ++i) {
        a_values[1] = i;

        long long current_x = 1;
        long long current_y = 0;

        long long val_ax = a_values[current_x];

        // Step 2: x = x + a[x], y = y + a[x]
        long long x_after_step2 = current_x + val_ax;
        long long y_added_step2 = val_ax;

        if (x_after_step2 <= 0 || x_after_step2 > N) {
            std::cout << y_added_step2 << "\n";
            continue;
        }

        long long val_ax_after_step2 = a_values[x_after_step2];

        // Step 3: y = y + a[x_after_step2], x = x_after_step2 - a[x_after_step2]
        long long x_after_step3 = x_after_step2 - val_ax_after_step2;
        long long y_added_step3 = val_ax_after_step2;

        // Now, we are at x_after_step3 with y_added_step2 + y_added_step3 accumulated.
        // We can use the precomputed DP table for x_after_step3.
        Result res = calculate_dp(x_after_step3); // This will use the precomputed values for x >= 2

        if (res.final_x == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << y_added_step2 + y_added_step3 + res.total_y << "\n";
        }
    }

    return 0;
}

