// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k = 1 (2 pieces)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string s_new = s_suffix + s_prefix;

        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (3 pieces)
    // If n is odd, and all characters are the same, then k=2 is impossible.
    // Example: "aaaaa". Any cut and reassembly will result in "aaaaa".
    // If n is even, and all characters are the same, then k=1 is impossible, k=2 is impossible.
    // Example: "aaaa". Any cut and reassembly will result in "aaaa".
    // This check covers the "qqqq" case and similar.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If we reach here, it means k=1 didn't work.
    // The problem statement guarantees s is a palindrome.
    // If not all characters are the same, and n > 1,
    // it's always possible to make 2 cuts to form a new palindrome.
    // Consider s = "abacaba".
    // Cut 1: "a" | "bacab" | "a" -> "abacaba" (original)
    // Cut 2: "a" | "b" | "acaba" -> "acabaab" (not palindrome)
    //
    // The logic for k=2 is that if the string is not composed of all identical characters,
    // and it's a palindrome, then it must be possible to find a new palindrome with 2 cuts.
    //
    // Example: "nolon" (n=5)
    // s[0] = 'n', s[1] = 'o', s[2] = 'l', s[3] = 'o', s[4] = 'n'
    // Not all same char.
    // k=1 attempts:
    // "o" + "noln" -> "onoln" (not palindrome)
    // "ol" + "non" -> "olnon" (not palindrome)
    // "olo" + "nn" -> "olonn" (not palindrome)
    // "olon" + "n" -> "olonn" (not palindrome)
    //
    // For k=2, we can always achieve a new palindrome if not all characters are the same.
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    //
    // If n is odd, say n = 2m + 1.
    // s = c_0 c_1 ... c_{m-1} c_m c_{m-1} ... c_1 c_0
    // If we cut it into s[0...m-1] | s[m] | s[m+1...n-1]
    // Let P1 = s[0...m-1], P2 = s[m], P3 = s[m+1...n-1]
    // P1 = s.substr(0, m)
    // P2 = s.substr(m, 1)
    // P3 = s.substr(m+1)
    //
    // Example "nolon", n=5, m=2
    // P1 = "no", P2 = "l", P3 = "on"
    // Rearrange to P3 + P2 + P1 = "on" + "l" + "no" = "onlno"
    // "onlno" is a palindrome and "onlno" != "nolon".
    // This works because P3 is the reverse of P1.
    //
    // If n is even, say n = 2m.
    // s = c_0 c_1 ... c_{m-1} c_{m-1} ... c_1 c_0
    // If we cut it into s[0...m-1] | s[m...n-1]
    // This is a k=1 cut. We already checked this.
    //
    // The problem states that if k=1 doesn't work, and not all characters are the same,
    // then k=2 is the answer.
    // The only case where it's impossible is when all characters are the same.
    //
    // So, if we haven't returned yet, it means k=1 didn't work, and not all characters are the same.
    // This implies k=2 is the answer.
    std::cout << 2 << std::endl;

    return 0;
}

