    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    long long min_goodness = goodness1;
    std::fill(partition.begin(), partition.end(), 1); // Default to all 1s

    // Case 2: a_1 and a_2 are in different subsequences.
    // This implies min_f = a_1 + a_2 + h.
    // To minimize max_f, we want a_{n-1} and a_n to be in the same subsequence.
    // If a_1 and a_2 are different, and a_{n-1} and a_n are same,
    // then max_f = a_{n-1} + a_n.
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2 + h)
    // This strategy is only possible if n >= 2.
    // We can achieve this by putting a_1 in subseq 1, a_2 in subseq 2,
    // and all other elements (a_3 to a_n) in subseq 2.
    // This ensures a_1 and a_2 are different.
    // It also ensures a_2, ..., a_n are in the same subsequence (subseq 2),
    // so a_{n-1} and a_n are in the same subsequence.
    // The minimum f value will be a_1 + a_2 + h.
    // The maximum f value will be a_{n-1} + a_n.
    // The other possible max f values are a_1 + a_k + h for k > 2.
    // The largest of these is a_1 + a_n + h.
    // So max_f = std::max(a_{n-1} + a_n, a_1 + a_n + h).
    // This is not quite right.
    // If a_1 is in subseq 1, and a_2, ..., a_n are in subseq 2:
    // min_f = a_1 + a_2 + h
    // max_f = std::max(a_1 + a_n + h, a_{n-1} + a_n)
    // goodness = max_f - min_f
    // This is the strategy where a_1 is separated from the rest.
    // The minimum value of f is a_1 + a_2 + h (a_1 and a_2 are different).
    // The maximum value of f is max(a_1 + a_n + h, a_{n-1} + a_n).
    // The goodness is max(a_1 + a_n + h, a_{n-1} + a_n) - (a_1 + a_2 + h).
    // This simplifies to max(a_n - a_2, a_{n-1} + a_n - a_1 - a_2 - h).
    // No, it's max(a_1 + a_n + h - (a_1 + a_2 + h), a_{n-1} + a_n - (a_1 + a_2 + h))
    // = max(a_n - a_2, a_{n-1} + a_n - a_1 - a_2 - h).
    // This is the goodness for the partition where a_1 is in one group and all others are in another.
    // Let's call this strategy "split_a1".
    long long min_f_split_a1 = elements[0].value + elements[1].value + h;
    long long max_f_split_a1 = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 1].value + elements[n - 2].value);
    long long goodness_split_a1 = max_f_split_a1 - min_f_split_a1;

    if (goodness_split_a1 < min_goodness) {
        min_goodness = goodness_split_a1;
        partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition[elements[i].original_index] = 2;
        }
    }

    // Case 3: a_1 and a_2 are in the same subsequence.
    // This implies min_f = a_1 + a_2.
    // To minimize max_f, we want a_{n-1} and a_n to be in different subsequences.
    // This can be achieved by putting a_n in subseq 1, and all other elements (a_1 to a_{n-1}) in subseq 2.
    // This ensures a_1 and a_2 are in the same subsequence (subseq 2).
    // It also ensures a_{n-1} and a_n are in different subsequences.
    // The minimum f value will be a_1 + a_2.
    // The maximum f value will be max(a_{n-1} + a_n + h, a_{n-1} + a_{n-2}).
    // No, it's max(a_1 + a_n + h, a_{n-1} + a_n + h, a_{n-2} + a_{n-1}).
    // The maximum f value will be max(a_{n-1} + a_n + h, a_{n-1} + a_{n-2}).
    // This is the strategy where a_n is separated from the rest.
    // Let's call this strategy "split_an".
    long long min_f_split_an = elements[0].value + elements[1].value;
    long long max_f_split_an = std::max(elements[n - 1].value + elements[n - 2].value + h, elements[n - 2].value + elements[n - 3].value);
    // This is only valid if n >= 3. If n=2, a_{n-3} is invalid.
    // If n=2, elements are a_1, a_2.
    // split_an: a_2 in subseq 1, a_1 in subseq 2.
    // min_f = a_1 + a_2 + h (a_1 and a_2 are different)
    // max_f = a_1 + a_2 + h
    // goodness = 0.
    // This is covered by split_a1 for n=2.
    // For n=2, split_a1: a_1 in subseq 1, a_2 in subseq 2.
    // min_f = a_1 + a_2 + h
    // max_f = a_1 + a_2 + h
    // goodness = 0.
    // So for n=2, min_goodness is 0.
    // The initial goodness1 for n=2 is (a_1+a_2)-(a_1+a_2) = 0.
    // So for n=2, all strategies yield 0.

    if (n >= 3) {
        long long goodness_split_an = max_f_split_an - min_f_split_an;
        if (goodness_split_an < min_goodness) {
            min_goodness = goodness_split_an;
            partition[elements[n - 1].original_index] = 1;
            for (int i = 0; i < n - 1; ++i) {
                partition[elements[i].original_index] = 2;
            }
        }
    }

    // Case 4: a_1 and a_n are in different subsequences.
    // This implies min_f = a_1 + a_2 (if a_1, a_2 same) or a_1 + a_2 + h (if a_1, a_2 different).
    // And max_f = a_{n-1} + a_n + h (if a_{n-1}, a_n different) or a_{n-1} + a_n (if a_{n-1}, a_n same).
    // The key observation is that the minimum possible value of f is either a_1 + a_2 or a_1 + a_2 + h.
    // The maximum possible value of f is either a_{n-1} + a_n or a_{n-1} + a_n + h.
    //
    // Let's consider the four critical values:
    // v1 = a_1 + a_2
    // v2 = a_1 + a_2 + h
    // v3 = a_{n-1} + a_n
    // v4 = a_{n-1} + a_n + h
    //
    // The actual min_f will be either v1 or v2.
    // The actual max_f will be either v3 or v4.
    //
    // If we put all elements in one group (e.g., all 1s):
    // min_f = v1, max_f = v3. Goodness = v3 - v1. (This is goodness1)
    //
    // If we put a_1 in group 1, and all others in group 2:
    // min_f = v2 (a_1 and a_2 are different)
    // max_f = max(a_1 + a_n + h, v3) (a_1 and a_n are different, a_{n-1} and a_n are same)
    // Goodness = max(a_1 + a_n + h, v3) - v2. (This is goodness_split_a1)
    //
    // If we put a_n in group 1, and all others in group 2:
    // min_f = v1 (a_1 and a_2 are same)
    // max_f = max(a_1 + a_n + h, v4) (a_1 and a_n are different, a_{n-1} and a_n are different)
    // Goodness = max(a_1 + a_n + h, v4) - v1. (This is goodness_split_an, but the max_f was wrong)
    // Let's re-evaluate split_an:
    // a_n in group 1, a_1, ..., a_{n-1} in group 2.
    // min_f: a_1 and a_2 are in group 2, so a_1 + a_2.
    // max_f:
    //   - a_i, a_j in group 2: max is a_{n-2} + a_{n-1}.
    //   - a_i in group 2, a_n in group 1: max is a_{n-1} + a_n + h.
    // So max_f = std::max(elements[n-2].value + elements[n-3].value, elements[n-1].value + elements[n-2].value + h);
    // This is for n >= 3.
    //
    // Let's re-evaluate goodness_split_an for n >= 3:
    // min_f = elements[0].value + elements[1].value;
    // max_f = std::max(elements[n-2].value + elements[n-3].value, elements[n-1].value + elements[n-2].value + h);
    // goodness = max_f - min_f;
    // This was already done.

    // The crucial case is when h is small.
    // If h is small, we want to avoid adding h to many pairs.
    // If h is large, we want to add h to as few pairs as possible, ideally 0.
    // If h is large, the best strategy is often to put all elements in one group,
    // so no pair gets +h. This gives goodness1.
    // Or, if n=2, put a_1 in group 1, a_2 in group 2. Then f(a_1, a_2) = a_1+a_2+h.
    // min_f = a_1+a_2+h, max_f = a_1+a_2+h. Goodness = 0.
    // This is covered by goodness_split_a1 for n=2.

    // Consider the case where a_1, a_n are in different groups.
    // And a_2, a_{n-1} are in the same group as a_1 or a_n.
    //
    // Let's consider the four critical values:
    // min_val_same = elements[0].value + elements[1].value
    // max_val_same = elements[n-1].value + elements[n-2].value
    // min_val_diff = elements[0].value + elements[1].value + h
    // max_val_diff = elements[n-1].value + elements[n-2].value + h
    //
    // The actual min_f will be one of {elements[0].value + elements[1].value, elements[0].value + elements[1].value + h}.
    // The actual max_f will be one of {elements[n-1].value + elements[n-2].value, elements[n-1].value + elements[n-2].value + h, elements[0].value + elements[n-1].value + h}.
    //
    // The key is that the minimum possible value of f is always `elements[0].value + elements[1].value` (if they are in the same group)
    // or `elements[0].value + elements[1].value + h` (if they are in different groups).
    // The maximum possible value of f is always `elements[n-1].value + elements[n-2].value` (if they are in the same group)
    // or `elements[n-1].value + elements[n-2].value + h` (if they are in different groups).
    //
    // What if we put elements[0] in group 1, elements[1]...elements[n-2] in group 2, elements[n-1] in group 1?
    // This means elements[0] and elements[n-1] are in group 1.
    // elements[1] and elements[n-2] are in group 2.
    //
    // min_f: elements[1] + elements[2] (same group 2)
    // max_f: elements[0] + elements[n-1] (same group 1)
    //        elements[0] + elements[1] + h (different groups)
    //        elements[n-1] + elements[1] + h (different groups)
    //        elements[n-2] + elements[n-3] (same group 2)
    //
    // This is getting complicated. Let's simplify.
    // The minimum possible value of f is `elements[0].value + elements[1].value`.
    // The maximum possible value of f is `elements[n-1].value + elements[0].value + h`.
    //
    // Consider the four values:
    // A = elements[0].value + elements[1].value
    // B = elements[0].value + elements[1].value + h
    // C = elements[n-2].value + elements[n-1].value
    // D = elements[n-2].value + elements[n-1].value + h
    // E = elements[0].value + elements[n-1].value + h
    //
    // The minimum f value for any partition is at least A.
    // The maximum f value for any partition is at most D.
    //
    // The goodness is `max_f - min_f`.
    //
    // Option 1: All elements in one group (e.g., all 1s).
    // min_f = A
    // max_f = C
    // Goodness = C - A. (This is `goodness1`)
    //
    // Option 2: elements[0] in group 1, all others in group 2.
    // min_f = B (elements[0] and elements[1] are different)
    // max_f = std::max(C, E) (elements[n-2] and elements[n-1] are same, elements[0] and elements[n-1] are different)
    // Goodness = std::max(C, E) - B. (This is `goodness_split_a1`)
    //
    // Option 3: elements[n-1] in group 1, all others in group 2. (Requires n >= 2)
    // min_f = A (elements[0] and elements[1] are same)
    // max_f = std::max(elements[n-3].value + elements[n-2].value, elements[n-2].value + elements[n-1].value + h)
    // (elements[n-3] and elements[n-2] are same, elements[n-2] and elements[n-1] are different)
    // Goodness = max_f - A. (This is `goodness_split_an`)
    //
    // The problem states that `h` is non-negative.
    //
    // Let's consider the case where `h` is very large.
    // In this case, we want to avoid `+h` terms if possible.
    // The best strategy is to put all elements in one group.
    // This gives `goodness1 = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)`.
    //
    // What if `h` is small?
    // Consider the partition where `elements[0]` is in group 1, and `elements[1]` is in group 2.
    // And `elements[n-1]` is in group 1, `elements[n-2]` is in group 2.
    //
    // Let's try a specific partition:
    // Put `elements[0]` in group 1.
    // Put `elements[n-1]` in group 1.
    // Put all other elements (`elements[1]` to `elements[n-2]`) in group 2.
    // This partition is valid if n >= 2.
    // If n=2: elements[0] in group 1, elements[1] in group 1.
    //   min_f = elements[0].value + elements[1].value
    //   max_f = elements[0].value + elements[1].value
    //   goodness = 0. (This is covered by goodness1)
    // If n=3: elements[0] in group 1, elements[2] in group 1, elements[1] in group 2.
    //   Pairs in same group: (elements[0], elements[2])
    //   Pairs in different groups: (elements[0], elements[1]), (elements[1], elements[2])
    //   min_f = elements[0].value + elements[1].value + h
    //   max_f = std::max(elements[0].value + elements[2].value, elements[1].value + elements[2].value + h)
    //   Goodness = max_f - min_f.
    //   Example 1: 3 2, 1 2 3. Sorted: 1 2 3. h=2.
    //   elements[0]=1, elements[1]=2, elements[2]=3.
    //   Partition: 1 in G1, 3 in G1, 2 in G2.
    //   f(1,2) = 1+2+2 = 5 (diff groups)
    //   f(1,3) = 1+3 = 4 (same group)
    //   f(2,3) = 2+3+2 = 7 (diff groups)
    //   min_f = 4, max_f = 7. Goodness = 3.
    //   The sample output gives goodness 1.
    //   Sample output partition: 1 2 2.
    //   1 in G1, 2 in G2, 3 in G2.
    //   f(1,2) = 1+2+2 = 5 (diff groups)
    //   f(1,3) = 1+3+2 = 6 (diff groups)
    //   f(2,3) = 2+3 = 5 (same group)
    //   min_f = 5, max_f = 6. Goodness = 1.
    //   This is exactly the "split_a1" strategy (elements[0] in G1, rest in G2).
    //   Let's re-check my calculation for goodness_split_a1 for sample 1:
    //   elements[0]=1, elements[1]=2, elements[2]=3, h=2.
    //   min_f_split_a1 = elements[0].value + elements[1].value + h = 1 + 2 + 2 = 5.
    //   max_f_split_a1 = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 1].value + elements[n - 2].value)
    //                  = std::max(1 + 3 + 2, 3 + 2) = std::max(6, 5) = 6.
    //   goodness_split_a1 = 6 - 5 = 1.
    //   This matches the sample output. So `goodness_split_a1` is correct.

    // What about the case where `elements[0]` and `elements[n-1]` are in the same group?
    // And `elements[1]` and `elements[n-2]` are in the other group.
    // This is the "split_a1_an_together" strategy.
    // Partition: elements[0] and elements[n-1] in group 1.
    // All other elements (elements[1] to elements[n-2]) in group 2.
    // This requires n >= 4 for elements[1] and elements[n-2] to be distinct and in group 2.
    // If n=2, elements[0], elements[1] in group 1. Goodness 0. (Covered by goodness1)
    // If n=3, elements[0], elements[2] in group 1. elements[1] in group 2.
    //   min_f: elements[0]+elements[1]+h (diff), elements[1]+elements[2]+h (diff)
    //          elements[0]+elements[2] (same)
    //   So min_f = elements[0].value + elements[2].value.
    //   max_f: elements[0]+elements[1]+h, elements[1]+elements[2]+h.
    //   So max_f = elements[1].value + elements[2].value + h.
    //   Goodness = (elements[1].value + elements[2].value + h) - (elements[0].value + elements[2].value)
    //            = elements[1].value - elements[0].value + h.
    //   For sample 1 (1 2 3, h=2): (2 - 1 + 2) = 3.
    //   This is worse than 1.

    // The problem boils down to considering the minimum and maximum possible values of f.
    // The minimum possible value of `a_i + a_j` is `elements[0].value + elements[1].value`.
    // The maximum possible value of `a_i + a_j` is `elements[n-1].value + elements[n-2].value`.
    //
    // Let `min_sum = elements[0].value + elements[1].value`.
    // Let `max_sum = elements[n-1].value + elements[n-2].value`.
    //
    // The possible values of f are in the range `[min_sum, max_sum + h]`.
    //
    // We need to find a partition that minimizes `max(f) - min(f)`.
    //
    // Consider the four boundary values:
    // `f_min_same = elements[0].value + elements[1].value`
    // `f_min_diff = elements[0].value + elements[1].value + h`
    // `f_max_same = elements[n-1].value + elements[n-2].value`
    // `f_max_diff = elements[n-1].value + elements[n-2].value + h`
    //
    // Also, `elements[0].value + elements[n-1].value + h` is a potential max_f if elements[0] and elements[n-1] are in different groups.
    //
    // The optimal partition will likely involve separating `elements[0]` or `elements[n-1]` from the rest, or keeping all together.
    //
    // Let's re-evaluate the three main strategies:
    //
    // Strategy A: All elements in one group (e.g., all 1s).
    //   min_f = elements[0].value + elements[1].value
    //   max_f = elements[n-1].value + elements[n-2].value
    //   Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    //   This is `goodness1`.

    // Strategy B: elements[0] in group 1, all others in group 2.
    //   min_f = elements[0].value + elements[1].value + h (because elements[0] and elements[1] are different)
    //   max_f = std::max(elements[n-1].value + elements[n-2].value, // elements[n-1], elements[n-2] are same (group 2)
    //                    elements[0].value + elements[n-1].value + h) // elements[0], elements[n-1] are different
    //   Goodness = max_f - min_f. (This is `goodness_split_a1`)

    // Strategy C: elements[n-1] in group 1, all others in group 2. (Requires n >= 2)
    //   min_f = elements[0].value + elements[1].value (because elements[0] and elements[1] are same)
    //   max_f = std::max(elements[n-2].value + elements[n-3].value, // elements[n-2], elements[n-3] are same (group 2)
    //                    elements[n-1].value + elements[n-2].value + h) // elements[n-1], elements[n-2] are different
    //   This is for n >= 3.
    //   If n=2: elements[0] in group 2, elements[1] in group 1.
    //     min_f = elements[0].value + elements[1].value + h
    //     max_f = elements[0].value + elements[1].value + h
    //     Goodness = 0.
    //   This is the same as Strategy B for n=2.
    //   So, for n >= 3, `goodness_split_an` is calculated as:
    //   min_f = elements[0].value + elements[1].value;
    //   max_f = std::max(elements[n-2].value + elements[n-3].value, elements[n-1].value + elements[n-2].value + h);
    //   Goodness = max_f - min_f.

    // The three strategies cover the most likely candidates for optimal partitions.
    // The logic for `goodness_split_a1` and `goodness_split_an` seems correct now.

    // Final check for n=2:
    // elements[0], elements[1].
    // goodness1: (elements[1].value + elements[0].value) - (elements[0].value + elements[1].value) = 0.
    // min_goodness = 0. partition = {1, 1}.
    //
    // goodness_split_a1:
    // min_f = elements[0].value + elements[1].value + h
    // max_f = std::max(elements[1].value + elements[0].value, elements[0].value + elements[1].value + h)
    //       = elements[0].value + elements[1].value + h
    // goodness = 0.
    // This is also 0.
    // So for n=2, any partition gives goodness 0. The code correctly handles this.

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    if (n < 3) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // min_r[i] stores the minimum r such that the substring s[i...r] contains a valid triplet.
    // If no such r exists for a given i, min_r[i] will remain n+1.
    std::vector<int> min_r(n, n + 1);

    // Iterate through all possible starting positions x for a triplet (0-indexed)
    for (int x = 0; x < n; ++x) {
        // Iterate through all possible common differences k
        // The condition is x + 2k < n, so 2k < n - x, k < (n - x) / 2
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a valid triplet (x, x+k, x+2k)
                // The rightmost index of this triplet is x + 2k.
                // For any l <= x, the minimum r required to contain this triplet is x + 2k.
                // We want to find the minimum r for each l.
                // So, for l = x, the minimum r is x + 2k.
                // For l = x-1, the minimum r is also x + 2k (if x-1 is valid).
                // This means min_r[l] should be updated with min(min_r[l], x + 2k) for all l <= x.
                // However, we only need to update min_r[x] because we are iterating x from 0 to n-1.
                // The final min_r[l] will be min(min_r[l], min_r[l+1]) after this loop.
                min_r[x] = std::min(min_r[x], x + 2 * k);
                // Optimization: If k is small, we might find a triplet quickly.
                // The problem statement implies k can be up to n.
                // However, for s_x = s_{x+k} = s_{x+2k}, the maximum k is (n-1-x)/2.
                // For small k, like k=1, k=2, k=3, k=4, we can check them first.
                // If we find a triplet with small k, it gives a smaller x+2k, which is better.
                // The maximum k for which a triplet can exist is (n-1-x)/2.
                // For example, if n=300000, x=0, k can be up to 149999.
                // This nested loop is O(N^2), which is too slow for N=300000.
                // N^2 = 9 * 10^10.
                // We need a faster way to find the minimum x+2k for each x.

                // The constraint on k is actually quite small for the problem.
                // If k is large, say k > 8, then x+2k will be large.
                // If x+2k is large, then min_r[x] will be large.
                // The crucial observation is that if a triplet (x, x+k, x+2k) exists,
